/* AUTO-GENERATED — Virginia Special Requirements bank (lazy-loaded by the CDL app). */
window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["VA"] = {"code":"VA","name":"Virginia","agency":"Virginia DMV","agencyShort":"DMV","handbook":"https://www.dmv.virginia.gov/licenses-ids/cdl/manual","links":{},"en":[{"q":"What is the maximum total outside width allowed for a vehicle and its load on Virginia highways (excluding mirrors)?","options":["96 inches","100 inches","102 inches","108 inches"],"answer":2,"explanation":"Virginia Code 46.2-1105 sets the maximum total outside width of a vehicle, including any load, at 102 inches (8 feet 6 inches), excluding mirrors and certain school-bus warning devices. Source: Code of Virginia 46.2-1105; Virginia CDL Manual / DMV 109.","handbook":"","hbref":""},{"q":"What is the maximum height allowed for a loaded or unloaded vehicle on Virginia highways?","options":["13 feet","13 feet 6 inches","14 feet","12 feet 6 inches"],"answer":1,"explanation":"Virginia Code 46.2-1110 prohibits any loaded or unloaded vehicle from exceeding a height of 13 feet 6 inches. Source: Code of Virginia 46.2-1110; Virginia DMV 109.","handbook":"","hbref":""},{"q":"On Virginia highways, what is the maximum single-axle weight allowed?","options":["18,000 pounds","20,000 pounds","22,400 pounds","24,000 pounds"],"answer":1,"explanation":"Virginia Code 46.2-1124 limits the single-axle weight of any vehicle or combination to 20,000 pounds. Source: Code of Virginia 46.2-1124; Virginia DMV 109.","handbook":"","hbref":""},{"q":"What is the maximum tandem-axle weight allowed on Virginia highways?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"answer":1,"explanation":"Virginia Code 46.2-1125 limits the tandem-axle weight of any vehicle or combination to 34,000 pounds. Source: Code of Virginia 46.2-1125; Virginia DMV 109.","handbook":"","hbref":""},{"q":"What is the maximum gross weight, regardless of axle spacing, allowed on Virginia interstate highways?","options":["73,280 pounds","76,000 pounds","80,000 pounds","90,000 pounds"],"answer":2,"explanation":"Virginia Code 46.2-1127 prohibits a gross weight, regardless of axle spacing, in excess of 80,000 pounds on interstate highways in the Commonwealth. Source: Code of Virginia 46.2-1127.","handbook":"","hbref":""},{"q":"On Virginia interstate highways, the single-axle and tandem-axle weight limits are, respectively:","options":["20,000 lb and 34,000 lb","18,000 lb and 32,000 lb","22,000 lb and 36,000 lb","20,000 lb and 40,000 lb"],"answer":0,"explanation":"Virginia Code 46.2-1127 sets the interstate single-axle limit at 20,000 pounds and the tandem-axle limit at 34,000 pounds, matching the general-highway limits. Source: Code of Virginia 46.2-1127.","handbook":"","hbref":""},{"q":"What is the maximum length for a single semitrailer operated in a tractor-truck/semitrailer combination on Virginia highways generally?","options":["45 feet","48 feet","53 feet","57 feet"],"answer":1,"explanation":"Virginia Code 46.2-1112 limits a semitrailer in a tractor-truck/semitrailer combination to 48 feet, though 53-foot semitrailers are permitted on the interstate system and certain qualifying highways. Source: Code of Virginia 46.2-1112; Virginia DMV hauling guidance.","handbook":"","hbref":""},{"q":"On Virginia's interstate system, a semitrailer is allowed a maximum length of up to:","options":["48 feet","50 feet","53 feet","60 feet"],"answer":2,"explanation":"Under Virginia Code 46.2-1112, semitrailers of up to 53 feet are allowed on the interstate system (and qualifying highways) when the kingpin-to-rearmost-axle distance does not exceed the prescribed limit; the general-highway baseline is 48 feet. Source: Code of Virginia 46.2-1112.","handbook":"","hbref":""},{"q":"In a double-trailer (twin) combination on Virginia highways, what is the maximum length of each individual trailer or semitrailer?","options":["27 feet","28 feet","28 1/2 feet","30 feet"],"answer":2,"explanation":"Virginia Code 46.2-1112 provides that no individual semitrailer or trailer in a combination shall exceed 28 1/2 feet in length. Source: Code of Virginia 46.2-1112; Virginia DMV 109.","handbook":"","hbref":""},{"q":"What is the general maximum length for a coupled vehicle/trailer combination on Virginia highways (excluding the special tractor-semitrailer exceptions)?","options":["60 feet","65 feet","70 feet","75 feet"],"answer":1,"explanation":"Virginia Code 46.2-1112 sets a general 65-foot maximum for coupled (combination) vehicles, with specific exceptions for tractor-semitrailer combinations on designated highways. Source: Code of Virginia 46.2-1112.","handbook":"","hbref":""},{"q":"On Virginia highways, what is the maximum length of a single motor vehicle (a straight/single-unit truck, other than buses and motor homes)?","options":["35 feet","40 feet","45 feet","48 feet"],"answer":1,"explanation":"Virginia Code 46.2-1112 prohibits operating a single motor vehicle longer than 40 feet on a highway (buses and motor homes have separate provisions). Source: Code of Virginia 46.2-1112; Virginia DMV hauling guidance.","handbook":"","hbref":""},{"q":"How does Virginia determine the maximum allowable gross weight under its bridge formula (Code 46.2-1126)?","options":["Solely by the registered weight on the vehicle's title","By the number of axles and the distance between the first and last axle","By the engine horsepower and tire rating","By the total cargo volume in cubic feet"],"answer":1,"explanation":"Virginia Code 46.2-1126 provides a table (the federal bridge formula as applied in Virginia) that sets maximum gross weight based on the number of axles and the distance between the extreme (first and last) axles. Source: Code of Virginia 46.2-1126.","handbook":"","hbref":""},{"q":"Under Virginia's gross-weight table (Code 46.2-1126), what is the highest gross weight the table permits regardless of how favorable the axle spacing is?","options":["76,000 pounds","80,000 pounds","84,000 pounds","88,000 pounds"],"answer":1,"explanation":"Virginia Code 46.2-1126's table caps the maximum gross weight at 80,000 pounds (the top value, applying to a 7-axle vehicle at full spacing); 80,000 pounds is also the absolute statutory ceiling under 46.2-1127. Source: Code of Virginia 46.2-1126 and 46.2-1127.","handbook":"","hbref":""},{"q":"A truck whose dimensions, reduced to the smallest practical configuration, still exceed Virginia's legal size or weight limits must do what before traveling on Virginia highways?","options":["Pay a flat overweight fine at the next weigh station","Obtain a hauling (oversize/overweight) permit in advance","Register the vehicle as a farm vehicle","Travel only between midnight and 5 a.m."],"answer":1,"explanation":"Virginia requires that if a vehicle reduced to its smallest practical dimensions still exceeds legal limits, the operator must obtain a hauling permit before traveling on the Commonwealth's highways. Source: Virginia Code Article 18 (46.2-1139 et seq.); Virginia DMV Hauling Permits.","handbook":"","hbref":""},{"q":"Which Virginia agency issues oversize/overweight hauling permits?","options":["The Virginia State Police","The Virginia Department of Transportation only","The Virginia Department of Motor Vehicles","The local sheriff's office"],"answer":2,"explanation":"The Virginia Department of Motor Vehicles issues oversize/overweight hauling permits; they are ordered through the state's automated online hauling permit system. Source: Virginia DMV Hauling Permits; Code of Virginia Article 18.","handbook":"","hbref":""},{"q":"How are Virginia oversize/overweight hauling permits typically obtained?","options":["By mailing a paper form to Richmond","Through the DMV's online automated hauling permit system","In person only, at a DMV customer service center","By calling the Virginia State Police dispatch line"],"answer":1,"explanation":"Virginia hauling permits are ordered through the DMV's automated online hauling permit system (current portal at ezhaulvirginia.com), which replaced the older VAHPS. Source: Virginia DMV Hauling Permits.","handbook":"","hbref":""},{"q":"A permit issued under Virginia Code 46.2-1129 for hauling Virginia-grown farm or forest products extends the single-axle, tandem-axle, and gross-weight limits by what percentage?","options":["Three percent","Five percent","Ten percent","Fifteen percent"],"answer":1,"explanation":"Virginia Code 46.2-1129 allows a permit extending the single-axle, tandem-axle, and gross-weight limits by five percent each for certain vehicles hauling Virginia-grown farm or forest products. Source: Code of Virginia 46.2-1129.","handbook":"","hbref":""},{"q":"Under the farm/forest-products weight extension in Virginia Code 46.2-1129, a permit may not authorize a gross weight exceeding:","options":["80,000 pounds","82,000 pounds","84,000 pounds","90,000 pounds"],"answer":2,"explanation":"Virginia Code 46.2-1129 provides that no such permit shall authorize operation of a motor vehicle whose gross weight exceeds 84,000 pounds. Source: Code of Virginia 46.2-1129.","handbook":"","hbref":""},{"q":"Does the five-percent farm/forest-products weight extension under Virginia Code 46.2-1129 apply on the interstate highway system?","options":["Yes, up to 84,000 pounds on interstates","No; interstate limits remain 20,000/34,000/80,000 pounds","Yes, but only with a State Police escort","Yes, up to 88,000 pounds on interstates"],"answer":1,"explanation":"The farm/forest-products extension does not raise interstate limits; Virginia Code 46.2-1127 keeps interstate caps at 20,000 lb single axle, 34,000 lb tandem axle, and 80,000 lb gross regardless of axle spacing. Source: Code of Virginia 46.2-1129 and 46.2-1127.","handbook":"","hbref":""},{"q":"In Virginia, exceeding which width threshold means a load is oversize and requires a hauling permit?","options":["More than 8 feet 0 inches (96 inches)","More than 8 feet 6 inches (102 inches)","More than 9 feet 0 inches (108 inches)","More than 10 feet 0 inches (120 inches)"],"answer":1,"explanation":"Virginia's legal width is 8 feet 6 inches (102 inches) per Code 46.2-1105; any load wider than 8 feet 6 inches is oversize and requires a DMV hauling permit. Source: Code of Virginia 46.2-1105; Virginia DMV Hauling Permits.","handbook":"","hbref":""},{"q":"In Virginia, which CDL class is required to operate a single vehicle with a gross vehicle weight rating (GVWR) of 26,001 pounds or more that is not towing a trailer over 10,000 pounds?","options":["Class A","Class B","Class C","Class D"],"answer":1,"explanation":"Virginia DMV defines a Class B CDL as any single vehicle with a GVWR of 26,001 pounds or more, or such a vehicle towing a unit not over 10,000 pounds GVWR. Source: Virginia DMV, CDL Classifications, Endorsements and Restrictions (dmv.virginia.gov/licenses-ids/cdl/class).","handbook":"","hbref":""},{"q":"Under Virginia rules, a Class A CDL is required for any combination of vehicles with a gross combination weight rating (GCWR) of 26,001 pounds or more, provided the vehicle being towed has a GVWR of more than what amount?","options":["5,000 pounds","8,000 pounds","10,000 pounds","15,000 pounds"],"answer":2,"explanation":"Virginia DMV defines Class A as a combination with a GCWR of 26,001+ pounds where the towed unit(s) exceed 10,000 pounds GVWR. Source: Virginia DMV, CDL Classifications, Endorsements and Restrictions (dmv.virginia.gov/licenses-ids/cdl/class).","handbook":"","hbref":""},{"q":"A Virginia driver operates a vehicle that does not meet Class A or B weight thresholds but is designed to transport 16 or more passengers including the driver. Which CDL class applies?","options":["Class A","Class B","Class C","No CDL is required"],"answer":2,"explanation":"Virginia DMV defines Class C as any vehicle not meeting Class A or B that either transports 16 or more occupants (including the driver) or carries hazardous materials requiring placards. Source: Virginia DMV, CDL Classifications, Endorsements and Restrictions (dmv.virginia.gov/licenses-ids/cdl/class).","handbook":"","hbref":""},{"q":"Which Virginia CDL endorsement permits the holder to drive a tank vehicle?","options":["Endorsement N","Endorsement T","Endorsement H","Endorsement P"],"answer":0,"explanation":"Virginia DMV assigns the N endorsement for tank (tanker) vehicles. The H endorsement is for hazardous materials, T for doubles/triples, and P for passenger vehicles. Source: Virginia DMV, CDL Classifications, Endorsements and Restrictions (dmv.virginia.gov/licenses-ids/cdl/class).","handbook":"","hbref":""},{"q":"Which Virginia CDL endorsement is required to drive a vehicle towing double or triple trailers?","options":["Endorsement P","Endorsement N","Endorsement T","Endorsement S"],"answer":2,"explanation":"Virginia DMV assigns the T endorsement to permit driving a vehicle towing a double or triple trailer. Source: Virginia DMV, CDL Classifications, Endorsements and Restrictions (dmv.virginia.gov/licenses-ids/cdl/class).","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a Virginia CDL valid only for intrastate (within Virginia) driving?","options":["16 years old","18 years old","21 years old","25 years old"],"answer":1,"explanation":"Virginia DMV requires an applicant to be at least 18 years of age for an intrastate CDL and at least 21 for an interstate CDL. Source: Virginia DMV, CDL Skills Test Eligibility Requirements (dmv.virginia.gov/licenses-ids/cdl/eligibility).","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a Virginia CDL that is valid for interstate (across state lines) operation?","options":["18 years old","19 years old","20 years old","21 years old"],"answer":3,"explanation":"Virginia DMV requires an applicant to be at least 21 years of age for an interstate CDL; 18 is the minimum for an intrastate-only CDL. Source: Virginia DMV, CDL Skills Test Eligibility Requirements (dmv.virginia.gov/licenses-ids/cdl/eligibility).","handbook":"","hbref":""},{"q":"Before taking the CDL skills test, a Virginia applicant must generally have held a Commercial Learner's Permit (CLP) for a minimum of how many days?","options":["7 days","10 days","14 days","30 days"],"answer":2,"explanation":"Per the federal standard adopted by Virginia, an applicant must hold the CLP for a minimum of 14 days before taking the skills test (unless they held a prior CDL or completed approved training). Source: Virginia DMV, CDL Skills Test Eligibility Requirements / Commercial Learner's Permit (dmv.virginia.gov/licenses-ids/cdl/eligibility).","handbook":"","hbref":""},{"q":"When driving a commercial vehicle on a Virginia Commercial Learner's Permit (CLP), the permit holder must be accompanied by whom?","options":["Any licensed adult over 21","A person holding a valid CDL for the same type of vehicle","A DMV examiner only","No one; solo driving is allowed"],"answer":1,"explanation":"Virginia DMV states a CLP allows operation of a commercial vehicle only when a person licensed to drive the same type of vehicle (a valid CDL holder for that class/type) is physically present with the permit holder. Source: Virginia DMV, Commercial Learner's Permit (dmv.virginia.gov/licenses-ids/cdl/permit).","handbook":"","hbref":""},{"q":"Which document or check is uniquely required to obtain a Virginia HazMat (H) endorsement that is NOT required for other endorsements?","options":["A fingerprint-based TSA security threat assessment","A second vision screening","An employer sponsorship letter","A notarized driving log"],"answer":0,"explanation":"Virginia DMV requires HazMat (HME) applicants to complete a fingerprint-based background check; DMV forwards the information to the TSA, which performs the security threat assessment and approves or denies the endorsement. Source: Virginia DMV, Hazardous Materials Endorsement (HME) (dmv.virginia.gov/licenses-ids/cdl/hazmat).","handbook":"","hbref":""},{"q":"How long is the fingerprint-based background check for a Virginia HazMat (H) endorsement valid?","options":["1 year","3 years","5 years","10 years"],"answer":2,"explanation":"Virginia DMV states the fingerprint-based background check for the HazMat endorsement is valid for up to five years, after which it must be renewed. Source: Virginia DMV, Hazardous Materials Endorsement (HME) (dmv.virginia.gov/licenses-ids/cdl/hazmat).","handbook":"","hbref":""},{"q":"A Virginia applicant who holds a valid TWIC (Transportation Worker Identification Credential) receives what benefit when applying for a HazMat endorsement?","options":["The knowledge exam is waived","A reduced fee and no new fingerprinting","Automatic approval without TSA review","A lifetime endorsement that never expires"],"answer":1,"explanation":"Virginia DMV charges TWIC holders a reduced non-refundable HazMat fee ($41 versus $83) and does not require new fingerprinting, since TWIC already involves a comparable TSA threat assessment. Source: Virginia DMV, Hazardous Materials Endorsement / Applying for a CDL (dmv.virginia.gov/licenses-ids/cdl/hazmat).","handbook":"","hbref":""},{"q":"Under the federal Entry-Level Driver Training (ELDT) rule applied in Virginia, training must be completed through a provider listed on which registry before the skills test?","options":["The Virginia DMV Approved Schools List","The FMCSA Training Provider Registry (TPR)","The National CDL Academy Directory","The DOT Carrier Safety Index"],"answer":1,"explanation":"ELDT must be completed by a provider listed on the FMCSA Training Provider Registry (TPR); Virginia DMV verifies completion electronically before skills testing. Source: Virginia DMV / FMCSA Entry-Level Driver Training (tpr.fmcsa.dot.gov; dmv.virginia.gov/licenses-ids/cdl/eligibility).","handbook":"","hbref":""},{"q":"Which of the following first-time actions does NOT trigger the federal ELDT training requirement in Virginia?","options":["Obtaining a CDL for the first time","Upgrading a Class B CDL to a Class A CDL","Renewing an existing CDL with the same class and endorsements","Obtaining a Passenger (P) endorsement for the first time"],"answer":2,"explanation":"ELDT is required for first-time CDL applicants, a Class B-to-Class A upgrade, and first-time H, P, or S endorsements. A simple renewal of an existing CDL with no new class or endorsement does not require ELDT. Source: FMCSA Entry-Level Driver Training rule, applied by Virginia DMV (fmcsa.dot.gov; dmv.virginia.gov).","handbook":"","hbref":""},{"q":"For a first-time Virginia HazMat applicant, when must the theory portion of ELDT be completed?","options":["After passing the HazMat knowledge exam","Before taking the HazMat knowledge exam at DMV","Only after the TSA approves the background check","Within 30 days after the endorsement is issued"],"answer":1,"explanation":"Under the ELDT rule applied in Virginia, first-time HazMat (H) endorsement applicants must complete the ELDT theory training before taking the HazMat knowledge exam at DMV. Source: FMCSA ELDT rule / Virginia DMV (fmcsa.dot.gov; dmv.virginia.gov/licenses-ids/cdl).","handbook":"","hbref":""},{"q":"How many medical self-certification categories must a Virginia CDL applicant choose from regarding their type of commercial motor vehicle operation?","options":["Two","Three","Four","Five"],"answer":2,"explanation":"Virginia DMV requires applicants to self-certify to one of four categories: excepted interstate, non-excepted interstate, excepted intrastate, or non-excepted intrastate. Source: Virginia DMV, Apply for a CDL or CLP (dmv.virginia.gov/licenses-ids/cdl/applying).","handbook":"","hbref":""},{"q":"A Virginia CDL applicant who drives across state lines and is NOT exempt from federal physical qualification rules should self-certify under which category?","options":["Excepted interstate","Non-excepted interstate","Excepted intrastate","Non-excepted intrastate"],"answer":1,"explanation":"A driver operating in interstate commerce who must meet federal medical qualification standards self-certifies as 'non-excepted interstate' and must maintain a valid medical examiner's certificate. Source: Virginia DMV, Apply for a CDL or CLP, medical self-certification (dmv.virginia.gov/licenses-ids/cdl/applying).","handbook":"","hbref":""},{"q":"A first-time Virginia CDL applicant who has never held a Virginia license must provide proof of identity, proof of legal presence, a Social Security number, and how many proofs of Virginia residency?","options":["One proof of residency","Two proofs of residency","Three proofs of residency","Residency proof is not required"],"answer":1,"explanation":"Virginia DMV requires a first-time applicant who has never held a Virginia license/ID to present one proof of identity, one proof of legal presence, one proof of Social Security number, and two proofs of Virginia residency. Source: Virginia DMV, Apply for a CDL or CLP (dmv.virginia.gov/licenses-ids/cdl/applying).","handbook":"","hbref":""},{"q":"An individual required to register with Virginia's Sex Offender and Crimes Against Minors Registry is ineligible for which CDL endorsement while registration is required?","options":["N (Tanker)","T (Doubles/Triples)","S (School Bus)","H (HazMat)"],"answer":2,"explanation":"Virginia prohibits issuance of the S (School Bus) endorsement to anyone required to register with the Sex Offender and Crimes Against Minors Registry during any period registration is required. Source: Virginia DMV, CDL Classifications, Endorsements and Restrictions (dmv.virginia.gov/licenses-ids/cdl/class).","handbook":"","hbref":""},{"q":"On a Virginia CDL or CLP, which restriction code indicates the holder may NOT operate a vehicle equipped with air brakes?","options":["Restriction E","Restriction L","Restriction K","Restriction B"],"answer":1,"explanation":"Virginia DMV applies the L restriction (no air brakes) when the applicant does not pass the air brake knowledge test or tests in a vehicle without air brakes. Restriction E is no manual transmission, K is Virginia/intrastate only, and B is corrective lenses. Source: Virginia DMV, CDL Classifications, Endorsements and Restrictions (dmv.virginia.gov/licenses-ids/cdl/class).","handbook":"","hbref":""},{"q":"In Virginia, what is the maximum blood alcohol concentration (BAC) at which a person may legally operate a commercial motor vehicle (CMV)?","options":["0.02","0.04","0.08","0.10"],"answer":1,"explanation":"Virginia disqualifies a CDL holder who operates a CMV with a BAC of 0.04 or higher — half the 0.08 limit for ordinary drivers. Source: Virginia DMV CDL Disqualifications page; Va. Code § 46.2-341.24.","handbook":"","hbref":""},{"q":"Under Virginia's implied-consent law for commercial drivers, by operating a CMV on a Virginia highway a driver is deemed to have agreed to what?","options":["A vehicle safety inspection at any weigh station","Chemical testing of blood and/or breath if lawfully arrested for a DUI offense","A mandatory drug screening before every shift","Random questioning by any law-enforcement officer"],"answer":1,"explanation":"Virginia's implied-consent statute provides that anyone operating a CMV on a highway has consented to give blood, breath, or both for chemical testing of alcohol/drug content if arrested for an offense under § 46.2-341.24, taken within three hours of the offense. Source: Va. Code § 46.2-341.26:2; Virginia DMV CDL manual.","handbook":"","hbref":""},{"q":"A Virginia CDL holder is convicted of a first major offense (such as a CMV DUI) while NOT carrying placarded hazardous materials. What is the disqualification period?","options":["60 days","6 months","1 year","3 years"],"answer":2,"explanation":"A first major offense (DUI, BAC 0.04+, test refusal, leaving the scene, etc.) results in a 1-year CDL disqualification in Virginia. Source: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 1, applied as the Virginia rule.","handbook":"","hbref":""},{"q":"If a Virginia driver commits a first major offense while operating a CMV that is transporting hazardous materials requiring placards, the disqualification period increases to:","options":["1 year","2 years","3 years","5 years"],"answer":2,"explanation":"A first major offense committed while transporting placarded hazardous materials raises the disqualification from 1 year to 3 years. Source: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"What is the CDL disqualification in Virginia for a second major offense (for example, a second CMV DUI conviction)?","options":["3 years","5 years","10 years","Lifetime"],"answer":3,"explanation":"A second major offense results in a lifetime CDL disqualification in Virginia, though reinstatement may be possible after 10 years under certain conditions. Source: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"A Virginia CDL holder refuses to submit to a required blood or breath test after being lawfully arrested for operating a CMV under the influence. How is this treated for CDL disqualification?","options":["It is only a serious traffic violation (60 days)","It is a major offense, carrying a 1-year first-offense disqualification","It carries no CDL disqualification, only a fine","It results in an automatic lifetime disqualification on the first refusal"],"answer":1,"explanation":"Refusing the chemical test is a major offense, disqualifying the driver for 1 year on a first offense (3 years if placarded hazmat) — the same as a DUI conviction. Source: Virginia DMV CDL Disqualifications; Va. Code § 46.2-341.26:2; 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"Which of the following is classified by Virginia as a 'serious traffic violation' for a CDL holder?","options":["Parking a CMV in a no-parking zone","Speeding 15 mph or more above the posted speed limit","An expired vehicle registration sticker","Failing to carry proof of insurance"],"answer":1,"explanation":"Virginia lists speeding 15 mph or more above the limit as a serious traffic violation, along with reckless driving, improper/erratic lane change, following too closely, texting while driving a CMV, and traffic offenses tied to a fatal crash. Source: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 2.","handbook":"","hbref":""},{"q":"How many days is a Virginia CDL holder disqualified for being convicted of TWO serious traffic violations (in separate incidents) within a 3-year period?","options":["30 days","60 days","90 days","120 days"],"answer":1,"explanation":"Two serious traffic violations within 3 years result in a 60-day CDL disqualification in Virginia. Source: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 2.","handbook":"","hbref":""},{"q":"A Virginia CDL holder is convicted of THREE serious traffic violations (separate incidents) within a 3-year period. What is the disqualification?","options":["60 days","90 days","120 days","180 days"],"answer":2,"explanation":"Three or more serious traffic violations within 3 years result in a 120-day CDL disqualification in Virginia. Source: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 2.","handbook":"","hbref":""},{"q":"The serious-traffic-violation disqualifications (60 / 120 days) apply only when the violations are counted within what time window?","options":["1 year","3 years","5 years","10 years"],"answer":1,"explanation":"Serious traffic violations are counted within a 3-year period for purposes of the 2-violation (60-day) and 3-violation (120-day) disqualifications. Source: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 2.","handbook":"","hbref":""},{"q":"What is the disqualification for a Virginia CDL holder's FIRST railroad-highway grade crossing violation while operating a CMV?","options":["30 days","60 days","120 days","1 year"],"answer":1,"explanation":"A first railroad-crossing violation results in a disqualification of no less than 60 days. Source: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 3.","handbook":"","hbref":""},{"q":"A Virginia CDL holder commits a SECOND railroad-highway grade crossing violation within 3 years. What is the disqualification?","options":["60 days","120 days","180 days","1 year"],"answer":1,"explanation":"A second railroad-crossing violation within 3 years results in a disqualification of no less than 120 days. Source: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 3.","handbook":"","hbref":""},{"q":"A Virginia CDL holder commits a THIRD railroad-highway grade crossing violation within 3 years. What is the disqualification?","options":["120 days","180 days","1 year","3 years"],"answer":2,"explanation":"A third or subsequent railroad-crossing violation within 3 years results in a disqualification of no less than 1 year. Source: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 3.","handbook":"","hbref":""},{"q":"What is the minimum disqualification in Virginia for a CDL holder's FIRST conviction of violating an out-of-service (OOS) order while driving a CMV?","options":["90 days","120 days","180 days","1 year"],"answer":2,"explanation":"Virginia disqualifies a driver no less than 180 days (up to 1 year) for a first out-of-service-order violation. Source: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 4.","handbook":"","hbref":""},{"q":"Compared with violating an out-of-service order while carrying ordinary cargo, a Virginia CDL driver who violates an OOS order while transporting placarded hazardous materials or 16+ passengers faces:","options":["A lower minimum disqualification","The same minimum but a higher maximum disqualification","No additional penalty","Only a monetary fine"],"answer":1,"explanation":"An OOS-order violation while transporting placarded hazmat or designed-for-16+-passenger loads keeps the 180-day minimum but raises the first-offense maximum to 2 years (versus 1 year for general cargo). Source: 49 CFR 383.51 Table 4, applied as the Virginia rule; Virginia DMV CDL Disqualifications.","handbook":"","hbref":""},{"q":"Under Virginia law, a CDL driver who texts or uses a handheld mobile telephone while driving a CMV may be assessed a civil penalty not to exceed:","options":["$250","$1,000","$2,750","$5,000"],"answer":2,"explanation":"Va. Code § 46.2-341.20:5 prohibits a CMV driver from texting or using a handheld mobile telephone and authorizes a civil penalty of up to $2,750; such a conviction is also a serious traffic violation for CDL purposes. Source: Va. Code § 46.2-341.20:5; Virginia DMV CDL Disqualifications.","handbook":"","hbref":""},{"q":"Conviction for texting while operating a commercial motor vehicle in Virginia is treated for CDL purposes as a:","options":["Major offense (1-year disqualification)","Serious traffic violation","Out-of-service order violation","Non-reportable infraction"],"answer":1,"explanation":"Texting while driving a CMV is listed among Virginia's serious traffic violations, so repeat convictions count toward the 2-in-3-years (60-day) and 3-in-3-years (120-day) disqualifications. Source: Virginia DMV CDL Disqualifications; Va. Code § 46.2-341.20:5; 49 CFR 383.51 Table 2.","handbook":"","hbref":""},{"q":"At what speed over the limit does ordinary speeding become 'reckless driving' under Virginia's general reckless-driving-by-speed statute (a charge that is also a CDL serious violation)?","options":["10 mph over the limit","15 mph over the limit","20 mph over the limit, or any speed over 85 mph","25 mph over the limit, or any speed over 90 mph"],"answer":2,"explanation":"Va. Code § 46.2-862 defines reckless driving by speed as 20 mph or more over the limit, or in excess of 85 mph regardless of the limit; reckless driving is also a CDL serious traffic violation (separate from the 15-mph-over serious-violation threshold). Source: Va. Code § 46.2-862; Virginia DMV CDL Disqualifications.","handbook":"","hbref":""},{"q":"A Virginia CDL holder is convicted of using a CMV in the commission of a felony involving the manufacturing, distributing, or dispensing of a controlled substance. What is the disqualification?","options":["1 year","3 years","10 years","Lifetime with no possibility of 10-year reinstatement"],"answer":3,"explanation":"Using a CMV to manufacture, distribute, or dispense controlled substances is a major offense carrying a lifetime disqualification that is NOT eligible for the 10-year reinstatement available to other lifetime disqualifications. Source: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"A CDL holder's disqualification for a CMV DUI in Virginia primarily affects which driving privilege?","options":["Only the privilege to operate motorcycles","The commercial (CDL) driving privilege","Only out-of-state driving privileges","Boating and watercraft privileges"],"answer":1,"explanation":"CDL disqualification removes the privilege to operate commercial motor vehicles; a separate license suspension may also apply, but the disqualification specifically targets the CDL/commercial driving privilege. Source: Virginia DMV CDL Disqualifications; Va. Code § 46.2-341.18.","handbook":"","hbref":""},{"q":"Under Virginia's Move Over law, on how many lanes must a highway have (and in which configuration) before the duty to change lanes for a stopped, flashing emergency vehicle applies?","options":["At least four lanes, with at least two lanes for traffic moving in the same direction as the driver","Any two-lane undivided highway","At least six lanes, three in each direction","Only on posted interstate highways"],"answer":0,"explanation":"Code of Virginia 46.2-861.1 (Virginia's Move Over law) requires drivers on roadways with at least four lanes, two of which carry traffic in the same direction, to change lanes away from a stationary emergency vehicle displaying flashing warning lights; if a safe lane change is not possible, the driver must reduce speed and proceed with caution. Source: Code of Virginia 46.2-861.1.","handbook":"","hbref":""},{"q":"In Virginia, when a driver cannot safely change lanes away from a stopped emergency vehicle showing flashing lights, what must the driver do instead?","options":["Proceed with caution and reduce speed below the posted limit","Stop completely until the emergency vehicle leaves","Sound the horn and maintain the posted speed","Activate hazard flashers and continue at normal speed"],"answer":0,"explanation":"Under Code of Virginia 46.2-861.1, if a lane change cannot be made safely, the driver must proceed with due caution and maintain a safe speed for highway conditions, reducing speed to protect emergency personnel at the scene. A violation is charged as reckless driving (Class 1 misdemeanor). Source: Code of Virginia 46.2-861.1.","handbook":"","hbref":""},{"q":"In Virginia, a violation of the Move Over law (failure to move over or slow for a stopped emergency vehicle) is charged as what?","options":["Reckless driving, a Class 1 misdemeanor","A non-moving civil infraction","A simple traffic infraction with no points","A felony if no injury occurs"],"answer":0,"explanation":"Code of Virginia 46.2-861.1 makes failure to yield or move over for a stationary emergency vehicle a form of reckless driving, which is a Class 1 misdemeanor carrying possible jail time, fines up to $2,500, and license suspension. Source: Code of Virginia 46.2-861.1.","handbook":"","hbref":""},{"q":"On Virginia's non-limited-access (non-interstate) highways, what is the maximum speed limit for a tractor-trailer or truck designed to transport property, absent posted exceptions?","options":["45 mph","55 mph","60 mph","65 mph"],"answer":0,"explanation":"Code of Virginia 46.2-870 sets the default limit on non-limited-access highways at 55 mph for passenger vehicles and buses but only 45 mph for trucks, tractor trucks, and combinations designed to transport property, i.e., 10 mph less than passenger vehicles. Source: Code of Virginia 46.2-870.","handbook":"","hbref":""},{"q":"On a Virginia interstate highway, what is the maximum speed limit for a commercial truck where the higher limit is posted after a traffic engineering study?","options":["70 mph, the same as for passenger vehicles","55 mph, while cars may go 70 mph","65 mph for trucks only","75 mph"],"answer":0,"explanation":"Code of Virginia 46.2-870 sets the interstate maximum at 55 mph, or 70 mph where lawfully posted signs are erected following an engineering study. On interstates the higher posted limit applies to all vehicles, including trucks; Virginia does not impose a separate lower truck speed limit on interstates. Source: Code of Virginia 46.2-870.","handbook":"","hbref":""},{"q":"At a railroad grade crossing in Virginia, a placarded hazardous-materials vehicle or a bus carrying passengers for hire must stop within what distance of the nearest rail?","options":["Within 50 feet but not less than 15 feet","Within 100 feet but not less than 25 feet","Within 30 feet but not less than 10 feet","Within 15 feet but not less than 5 feet"],"answer":0,"explanation":"Code of Virginia 46.2-886 requires vehicles carrying passengers for hire or carrying explosive substances or flammable liquids as cargo to stop within 50 feet but not less than 15 feet from the nearest rail, then look and listen before proceeding. This matches the Virginia CDL Manual railroad-crossing rule. Source: Code of Virginia 46.2-886; Virginia CDL Manual.","handbook":"","hbref":""},{"q":"After stopping at a railroad crossing, what does Virginia law require regarding gear changes while the vehicle is on the tracks?","options":["The driver must cross in a gear that requires no gear change while on the tracks","The driver should downshift to the lowest gear midway across","The driver may shift freely as long as speed is maintained","The driver must shift to neutral while crossing"],"answer":0,"explanation":"Code of Virginia 46.2-886 states that after stopping and upon proceeding, the driver must cross only in such gear that there will be no necessity for changing gears while traversing the crossing, and must not shift gears while crossing. Source: Code of Virginia 46.2-886; Virginia CDL Manual.","handbook":"","hbref":""},{"q":"In Virginia, a motorist approaching a stopped school bus that is loading or unloading children on an undivided two-lane road must do what?","options":["Stop when approaching from any direction and remain stopped until the bus moves or stops flashing","Stop only if traveling in the same direction as the bus","Slow to 20 mph but need not stop","Stop only if children are visibly crossing"],"answer":0,"explanation":"Code of Virginia 46.2-859 requires a driver approaching from any direction to stop for a school bus that is stopped and displaying its warning devices to load or discharge passengers, and to remain stopped until the persons are clear and the bus is again in motion. A violation is reckless driving. Source: Code of Virginia 46.2-859.","handbook":"","hbref":""},{"q":"On a Virginia divided highway, under what condition is an oncoming driver NOT required to stop for a school bus stopped on the opposite roadway?","options":["When the roadways are separated by a physical barrier or an unpaved area","When there is a painted double-yellow center line","When the speed limit is 45 mph or higher","When there is a center turn lane between the roadways"],"answer":0,"explanation":"Code of Virginia 46.2-859 exempts a driver from stopping only when the school bus is on the other roadway of a divided highway (or an access road/driveway) that is separated from the driver's roadway by a physical barrier or an unpaved area. A mere painted line or turn lane does not qualify. Source: Code of Virginia 46.2-859.","handbook":"","hbref":""},{"q":"When a commercial vehicle must stop on a Virginia highway, the driver must place red reflective triangle warning devices within how many minutes of stopping?","options":["Within 10 minutes","Within 5 minutes","Within 15 minutes","Immediately, within 1 minute"],"answer":0,"explanation":"Code of Virginia 46.2-111 requires the operator of a stopped commercial motor vehicle to place the required red reflectorized triangular warning devices within 10 minutes of stopping, keeping hazard flashers on until they are in place. Source: Code of Virginia 46.2-111.","handbook":"","hbref":""},{"q":"For a commercial vehicle stopped on a level, straight Virginia roadway, where must the three warning triangles be placed?","options":["100 ft to the rear, 100 ft to the front, and one at the traffic side within 10 ft of the vehicle","10 ft, 100 ft, and 200 ft all to the rear","50 ft, 100 ft, and 150 ft to the rear only","One on each side and one on the roof"],"answer":0,"explanation":"Code of Virginia 46.2-111 directs placement of one triangle not less than 100 feet in the direction of approaching traffic, one not less than 100 feet in the opposite direction, and one on the traffic side not closer than 10 feet to the front or rear of the vehicle. Source: Code of Virginia 46.2-111.","handbook":"","hbref":""},{"q":"If a Virginia commercial vehicle is stopped within 500 feet of a curve, hilltop, or other obstruction, how should the warning device in that direction be placed?","options":["Far enough to give ample warning, but in no case less than 500 feet from the vehicle","Exactly 100 feet from the vehicle","No farther than 200 feet from the vehicle","Directly on the obstruction itself"],"answer":0,"explanation":"Code of Virginia 46.2-111 requires that where a stop is within 500 feet of a curve, crest of a hill, or other obstruction, the warning device in that direction be placed to afford ample warning, in no case less than 500 feet from the stopped vehicle. Source: Code of Virginia 46.2-111.","handbook":"","hbref":""},{"q":"On Virginia's Interstate 81 and on interstates with more than two lanes in each direction, what lane restriction applies to commercial motor vehicles?","options":["They are prohibited from driving in the left-most lane","They may use only the left-most lane","They must stay within 10 mph of the truck minimum speed","They are restricted to the center lane only"],"answer":0,"explanation":"Code of Virginia 46.2-803.1 prohibits commercial motor vehicles from operating in the left-most lane on I-81 and on interstate highways with more than two travel lanes in each direction (generally where the limit is 65 mph or higher). Buses and vehicles preparing for a left exit are excepted. Source: Code of Virginia 46.2-803.1.","handbook":"","hbref":""},{"q":"On a Virginia laned highway, where must any vehicle traveling slower than the normal speed of traffic be driven?","options":["In the lane nearest the right edge or right curb, except when passing or preparing to turn left","In any lane the driver chooses","In the center lane to balance traffic","In the left lane to stay clear of merging traffic"],"answer":0,"explanation":"Code of Virginia 46.2-804 requires a vehicle proceeding slower than the normal speed of traffic to be driven in the lane nearest the right edge or curb, except when overtaking and passing, preparing for a left turn, or where right lanes are reserved for slow traffic. Source: Code of Virginia 46.2-804.","handbook":"","hbref":""},{"q":"Which Virginia scenic parkways generally prohibit commercial trucks from operating on them?","options":["The George Washington Memorial Parkway and the Colonial Parkway","Interstate 95 and Interstate 64","The Capital Beltway (I-495)","U.S. Route 29 and U.S. Route 58"],"answer":0,"explanation":"The federally administered George Washington Memorial Parkway and the Colonial Parkway in Virginia prohibit commercial trucks; the GW Parkway requires a special National Park Service permit for any commercial vehicle, and the Colonial Parkway bars trucks except passenger buses. Source: National Park Service / VDOT truck-restriction guidance.","handbook":"","hbref":""},{"q":"Certain hazardous-materials classes are prohibited from Virginia's water-proximate tunnels such as the Hampton Roads Bridge-Tunnel. What governs these restrictions?","options":["VDOT regulations governing hazardous materials through bridge-tunnel facilities (24VAC30-61), based on hazard class","Federal interstate weight limits only","The vehicle's gross combination weight rating alone","Whether the load is insured"],"answer":0,"explanation":"Virginia administrative regulation 24VAC30-61 governs transportation of hazardous materials through the state's urban and water-proximate tunnels (Hampton Roads, Monitor-Merrimac, and the Elizabeth River tunnels), prohibiting certain hazard classes such as explosives and poison gases. Source: 24VAC30-61; VDOT Hazardous Materials guidance.","handbook":"","hbref":""},{"q":"Southbound trucks descending the steep Fancy Gap grade on Interstate 77 in Virginia should be especially aware of what safety feature?","options":["Multiple runaway truck escape ramps on the long downgrade","A mandatory truck weigh station at the summit","A tunnel that bans all trucks","A reversible HOV lane"],"answer":0,"explanation":"Interstate 77 climbs over 1,500 feet up Fancy Gap with grades up to about 4.5%; the long southbound descent into North Carolina includes multiple runaway truck escape ramps for vehicles that lose braking. Drivers should select a low gear before descending. Source: VDOT/Virginia CDL Manual mountain-driving guidance.","handbook":"","hbref":""},{"q":"In Virginia, the minimum-speed rule states that a driver shall not operate at a speed so slow as to do what?","options":["Impede or block the normal and reasonable movement of traffic, except when reduced speed is necessary for safety or law","Travel below 40 mph on any highway","Fall more than 5 mph below the posted limit","Cause other drivers to use their horns"],"answer":0,"explanation":"Code of Virginia 46.2-877 prohibits driving at such a slow speed as to impede the normal and reasonable movement of traffic, except when reduced speed is necessary for safe operation or to comply with law. Source: Code of Virginia 46.2-877.","handbook":"","hbref":""},{"q":"Besides the four-lane requirement, Virginia's Move Over duty applies to stationary vehicles displaying warning lights operated by which of the following?","options":["Police, fire, ambulance, VDOT, utility, and tow trucks","Police and ambulances only","Only state police cruisers","Only vehicles owned by VDOT"],"answer":0,"explanation":"Code of Virginia 46.2-861.1 extends the Move Over duty to a broad set of stationary vehicles displaying flashing warning lights, including law-enforcement, fire, ambulance, Virginia Department of Transportation, utility, and towing/recovery vehicles. Source: Code of Virginia 46.2-861.1.","handbook":"","hbref":""},{"q":"As a lesser alternative to reckless driving, Virginia law allows a stopped-school-bus passing violation to be enforced as a civil penalty of what amount, with the vehicle's owner potentially liable?","options":["$250","$50","$1,000","$2,500"],"answer":0,"explanation":"Code of Virginia 46.2-844 provides a civil-penalty alternative of $250 for failing to stop for a stopped school bus, and the registered owner of the vehicle may be held liable when the bus's video-monitoring system captures the violation. The criminal offense under 46.2-859 remains reckless driving. Source: Code of Virginia 46.2-844 and 46.2-859.","handbook":"","hbref":""},{"q":"Which agency issues Commercial Driver's Licenses (CDLs) in Virginia?","options":["The Virginia Department of Motor Vehicles (DMV)","The Federal Motor Carrier Safety Administration (FMCSA)","The Virginia Department of Transportation (VDOT)","The Virginia State Police Motor Carrier Division"],"answer":0,"explanation":"CDLs in Virginia are issued by the Virginia Department of Motor Vehicles (DMV). FMCSA sets federal standards but does not issue licenses, and VDOT handles roads/permits, not licensing. Source: Virginia DMV, Apply for a CDL or CLP.","handbook":"","hbref":""},{"q":"Where must you go to apply for a Virginia CDL or Commercial Learner's Permit (CLP)?","options":["In person at a DMV customer service center","Entirely online through the DMV website","At any FMCSA-approved truck dealership","By mail to the DMV headquarters in Richmond"],"answer":0,"explanation":"Virginia requires you to apply for a CDL or CLP in person at a DMV customer service center; the initial CDL/CLP application cannot be completed entirely online. Source: Virginia DMV, Apply for a CDL or CLP.","handbook":"","hbref":""},{"q":"Federal regulations require every CDL or CLP applicant in Virginia to self-certify to how many categories of commercial motor vehicle operation?","options":["Four","Two","Three","Five"],"answer":0,"explanation":"Anyone holding or applying for a CDL/CLP in Virginia must self-certify to one of four categories of CMV operation. Source: Virginia DMV, CDL Medical Certification Requirements.","handbook":"","hbref":""},{"q":"Which of the following is one of the four self-certification categories used by Virginia DMV?","options":["Non-excepted Interstate (NI)","Restricted Commercial Operation","Intrastate Hazmat Only","Federal Excepted Carrier"],"answer":0,"explanation":"The four categories are Excepted Interstate (EI), Excepted Intrastate (EA), Non-excepted Interstate (NI), and Non-excepted Intrastate (NA). 'Non-excepted Interstate' is a valid category; the others listed are not. Source: Virginia DMV, CDL Medical Certification Requirements.","handbook":"","hbref":""},{"q":"Which self-certification category generally does NOT require the driver to maintain a medical examiner's certificate on file with Virginia DMV?","options":["Excepted Interstate (EI)","Non-excepted Interstate (NI)","Non-excepted Intrastate (NA)","Any interstate category"],"answer":0,"explanation":"Drivers certifying to excepted categories (excepted interstate or excepted intrastate) are not required to provide a medical examiner's certificate; only non-excepted interstate and non-excepted intrastate drivers must. Source: Virginia DMV, CDL Medical Certification Requirements.","handbook":"","hbref":""},{"q":"A driver self-certifying as non-excepted interstate in Virginia must have the physical exam performed by a medical examiner who is:","options":["Listed on FMCSA's National Registry of Certified Medical Examiners","Employed directly by the Virginia DMV","Approved by the Virginia Department of Health","Any licensed physician of the driver's choosing"],"answer":0,"explanation":"Non-excepted drivers must be examined by a medical examiner listed on FMCSA's National Registry of Certified Medical Examiners. Not every licensed physician qualifies. Source: Virginia DMV, CDL Medical Certification Requirements.","handbook":"","hbref":""},{"q":"Effective May 5, 2025, how must a Medical Examiner's Certificate (MEC) be submitted to Virginia DMV?","options":["Electronically by the medical examiner through the FMCSA National Registry portal","By the driver bringing the paper certificate to a DMV office","By the driver uploading a scanned copy to the DMV website","By the driver's employer faxing it to FMCSA"],"answer":0,"explanation":"As of May 5, 2025, Virginia DMV no longer accepts MECs directly from drivers; the medical examiner must submit the certificate electronically through the FMCSA National Registry portal. Source: Virginia DMV, CDL Medical Certification Requirements.","handbook":"","hbref":""},{"q":"To obtain a Virginia CLP, an applicant must at minimum pass which knowledge exam?","options":["The CDL general knowledge exam","The combination vehicles exam only","The air brakes exam only","The hazardous materials exam"],"answer":0,"explanation":"To get a CLP you must pass the CDL general knowledge exam, plus any additional knowledge exams (such as air brakes or tank) for the vehicles you intend to drive. Source: Virginia DMV, Commercial Learner's Permit.","handbook":"","hbref":""},{"q":"After being issued a Virginia CLP, how long must you hold it before you are eligible to take the CDL skills test?","options":["At least 14 days","At least 30 days","At least 7 days","At least 60 days"],"answer":0,"explanation":"Virginia requires a minimum 14-day CLP holding period before taking the skills test. This may be waived with proof of a prior CDL or completion of Entry-Level Driver Training. Source: Virginia DMV, CDL Skills Test Eligibility / Commercial Learner's Permit.","handbook":"","hbref":""},{"q":"How long is a Virginia Commercial Learner's Permit (CLP) valid, and can it be renewed?","options":["Valid for 1 year and cannot be renewed","Valid for 180 days and can be renewed once","Valid for 2 years and renewed annually","Valid for 6 months with unlimited renewals"],"answer":0,"explanation":"A Virginia CLP is valid for 1 year and cannot be renewed; if it expires you must reapply and re-test. Source: Virginia DMV, Commercial Learner's Permit.","handbook":"","hbref":""},{"q":"The Virginia CDL skills test consists of which three parts, performed in order?","options":["Pre-trip inspection, basic vehicle control, and on-road driving","Written knowledge, vision screening, and road test","Air brake check, backing, and highway merging","Coupling/uncoupling, parallel parking, and night driving"],"answer":0,"explanation":"The CDL skills test has three parts: the pre-trip vehicle inspection, basic vehicle control skills, and the on-road driving test, given in that order. Source: FMCSA CDL standard applied in Virginia; Virginia DMV CDL Skills Tests.","handbook":"","hbref":""},{"q":"Who must provide the vehicle used for the Virginia CDL on-road driving test?","options":["The applicant, who must bring a properly registered vehicle of the type they wish to drive","The Virginia DMV, which supplies a test truck","The applicant's ELDT training school only","FMCSA, from its regional inspection fleet"],"answer":0,"explanation":"The applicant must provide a properly registered vehicle representative of the class/type of CDL they are seeking for the on-road test. Source: Virginia DMV, CDL Skills Test Eligibility.","handbook":"","hbref":""},{"q":"When did the federal Entry-Level Driver Training (ELDT) requirement that applies in Virginia take effect?","options":["February 7, 2022","May 5, 2025","January 1, 2020","July 1, 2023"],"answer":0,"explanation":"ELDT requirements became effective February 7, 2022. (May 5, 2025 is the separate date for the electronic MEC submission change.) Source: Virginia DMV, Entry-Level Driver Training.","handbook":"","hbref":""},{"q":"An ELDT training provider used by a Virginia CDL applicant must be:","options":["Listed on FMCSA's Training Provider Registry (TPR)","Certified only by the Virginia DMV","Accredited by the Virginia Board of Education","Any commercial driving school with a business license"],"answer":0,"explanation":"ELDT must be completed through a provider listed on FMCSA's Training Provider Registry (TPR). A general business license or state-board accreditation is not sufficient. Source: Virginia DMV, Entry-Level Driver Training.","handbook":"","hbref":""},{"q":"For a first-time Class A or B applicant in Virginia, when must the ELDT theory and behind-the-wheel training be completed?","options":["Before taking the road skills exam","Before applying for the CLP","Within 30 days after passing the skills test","Before taking the general knowledge exam"],"answer":0,"explanation":"For CDL classes (and P/S endorsements), ELDT theory and behind-the-wheel training must be completed before the road skills exam. (For hazmat, the theory portion must be done before the hazmat knowledge exam.) Source: Virginia DMV, Entry-Level Driver Training.","handbook":"","hbref":""},{"q":"For the hazardous materials (H) endorsement in Virginia, the ELDT theory portion must be completed before:","options":["Taking the hazmat knowledge exam","Taking the on-road skills test","Submitting the self-certification form","The CLP is issued"],"answer":0,"explanation":"Unlike the CDL class training, the hazmat ELDT theory portion must be completed before taking the hazmat knowledge exam (there is no separate hazmat skills test). Source: Virginia DMV, Entry-Level Driver Training.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain an intrastate Virginia CDL versus an interstate CDL?","options":["18 for intrastate and 21 for interstate","21 for intrastate and 25 for interstate","16 for intrastate and 18 for interstate","18 for both intrastate and interstate"],"answer":0,"explanation":"You must be at least 18 to get an intrastate CDL and at least 21 to get an interstate CDL. Source: Virginia DMV, CDL Skills Test Eligibility / Apply for a CDL or CLP.","handbook":"","hbref":""},{"q":"A person applying for a CDL in Virginia who has never held a Virginia driver's license or ID must provide two proofs of which of the following?","options":["Virginia residency","Social Security number","Legal presence","Identity"],"answer":0,"explanation":"First-time Virginia applicants must present one proof of identity, one proof of legal presence, one proof of Social Security number, and two proofs of Virginia residency. Source: Virginia DMV, Apply for a CDL or CLP.","handbook":"","hbref":""},{"q":"For most drivers, how long is a standard Virginia CDL valid before it must be renewed?","options":["8 years, expiring on the holder's birthday","4 years, expiring on the holder's birthday","5 years, expiring at year-end","10 years, expiring on the issue-date anniversary"],"answer":0,"explanation":"A standard Virginia CDL is valid for 8 years and expires on the holder's birthday (drivers age 75 or older receive a 5-year cycle). Source: Virginia DMV, Renew Your CDL.","handbook":"","hbref":""},{"q":"In Virginia, if a CDL has been expired or downgraded for more than one year, what must the holder do to get it back?","options":["Retake both the knowledge exam and the road skills test for that CDL type","Simply pay a late fee and renew online","Retake only the vision screening","Wait an additional 14-day holding period only"],"answer":0,"explanation":"If a Virginia CDL has been expired or downgraded for more than one year, the holder must retake the knowledge exam and the road skills test required for the type of CDL they held. Source: Virginia DMV, Renew Your CDL.","handbook":"","hbref":""}],"ru":{"0":{"q":"Какова максимальная общая внешняя ширина, разрешённая для транспортного средства с грузом на дорогах Вирджинии (без учёта зеркал)?","options":["96 inches","100 inches","102 inches","108 inches"],"explanation":"Кодекс Вирджинии 46.2-1105 устанавливает максимальную общую внешнюю ширину транспортного средства, включая любой груз, равной 102 inches (8 feet 6 inches), без учёта зеркал и некоторых предупреждающих устройств школьных автобусов. Источник: Code of Virginia 46.2-1105; Virginia CDL Manual / DMV 109."},"1":{"q":"Какова максимальная высота, разрешённая для гружёного или негружёного транспортного средства на дорогах Вирджинии?","options":["13 feet","13 feet 6 inches","14 feet","12 feet 6 inches"],"explanation":"Кодекс Вирджинии 46.2-1110 запрещает любому гружёному или негружёному транспортному средству превышать высоту 13 feet 6 inches. Источник: Code of Virginia 46.2-1110; Virginia DMV 109."},"2":{"q":"Какова максимальная нагрузка на одиночную ось, разрешённая на дорогах Вирджинии?","options":["18,000 pounds","20,000 pounds","22,400 pounds","24,000 pounds"],"explanation":"Кодекс Вирджинии 46.2-1124 ограничивает нагрузку на одиночную ось любого транспортного средства или автопоезда величиной 20,000 pounds. Источник: Code of Virginia 46.2-1124; Virginia DMV 109."},"3":{"q":"Какова максимальная нагрузка на сдвоенную ось, разрешённая на дорогах Вирджинии?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"Кодекс Вирджинии 46.2-1125 ограничивает нагрузку на сдвоенную ось любого транспортного средства или автопоезда величиной 34,000 pounds. Источник: Code of Virginia 46.2-1125; Virginia DMV 109."},"4":{"q":"Каков максимальный полный вес, независимо от расстояния между осями, разрешённый на междуштатных автомагистралях Вирджинии?","options":["73,280 pounds","76,000 pounds","80,000 pounds","90,000 pounds"],"explanation":"Кодекс Вирджинии 46.2-1127 запрещает полный вес, независимо от расстояния между осями, превышающий 80,000 pounds на междуштатных автомагистралях Содружества. Источник: Code of Virginia 46.2-1127."},"5":{"q":"На междуштатных автомагистралях Вирджинии пределы нагрузки на одиночную и сдвоенную ось составляют соответственно:","options":["20,000 lb and 34,000 lb","18,000 lb and 32,000 lb","22,000 lb and 36,000 lb","20,000 lb and 40,000 lb"],"explanation":"Кодекс Вирджинии 46.2-1127 устанавливает предел нагрузки на одиночную ось на междуштатных автомагистралях в 20,000 pounds, а на сдвоенную ось — в 34,000 pounds, что совпадает с пределами для обычных дорог. Источник: Code of Virginia 46.2-1127."},"6":{"q":"Какова максимальная длина одиночного полуприцепа, эксплуатируемого в составе автопоезда «тягач/полуприцеп», на дорогах Вирджинии в общем случае?","options":["45 feet","48 feet","53 feet","57 feet"],"explanation":"Кодекс Вирджинии 46.2-1112 ограничивает полуприцеп в составе автопоезда «тягач/полуприцеп» длиной 48 feet, хотя полуприцепы длиной 53-foot разрешены на междуштатной системе автомагистралей и некоторых отвечающих требованиям дорогах. Источник: Code of Virginia 46.2-1112; рекомендации Virginia DMV по перевозкам."},"7":{"q":"На междуштатной системе автомагистралей Вирджинии полуприцепу разрешается максимальная длина до:","options":["48 feet","50 feet","53 feet","60 feet"],"explanation":"Согласно Кодексу Вирджинии 46.2-1112, полуприцепы длиной до 53 feet разрешены на междуштатной системе (и отвечающих требованиям дорогах), когда расстояние от шкворня до самой задней оси не превышает установленного предела; базовый предел для обычных дорог составляет 48 feet. Источник: Code of Virginia 46.2-1112."},"8":{"q":"В составе двойного автопоезда (со сдвоенными прицепами) на дорогах Вирджинии какова максимальная длина каждого отдельного прицепа или полуприцепа?","options":["27 feet","28 feet","28 1/2 feet","30 feet"],"explanation":"Кодекс Вирджинии 46.2-1112 предусматривает, что ни один отдельный полуприцеп или прицеп в составе автопоезда не должен превышать 28 1/2 feet в длину. Источник: Code of Virginia 46.2-1112; Virginia DMV 109."},"9":{"q":"Какова общая максимальная длина сцепленного автопоезда «транспортное средство/прицеп» на дорогах Вирджинии (исключая особые случаи для «тягач/полуприцеп»)?","options":["60 feet","65 feet","70 feet","75 feet"],"explanation":"Кодекс Вирджинии 46.2-1112 устанавливает общий максимум в 65 feet для сцепленных (комбинированных) транспортных средств, с особыми исключениями для автопоездов «тягач/полуприцеп» на установленных дорогах. Источник: Code of Virginia 46.2-1112."},"10":{"q":"На дорогах Вирджинии какова максимальная длина одиночного транспортного средства (прямого/одиночного грузовика, кроме автобусов и автодомов)?","options":["35 feet","40 feet","45 feet","48 feet"],"explanation":"Кодекс Вирджинии 46.2-1112 запрещает эксплуатацию одиночного транспортного средства длиннее 40 feet на дороге (для автобусов и автодомов действуют отдельные положения). Источник: Code of Virginia 46.2-1112; рекомендации Virginia DMV по перевозкам."},"11":{"q":"Как Вирджиния определяет максимально допустимый полный вес по своей мостовой формуле (Кодекс 46.2-1126)?","options":["Исключительно по зарегистрированному весу в свидетельстве о праве собственности на транспортное средство","По количеству осей и расстоянию между первой и последней осью","По мощности двигателя в лошадиных силах и рейтингу шин","По общему объёму груза в кубических футах"],"explanation":"Кодекс Вирджинии 46.2-1126 предусматривает таблицу (федеральную мостовую формулу в применении к Вирджинии), которая устанавливает максимальный полный вес исходя из количества осей и расстояния между крайними (первой и последней) осями. Источник: Code of Virginia 46.2-1126."},"12":{"q":"Согласно таблице полного веса Вирджинии (Кодекс 46.2-1126), каков наибольший полный вес, который таблица допускает независимо от того, насколько благоприятно расстояние между осями?","options":["76,000 pounds","80,000 pounds","84,000 pounds","88,000 pounds"],"explanation":"Таблица Кодекса Вирджинии 46.2-1126 ограничивает максимальный полный вес величиной 80,000 pounds (верхнее значение, применимое к 7-осному транспортному средству при полном расстоянии между осями); 80,000 pounds также является абсолютным законодательным потолком согласно 46.2-1127. Источник: Code of Virginia 46.2-1126 and 46.2-1127."},"13":{"q":"Грузовик, габариты которого, сведённые к наименьшей практически возможной конфигурации, всё ещё превышают законные пределы по размеру или весу в Вирджинии, должен сделать что, прежде чем выехать на дороги Вирджинии?","options":["Уплатить фиксированный штраф за перевес на ближайшей весовой станции","Заранее получить разрешение на перевозку (негабаритный/тяжеловесный груз)","Зарегистрировать транспортное средство как сельскохозяйственное","Передвигаться только между полуночью и 5 a.m."],"explanation":"Вирджиния требует, чтобы, если транспортное средство, сведённое к наименьшим практически возможным габаритам, всё ещё превышает законные пределы, оператор получил разрешение на перевозку, прежде чем выехать на дороги Содружества. Источник: Virginia Code Article 18 (46.2-1139 et seq.); Virginia DMV Hauling Permits."},"14":{"q":"Какое ведомство Вирджинии выдаёт разрешения на перевозку негабаритных/тяжеловесных грузов?","options":["Полиция штата Вирджиния (Virginia State Police)","Только Министерство транспорта Вирджинии (Virginia Department of Transportation)","Министерство транспортных средств Вирджинии (Virginia Department of Motor Vehicles)","Местное управление шерифа"],"explanation":"Министерство транспортных средств Вирджинии (Virginia Department of Motor Vehicles) выдаёт разрешения на перевозку негабаритных/тяжеловесных грузов; они оформляются через автоматизированную онлайн-систему выдачи разрешений на перевозку штата. Источник: Virginia DMV Hauling Permits; Code of Virginia Article 18."},"15":{"q":"Как обычно получают разрешения на перевозку негабаритных/тяжеловесных грузов в Вирджинии?","options":["Отправив бумажную форму по почте в Ричмонд","Через автоматизированную онлайн-систему выдачи разрешений на перевозку DMV","Только лично, в центре обслуживания клиентов DMV","Позвонив на диспетчерскую линию Полиции штата Вирджиния (Virginia State Police)"],"explanation":"Разрешения на перевозку в Вирджинии оформляются через автоматизированную онлайн-систему выдачи разрешений на перевозку DMV (текущий портал ezhaulvirginia.com), которая заменила прежнюю VAHPS. Источник: Virginia DMV Hauling Permits."},"16":{"q":"Разрешение, выданное согласно Кодексу Вирджинии 46.2-1129 для перевозки выращенных в Вирджинии сельскохозяйственных или лесных продуктов, увеличивает пределы нагрузки на одиночную ось, сдвоенную ось и полного веса на какой процент?","options":["Три процента","Пять процентов","Десять процентов","Пятнадцать процентов"],"explanation":"Кодекс Вирджинии 46.2-1129 допускает разрешение, увеличивающее пределы нагрузки на одиночную ось, сдвоенную ось и полного веса на пять процентов каждый для некоторых транспортных средств, перевозящих выращенные в Вирджинии сельскохозяйственные или лесные продукты. Источник: Code of Virginia 46.2-1129."},"17":{"q":"В рамках увеличения веса для сельскохозяйственных/лесных продуктов согласно Кодексу Вирджинии 46.2-1129, разрешение не может санкционировать полный вес, превышающий:","options":["80,000 pounds","82,000 pounds","84,000 pounds","90,000 pounds"],"explanation":"Кодекс Вирджинии 46.2-1129 предусматривает, что никакое такое разрешение не должно санкционировать эксплуатацию транспортного средства, полный вес которого превышает 84,000 pounds. Источник: Code of Virginia 46.2-1129."},"18":{"q":"Применяется ли пятипроцентное увеличение веса для сельскохозяйственных/лесных продуктов согласно Кодексу Вирджинии 46.2-1129 на междуштатной системе автомагистралей?","options":["Да, до 84,000 pounds на междуштатных автомагистралях","Нет; пределы для междуштатных автомагистралей остаются 20,000/34,000/80,000 pounds","Да, но только с сопровождением Полиции штата (State Police)","Да, до 88,000 pounds на междуштатных автомагистралях"],"explanation":"Увеличение для сельскохозяйственных/лесных продуктов не повышает пределы для междуштатных автомагистралей; Кодекс Вирджинии 46.2-1127 сохраняет потолки для междуштатных автомагистралей на уровне 20,000 lb на одиночную ось, 34,000 lb на сдвоенную ось и 80,000 lb полного веса независимо от расстояния между осями. Источник: Code of Virginia 46.2-1129 and 46.2-1127."},"19":{"q":"В Вирджинии превышение какого порога ширины означает, что груз является негабаритным и требует разрешения на перевозку?","options":["Более 8 feet 0 inches (96 inches)","Более 8 feet 6 inches (102 inches)","Более 9 feet 0 inches (108 inches)","Более 10 feet 0 inches (120 inches)"],"explanation":"Законная ширина в Вирджинии составляет 8 feet 6 inches (102 inches) согласно Кодексу 46.2-1105; любой груз шире 8 feet 6 inches является негабаритным и требует разрешения на перевозку от DMV. Источник: Code of Virginia 46.2-1105; Virginia DMV Hauling Permits."},"20":{"q":"В Вирджинии какой класс CDL требуется для управления одиночным транспортным средством с полной разрешённой массой (GVWR) 26,001 pounds или более, которое не буксирует прицеп тяжелее 10,000 pounds?","options":["Class A","Class B","Class C","Class D"],"explanation":"Virginia DMV определяет CDL класса Class B как любое одиночное транспортное средство с GVWR 26,001 pounds или более, либо такое транспортное средство, буксирующее единицу с GVWR не более 10,000 pounds. Источник: Virginia DMV, CDL Classifications, Endorsements and Restrictions (dmv.virginia.gov/licenses-ids/cdl/class)."},"21":{"q":"Согласно правилам Вирджинии, CDL класса Class A требуется для любого автопоезда с полной разрешённой массой автопоезда (GCWR) 26,001 pounds или более, при условии, что буксируемое транспортное средство имеет GVWR более какой величины?","options":["5,000 pounds","8,000 pounds","10,000 pounds","15,000 pounds"],"explanation":"Virginia DMV определяет Class A как автопоезд с GCWR 26,001+ pounds, где буксируемая единица (единицы) превышает 10,000 pounds GVWR. Источник: Virginia DMV, CDL Classifications, Endorsements and Restrictions (dmv.virginia.gov/licenses-ids/cdl/class)."},"22":{"q":"Водитель в Вирджинии управляет транспортным средством, которое не отвечает весовым порогам Class A или B, но рассчитано на перевозку 16 или более пассажиров, включая водителя. Какой класс CDL применяется?","options":["Class A","Class B","Class C","CDL не требуется"],"explanation":"Virginia DMV определяет Class C как любое транспортное средство, не отвечающее требованиям Class A или B, которое либо перевозит 16 или более человек (включая водителя), либо перевозит опасные материалы, требующие табличек-плакатов. Источник: Virginia DMV, CDL Classifications, Endorsements and Restrictions (dmv.virginia.gov/licenses-ids/cdl/class)."},"23":{"q":"Какое разрешение (endorsement) CDL в Вирджинии позволяет его обладателю управлять цистерной?","options":["Endorsement N","Endorsement T","Endorsement H","Endorsement P"],"explanation":"Virginia DMV присваивает разрешение N для цистерн (танкеров). Разрешение H предназначено для опасных материалов, T — для сдвоенных/строенных прицепов, а P — для пассажирских транспортных средств. Источник: Virginia DMV, CDL Classifications, Endorsements and Restrictions (dmv.virginia.gov/licenses-ids/cdl/class)."},"24":{"q":"Какое разрешение (endorsement) CDL в Вирджинии требуется для управления транспортным средством, буксирующим сдвоенные или строенные прицепы?","options":["Endorsement P","Endorsement N","Endorsement T","Endorsement S"],"explanation":"Virginia DMV присваивает разрешение T, чтобы разрешить управление транспортным средством, буксирующим сдвоенный или строенный прицеп. Источник: Virginia DMV, CDL Classifications, Endorsements and Restrictions (dmv.virginia.gov/licenses-ids/cdl/class)."},"25":{"q":"Каков минимальный возраст для получения CDL в Вирджинии, действительного только для вождения внутри штата (в пределах Вирджинии)?","options":["16 лет","18 лет","21 год","25 лет"],"explanation":"Virginia DMV требует, чтобы заявитель был не моложе 18 лет для внутриштатного CDL и не моложе 21 года для междуштатного CDL. Источник: Virginia DMV, CDL Skills Test Eligibility Requirements (dmv.virginia.gov/licenses-ids/cdl/eligibility)."},"26":{"q":"Каков минимальный возраст для получения CDL в Вирджинии, действительного для междуштатной эксплуатации (через границы штатов)?","options":["18 лет","19 лет","20 лет","21 год"],"explanation":"Virginia DMV требует, чтобы заявитель был не моложе 21 года для междуштатного CDL; 18 лет — минимальный возраст для CDL, действительного только внутри штата. Источник: Virginia DMV, CDL Skills Test Eligibility Requirements (dmv.virginia.gov/licenses-ids/cdl/eligibility)."},"27":{"q":"Прежде чем сдавать экзамен по навыкам вождения на CDL, заявитель в Вирджинии должен, как правило, владеть коммерческим ученическим разрешением (CLP) минимум сколько дней?","options":["7 days","10 days","14 days","30 days"],"explanation":"Согласно федеральному стандарту, принятому Вирджинией, заявитель должен владеть CLP минимум 14 days, прежде чем сдавать экзамен по навыкам вождения (за исключением случаев, когда он ранее имел CDL или прошёл одобренное обучение). Источник: Virginia DMV, CDL Skills Test Eligibility Requirements / Commercial Learner's Permit (dmv.virginia.gov/licenses-ids/cdl/eligibility)."},"28":{"q":"При управлении коммерческим транспортным средством с коммерческим ученическим разрешением (CLP) в Вирджинии обладатель разрешения должен сопровождаться кем?","options":["Любым лицензированным взрослым старше 21 года","Лицом, имеющим действительный CDL для того же типа транспортного средства","Только экзаменатором DMV","Никем; разрешено вождение в одиночку"],"explanation":"Virginia DMV указывает, что CLP позволяет управление коммерческим транспортным средством только тогда, когда лицо, имеющее лицензию на управление тем же типом транспортного средства (действительный обладатель CDL для этого класса/типа), физически присутствует рядом с обладателем разрешения. Источник: Virginia DMV, Commercial Learner's Permit (dmv.virginia.gov/licenses-ids/cdl/permit)."},"29":{"q":"Какой документ или проверка уникально требуется для получения разрешения HazMat (H) в Вирджинии, которое НЕ требуется для других разрешений?","options":["Оценка угрозы безопасности TSA на основе отпечатков пальцев","Повторная проверка зрения","Спонсорское письмо от работодателя","Нотариально заверенный журнал вождения"],"explanation":"Virginia DMV требует, чтобы заявители на HazMat (HME) прошли проверку биографических данных на основе отпечатков пальцев; DMV передаёт информацию в TSA, которая проводит оценку угрозы безопасности и одобряет или отклоняет разрешение. Источник: Virginia DMV, Hazardous Materials Endorsement (HME) (dmv.virginia.gov/licenses-ids/cdl/hazmat)."},"30":{"q":"Как долго действительна проверка биографических данных на основе отпечатков пальцев для разрешения HazMat (H) в Вирджинии?","options":["1 year","3 years","5 years","10 years"],"explanation":"Virginia DMV указывает, что проверка биографических данных на основе отпечатков пальцев для разрешения HazMat действительна до пяти лет, после чего её необходимо продлить. Источник: Virginia DMV, Hazardous Materials Endorsement (HME) (dmv.virginia.gov/licenses-ids/cdl/hazmat)."},"31":{"q":"Заявитель в Вирджинии, имеющий действительный TWIC (Transportation Worker Identification Credential), получает какое преимущество при подаче заявления на разрешение HazMat?","options":["Экзамен на знание отменяется","Сниженная плата и отсутствие нового снятия отпечатков пальцев","Автоматическое одобрение без рассмотрения TSA","Пожизненное разрешение, которое никогда не истекает"],"explanation":"Virginia DMV взимает с обладателей TWIC сниженную невозвратную плату за HazMat ($41 вместо $83) и не требует нового снятия отпечатков пальцев, поскольку TWIC уже предполагает сопоставимую оценку угрозы со стороны TSA. Источник: Virginia DMV, Hazardous Materials Endorsement / Applying for a CDL (dmv.virginia.gov/licenses-ids/cdl/hazmat)."},"32":{"q":"Согласно федеральному правилу об обучении водителей начального уровня (ELDT), применяемому в Вирджинии, обучение должно быть завершено у поставщика, внесённого в какой реестр, до экзамена по навыкам вождения?","options":["Список одобренных школ Virginia DMV","Реестр поставщиков обучения FMCSA (Training Provider Registry, TPR)","Национальный справочник CDL-академий","Индекс безопасности перевозчиков DOT"],"explanation":"ELDT должно быть завершено у поставщика, внесённого в Реестр поставщиков обучения FMCSA (TPR); Virginia DMV проверяет завершение обучения в электронном виде до экзамена по навыкам вождения. Источник: Virginia DMV / FMCSA Entry-Level Driver Training (tpr.fmcsa.dot.gov; dmv.virginia.gov/licenses-ids/cdl/eligibility)."},"33":{"q":"Какое из следующих действий, совершаемых впервые, НЕ влечёт за собой требование федерального обучения ELDT в Вирджинии?","options":["Получение CDL впервые","Повышение CDL с Class B до Class A","Продление существующего CDL с тем же классом и разрешениями","Получение пассажирского разрешения (P) впервые"],"explanation":"ELDT требуется для впервые подающих заявление на CDL, для повышения с Class B до Class A и для впервые получаемых разрешений H, P или S. Простое продление существующего CDL без нового класса или разрешения не требует ELDT. Источник: FMCSA Entry-Level Driver Training rule, применяемое Virginia DMV (fmcsa.dot.gov; dmv.virginia.gov)."},"34":{"q":"Для впервые подающего заявление на HazMat в Вирджинии, когда должна быть завершена теоретическая часть ELDT?","options":["После сдачи экзамена на знание HazMat","До сдачи экзамена на знание HazMat в DMV","Только после того, как TSA одобрит проверку биографических данных","В течение 30 days после выдачи разрешения"],"explanation":"Согласно правилу ELDT, применяемому в Вирджинии, впервые подающие заявление на разрешение HazMat (H) должны завершить теоретическое обучение ELDT до сдачи экзамена на знание HazMat в DMV. Источник: FMCSA ELDT rule / Virginia DMV (fmcsa.dot.gov; dmv.virginia.gov/licenses-ids/cdl)."},"35":{"q":"Из скольких категорий медицинской самосертификации должен выбрать заявитель на CDL в Вирджинии относительно своего типа эксплуатации коммерческого автотранспортного средства?","options":["Двух","Трёх","Четырёх","Пяти"],"explanation":"Virginia DMV требует, чтобы заявители самостоятельно сертифицировались по одной из четырёх категорий: excepted interstate, non-excepted interstate, excepted intrastate или non-excepted intrastate. Источник: Virginia DMV, Apply for a CDL or CLP (dmv.virginia.gov/licenses-ids/cdl/applying)."},"36":{"q":"Заявитель на CDL в Вирджинии, который ездит через границы штатов и НЕ освобождён от федеральных правил физической пригодности, должен самостоятельно сертифицироваться по какой категории?","options":["Excepted interstate","Non-excepted interstate","Excepted intrastate","Non-excepted intrastate"],"explanation":"Водитель, осуществляющий междуштатные перевозки, который должен соответствовать федеральным медицинским требованиям, самостоятельно сертифицируется как «non-excepted interstate» и должен иметь действительный медицинский сертификат от медицинского эксперта. Источник: Virginia DMV, Apply for a CDL or CLP, medical self-certification (dmv.virginia.gov/licenses-ids/cdl/applying)."},"37":{"q":"Впервые подающий заявление на CDL в Вирджинии, который никогда не имел лицензии Вирджинии, должен предоставить подтверждение личности, подтверждение законного присутствия, номер социального страхования и сколько подтверждений проживания в Вирджинии?","options":["Одно подтверждение проживания","Два подтверждения проживания","Три подтверждения проживания","Подтверждение проживания не требуется"],"explanation":"Virginia DMV требует, чтобы впервые подающий заявление, который никогда не имел лицензии/удостоверения Вирджинии, предъявил одно подтверждение личности, одно подтверждение законного присутствия, одно подтверждение номера социального страхования и два подтверждения проживания в Вирджинии. Источник: Virginia DMV, Apply for a CDL or CLP (dmv.virginia.gov/licenses-ids/cdl/applying)."},"38":{"q":"Лицо, обязанное зарегистрироваться в Реестре лиц, совершивших половые преступления и преступления против несовершеннолетних Вирджинии (Sex Offender and Crimes Against Minors Registry), не имеет права на получение какого разрешения CDL в течение всего периода, пока требуется регистрация?","options":["N (Цистерна)","T (Сдвоенные/строенные прицепы)","S (Школьный автобус)","H (HazMat)"],"explanation":"Вирджиния запрещает выдачу разрешения S (Школьный автобус) любому лицу, обязанному зарегистрироваться в Sex Offender and Crimes Against Minors Registry, в течение любого периода, когда требуется регистрация. Источник: Virginia DMV, CDL Classifications, Endorsements and Restrictions (dmv.virginia.gov/licenses-ids/cdl/class)."},"39":{"q":"На CDL или CLP в Вирджинии, какой код ограничения указывает, что обладатель НЕ может управлять транспортным средством, оснащённым пневматическими тормозами?","options":["Restriction E","Restriction L","Restriction K","Restriction B"],"explanation":"Virginia DMV применяет ограничение L (без пневматических тормозов), когда заявитель не сдаёт тест на знание пневматических тормозов или проходит испытание на транспортном средстве без пневматических тормозов. Ограничение E означает отсутствие механической коробки передач, K — только Вирджиния/внутри штата, а B — корректирующие линзы. Источник: Virginia DMV, CDL Classifications, Endorsements and Restrictions (dmv.virginia.gov/licenses-ids/cdl/class)."},"40":{"q":"В Вирджинии каков максимальный уровень концентрации алкоголя в крови (BAC), при котором лицо может законно управлять коммерческим автотранспортным средством (CMV)?","options":["0.02","0.04","0.08","0.10"],"explanation":"Вирджиния дисквалифицирует обладателя CDL, который управляет CMV с BAC 0.04 или выше — это половина предела 0.08 для обычных водителей. Источник: Virginia DMV CDL Disqualifications page; Va. Code § 46.2-341.24."},"41":{"q":"Согласно закону Вирджинии о подразумеваемом согласии для коммерческих водителей, управляя CMV на дороге Вирджинии, водитель считается согласившимся на что?","options":["Проверку безопасности транспортного средства на любой весовой станции","Химическое исследование крови и/или дыхания в случае законного ареста за правонарушение DUI","Обязательное наркологическое обследование перед каждой сменой","Произвольный опрос любым сотрудником правоохранительных органов"],"explanation":"Закон Вирджинии о подразумеваемом согласии предусматривает, что любое лицо, управляющее CMV на дороге, дало согласие на сдачу крови, дыхания или того и другого для химического исследования содержания алкоголя/наркотиков в случае ареста за правонарушение по § 46.2-341.24, при этом образец берётся в течение трёх часов с момента правонарушения. Источник: Va. Code § 46.2-341.26:2; Virginia DMV CDL manual."},"42":{"q":"Обладатель CDL в Вирджинии осуждён за первое тяжкое правонарушение (например, DUI на CMV), НЕ перевозя при этом опасные материалы с табличками-плакатами. Каков период дисквалификации?","options":["60 days","6 months","1 year","3 years"],"explanation":"Первое тяжкое правонарушение (DUI, BAC 0.04+, отказ от теста, оставление места происшествия и т. д.) влечёт за собой дисквалификацию CDL на 1 year в Вирджинии. Источник: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 1, применяемое как правило Вирджинии."},"43":{"q":"Если водитель в Вирджинии совершает первое тяжкое правонарушение при управлении CMV, перевозящим опасные материалы, требующие табличек-плакатов, период дисквалификации увеличивается до:","options":["1 year","2 years","3 years","5 years"],"explanation":"Первое тяжкое правонарушение, совершённое при перевозке опасных материалов с табличками-плакатами, увеличивает дисквалификацию с 1 year до 3 years. Источник: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 1."},"44":{"q":"Какова дисквалификация CDL в Вирджинии за второе тяжкое правонарушение (например, второе осуждение за DUI на CMV)?","options":["3 years","5 years","10 years","Пожизненно"],"explanation":"Второе тяжкое правонарушение влечёт за собой пожизненную дисквалификацию CDL в Вирджинии, хотя восстановление может быть возможно через 10 years при определённых условиях. Источник: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 1."},"45":{"q":"Обладатель CDL в Вирджинии отказывается пройти обязательный анализ крови или дыхания после законного ареста за управление CMV в состоянии опьянения. Как это рассматривается для целей дисквалификации CDL?","options":["Это всего лишь серьёзное нарушение правил дорожного движения (60 days)","Это тяжкое правонарушение, влекущее дисквалификацию на 1 year за первое нарушение","Это не влечёт дисквалификации CDL, только штраф","Это влечёт автоматическую пожизненную дисквалификацию при первом отказе"],"explanation":"Отказ от химического теста является тяжким правонарушением, дисквалифицирующим водителя на 1 year за первое нарушение (3 years при перевозке опасных грузов с табличками-плакатами) — так же, как осуждение за DUI. Источник: Virginia DMV CDL Disqualifications; Va. Code § 46.2-341.26:2; 49 CFR 383.51 Table 1."},"46":{"q":"Что из перечисленного классифицируется Вирджинией как «серьёзное нарушение правил дорожного движения» для обладателя CDL?","options":["Парковка CMV в зоне, где парковка запрещена","Превышение скорости на 15 mph или более сверх установленного ограничения","Просроченная регистрационная наклейка транспортного средства","Отсутствие при себе подтверждения страховки"],"explanation":"Вирджиния относит превышение скорости на 15 mph или более сверх ограничения к серьёзным нарушениям правил дорожного движения, наряду с безрассудным вождением, неправильной/беспорядочной сменой полосы, слишком близким следованием, набором текста за рулём CMV и нарушениями правил дорожного движения, связанными с ДТП со смертельным исходом. Источник: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 2."},"47":{"q":"На сколько дней дисквалифицируется обладатель CDL в Вирджинии за осуждение по ДВУМ серьёзным нарушениям правил дорожного движения (в отдельных происшествиях) в течение 3-летнего периода?","options":["30 days","60 days","90 days","120 days"],"explanation":"Два серьёзных нарушения правил дорожного движения в течение 3 years влекут за собой дисквалификацию CDL на 60 days в Вирджинии. Источник: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 2."},"48":{"q":"Обладатель CDL в Вирджинии осуждён за ТРИ серьёзных нарушения правил дорожного движения (отдельные происшествия) в течение 3-летнего периода. Какова дисквалификация?","options":["60 days","90 days","120 days","180 days"],"explanation":"Три или более серьёзных нарушений правил дорожного движения в течение 3 years влекут за собой дисквалификацию CDL на 120 days в Вирджинии. Источник: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 2."},"49":{"q":"Дисквалификации за серьёзные нарушения правил дорожного движения (60 / 120 days) применяются только тогда, когда нарушения учитываются в течение какого временного окна?","options":["1 year","3 years","5 years","10 years"],"explanation":"Серьёзные нарушения правил дорожного движения учитываются в течение 3-летнего периода для целей дисквалификаций за 2 нарушения (60 days) и 3 нарушения (120 days). Источник: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 2."},"50":{"q":"Какова дисквалификация за ПЕРВОЕ нарушение правил пересечения железнодорожного переезда обладателем CDL в Вирджинии при управлении CMV?","options":["30 days","60 days","120 days","1 year"],"explanation":"Первое нарушение правил железнодорожного переезда влечёт за собой дисквалификацию не менее чем на 60 days. Источник: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 3."},"51":{"q":"Обладатель CDL в Вирджинии совершает ВТОРОЕ нарушение правил пересечения железнодорожного переезда в течение 3 years. Какова дисквалификация?","options":["60 days","120 days","180 days","1 year"],"explanation":"Второе нарушение правил железнодорожного переезда в течение 3 years влечёт за собой дисквалификацию не менее чем на 120 days. Источник: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 3."},"52":{"q":"Обладатель CDL в Вирджинии совершает ТРЕТЬЕ нарушение правил пересечения железнодорожного переезда в течение 3 years. Какова дисквалификация?","options":["120 days","180 days","1 year","3 years"],"explanation":"Третье или последующее нарушение правил железнодорожного переезда в течение 3 years влечёт за собой дисквалификацию не менее чем на 1 year. Источник: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 3."},"53":{"q":"Какова минимальная дисквалификация в Вирджинии за ПЕРВОЕ осуждение обладателя CDL за нарушение предписания о выводе из эксплуатации (out-of-service, OOS) при управлении CMV?","options":["90 days","120 days","180 days","1 year"],"explanation":"Вирджиния дисквалифицирует водителя не менее чем на 180 days (до 1 year) за первое нарушение предписания о выводе из эксплуатации. Источник: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 4."},"54":{"q":"По сравнению с нарушением предписания о выводе из эксплуатации при перевозке обычного груза, водитель CDL в Вирджинии, нарушающий предписание OOS при перевозке опасных материалов с табличками-плакатами или 16+ пассажиров, сталкивается с:","options":["Меньшей минимальной дисквалификацией","Той же минимальной, но более высокой максимальной дисквалификацией","Отсутствием дополнительного наказания","Только денежным штрафом"],"explanation":"Нарушение предписания OOS при перевозке опасных грузов с табличками-плакатами или грузов, рассчитанных на 16+ пассажиров, сохраняет минимум в 180 days, но повышает максимум за первое нарушение до 2 years (против 1 year для обычного груза). Источник: 49 CFR 383.51 Table 4, применяемое как правило Вирджинии; Virginia DMV CDL Disqualifications."},"55":{"q":"Согласно закону Вирджинии, водителю CDL, который набирает текст или пользуется ручным мобильным телефоном при управлении CMV, может быть назначен гражданско-правовой штраф, не превышающий:","options":["$250","$1,000","$2,750","$5,000"],"explanation":"Va. Code § 46.2-341.20:5 запрещает водителю CMV набирать текст или пользоваться ручным мобильным телефоном и предусматривает гражданско-правовой штраф до $2,750; такое осуждение также является серьёзным нарушением правил дорожного движения для целей CDL. Источник: Va. Code § 46.2-341.20:5; Virginia DMV CDL Disqualifications."},"56":{"q":"Осуждение за набор текста при управлении коммерческим автотранспортным средством в Вирджинии для целей CDL рассматривается как:","options":["Тяжкое правонарушение (дисквалификация на 1 year)","Серьёзное нарушение правил дорожного движения","Нарушение предписания о выводе из эксплуатации","Не подлежащее регистрации правонарушение"],"explanation":"Набор текста за рулём CMV входит в число серьёзных нарушений правил дорожного движения Вирджинии, поэтому повторные осуждения засчитываются в счёт дисквалификаций за 2 нарушения за 3 years (60 days) и 3 нарушения за 3 years (120 days). Источник: Virginia DMV CDL Disqualifications; Va. Code § 46.2-341.20:5; 49 CFR 383.51 Table 2."},"57":{"q":"При какой скорости сверх ограничения обычное превышение скорости становится «безрассудным вождением» согласно общему закону Вирджинии о безрассудном вождении по скорости (обвинение, которое также является серьёзным нарушением для CDL)?","options":["10 mph сверх ограничения","15 mph сверх ограничения","20 mph сверх ограничения, или любая скорость свыше 85 mph","25 mph сверх ограничения, или любая скорость свыше 90 mph"],"explanation":"Va. Code § 46.2-862 определяет безрассудное вождение по скорости как превышение на 20 mph или более сверх ограничения, или свыше 85 mph независимо от ограничения; безрассудное вождение также является серьёзным нарушением правил дорожного движения для CDL (отдельно от порога серьёзного нарушения «15 mph сверх ограничения»). Источник: Va. Code § 46.2-862; Virginia DMV CDL Disqualifications."},"58":{"q":"Обладатель CDL в Вирджинии осуждён за использование CMV при совершении тяжкого преступления, связанного с изготовлением, распространением или сбытом контролируемого вещества. Какова дисквалификация?","options":["1 year","3 years","10 years","Пожизненно без возможности восстановления через 10 years"],"explanation":"Использование CMV для изготовления, распространения или сбыта контролируемых веществ является тяжким правонарушением, влекущим пожизненную дисквалификацию, которая НЕ подлежит восстановлению через 10 years, доступному для других пожизненных дисквалификаций. Источник: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 1."},"59":{"q":"Дисквалификация обладателя CDL за DUI на CMV в Вирджинии в первую очередь затрагивает какую привилегию вождения?","options":["Только привилегию управлять мотоциклами","Привилегию коммерческого вождения (CDL)","Только привилегии вождения за пределами штата","Привилегии управления лодками и водными транспортными средствами"],"explanation":"Дисквалификация CDL лишает привилегии управлять коммерческими автотранспортными средствами; может также применяться отдельное приостановление лицензии, но дисквалификация специально нацелена на привилегию вождения CDL/коммерческого транспорта. Источник: Virginia DMV CDL Disqualifications; Va. Code § 46.2-341.18."},"60":{"q":"Согласно закону Вирджинии «Move Over» (закон об уступке дороги), сколько полос (и в какой конфигурации) должно быть на дороге, чтобы возникала обязанность сменить полосу при остановленном аварийном транспортном средстве с мигающими огнями?","options":["Не менее четырёх полос, при этом не менее двух полос для движения в том же направлении, что и водитель","Любая двухполосная дорога без разделительной полосы","Не менее шести полос, по три в каждом направлении","Только на обозначенных межштатных автомагистралях"],"explanation":"Code of Virginia 46.2-861.1 (закон Вирджинии «Move Over») требует, чтобы водители на дорогах с не менее чем четырьмя полосами, две из которых обслуживают движение в одном направлении, сменили полосу, отъезжая от неподвижного аварийного транспортного средства с мигающими предупредительными огнями; если безопасная смена полосы невозможна, водитель должен снизить скорость и продолжать движение с осторожностью. Источник: Code of Virginia 46.2-861.1."},"61":{"q":"В Вирджинии, когда водитель не может безопасно сменить полосу, отъезжая от остановленного аварийного транспортного средства с мигающими огнями, что он должен сделать вместо этого?","options":["Продолжать движение с осторожностью и снизить скорость ниже установленного предела","Полностью остановиться, пока аварийное транспортное средство не уедет","Подать звуковой сигнал и поддерживать установленную скорость","Включить аварийную сигнализацию и продолжать движение с нормальной скоростью"],"explanation":"Согласно Code of Virginia 46.2-861.1, если смену полосы нельзя выполнить безопасно, водитель должен продолжать движение с должной осторожностью и поддерживать безопасную для дорожных условий скорость, снижая её, чтобы защитить аварийный персонал на месте. Нарушение квалифицируется как безрассудное вождение (reckless driving, проступок класса 1 — Class 1 misdemeanor). Источник: Code of Virginia 46.2-861.1."},"62":{"q":"В Вирджинии нарушение закона «Move Over» (несоблюдение требования сменить полосу или снизить скорость перед остановленным аварийным транспортным средством) квалифицируется как что?","options":["Безрассудное вождение, проступок класса 1 (Class 1 misdemeanor)","Гражданское правонарушение без участия движения","Простое нарушение правил дорожного движения без штрафных баллов","Тяжкое преступление (felony), если травмы не было"],"explanation":"Code of Virginia 46.2-861.1 относит несоблюдение требования уступить дорогу или сменить полосу перед неподвижным аварийным транспортным средством к форме безрассудного вождения (reckless driving), которое является проступком класса 1 (Class 1 misdemeanor) и влечёт возможное тюремное заключение, штрафы до $2,500 и приостановление действия прав. Источник: Code of Virginia 46.2-861.1."},"63":{"q":"На дорогах Вирджинии с неограниченным доступом (немежштатных) каков максимальный предел скорости для седельного тягача с прицепом или грузовика, предназначенного для перевозки имущества, при отсутствии обозначенных исключений?","options":["45 mph","55 mph","60 mph","65 mph"],"explanation":"Code of Virginia 46.2-870 устанавливает на дорогах с неограниченным доступом предел по умолчанию в 55 mph для легковых автомобилей и автобусов, но лишь 45 mph для грузовиков, седельных тягачей и автопоездов, предназначенных для перевозки имущества, то есть на 10 mph меньше, чем для легковых автомобилей. Источник: Code of Virginia 46.2-870."},"64":{"q":"На межштатной автомагистрали Вирджинии каков максимальный предел скорости для коммерческого грузовика там, где после инженерно-транспортного исследования установлен более высокий предел?","options":["70 mph, так же, как и для легковых автомобилей","55 mph, тогда как легковые автомобили могут ехать 70 mph","65 mph только для грузовиков","75 mph"],"explanation":"Code of Virginia 46.2-870 устанавливает максимум на межштатных автомагистралях в 55 mph или 70 mph там, где после инженерного исследования установлены законные знаки. На межштатных автомагистралях более высокий обозначенный предел применяется ко всем транспортным средствам, включая грузовики; Вирджиния не вводит отдельного пониженного предела скорости для грузовиков на межштатных автомагистралях. Источник: Code of Virginia 46.2-870."},"65":{"q":"На железнодорожном переезде в Вирджинии транспортное средство с табличками опасных грузов (placarded HazMat) или автобус, перевозящий пассажиров за плату, должны остановиться в пределах какого расстояния от ближайшего рельса?","options":["В пределах 50 feet, но не ближе 15 feet","В пределах 100 feet, но не ближе 25 feet","В пределах 30 feet, но не ближе 10 feet","В пределах 15 feet, но не ближе 5 feet"],"explanation":"Code of Virginia 46.2-886 требует, чтобы транспортные средства, перевозящие пассажиров за плату или перевозящие взрывчатые вещества либо легковоспламеняющиеся жидкости в качестве груза, останавливались в пределах 50 feet, но не ближе 15 feet от ближайшего рельса, затем смотрели и слушали перед продолжением движения. Это соответствует правилу о железнодорожных переездах в Virginia CDL Manual. Источник: Code of Virginia 46.2-886; Virginia CDL Manual."},"66":{"q":"После остановки на железнодорожном переезде что требует закон Вирджинии в отношении переключения передач, пока транспортное средство находится на путях?","options":["Водитель должен пересекать переезд на такой передаче, чтобы не требовалось переключение передач, пока он находится на путях","Водитель должен переключиться на низшую передачу на середине переезда","Водитель может свободно переключаться, пока поддерживается скорость","Водитель должен перейти на нейтраль при пересечении"],"explanation":"Code of Virginia 46.2-886 гласит, что после остановки и при продолжении движения водитель должен пересекать переезд только на такой передаче, чтобы не возникало необходимости переключать передачи во время прохождения переезда, и не должен переключать передачи при пересечении. Источник: Code of Virginia 46.2-886; Virginia CDL Manual."},"67":{"q":"В Вирджинии водитель, приближающийся к остановленному школьному автобусу, который высаживает или забирает детей на двухполосной дороге без разделительной полосы, должен сделать что?","options":["Остановиться при приближении с любого направления и оставаться остановленным, пока автобус не тронется или не перестанет мигать","Остановиться только при движении в том же направлении, что и автобус","Снизить скорость до 20 mph, но останавливаться не обязан","Остановиться только если дети явно переходят дорогу"],"explanation":"Code of Virginia 46.2-859 требует, чтобы водитель, приближающийся с любого направления, останавливался перед школьным автобусом, который остановлен и отображает свои предупредительные устройства для посадки или высадки пассажиров, и оставался остановленным, пока люди не отойдут на безопасное расстояние и автобус снова не придёт в движение. Нарушение является безрассудным вождением (reckless driving). Источник: Code of Virginia 46.2-859."},"68":{"q":"На разделённой автомагистрали Вирджинии при каком условии встречный водитель НЕ обязан останавливаться перед школьным автобусом, остановившимся на противоположной проезжей части?","options":["Когда проезжие части разделены физическим барьером или немощёным участком","Когда есть нанесённая двойная жёлтая осевая линия","Когда предел скорости составляет 45 mph или выше","Когда между проезжими частями есть центральная полоса для поворота"],"explanation":"Code of Virginia 46.2-859 освобождает водителя от остановки только тогда, когда школьный автобус находится на другой проезжей части разделённой автомагистрали (или на подъездной дороге/частном проезде), отделённой от проезжей части водителя физическим барьером или немощёным участком. Просто нанесённая линия или полоса для поворота не подпадают под это условие. Источник: Code of Virginia 46.2-859."},"69":{"q":"Когда коммерческое транспортное средство вынуждено остановиться на дороге Вирджинии, водитель должен выставить красные светоотражающие треугольные предупредительные устройства в течение скольких минут после остановки?","options":["В течение 10 минут","В течение 5 минут","В течение 15 минут","Немедленно, в течение 1 минуты"],"explanation":"Code of Virginia 46.2-111 требует, чтобы оператор остановленного коммерческого транспортного средства выставил необходимые красные светоотражающие треугольные предупредительные устройства в течение 10 минут после остановки, оставляя аварийную сигнализацию включённой, пока они не будут выставлены. Источник: Code of Virginia 46.2-111."},"70":{"q":"Для коммерческого транспортного средства, остановившегося на ровной прямой дороге Вирджинии, где должны быть выставлены три предупредительных треугольника?","options":["100 ft сзади, 100 ft спереди и один со стороны движения в пределах 10 ft от транспортного средства","10 ft, 100 ft и 200 ft — все сзади","50 ft, 100 ft и 150 ft только сзади","По одному с каждой стороны и один на крыше"],"explanation":"Code of Virginia 46.2-111 предписывает размещение одного треугольника не ближе 100 feet в направлении приближающегося движения, одного не ближе 100 feet в противоположном направлении и одного со стороны движения не ближе 10 feet к передней или задней части транспортного средства. Источник: Code of Virginia 46.2-111."},"71":{"q":"Если коммерческое транспортное средство в Вирджинии остановилось в пределах 500 feet от поворота, вершины холма или иного препятствия, как следует выставить предупредительное устройство в этом направлении?","options":["Достаточно далеко, чтобы обеспечить заблаговременное предупреждение, но ни в коем случае не ближе 500 feet от транспортного средства","Точно в 100 feet от транспортного средства","Не дальше 200 feet от транспортного средства","Прямо на самом препятствии"],"explanation":"Code of Virginia 46.2-111 требует, чтобы там, где остановка происходит в пределах 500 feet от поворота, вершины холма или иного препятствия, предупредительное устройство в этом направлении было выставлено так, чтобы обеспечить заблаговременное предупреждение, ни в коем случае не ближе 500 feet от остановленного транспортного средства. Источник: Code of Virginia 46.2-111."},"72":{"q":"На межштатной автомагистрали 81 в Вирджинии и на межштатных автомагистралях с более чем двумя полосами в каждом направлении какое ограничение по полосам применяется к коммерческим транспортным средствам?","options":["Им запрещено двигаться по крайней левой полосе","Они могут использовать только крайнюю левую полосу","Они должны держаться в пределах 10 mph от минимальной скорости для грузовиков","Они ограничены только центральной полосой"],"explanation":"Code of Virginia 46.2-803.1 запрещает коммерческим транспортным средствам двигаться по крайней левой полосе на I-81 и на межштатных автомагистралях с более чем двумя полосами движения в каждом направлении (как правило, там, где предел составляет 65 mph или выше). Автобусы и транспортные средства, готовящиеся к левому съезду, являются исключением. Источник: Code of Virginia 46.2-803.1."},"73":{"q":"На дороге Вирджинии с разметкой полос, где должно двигаться любое транспортное средство, едущее медленнее нормальной скорости движения?","options":["По полосе, ближайшей к правому краю или правому бордюру, кроме случаев обгона или подготовки к левому повороту","По любой полосе, выбранной водителем","По центральной полосе для уравновешивания движения","По левой полосе, чтобы держаться подальше от вливающегося потока"],"explanation":"Code of Virginia 46.2-804 требует, чтобы транспортное средство, движущееся медленнее нормальной скорости движения, двигалось по полосе, ближайшей к правому краю или бордюру, кроме случаев обгона и опережения, подготовки к левому повороту или там, где правые полосы зарезервированы для медленного движения. Источник: Code of Virginia 46.2-804."},"74":{"q":"Какие живописные парковые шоссе (parkways) Вирджинии, как правило, запрещают движение коммерческих грузовиков?","options":["George Washington Memorial Parkway и Colonial Parkway","Межштатная автомагистраль 95 и межштатная автомагистраль 64","Кольцевая автодорога столицы — Capital Beltway (I-495)","Шоссе U.S. Route 29 и U.S. Route 58"],"explanation":"Находящиеся в федеральном ведении George Washington Memorial Parkway и Colonial Parkway в Вирджинии запрещают движение коммерческих грузовиков; на GW Parkway для любого коммерческого транспортного средства требуется специальное разрешение National Park Service, а Colonial Parkway не допускает грузовики, за исключением пассажирских автобусов. Источник: National Park Service / руководство VDOT по ограничениям для грузовиков."},"75":{"q":"Определённые классы опасных грузов запрещены к перевозке через расположенные у воды тоннели Вирджинии, такие как Hampton Roads Bridge-Tunnel. Чем регулируются эти ограничения?","options":["Нормативами VDOT, регулирующими провоз опасных грузов через мостовые-тоннельные сооружения (24VAC30-61), в зависимости от класса опасности","Только федеральными ограничениями по весу на межштатных автомагистралях","Только полной массой автопоезда (gross combination weight rating)","Тем, застрахован ли груз"],"explanation":"Административный норматив Вирджинии 24VAC30-61 регулирует перевозку опасных грузов через городские и расположенные у воды тоннели штата (Hampton Roads, Monitor-Merrimac и тоннели реки Elizabeth), запрещая определённые классы опасности, такие как взрывчатые вещества и ядовитые газы. Источник: 24VAC30-61; руководство VDOT по опасным грузам."},"76":{"q":"Грузовики, движущиеся на юг вниз по крутому спуску Fancy Gap на межштатной автомагистрали 77 в Вирджинии, должны особенно учитывать какую функцию безопасности?","options":["Несколько аварийных съездов для грузовиков на длинном спуске","Обязательную весовую станцию для грузовиков на вершине","Тоннель, который запрещает все грузовики","Реверсивную полосу HOV"],"explanation":"Межштатная автомагистраль 77 поднимается более чем на 1,500 feet через Fancy Gap с уклонами примерно до 4.5%; длинный спуск в южном направлении в Северную Каролину включает несколько аварийных съездов для грузовиков, потерявших торможение. Водителям следует выбрать низкую передачу перед спуском. Источник: руководство VDOT/Virginia CDL Manual по горному вождению."},"77":{"q":"В Вирджинии правило о минимальной скорости гласит, что водитель не должен двигаться со столь малой скоростью, чтобы делать что?","options":["Препятствовать или блокировать нормальное и разумное движение транспорта, за исключением случаев, когда снижение скорости необходимо для безопасности или по закону","Двигаться медленнее 40 mph на любой дороге","Отставать более чем на 5 mph от установленного предела","Заставлять других водителей пользоваться сигналом"],"explanation":"Code of Virginia 46.2-877 запрещает движение со столь малой скоростью, чтобы препятствовать нормальному и разумному движению транспорта, за исключением случаев, когда снижение скорости необходимо для безопасной эксплуатации или для соблюдения закона. Источник: Code of Virginia 46.2-877."},"78":{"q":"Помимо требования о четырёх полосах, обязанность «Move Over» в Вирджинии применяется к неподвижным транспортным средствам с предупредительными огнями, управляемым кем из перечисленных?","options":["Полиция, пожарные, скорая помощь, VDOT, коммунальные службы и эвакуаторы","Только полиция и скорая помощь","Только патрульные машины полиции штата","Только транспортные средства, принадлежащие VDOT"],"explanation":"Code of Virginia 46.2-861.1 распространяет обязанность «Move Over» на широкий круг неподвижных транспортных средств с мигающими предупредительными огнями, включая транспорт правоохранительных органов, пожарной службы, скорой помощи, Virginia Department of Transportation, коммунальных служб и эвакуации/буксировки. Источник: Code of Virginia 46.2-861.1."},"79":{"q":"В качестве менее строгой альтернативы безрассудному вождению закон Вирджинии позволяет применять за проезд мимо остановленного школьного автобуса гражданский штраф в каком размере, при этом ответственность может нести владелец транспортного средства?","options":["$250","$50","$1,000","$2,500"],"explanation":"Code of Virginia 46.2-844 предусматривает альтернативу в виде гражданского штрафа в $250 за непредоставление остановки перед остановленным школьным автобусом, и зарегистрированный владелец транспортного средства может быть привлечён к ответственности, когда система видеонаблюдения автобуса фиксирует нарушение. Уголовное правонарушение по 46.2-859 остаётся безрассудным вождением (reckless driving). Источник: Code of Virginia 46.2-844 и 46.2-859."},"80":{"q":"Какое ведомство выдаёт коммерческие водительские права (CDL) в Вирджинии?","options":["Virginia Department of Motor Vehicles (DMV)","Federal Motor Carrier Safety Administration (FMCSA)","Virginia Department of Transportation (VDOT)","Подразделение по автоперевозкам полиции штата Вирджиния (Virginia State Police Motor Carrier Division)"],"explanation":"CDL в Вирджинии выдаёт Virginia Department of Motor Vehicles (DMV). FMCSA устанавливает федеральные стандарты, но не выдаёт права, а VDOT занимается дорогами/разрешениями, а не лицензированием. Источник: Virginia DMV, Apply for a CDL or CLP."},"81":{"q":"Куда нужно обратиться, чтобы подать заявление на получение CDL или Commercial Learner's Permit (CLP) в Вирджинии?","options":["Лично в центре обслуживания клиентов DMV","Полностью онлайн через веб-сайт DMV","В любом одобренном FMCSA дилерском центре грузовиков","По почте в штаб-квартиру DMV в Richmond"],"explanation":"Вирджиния требует, чтобы вы подавали заявление на получение CDL или CLP лично в центре обслуживания клиентов DMV; первоначальное заявление на CDL/CLP нельзя оформить полностью онлайн. Источник: Virginia DMV, Apply for a CDL or CLP."},"82":{"q":"Федеральные нормативы требуют, чтобы каждый заявитель на CDL или CLP в Вирджинии самостоятельно подтвердил (self-certify) принадлежность к скольким категориям эксплуатации коммерческого транспортного средства?","options":["Четырём","Двум","Трём","Пяти"],"explanation":"Любой, кто имеет или подаёт заявление на CDL/CLP в Вирджинии, должен самостоятельно подтвердить (self-certify) принадлежность к одной из четырёх категорий эксплуатации CMV. Источник: Virginia DMV, CDL Medical Certification Requirements."},"83":{"q":"Что из перечисленного является одной из четырёх категорий самоподтверждения (self-certification), используемых Virginia DMV?","options":["Non-excepted Interstate (NI)","Ограниченная коммерческая эксплуатация (Restricted Commercial Operation)","Только внутриштатные опасные грузы (Intrastate Hazmat Only)","Федеральный исключённый перевозчик (Federal Excepted Carrier)"],"explanation":"Эти четыре категории: Excepted Interstate (EI), Excepted Intrastate (EA), Non-excepted Interstate (NI) и Non-excepted Intrastate (NA). «Non-excepted Interstate» — действительная категория; остальные перечисленные таковыми не являются. Источник: Virginia DMV, CDL Medical Certification Requirements."},"84":{"q":"Какая категория самоподтверждения, как правило, НЕ требует, чтобы водитель имел в Virginia DMV действующий сертификат медицинского эксперта (medical examiner's certificate)?","options":["Excepted Interstate (EI)","Non-excepted Interstate (NI)","Non-excepted Intrastate (NA)","Любая межштатная категория"],"explanation":"Водители, подтверждающие исключённые категории (excepted interstate или excepted intrastate), не обязаны предоставлять сертификат медицинского эксперта; это требуется только водителям non-excepted interstate и non-excepted intrastate. Источник: Virginia DMV, CDL Medical Certification Requirements."},"85":{"q":"Водитель, самостоятельно подтверждающий категорию non-excepted interstate в Вирджинии, должен пройти медицинский осмотр у медицинского эксперта, который:","options":["Внесён в FMCSA National Registry of Certified Medical Examiners","Работает непосредственно в Virginia DMV","Одобрен Virginia Department of Health","Любой лицензированный врач по выбору водителя"],"explanation":"Водители категории non-excepted должны проходить осмотр у медицинского эксперта, внесённого в FMCSA National Registry of Certified Medical Examiners. Не каждый лицензированный врач подходит. Источник: Virginia DMV, CDL Medical Certification Requirements."},"86":{"q":"Начиная с 5 мая 2025 года (May 5, 2025), как должен подаваться в Virginia DMV сертификат медицинского эксперта (Medical Examiner's Certificate, MEC)?","options":["Электронно медицинским экспертом через портал FMCSA National Registry","Водитель приносит бумажный сертификат в офис DMV","Водитель загружает скан-копию на веб-сайт DMV","Работодатель водителя отправляет его по факсу в FMCSA"],"explanation":"С 5 мая 2025 года Virginia DMV больше не принимает MEC напрямую от водителей; медицинский эксперт должен подать сертификат электронно через портал FMCSA National Registry. Источник: Virginia DMV, CDL Medical Certification Requirements."},"87":{"q":"Чтобы получить CLP в Вирджинии, заявитель должен как минимум сдать какой экзамен на знание?","options":["Общий экзамен на знание для CDL (CDL general knowledge exam)","Только экзамен по комбинированным транспортным средствам","Только экзамен по пневматическим тормозам (air brakes)","Экзамен по опасным грузам (hazardous materials)"],"explanation":"Чтобы получить CLP, вы должны сдать общий экзамен на знание для CDL (CDL general knowledge exam), а также любые дополнительные экзамены на знание (например, по пневматическим тормозам или цистернам) для транспортных средств, которыми вы намерены управлять. Источник: Virginia DMV, Commercial Learner's Permit."},"88":{"q":"После выдачи CLP в Вирджинии сколько времени вы должны им владеть, прежде чем получите право сдавать практический экзамен на навыки CDL?","options":["Не менее 14 дней","Не менее 30 дней","Не менее 7 дней","Не менее 60 дней"],"explanation":"Вирджиния требует минимальный срок владения CLP в 14 дней перед сдачей экзамена на навыки. Это требование может быть отменено при наличии подтверждения ранее имевшегося CDL или завершения Entry-Level Driver Training. Источник: Virginia DMV, CDL Skills Test Eligibility / Commercial Learner's Permit."},"89":{"q":"Сколько времени действует Commercial Learner's Permit (CLP) в Вирджинии и можно ли его продлить?","options":["Действует 1 год и не подлежит продлению","Действует 180 дней и может быть продлён один раз","Действует 2 года и продлевается ежегодно","Действует 6 месяцев с неограниченным числом продлений"],"explanation":"CLP в Вирджинии действует 1 год и не подлежит продлению; если срок его действия истёк, вы должны подать заявление заново и пересдать экзамены. Источник: Virginia DMV, Commercial Learner's Permit."},"90":{"q":"Из каких трёх частей состоит экзамен на навыки CDL в Вирджинии, выполняемых по порядку?","options":["Предрейсовый осмотр, базовое управление транспортным средством и вождение по дороге","Письменный экзамен на знание, проверка зрения и дорожный тест","Проверка пневматических тормозов, движение задним ходом и вливание в поток на автомагистрали","Сцепка/расцепка, параллельная парковка и ночное вождение"],"explanation":"Экзамен на навыки CDL состоит из трёх частей: предрейсовый осмотр транспортного средства, базовые навыки управления транспортным средством и дорожный тест на вождение, проводимых именно в этом порядке. Источник: стандарт FMCSA CDL, применяемый в Вирджинии; Virginia DMV CDL Skills Tests."},"91":{"q":"Кто должен предоставить транспортное средство, используемое для дорожного теста на вождение для CDL в Вирджинии?","options":["Заявитель, который должен предоставить надлежащим образом зарегистрированное транспортное средство того типа, которым он хочет управлять","Virginia DMV, которое предоставляет тестовый грузовик","Только школа обучения ELDT заявителя","FMCSA, из своего регионального инспекционного автопарка"],"explanation":"Заявитель должен предоставить надлежащим образом зарегистрированное транспортное средство, представляющее класс/тип CDL, который он стремится получить, для дорожного теста. Источник: Virginia DMV, CDL Skills Test Eligibility."},"92":{"q":"Когда вступило в силу федеральное требование Entry-Level Driver Training (ELDT), применяемое в Вирджинии?","options":["7 февраля 2022 года (February 7, 2022)","5 мая 2025 года (May 5, 2025)","1 января 2020 года (January 1, 2020)","1 июля 2023 года (July 1, 2023)"],"explanation":"Требования ELDT вступили в силу 7 февраля 2022 года (February 7, 2022). (5 мая 2025 года — это отдельная дата изменения, касающегося электронной подачи MEC.) Источник: Virginia DMV, Entry-Level Driver Training."},"93":{"q":"Поставщик обучения ELDT, которым пользуется заявитель на CDL в Вирджинии, должен быть:","options":["Внесён в FMCSA Training Provider Registry (TPR)","Сертифицирован только Virginia DMV","Аккредитован Virginia Board of Education","Любой коммерческой автошколой с лицензией на ведение бизнеса"],"explanation":"ELDT должно проводиться у поставщика, внесённого в FMCSA Training Provider Registry (TPR). Общей лицензии на ведение бизнеса или аккредитации совета штата недостаточно. Источник: Virginia DMV, Entry-Level Driver Training."},"94":{"q":"Для впервые подающего заявление на класс A или B в Вирджинии, когда должны быть завершены теоретическое и практическое (за рулём) обучение ELDT?","options":["Перед сдачей дорожного экзамена на навыки","Перед подачей заявления на CLP","В течение 30 дней после сдачи экзамена на навыки","Перед сдачей общего экзамена на знание"],"explanation":"Для классов CDL (а также для подтверждений P/S) теоретическое и практическое (за рулём) обучение ELDT должно быть завершено перед дорожным экзаменом на навыки. (Для опасных грузов теоретическая часть должна быть пройдена перед экзаменом на знание по опасным грузам.) Источник: Virginia DMV, Entry-Level Driver Training."},"95":{"q":"Для подтверждения по опасным грузам (H) в Вирджинии теоретическая часть ELDT должна быть завершена перед:","options":["Сдачей экзамена на знание по опасным грузам (hazmat knowledge exam)","Сдачей дорожного теста на навыки","Подачей формы самоподтверждения","Выдачей CLP"],"explanation":"В отличие от обучения по классам CDL, теоретическая часть ELDT по опасным грузам должна быть завершена перед сдачей экзамена на знание по опасным грузам (отдельного теста на навыки по опасным грузам нет). Источник: Virginia DMV, Entry-Level Driver Training."},"96":{"q":"Каков минимальный возраст для получения внутриштатного CDL Вирджинии по сравнению с межштатным CDL?","options":["18 для внутриштатного и 21 для межштатного","21 для внутриштатного и 25 для межштатного","16 для внутриштатного и 18 для межштатного","18 как для внутриштатного, так и для межштатного"],"explanation":"Вам должно быть не менее 18 лет для получения внутриштатного CDL и не менее 21 года для получения межштатного CDL. Источник: Virginia DMV, CDL Skills Test Eligibility / Apply for a CDL or CLP."},"97":{"q":"Лицо, подающее заявление на CDL в Вирджинии, которое никогда не имело водительских прав или удостоверения личности Вирджинии, должно предоставить два подтверждения чего из перечисленного?","options":["Проживания в Вирджинии (Virginia residency)","Номера социального страхования (Social Security number)","Законного пребывания (legal presence)","Личности (identity)"],"explanation":"Впервые подающие заявление в Вирджинии должны предъявить одно подтверждение личности, одно подтверждение законного пребывания, одно подтверждение номера социального страхования и два подтверждения проживания в Вирджинии. Источник: Virginia DMV, Apply for a CDL or CLP."},"98":{"q":"Для большинства водителей сколько времени действует стандартный CDL Вирджинии до того, как его необходимо продлить?","options":["8 лет, с истечением срока в день рождения владельца","4 года, с истечением срока в день рождения владельца","5 лет, с истечением срока в конце года","10 лет, с истечением срока в годовщину даты выдачи"],"explanation":"Стандартный CDL Вирджинии действует 8 лет и истекает в день рождения владельца (водители в возрасте 75 лет и старше получают 5-летний цикл). Источник: Virginia DMV, Renew Your CDL."},"99":{"q":"В Вирджинии, если срок действия CDL истёк или права были понижены (downgraded) более чем на один год, что должен сделать владелец, чтобы вернуть их?","options":["Пересдать как экзамен на знание, так и дорожный тест на навыки для данного типа CDL","Просто оплатить штраф за просрочку и продлить онлайн","Пересдать только проверку зрения","Только выждать дополнительный 14-дневный срок владения"],"explanation":"Если срок действия CDL Вирджинии истёк или права были понижены (downgraded) более чем на один год, владелец должен пересдать экзамен на знание и дорожный тест на навыки, требуемые для того типа CDL, который он имел. Источник: Virginia DMV, Renew Your CDL."}},"tr":{"0":{"q":"Virginia karayollarında bir araç ve yükü için izin verilen maksimum toplam dış genişlik nedir (aynalar hariç)?","options":["96 inches","100 inches","102 inches","108 inches"],"explanation":"Virginia Code 46.2-1105, bir aracın yükü dahil maksimum toplam dış genişliğini, aynalar ve bazı okul otobüsü uyarı cihazları hariç olmak üzere 102 inches (8 feet 6 inches) olarak belirler. Kaynak: Code of Virginia 46.2-1105; Virginia CDL Manual / DMV 109."},"1":{"q":"Virginia karayollarında yüklü veya yüksüz bir araç için izin verilen maksimum yükseklik nedir?","options":["13 feet","13 feet 6 inches","14 feet","12 feet 6 inches"],"explanation":"Virginia Code 46.2-1110, yüklü veya yüksüz herhangi bir aracın 13 feet 6 inches yüksekliği aşmasını yasaklar. Kaynak: Code of Virginia 46.2-1110; Virginia DMV 109."},"2":{"q":"Virginia karayollarında izin verilen maksimum tek aks ağırlığı nedir?","options":["18,000 pounds","20,000 pounds","22,400 pounds","24,000 pounds"],"explanation":"Virginia Code 46.2-1124, herhangi bir araç veya kombinasyonun tek aks ağırlığını 20,000 pounds ile sınırlar. Kaynak: Code of Virginia 46.2-1124; Virginia DMV 109."},"3":{"q":"Virginia karayollarında izin verilen maksimum çift aks (tandem) ağırlığı nedir?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"Virginia Code 46.2-1125, herhangi bir araç veya kombinasyonun çift aks (tandem) ağırlığını 34,000 pounds ile sınırlar. Kaynak: Code of Virginia 46.2-1125; Virginia DMV 109."},"4":{"q":"Aks aralığından bağımsız olarak, Virginia eyaletler arası (interstate) karayollarında izin verilen maksimum brüt ağırlık nedir?","options":["73,280 pounds","76,000 pounds","80,000 pounds","90,000 pounds"],"explanation":"Virginia Code 46.2-1127, Commonwealth'teki eyaletler arası karayollarında aks aralığından bağımsız olarak 80,000 pounds'u aşan brüt ağırlığı yasaklar. Kaynak: Code of Virginia 46.2-1127."},"5":{"q":"Virginia eyaletler arası (interstate) karayollarında tek aks ve çift aks (tandem) ağırlık sınırları sırasıyla nelerdir?","options":["20,000 lb and 34,000 lb","18,000 lb and 32,000 lb","22,000 lb and 36,000 lb","20,000 lb and 40,000 lb"],"explanation":"Virginia Code 46.2-1127, eyaletler arası tek aks sınırını 20,000 pounds ve çift aks (tandem) sınırını 34,000 pounds olarak belirler; bu değerler genel karayolu sınırlarıyla aynıdır. Kaynak: Code of Virginia 46.2-1127."},"6":{"q":"Virginia karayollarında genel olarak çekici-kamyon/yarı römork kombinasyonunda kullanılan tek bir yarı römork için maksimum uzunluk nedir?","options":["45 feet","48 feet","53 feet","57 feet"],"explanation":"Virginia Code 46.2-1112, çekici-kamyon/yarı römork kombinasyonundaki bir yarı römorku 48 feet ile sınırlar; ancak 53-foot yarı römorklara eyaletler arası sistemde ve belirli uygun karayollarında izin verilir. Kaynak: Code of Virginia 46.2-1112; Virginia DMV taşıma kılavuzu."},"7":{"q":"Virginia'nın eyaletler arası (interstate) sisteminde bir yarı römorka izin verilen maksimum uzunluk en fazla ne kadardır?","options":["48 feet","50 feet","53 feet","60 feet"],"explanation":"Virginia Code 46.2-1112 uyarınca, kingpin'den en arka aksa kadar olan mesafe belirlenen sınırı aşmadığında eyaletler arası sistemde (ve uygun karayollarında) 53 feet'e kadar yarı römorklara izin verilir; genel karayolu temel değeri 48 feet'tir. Kaynak: Code of Virginia 46.2-1112."},"8":{"q":"Virginia karayollarında çift römorklu (ikiz) bir kombinasyonda, her bir römork veya yarı römorkun maksimum uzunluğu nedir?","options":["27 feet","28 feet","28 1/2 feet","30 feet"],"explanation":"Virginia Code 46.2-1112, bir kombinasyondaki hiçbir münferit yarı römork veya römorkun 28 1/2 feet uzunluğu aşamayacağını öngörür. Kaynak: Code of Virginia 46.2-1112; Virginia DMV 109."},"9":{"q":"Virginia karayollarında bağlı araç/römork kombinasyonu için genel maksimum uzunluk nedir (özel çekici-yarı römork istisnaları hariç)?","options":["60 feet","65 feet","70 feet","75 feet"],"explanation":"Virginia Code 46.2-1112, bağlı (kombinasyon) araçlar için genel olarak 65-foot maksimum belirler; belirlenmiş karayollarındaki çekici-yarı römork kombinasyonları için özel istisnalar vardır. Kaynak: Code of Virginia 46.2-1112."},"10":{"q":"Virginia karayollarında tek bir motorlu aracın (otobüsler ve karavanlar dışında düz/tek üniteli bir kamyon) maksimum uzunluğu nedir?","options":["35 feet","40 feet","45 feet","48 feet"],"explanation":"Virginia Code 46.2-1112, bir karayolunda 40 feet'ten uzun tek bir motorlu aracın kullanılmasını yasaklar (otobüsler ve karavanlar için ayrı hükümler vardır). Kaynak: Code of Virginia 46.2-1112; Virginia DMV taşıma kılavuzu."},"11":{"q":"Virginia, köprü formülü (Code 46.2-1126) kapsamında izin verilen maksimum brüt ağırlığı nasıl belirler?","options":["Yalnızca aracın ruhsatındaki tescilli ağırlığa göre","Aks sayısı ile ilk ve son aks arasındaki mesafeye göre","Motor beygir gücü ve lastik derecelendirmesine göre","Toplam kargo hacmine göre (kübik feet cinsinden)"],"explanation":"Virginia Code 46.2-1126, maksimum brüt ağırlığı aks sayısına ve uç (ilk ve son) akslar arasındaki mesafeye göre belirleyen bir tablo (Virginia'da uygulandığı şekliyle federal köprü formülü) sağlar. Kaynak: Code of Virginia 46.2-1126."},"12":{"q":"Virginia'nın brüt ağırlık tablosuna (Code 46.2-1126) göre, aks aralığı ne kadar uygun olursa olsun tablonun izin verdiği en yüksek brüt ağırlık nedir?","options":["76,000 pounds","80,000 pounds","84,000 pounds","88,000 pounds"],"explanation":"Virginia Code 46.2-1126'nın tablosu maksimum brüt ağırlığı 80,000 pounds ile sınırlar (en yüksek değer, tam aralıktaki 7 akslı bir araca uygulanır); 80,000 pounds aynı zamanda 46.2-1127 uyarınca mutlak yasal üst sınırdır. Kaynak: Code of Virginia 46.2-1126 ve 46.2-1127."},"13":{"q":"En küçük pratik yapılandırmaya indirildiğinde dahi boyutları veya ağırlığı Virginia'nın yasal sınırlarını aşan bir kamyon, Virginia karayollarında seyahat etmeden önce ne yapmalıdır?","options":["Bir sonraki kantarda sabit bir aşırı yük cezası ödemek","Önceden bir taşıma (aşırı boyut/aşırı ağırlık) izni almak","Aracı bir çiftlik aracı olarak tescil ettirmek","Yalnızca gece yarısı ile sabah 5 arasında seyahat etmek"],"explanation":"Virginia, en küçük pratik boyutlarına indirilmiş bir araç hâlâ yasal sınırları aşıyorsa, operatörün Commonwealth'in karayollarında seyahat etmeden önce bir taşıma izni almasını gerektirir. Kaynak: Virginia Code Article 18 (46.2-1139 et seq.); Virginia DMV Hauling Permits."},"14":{"q":"Aşırı boyut/aşırı ağırlık taşıma izinlerini hangi Virginia kurumu verir?","options":["Virginia Eyalet Polisi (Virginia State Police)","Yalnızca Virginia Ulaştırma Bakanlığı (Virginia Department of Transportation)","Virginia Motorlu Taşıtlar Dairesi (Virginia Department of Motor Vehicles)","Yerel şerif ofisi"],"explanation":"Aşırı boyut/aşırı ağırlık taşıma izinlerini Virginia Department of Motor Vehicles verir; bunlar eyaletin otomatik çevrimiçi taşıma izni sistemi üzerinden talep edilir. Kaynak: Virginia DMV Hauling Permits; Code of Virginia Article 18."},"15":{"q":"Virginia aşırı boyut/aşırı ağırlık taşıma izinleri tipik olarak nasıl alınır?","options":["Richmond'a kâğıt bir form postalayarak","DMV'nin çevrimiçi otomatik taşıma izni sistemi aracılığıyla","Yalnızca şahsen, bir DMV müşteri hizmetleri merkezinde","Virginia Eyalet Polisi sevkiyat hattını arayarak"],"explanation":"Virginia taşıma izinleri, eski VAHPS'nin yerini alan DMV'nin otomatik çevrimiçi taşıma izni sistemi (güncel portal: ezhaulvirginia.com) aracılığıyla talep edilir. Kaynak: Virginia DMV Hauling Permits."},"16":{"q":"Virginia'da yetiştirilen çiftlik veya orman ürünlerinin taşınması için Virginia Code 46.2-1129 kapsamında verilen bir izin, tek aks, çift aks (tandem) ve brüt ağırlık sınırlarını hangi yüzdeyle artırır?","options":["Yüzde üç","Yüzde beş","Yüzde on","Yüzde on beş"],"explanation":"Virginia Code 46.2-1129, Virginia'da yetiştirilen çiftlik veya orman ürünlerini taşıyan belirli araçlar için tek aks, çift aks (tandem) ve brüt ağırlık sınırlarının her birini yüzde beş artıran bir izne olanak tanır. Kaynak: Code of Virginia 46.2-1129."},"17":{"q":"Virginia Code 46.2-1129'daki çiftlik/orman ürünleri ağırlık artışı kapsamında, bir izin hangi brüt ağırlığı aşan bir kullanıma yetki veremez?","options":["80,000 pounds","82,000 pounds","84,000 pounds","90,000 pounds"],"explanation":"Virginia Code 46.2-1129, böyle bir iznin brüt ağırlığı 84,000 pounds'u aşan bir motorlu aracın kullanımına yetki veremeyeceğini öngörür. Kaynak: Code of Virginia 46.2-1129."},"18":{"q":"Virginia Code 46.2-1129 kapsamındaki yüzde beşlik çiftlik/orman ürünleri ağırlık artışı, eyaletler arası (interstate) karayolu sisteminde uygulanır mı?","options":["Evet, eyaletler arası yollarda 84,000 pounds'a kadar","Hayır; eyaletler arası sınırlar 20,000/34,000/80,000 pounds olarak kalır","Evet, ancak yalnızca Eyalet Polisi eskortuyla","Evet, eyaletler arası yollarda 88,000 pounds'a kadar"],"explanation":"Çiftlik/orman ürünleri artışı eyaletler arası sınırları yükseltmez; Virginia Code 46.2-1127, aks aralığından bağımsız olarak eyaletler arası üst sınırları 20,000 lb tek aks, 34,000 lb çift aks (tandem) ve 80,000 lb brüt olarak korur. Kaynak: Code of Virginia 46.2-1129 ve 46.2-1127."},"19":{"q":"Virginia'da, hangi genişlik eşiğinin aşılması bir yükün aşırı boyutlu olduğu ve bir taşıma izni gerektirdiği anlamına gelir?","options":["8 feet 0 inches'tan (96 inches) fazlası","8 feet 6 inches'tan (102 inches) fazlası","9 feet 0 inches'tan (108 inches) fazlası","10 feet 0 inches'tan (120 inches) fazlası"],"explanation":"Code 46.2-1105 uyarınca Virginia'nın yasal genişliği 8 feet 6 inches'tır (102 inches); 8 feet 6 inches'tan daha geniş herhangi bir yük aşırı boyutludur ve bir DMV taşıma izni gerektirir. Kaynak: Code of Virginia 46.2-1105; Virginia DMV Hauling Permits."},"20":{"q":"Virginia'da, 10,000 pounds'tan ağır bir römork çekmeyen ve brüt araç ağırlık derecesi (GVWR) 26,001 pounds veya daha fazla olan tek bir aracı kullanmak için hangi CDL sınıfı gereklidir?","options":["Class A","Class B","Class C","Class D"],"explanation":"Virginia DMV, Class B CDL'yi, GVWR'si 26,001 pounds veya daha fazla olan herhangi bir tek araç ya da GVWR'si 10,000 pounds'u aşmayan bir üniteyi çeken böyle bir araç olarak tanımlar. Kaynak: Virginia DMV, CDL Classifications, Endorsements and Restrictions (dmv.virginia.gov/licenses-ids/cdl/class)."},"21":{"q":"Virginia kurallarına göre, brüt kombinasyon ağırlık derecesi (GCWR) 26,001 pounds veya daha fazla olan herhangi bir araç kombinasyonu için Class A CDL gereklidir; ancak çekilen aracın GVWR'sinin hangi miktardan fazla olması şartıyla?","options":["5,000 pounds","8,000 pounds","10,000 pounds","15,000 pounds"],"explanation":"Virginia DMV, Class A'yı, GCWR'si 26,001+ pounds olan ve çekilen ünitenin/ünitelerin GVWR'si 10,000 pounds'u aşan bir kombinasyon olarak tanımlar. Kaynak: Virginia DMV, CDL Classifications, Endorsements and Restrictions (dmv.virginia.gov/licenses-ids/cdl/class)."},"22":{"q":"Bir Virginia sürücüsü, Class A veya B ağırlık eşiklerini karşılamayan ancak sürücü dahil 16 veya daha fazla yolcu taşımak üzere tasarlanmış bir aracı kullanmaktadır. Hangi CDL sınıfı geçerlidir?","options":["Class A","Class B","Class C","CDL gerekli değildir"],"explanation":"Virginia DMV, Class C'yi, Class A veya B'yi karşılamayan ve ya 16 veya daha fazla kişi (sürücü dahil) taşıyan ya da plaka (placard) gerektiren tehlikeli maddeler taşıyan herhangi bir araç olarak tanımlar. Kaynak: Virginia DMV, CDL Classifications, Endorsements and Restrictions (dmv.virginia.gov/licenses-ids/cdl/class)."},"23":{"q":"Hangi Virginia CDL onayı (endorsement) sahibine bir tank aracı kullanma izni verir?","options":["Endorsement N","Endorsement T","Endorsement H","Endorsement P"],"explanation":"Virginia DMV, tank (tanker) araçları için N onayını (endorsement) atar. H onayı tehlikeli maddeler için, T çift/üçlü römorklar için ve P yolcu araçları içindir. Kaynak: Virginia DMV, CDL Classifications, Endorsements and Restrictions (dmv.virginia.gov/licenses-ids/cdl/class)."},"24":{"q":"Çift veya üçlü römork çeken bir aracı kullanmak için hangi Virginia CDL onayı (endorsement) gereklidir?","options":["Endorsement P","Endorsement N","Endorsement T","Endorsement S"],"explanation":"Virginia DMV, çift veya üçlü römork çeken bir aracın kullanılmasına izin vermek için T onayını (endorsement) atar. Kaynak: Virginia DMV, CDL Classifications, Endorsements and Restrictions (dmv.virginia.gov/licenses-ids/cdl/class)."},"25":{"q":"Yalnızca eyalet içi (Virginia içinde) sürüş için geçerli bir Virginia CDL almanın asgari yaşı nedir?","options":["16 years old","18 years old","21 years old","25 years old"],"explanation":"Virginia DMV, eyalet içi bir CDL için başvuru sahibinin en az 18 yaşında ve eyaletler arası bir CDL için en az 21 yaşında olmasını gerektirir. Kaynak: Virginia DMV, CDL Skills Test Eligibility Requirements (dmv.virginia.gov/licenses-ids/cdl/eligibility)."},"26":{"q":"Eyaletler arası (eyalet sınırları boyunca) kullanım için geçerli bir Virginia CDL almanın asgari yaşı nedir?","options":["18 years old","19 years old","20 years old","21 years old"],"explanation":"Virginia DMV, eyaletler arası bir CDL için başvuru sahibinin en az 21 yaşında olmasını gerektirir; yalnızca eyalet içi bir CDL için asgari yaş 18'dir. Kaynak: Virginia DMV, CDL Skills Test Eligibility Requirements (dmv.virginia.gov/licenses-ids/cdl/eligibility)."},"27":{"q":"CDL beceri sınavına girmeden önce, bir Virginia başvuru sahibinin genellikle bir Ticari Öğrenci İzni (Commercial Learner's Permit, CLP) sahibi olarak en az kaç gün beklemesi gerekir?","options":["7 days","10 days","14 days","30 days"],"explanation":"Virginia tarafından benimsenen federal standarda göre, bir başvuru sahibi beceri sınavına girmeden önce CLP'yi en az 14 days süreyle elinde bulundurmalıdır (önceden bir CDL sahibi olması veya onaylı bir eğitimi tamamlamış olması durumları hariç). Kaynak: Virginia DMV, CDL Skills Test Eligibility Requirements / Commercial Learner's Permit (dmv.virginia.gov/licenses-ids/cdl/eligibility)."},"28":{"q":"Bir Virginia Ticari Öğrenci İzni (CLP) ile ticari bir araç kullanırken, izin sahibinin yanında kim bulunmalıdır?","options":["21 yaşından büyük herhangi bir lisanslı yetişkin","Aynı tür araç için geçerli bir CDL sahibi olan bir kişi","Yalnızca bir DMV sınav görevlisi","Hiç kimse; tek başına sürüşe izin verilir"],"explanation":"Virginia DMV, bir CLP'nin yalnızca aynı tür aracı kullanmak için lisanslı bir kişi (o sınıf/tür için geçerli bir CDL sahibi) izin sahibiyle fiziksel olarak birlikteyken ticari bir aracın kullanılmasına izin verdiğini belirtir. Kaynak: Virginia DMV, Commercial Learner's Permit (dmv.virginia.gov/licenses-ids/cdl/permit)."},"29":{"q":"Bir Virginia HazMat (H) onayı (endorsement) almak için, diğer onaylarda gerekli OLMAYAN hangi belge veya kontrol özel olarak gereklidir?","options":["Parmak izine dayalı bir TSA güvenlik tehdidi değerlendirmesi","İkinci bir görme taraması","İşveren sponsorluk mektubu","Noter onaylı bir sürüş günlüğü"],"explanation":"Virginia DMV, HazMat (HME) başvuru sahiplerinin parmak izine dayalı bir geçmiş kontrolünü tamamlamasını gerektirir; DMV bilgileri TSA'ya iletir ve TSA güvenlik tehdidi değerlendirmesini yapar ve onayı kabul veya reddeder. Kaynak: Virginia DMV, Hazardous Materials Endorsement (HME) (dmv.virginia.gov/licenses-ids/cdl/hazmat)."},"30":{"q":"Bir Virginia HazMat (H) onayı (endorsement) için parmak izine dayalı geçmiş kontrolü ne kadar süre geçerlidir?","options":["1 year","3 years","5 years","10 years"],"explanation":"Virginia DMV, HazMat onayı için parmak izine dayalı geçmiş kontrolünün en fazla beş yıl geçerli olduğunu ve ardından yenilenmesi gerektiğini belirtir. Kaynak: Virginia DMV, Hazardous Materials Endorsement (HME) (dmv.virginia.gov/licenses-ids/cdl/hazmat)."},"31":{"q":"Geçerli bir TWIC (Transportation Worker Identification Credential) sahibi olan bir Virginia başvuru sahibi, bir HazMat onayı için başvururken hangi avantajı elde eder?","options":["Bilgi sınavından muaf tutulur","İndirimli ücret ve yeni parmak izi alınmaması","TSA incelemesi olmaksızın otomatik onay","Hiç sona ermeyen ömür boyu bir onay"],"explanation":"Virginia DMV, TWIC sahiplerinden indirimli, iade edilmeyen bir HazMat ücreti ($41 yerine $83) alır ve yeni parmak izi gerektirmez; çünkü TWIC zaten benzer bir TSA tehdit değerlendirmesini içerir. Kaynak: Virginia DMV, Hazardous Materials Endorsement / Applying for a CDL (dmv.virginia.gov/licenses-ids/cdl/hazmat)."},"32":{"q":"Virginia'da uygulanan federal Giriş Seviyesi Sürücü Eğitimi (Entry-Level Driver Training, ELDT) kuralı kapsamında, eğitim beceri sınavından önce hangi sicilde listelenen bir sağlayıcı aracılığıyla tamamlanmalıdır?","options":["Virginia DMV Onaylı Okullar Listesi","FMCSA Eğitim Sağlayıcı Sicili (Training Provider Registry, TPR)","National CDL Academy Directory","DOT Carrier Safety Index"],"explanation":"ELDT, FMCSA Eğitim Sağlayıcı Sicili'nde (Training Provider Registry, TPR) listelenen bir sağlayıcı tarafından tamamlanmalıdır; Virginia DMV, beceri sınavından önce tamamlanmayı elektronik olarak doğrular. Kaynak: Virginia DMV / FMCSA Entry-Level Driver Training (tpr.fmcsa.dot.gov; dmv.virginia.gov/licenses-ids/cdl/eligibility)."},"33":{"q":"Aşağıdaki ilk kez yapılan işlemlerden hangisi Virginia'da federal ELDT eğitim gerekliliğini TETİKLEMEZ?","options":["İlk kez bir CDL almak","Class B CDL'yi Class A CDL'ye yükseltmek","Mevcut bir CDL'yi aynı sınıf ve onaylarla yenilemek","İlk kez bir Yolcu (P) onayı almak"],"explanation":"ELDT, ilk kez CDL başvuru sahipleri, Class B'den Class A'ya yükseltme ve ilk kez H, P veya S onayları için gereklidir. Yeni bir sınıf veya onay olmaksızın mevcut bir CDL'nin basit bir yenilemesi ELDT gerektirmez. Kaynak: FMCSA Entry-Level Driver Training rule, applied by Virginia DMV (fmcsa.dot.gov; dmv.virginia.gov)."},"34":{"q":"İlk kez başvuran bir Virginia HazMat başvuru sahibi için, ELDT'nin teori bölümü ne zaman tamamlanmalıdır?","options":["HazMat bilgi sınavını geçtikten sonra","DMV'de HazMat bilgi sınavına girmeden önce","Yalnızca TSA geçmiş kontrolünü onayladıktan sonra","Onay verildikten sonraki 30 gün içinde"],"explanation":"Virginia'da uygulanan ELDT kuralı kapsamında, ilk kez başvuran HazMat (H) onayı başvuru sahipleri, DMV'de HazMat bilgi sınavına girmeden önce ELDT teori eğitimini tamamlamalıdır. Kaynak: FMCSA ELDT rule / Virginia DMV (fmcsa.dot.gov; dmv.virginia.gov/licenses-ids/cdl)."},"35":{"q":"Bir Virginia CDL başvuru sahibi, ticari motorlu araç kullanım türüyle ilgili kaç adet tıbbi öz-beyan kategorisi arasından seçim yapmalıdır?","options":["İki","Üç","Dört","Beş"],"explanation":"Virginia DMV, başvuru sahiplerinin dört kategoriden birine öz-beyanda bulunmasını gerektirir: muaf eyaletler arası (excepted interstate), muaf olmayan eyaletler arası (non-excepted interstate), muaf eyalet içi (excepted intrastate) veya muaf olmayan eyalet içi (non-excepted intrastate). Kaynak: Virginia DMV, Apply for a CDL or CLP (dmv.virginia.gov/licenses-ids/cdl/applying)."},"36":{"q":"Eyalet sınırları boyunca araç kullanan ve federal fiziksel yeterlilik kurallarından muaf OLMAYAN bir Virginia CDL başvuru sahibi hangi kategoride öz-beyanda bulunmalıdır?","options":["Muaf eyaletler arası (Excepted interstate)","Muaf olmayan eyaletler arası (Non-excepted interstate)","Muaf eyalet içi (Excepted intrastate)","Muaf olmayan eyalet içi (Non-excepted intrastate)"],"explanation":"Eyaletler arası ticarette faaliyet gösteren ve federal tıbbi yeterlilik standartlarını karşılaması gereken bir sürücü, 'non-excepted interstate' olarak öz-beyanda bulunur ve geçerli bir tıbbi muayene sertifikası bulundurmalıdır. Kaynak: Virginia DMV, Apply for a CDL or CLP, medical self-certification (dmv.virginia.gov/licenses-ids/cdl/applying)."},"37":{"q":"Daha önce hiç Virginia ehliyeti almamış, ilk kez başvuran bir Virginia CDL başvuru sahibi; kimlik kanıtı, yasal varlık kanıtı, bir Sosyal Güvenlik numarası ve kaç adet Virginia ikamet kanıtı sunmalıdır?","options":["Bir ikamet kanıtı","İki ikamet kanıtı","Üç ikamet kanıtı","İkamet kanıtı gerekli değildir"],"explanation":"Virginia DMV, daha önce hiç Virginia ehliyeti/kimliği almamış, ilk kez başvuran bir başvuru sahibinin bir kimlik kanıtı, bir yasal varlık kanıtı, bir Sosyal Güvenlik numarası kanıtı ve iki Virginia ikamet kanıtı sunmasını gerektirir. Kaynak: Virginia DMV, Apply for a CDL or CLP (dmv.virginia.gov/licenses-ids/cdl/applying)."},"38":{"q":"Virginia'nın Cinsel Suçlular ve Reşit Olmayanlara Karşı İşlenen Suçlar Sicili'ne (Sex Offender and Crimes Against Minors Registry) kaydolması gereken bir kişi, kayıt zorunluluğu devam ettiği sürece hangi CDL onayını (endorsement) almaya uygun değildir?","options":["N (Tanker)","T (Çift/Üçlü)","S (Okul Otobüsü)","H (HazMat)"],"explanation":"Virginia, Sex Offender and Crimes Against Minors Registry'ye kaydolması gereken herhangi bir kişiye, kayıt zorunluluğunun devam ettiği herhangi bir dönemde S (Okul Otobüsü) onayının verilmesini yasaklar. Kaynak: Virginia DMV, CDL Classifications, Endorsements and Restrictions (dmv.virginia.gov/licenses-ids/cdl/class)."},"39":{"q":"Bir Virginia CDL veya CLP üzerinde, sahibinin havalı frenle (air brakes) donatılmış bir aracı kullanAMAYacağını hangi kısıtlama kodu gösterir?","options":["Restriction E","Restriction L","Restriction K","Restriction B"],"explanation":"Virginia DMV, başvuru sahibi havalı fren bilgi testini geçemediğinde veya havalı freni olmayan bir araçta sınava girdiğinde L kısıtlamasını (havalı fren yok) uygular. Restriction E manuel şanzıman yok, K yalnızca Virginia/eyalet içi ve B düzeltici lensler anlamına gelir. Kaynak: Virginia DMV, CDL Classifications, Endorsements and Restrictions (dmv.virginia.gov/licenses-ids/cdl/class)."},"40":{"q":"Virginia'da, bir kişinin ticari bir motorlu aracı (CMV) yasal olarak kullanabileceği maksimum kandaki alkol konsantrasyonu (BAC) nedir?","options":["0.02","0.04","0.08","0.10"],"explanation":"Virginia, bir CMV'yi 0.04 veya daha yüksek bir BAC ile kullanan bir CDL sahibini diskalifiye eder — bu, sıradan sürücüler için olan 0.08 sınırının yarısıdır. Kaynak: Virginia DMV CDL Disqualifications sayfası; Va. Code § 46.2-341.24."},"41":{"q":"Virginia'nın ticari sürücüler için zımni rıza (implied-consent) yasası uyarınca, bir Virginia karayolunda bir CMV kullanan sürücü neyi kabul etmiş sayılır?","options":["Herhangi bir kantarda bir araç güvenlik denetimi","Bir DUI suçundan yasal olarak tutuklanması halinde kan ve/veya nefesin kimyasal testi","Her vardiyadan önce zorunlu bir uyuşturucu taraması","Herhangi bir kolluk görevlisi tarafından rastgele sorgulanma"],"explanation":"Virginia'nın zımni rıza yasası, bir karayolunda CMV kullanan herhangi bir kişinin, § 46.2-341.24 kapsamındaki bir suçtan tutuklanması halinde, suçtan sonraki üç saat içinde alınmak üzere, alkol/uyuşturucu içeriğinin kimyasal testi için kan, nefes veya her ikisini de vermeye rıza gösterdiğini öngörür. Kaynak: Va. Code § 46.2-341.26:2; Virginia DMV CDL manual."},"42":{"q":"Bir Virginia CDL sahibi, plakalı (placarded) tehlikeli madde TAŞIMAZKEN ilk büyük suçtan (örneğin bir CMV DUI) mahkûm olur. Diskalifiye süresi nedir?","options":["60 days","6 months","1 year","3 years"],"explanation":"İlk büyük suç (DUI, BAC 0.04+, test reddi, olay yerini terk etme vb.) Virginia'da 1-year CDL diskalifikasyonuyla sonuçlanır. Kaynak: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 1, Virginia kuralı olarak uygulanır."},"43":{"q":"Bir Virginia sürücüsü, plaka (placard) gerektiren tehlikeli madde taşıyan bir CMV'yi kullanırken ilk büyük suçu işlerse, diskalifiye süresi şuna yükselir:","options":["1 year","2 years","3 years","5 years"],"explanation":"Plakalı (placarded) tehlikeli madde taşınırken işlenen ilk büyük suç, diskalifikasyonu 1 year'dan 3 years'a yükseltir. Kaynak: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 1."},"44":{"q":"Virginia'da ikinci bir büyük suç için (örneğin ikinci bir CMV DUI mahkûmiyeti) CDL diskalifikasyonu nedir?","options":["3 years","5 years","10 years","Ömür boyu"],"explanation":"İkinci bir büyük suç, Virginia'da ömür boyu CDL diskalifikasyonuyla sonuçlanır; ancak belirli koşullar altında 10 years sonra yeniden işleme alınma mümkün olabilir. Kaynak: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 1."},"45":{"q":"Bir Virginia CDL sahibi, bir CMV'yi etki altında kullanmaktan yasal olarak tutuklandıktan sonra gerekli kan veya nefes testini vermeyi reddeder. Bu, CDL diskalifikasyonu açısından nasıl değerlendirilir?","options":["Yalnızca ciddi bir trafik ihlalidir (60 days)","Büyük bir suçtur ve ilk suç için 1 yıllık bir diskalifikasyon taşır","Hiçbir CDL diskalifikasyonu taşımaz, yalnızca bir para cezası","İlk reddetmede otomatik olarak ömür boyu diskalifikasyonla sonuçlanır"],"explanation":"Kimyasal testi reddetmek büyük bir suçtur ve sürücüyü ilk suçta 1 year (plakalı hazmat ise 3 years) diskalifiye eder — bir DUI mahkûmiyetiyle aynı. Kaynak: Virginia DMV CDL Disqualifications; Va. Code § 46.2-341.26:2; 49 CFR 383.51 Table 1."},"46":{"q":"Aşağıdakilerden hangisi Virginia tarafından bir CDL sahibi için 'ciddi trafik ihlali' (serious traffic violation) olarak sınıflandırılır?","options":["Bir CMV'yi park yasağı bölgesine park etmek","Belirtilen hız sınırının 15 mph veya daha fazla üzerinde hız yapmak","Süresi dolmuş bir araç tescil etiketi","Sigorta kanıtı taşımamak"],"explanation":"Virginia, hız sınırının 15 mph veya daha fazla üzerinde hız yapmayı; dikkatsiz sürüş, uygunsuz/düzensiz şerit değişikliği, çok yakın takip, bir CMV kullanırken mesajlaşma ve ölümlü bir kazaya bağlı trafik suçlarıyla birlikte ciddi bir trafik ihlali olarak listeler. Kaynak: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 2."},"47":{"q":"Bir Virginia CDL sahibi, 3 yıllık bir süre içinde (ayrı olaylarda) İKİ ciddi trafik ihlalinden mahkûm olduğunda kaç gün diskalifiye edilir?","options":["30 days","60 days","90 days","120 days"],"explanation":"3 yıl içinde iki ciddi trafik ihlali, Virginia'da 60-day CDL diskalifikasyonuyla sonuçlanır. Kaynak: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 2."},"48":{"q":"Bir Virginia CDL sahibi, 3 yıllık bir süre içinde (ayrı olaylarda) ÜÇ ciddi trafik ihlalinden mahkûm olur. Diskalifikasyon nedir?","options":["60 days","90 days","120 days","180 days"],"explanation":"3 yıl içinde üç veya daha fazla ciddi trafik ihlali, Virginia'da 120-day CDL diskalifikasyonuyla sonuçlanır. Kaynak: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 2."},"49":{"q":"Ciddi trafik ihlali diskalifikasyonları (60 / 120 days) yalnızca ihlaller hangi zaman aralığında sayıldığında uygulanır?","options":["1 year","3 years","5 years","10 years"],"explanation":"Ciddi trafik ihlalleri, 2 ihlal (60-day) ve 3 ihlal (120-day) diskalifikasyonları amacıyla 3 yıllık bir süre içinde sayılır. Kaynak: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 2."},"50":{"q":"Bir CMV kullanırken bir Virginia CDL sahibinin İLK demiryolu-karayolu hemzemin geçit ihlali için diskalifikasyon nedir?","options":["30 days","60 days","120 days","1 year"],"explanation":"İlk demiryolu geçit ihlali, 60 days'den az olmayan bir diskalifikasyonla sonuçlanır. Kaynak: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 3."},"51":{"q":"Bir Virginia CDL sahibi, 3 yıl içinde İKİNCİ bir demiryolu-karayolu hemzemin geçit ihlali işler. Diskalifikasyon nedir?","options":["60 days","120 days","180 days","1 year"],"explanation":"3 yıl içinde ikinci bir demiryolu geçit ihlali, 120 days'den az olmayan bir diskalifikasyonla sonuçlanır. Kaynak: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 3."},"52":{"q":"Bir Virginia CDL sahibi, 3 yıl içinde ÜÇÜNCÜ bir demiryolu-karayolu hemzemin geçit ihlali işler. Diskalifikasyon nedir?","options":["120 days","180 days","1 year","3 years"],"explanation":"3 yıl içinde üçüncü veya sonraki bir demiryolu geçit ihlali, 1 year'dan az olmayan bir diskalifikasyonla sonuçlanır. Kaynak: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 3."},"53":{"q":"Bir CMV kullanırken bir hizmet dışı (out-of-service, OOS) emrini ihlal etmekten bir CDL sahibinin İLK mahkûmiyeti için Virginia'daki asgari diskalifikasyon nedir?","options":["90 days","120 days","180 days","1 year"],"explanation":"Virginia, ilk hizmet dışı emir ihlali için bir sürücüyü 180 days'den az olmamak üzere (en fazla 1 year) diskalifiye eder. Kaynak: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 4."},"54":{"q":"Sıradan kargo taşırken bir hizmet dışı emri ihlal etmeye kıyasla, plakalı (placarded) tehlikeli madde veya 16+ yolcu taşırken bir OOS emrini ihlal eden bir Virginia CDL sürücüsü şununla karşı karşıya kalır:","options":["Daha düşük bir asgari diskalifikasyon","Aynı asgari ancak daha yüksek bir azami diskalifikasyon","Ek bir ceza yok","Yalnızca bir para cezası"],"explanation":"Plakalı hazmat veya 16+ yolcu taşımak için tasarlanmış yükler taşınırken yapılan bir OOS emri ihlali, 180-day asgariyi korur ancak ilk suç azamisini 2 years'a yükseltir (genel kargo için 1 year'a kıyasla). Kaynak: 49 CFR 383.51 Table 4, Virginia kuralı olarak uygulanır; Virginia DMV CDL Disqualifications."},"55":{"q":"Virginia yasalarına göre, bir CMV kullanırken mesajlaşan veya elde tutulan bir cep telefonu kullanan bir CDL sürücüsüne, şunu aşmayacak bir idari para cezası verilebilir:","options":["$250","$1,000","$2,750","$5,000"],"explanation":"Va. Code § 46.2-341.20:5, bir CMV sürücüsünün mesajlaşmasını veya elde tutulan bir cep telefonu kullanmasını yasaklar ve $2,750'ye kadar bir idari para cezasına yetki verir; böyle bir mahkûmiyet aynı zamanda CDL amaçları için ciddi bir trafik ihlalidir. Kaynak: Va. Code § 46.2-341.20:5; Virginia DMV CDL Disqualifications."},"56":{"q":"Virginia'da ticari bir motorlu aracı kullanırken mesajlaşma mahkûmiyeti, CDL amaçları için şu şekilde değerlendirilir:","options":["Büyük suç (1-year diskalifikasyon)","Ciddi trafik ihlali","Hizmet dışı emir ihlali","Bildirimi yapılamayan ihlal"],"explanation":"Bir CMV kullanırken mesajlaşma, Virginia'nın ciddi trafik ihlalleri arasında listelenir, dolayısıyla tekrarlanan mahkûmiyetler 3 yılda 2 (60-day) ve 3 yılda 3 (120-day) diskalifikasyonlarına dahil olur. Kaynak: Virginia DMV CDL Disqualifications; Va. Code § 46.2-341.20:5; 49 CFR 383.51 Table 2."},"57":{"q":"Virginia'nın genel hızla-dikkatsiz-sürüş yasası kapsamında (aynı zamanda bir CDL ciddi ihlali olan bir suçlama), sıradan hız aşımı hangi hızda 'dikkatsiz sürüş' (reckless driving) haline gelir?","options":["Sınırın 10 mph üzerinde","Sınırın 15 mph üzerinde","Sınırın 20 mph üzerinde veya 85 mph üzerinde herhangi bir hız","Sınırın 25 mph üzerinde veya 90 mph üzerinde herhangi bir hız"],"explanation":"Va. Code § 46.2-862, hızla dikkatsiz sürüşü sınırın 20 mph veya daha fazla üzerinde ya da sınırdan bağımsız olarak 85 mph'i aşan hız olarak tanımlar; dikkatsiz sürüş aynı zamanda bir CDL ciddi trafik ihlalidir (sınırın 15 mph üzerindeki ciddi ihlal eşiğinden ayrı olarak). Kaynak: Va. Code § 46.2-862; Virginia DMV CDL Disqualifications."},"58":{"q":"Bir Virginia CDL sahibi, kontrollü bir maddenin imalatı, dağıtımı veya temini içeren bir suçun işlenmesinde bir CMV kullanmaktan mahkûm olur. Diskalifikasyon nedir?","options":["1 year","3 years","10 years","10 yıllık yeniden işleme alınma imkanı olmaksızın ömür boyu"],"explanation":"Kontrollü maddeleri imal etmek, dağıtmak veya temin etmek için bir CMV kullanmak, diğer ömür boyu diskalifikasyonlarda mevcut olan 10 yıllık yeniden işleme alınma için uygun OLMAYAN ömür boyu bir diskalifikasyon taşıyan büyük bir suçtur. Kaynak: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 1."},"59":{"q":"Virginia'da bir CMV DUI için bir CDL sahibinin diskalifikasyonu öncelikle hangi sürüş ayrıcalığını etkiler?","options":["Yalnızca motosiklet kullanma ayrıcalığını","Ticari (CDL) sürüş ayrıcalığını","Yalnızca eyalet dışı sürüş ayrıcalıklarını","Tekne ve deniz aracı ayrıcalıklarını"],"explanation":"CDL diskalifikasyonu, ticari motorlu araçları kullanma ayrıcalığını kaldırır; ayrı bir ehliyet askıya alması da uygulanabilir, ancak diskalifikasyon özellikle CDL/ticari sürüş ayrıcalığını hedef alır. Kaynak: Virginia DMV CDL Disqualifications; Va. Code § 46.2-341.18."},"60":{"q":"Virginia'nın Yer Aç (Move Over) yasasına göre, durmuş ve yanıp sönen ışıkları çalışan bir acil durum aracı için şerit değiştirme yükümlülüğünün geçerli olabilmesi için bir karayolunun en az kaç şeride (ve hangi düzende) sahip olması gerekir?","options":["En az dört şerit, bunların en az ikisi sürücüyle aynı yönde ilerleyen trafik için olmalı","Herhangi bir iki şeritli bölünmemiş karayolu","Her yönde üç şerit olmak üzere en az altı şerit","Yalnızca işaretlenmiş eyaletler arası otoyollarda"],"explanation":"Code of Virginia 46.2-861.1 (Virginia'nın Yer Aç yasası), en az dört şeritli ve bunların ikisi aynı yönde trafik taşıyan karayollarındaki sürücülerin, yanıp sönen uyarı ışıkları gösteren sabit bir acil durum aracından uzağa şerit değiştirmesini gerektirir; güvenli bir şerit değişikliği mümkün değilse, sürücü hızını azaltmalı ve dikkatle ilerlemelidir. Kaynak: Code of Virginia 46.2-861.1."},"61":{"q":"Virginia'da, bir sürücü yanıp sönen ışıkları gösteren durmuş bir acil durum aracından uzağa güvenli bir şekilde şerit değiştiremediğinde, bunun yerine ne yapmalıdır?","options":["Dikkatle ilerlemeli ve hızını işaretli sınırın altına düşürmeli","Acil durum aracı ayrılana kadar tamamen durmalı","Kornaya basmalı ve işaretli hızı korumalı","Dörtlü flaşörleri açmalı ve normal hızda devam etmeli"],"explanation":"Code of Virginia 46.2-861.1 uyarınca, şerit değişikliği güvenli bir şekilde yapılamıyorsa, sürücü gereken dikkatle ilerlemeli ve karayolu koşulları için güvenli bir hızı korumalı, olay yerindeki acil durum personelini korumak için hızını azaltmalıdır. İhlal, pervasız sürüş (Class 1 misdemeanor) olarak işlem görür. Kaynak: Code of Virginia 46.2-861.1."},"62":{"q":"Virginia'da, Yer Aç yasasının ihlali (durmuş bir acil durum aracı için yer açmama veya yavaşlamama) ne olarak işlem görür?","options":["Pervasız sürüş, bir Class 1 misdemeanor","Hareketsiz bir hukuki ihlal","Puansız basit bir trafik ihlali","Yaralanma olmazsa bir felony"],"explanation":"Code of Virginia 46.2-861.1, sabit bir acil durum aracı için yol vermeme veya yer açmamayı bir pervasız sürüş türü haline getirir; bu, olası hapis cezası, 2.500 dolara kadar para cezası ve ehliyet askıya alınması içeren bir Class 1 misdemeanor'dır. Kaynak: Code of Virginia 46.2-861.1."},"63":{"q":"Virginia'nın erişimi sınırlı olmayan (eyaletler arası olmayan) karayollarında, işaretli istisnalar dışında, mülk taşımak için tasarlanmış bir çekici-römork veya kamyon için maksimum hız sınırı nedir?","options":["45 mph","55 mph","60 mph","65 mph"],"explanation":"Code of Virginia 46.2-870, erişimi sınırlı olmayan karayollarında varsayılan sınırı yolcu araçları ve otobüsler için 55 mph, ancak mülk taşımak için tasarlanmış kamyonlar, çekici kamyonlar ve kombinasyonlar için yalnızca 45 mph olarak belirler; yani yolcu araçlarından 10 mph daha az. Kaynak: Code of Virginia 46.2-870."},"64":{"q":"Bir Virginia eyaletler arası otoyolunda, bir trafik mühendisliği çalışmasının ardından daha yüksek sınırın işaretlendiği yerlerde, ticari bir kamyon için maksimum hız sınırı nedir?","options":["70 mph, yolcu araçlarıyla aynı","55 mph, otomobiller 70 mph gidebilirken","Yalnızca kamyonlar için 65 mph","75 mph"],"explanation":"Code of Virginia 46.2-870, eyaletler arası maksimumu 55 mph olarak, veya bir mühendislik çalışmasının ardından yasal olarak işaretler dikildiği yerlerde 70 mph olarak belirler. Eyaletler arası otoyollarda daha yüksek işaretli sınır, kamyonlar dahil tüm araçlar için geçerlidir; Virginia eyaletler arası otoyollarda kamyonlar için ayrı bir daha düşük hız sınırı uygulamaz. Kaynak: Code of Virginia 46.2-870."},"65":{"q":"Virginia'da bir demiryolu hemzemin geçidinde, plakartlı tehlikeli madde aracı veya ücret karşılığı yolcu taşıyan bir otobüs, en yakın raydan ne kadar mesafe içinde durmalıdır?","options":["50 feet içinde ancak 15 feet'ten az olmamak üzere","100 feet içinde ancak 25 feet'ten az olmamak üzere","30 feet içinde ancak 10 feet'ten az olmamak üzere","15 feet içinde ancak 5 feet'ten az olmamak üzere"],"explanation":"Code of Virginia 46.2-886, ücret karşılığı yolcu taşıyan veya yük olarak patlayıcı maddeler ya da yanıcı sıvılar taşıyan araçların, en yakın raydan 50 feet içinde ancak 15 feet'ten az olmamak üzere durmasını, ardından ilerlemeden önce bakıp dinlemesini gerektirir. Bu, Virginia CDL Kılavuzu'nun demiryolu geçidi kuralıyla uyumludur. Kaynak: Code of Virginia 46.2-886; Virginia CDL Manual."},"66":{"q":"Bir demiryolu geçidinde durduktan sonra, araç raylar üzerindeyken vites değişiklikleriyle ilgili olarak Virginia yasası ne gerektirir?","options":["Sürücü, raylar üzerindeyken vites değiştirmeyi gerektirmeyen bir vitesle geçmelidir","Sürücü, geçişin ortasında en düşük vitese geçmelidir","Sürücü, hız korunduğu sürece serbestçe vites değiştirebilir","Sürücü, geçerken boşa almalıdır"],"explanation":"Code of Virginia 46.2-886, durduktan ve ilerlerken sürücünün yalnızca geçişi geçerken vites değiştirmeye gerek olmayacak bir vitesle geçmesi ve geçerken vites değiştirmemesi gerektiğini belirtir. Kaynak: Code of Virginia 46.2-886; Virginia CDL Manual."},"67":{"q":"Virginia'da, bölünmemiş iki şeritli bir yolda çocukları indiren veya bindiren durmuş bir okul otobüsüne yaklaşan bir sürücü ne yapmalıdır?","options":["Herhangi bir yönden yaklaşırken durmalı ve otobüs hareket edene veya ışıkları yanıp sönmeyi bırakana kadar durmuş halde kalmalı","Yalnızca otobüsle aynı yönde seyrediyorsa durmalı","20 mph'ye yavaşlamalı ancak durması gerekmez","Yalnızca çocuklar görünür şekilde karşıdan karşıya geçiyorsa durmalı"],"explanation":"Code of Virginia 46.2-859, herhangi bir yönden yaklaşan bir sürücünün, yolcu indirmek veya bindirmek için durmuş ve uyarı cihazlarını gösteren bir okul otobüsü için durmasını ve kişiler güvenli mesafeye geçene ve otobüs tekrar hareket edene kadar durmuş halde kalmasını gerektirir. Bir ihlal, pervasız sürüştür. Kaynak: Code of Virginia 46.2-859."},"68":{"q":"Bölünmüş bir Virginia karayolunda, karşı yönden gelen bir sürücünün, karşı taraftaki yolda durmuş bir okul otobüsü için durmasının gerekmediği koşul hangisidir?","options":["Yollar fiziksel bir bariyer veya asfaltsız bir alanla ayrıldığında","Boyalı çift sarı orta çizgi olduğunda","Hız sınırı 45 mph veya daha yüksek olduğunda","Yollar arasında bir orta dönüş şeridi olduğunda"],"explanation":"Code of Virginia 46.2-859, yalnızca okul otobüsü bölünmüş bir karayolunun (veya bir servis yolu/araç yolunun) diğer yolunda olduğunda ve bu yol sürücünün yolundan fiziksel bir bariyer ya da asfaltsız bir alanla ayrıldığında sürücüyü durma yükümlülüğünden muaf tutar. Yalnızca boyalı bir çizgi veya dönüş şeridi bu niteliğe uymaz. Kaynak: Code of Virginia 46.2-859."},"69":{"q":"Bir ticari araç bir Virginia karayolunda durmak zorunda kaldığında, sürücü durduktan sonra kaç dakika içinde kırmızı yansıtıcı üçgen uyarı cihazlarını yerleştirmelidir?","options":["10 dakika içinde","5 dakika içinde","15 dakika içinde","Hemen, 1 dakika içinde"],"explanation":"Code of Virginia 46.2-111, durmuş bir ticari motorlu aracın operatörünün, durduktan sonra 10 dakika içinde gerekli kırmızı yansıtıcı üçgen uyarı cihazlarını yerleştirmesini ve bunlar yerleştirilene kadar dörtlü flaşörleri açık tutmasını gerektirir. Kaynak: Code of Virginia 46.2-111."},"70":{"q":"Düz, dümdüz bir Virginia yolunda durmuş bir ticari araç için üç uyarı üçgeni nereye yerleştirilmelidir?","options":["Arkaya 100 ft, öne 100 ft ve biri trafik tarafında aracın 10 ft yakınına","Hepsi arkaya olmak üzere 10 ft, 100 ft ve 200 ft","Yalnızca arkaya 50 ft, 100 ft ve 150 ft","Her iki yana birer tane ve biri tavana"],"explanation":"Code of Virginia 46.2-111, bir üçgenin yaklaşan trafik yönünde 100 feet'ten az olmamak üzere, birinin ters yönde 100 feet'ten az olmamak üzere ve birinin trafik tarafında aracın önüne veya arkasına 10 feet'ten yakın olmamak üzere yerleştirilmesini yönlendirir. Kaynak: Code of Virginia 46.2-111."},"71":{"q":"Bir Virginia ticari aracı bir virajın, tepe noktasının veya başka bir engelin 500 feet içinde durmuşsa, o yöndeki uyarı cihazı nasıl yerleştirilmelidir?","options":["Yeterli uyarı sağlayacak kadar uzağa, ancak hiçbir durumda araçtan 500 feet'ten az olmamak üzere","Araçtan tam olarak 100 feet uzağa","Araçtan en fazla 200 feet uzağa","Doğrudan engelin kendi üzerine"],"explanation":"Code of Virginia 46.2-111, bir virajın, tepenin zirvesinin veya başka bir engelin 500 feet içinde durulduğunda, o yöndeki uyarı cihazının yeterli uyarı sağlayacak şekilde, hiçbir durumda durmuş araçtan 500 feet'ten az olmamak üzere yerleştirilmesini gerektirir. Kaynak: Code of Virginia 46.2-111."},"72":{"q":"Virginia'nın Interstate 81'inde ve her yönde ikiden fazla şeride sahip eyaletler arası otoyollarda, ticari motorlu araçlara hangi şerit kısıtlaması uygulanır?","options":["En sol şeritte sürmeleri yasaktır","Yalnızca en sol şeridi kullanabilirler","Kamyon minimum hızının 10 mph içinde kalmalıdırlar","Yalnızca orta şeritle sınırlıdırlar"],"explanation":"Code of Virginia 46.2-803.1, ticari motorlu araçların I-81'de ve her yönde ikiden fazla seyir şeridine sahip eyaletler arası otoyollarda (genellikle sınırın 65 mph veya daha yüksek olduğu yerlerde) en sol şeritte çalışmasını yasaklar. Otobüsler ve sol çıkışa hazırlanan araçlar istisnadır. Kaynak: Code of Virginia 46.2-803.1."},"73":{"q":"Şeritli bir Virginia karayolunda, trafiğin normal hızından daha yavaş seyreden herhangi bir araç nerede sürülmelidir?","options":["Sol dönüş için sollama veya hazırlık dışında, sağ kenara veya sağ bordüre en yakın şeritte","Sürücünün seçtiği herhangi bir şeritte","Trafiği dengelemek için orta şeritte","Birleşen trafikten uzak durmak için sol şeritte"],"explanation":"Code of Virginia 46.2-804, trafiğin normal hızından daha yavaş ilerleyen bir aracın, sollama ve geçiş, sol dönüşe hazırlanma veya sağ şeritlerin yavaş trafik için ayrıldığı durumlar dışında, sağ kenara veya bordüre en yakın şeritte sürülmesini gerektirir. Kaynak: Code of Virginia 46.2-804."},"74":{"q":"Hangi Virginia manzaralı parkway'leri genellikle ticari kamyonların üzerinde çalışmasını yasaklar?","options":["George Washington Memorial Parkway ve Colonial Parkway","Interstate 95 ve Interstate 64","Capital Beltway (I-495)","U.S. Route 29 ve U.S. Route 58"],"explanation":"Federal olarak yönetilen George Washington Memorial Parkway ve Virginia'daki Colonial Parkway ticari kamyonları yasaklar; GW Parkway herhangi bir ticari araç için özel bir National Park Service izni gerektirir ve Colonial Parkway yolcu otobüsleri dışında kamyonları engeller. Kaynak: National Park Service / VDOT kamyon kısıtlaması rehberi."},"75":{"q":"Belirli tehlikeli madde sınıflarının, Hampton Roads Bridge-Tunnel gibi Virginia'nın suya yakın tünellerinde bulunması yasaktır. Bu kısıtlamaları ne yönetir?","options":["Tehlike sınıfına dayalı olarak, köprü-tünel tesislerinden tehlikeli madde geçişini yöneten VDOT yönetmelikleri (24VAC30-61)","Yalnızca federal eyaletler arası ağırlık sınırları","Yalnızca aracın brüt kombinasyon ağırlık derecelendirmesi","Yükün sigortalı olup olmadığı"],"explanation":"Virginia idari yönetmeliği 24VAC30-61, eyaletin kentsel ve suya yakın tünellerinden (Hampton Roads, Monitor-Merrimac ve Elizabeth River tünelleri) tehlikeli madde taşınmasını yönetir ve patlayıcılar ile zehirli gazlar gibi belirli tehlike sınıflarını yasaklar. Kaynak: 24VAC30-61; VDOT Tehlikeli Maddeler rehberi."},"76":{"q":"Virginia'da Interstate 77 üzerindeki dik Fancy Gap eğiminden inen güneye giden kamyonlar, özellikle hangi güvenlik özelliğinin farkında olmalıdır?","options":["Uzun yokuş aşağı bölümdeki birden fazla kaçak kamyon kaçış rampası","Zirvede zorunlu bir kamyon kantar istasyonu","Tüm kamyonları yasaklayan bir tünel","Çift yönlü bir HOV şeridi"],"explanation":"Interstate 77, Fancy Gap üzerinde 1.500 feet'ten fazla yükselir ve eğimler yaklaşık %4,5'e kadar çıkar; Kuzey Carolina'ya uzun güney inişi, frenlemesini kaybeden araçlar için birden fazla kaçak kamyon kaçış rampası içerir. Sürücüler inmeden önce düşük bir vites seçmelidir. Kaynak: VDOT/Virginia CDL Manual dağ sürüşü rehberi."},"77":{"q":"Virginia'da minimum hız kuralı, bir sürücünün ne yapacak kadar yavaş bir hızda araç kullanmamasını belirtir?","options":["Güvenlik veya yasa nedeniyle azaltılmış hızın gerekli olduğu durumlar dışında, trafiğin normal ve makul hareketini engellemek veya tıkamak","Herhangi bir karayolunda 40 mph'nin altında seyretmek","İşaretli sınırın 5 mph'den fazla altına düşmek","Diğer sürücülerin kornalarını kullanmasına neden olmak"],"explanation":"Code of Virginia 46.2-877, güvenli kullanım için veya yasaya uymak için azaltılmış hızın gerekli olduğu durumlar dışında, trafiğin normal ve makul hareketini engelleyecek kadar yavaş bir hızda araç kullanmayı yasaklar. Kaynak: Code of Virginia 46.2-877."},"78":{"q":"Virginia'da minimum hız kuralı, bir sürücünün ne yapacak kadar yavaş bir hızda araç kullanmamasını belirtir?","options":["Güvenlik veya yasa nedeniyle azaltılmış hızın gerekli olduğu durumlar dışında, trafiğin normal ve makul hareketini engellemek veya tıkamak","Herhangi bir karayolunda 40 mph'nin altında seyretmek","İşaretli sınırın 5 mph'den fazla altına düşmek","Diğer sürücülerin kornalarını kullanmasına neden olmak"],"explanation":"Code of Virginia 46.2-877, güvenli kullanım için veya yasaya uymak için azaltılmış hızın gerekli olduğu durumlar dışında, trafiğin normal ve makul hareketini engelleyecek kadar yavaş bir hızda araç kullanmayı yasaklar. Kaynak: Code of Virginia 46.2-877."},"79":{"q":"Dört şerit gereksinimine ek olarak, Virginia'nın Yer Aç yükümlülüğü, aşağıdakilerden hangisi tarafından işletilen ve uyarı ışıkları gösteren sabit araçlar için geçerlidir?","options":["Polis, itfaiye, ambulans, VDOT, kamu hizmeti ve çekici araçları","Yalnızca polis ve ambulanslar","Yalnızca eyalet polisi devriye araçları","Yalnızca VDOT'a ait araçlar"],"explanation":"Code of Virginia 46.2-861.1, Yer Aç yükümlülüğünü, yanıp sönen uyarı ışıkları gösteren geniş bir sabit araç grubuna genişletir; bunlara kolluk kuvvetleri, itfaiye, ambulans, Virginia Department of Transportation, kamu hizmeti ve çekme/kurtarma araçları dahildir. Kaynak: Code of Virginia 46.2-861.1."},"80":{"q":"Virginia'da Ticari Sürücü Belgelerini (CDL) hangi kurum verir?","options":["Virginia Department of Motor Vehicles (DMV)","Federal Motor Carrier Safety Administration (FMCSA)","Virginia Department of Transportation (VDOT)","Virginia State Police Motor Carrier Division"],"explanation":"Virginia'da CDL'ler Virginia Department of Motor Vehicles (DMV) tarafından verilir. FMCSA federal standartları belirler ancak ehliyet vermez ve VDOT ehliyetlendirmeyle değil yollar/izinlerle ilgilenir. Kaynak: Virginia DMV, Apply for a CDL or CLP."},"81":{"q":"Bir Virginia CDL'i veya Ticari Öğrenici Belgesi (CLP) için başvurmak için nereye gitmelisiniz?","options":["Bir DMV müşteri hizmetleri merkezine şahsen","Tamamen DMV web sitesi üzerinden çevrimiçi","Herhangi bir FMCSA onaylı kamyon bayisinde","Posta yoluyla Richmond'daki DMV genel merkezine"],"explanation":"Virginia, bir CDL veya CLP için bir DMV müşteri hizmetleri merkezine şahsen başvurmanızı gerektirir; ilk CDL/CLP başvurusu tamamen çevrimiçi olarak tamamlanamaz. Kaynak: Virginia DMV, Apply for a CDL or CLP."},"82":{"q":"Federal yönetmelikler, Virginia'daki her CDL veya CLP başvuru sahibinin kaç ticari motorlu araç kullanım kategorisine kendi kendine sertifika vermesini gerektirir?","options":["Dört","İki","Üç","Beş"],"explanation":"Virginia'da bir CDL/CLP'ye sahip olan veya başvuran herkes, dört CMV kullanım kategorisinden birine kendi kendine sertifika vermelidir. Kaynak: Virginia DMV, CDL Medical Certification Requirements."},"83":{"q":"Aşağıdakilerden hangisi Virginia DMV tarafından kullanılan dört kendi kendine sertifikalandırma kategorisinden biridir?","options":["Non-excepted Interstate (NI)","Restricted Commercial Operation","Intrastate Hazmat Only","Federal Excepted Carrier"],"explanation":"Dört kategori şunlardır: Excepted Interstate (EI), Excepted Intrastate (EA), Non-excepted Interstate (NI) ve Non-excepted Intrastate (NA). 'Non-excepted Interstate' geçerli bir kategoridir; listelenen diğerleri değildir. Kaynak: Virginia DMV, CDL Medical Certification Requirements."},"84":{"q":"Hangi kendi kendine sertifikalandırma kategorisi genellikle sürücünün Virginia DMV'de dosyada bir tıbbi muayene sertifikası bulundurmasını GEREKTİRMEZ?","options":["Excepted Interstate (EI)","Non-excepted Interstate (NI)","Non-excepted Intrastate (NA)","Herhangi bir eyaletler arası kategori"],"explanation":"İstisna kategorilerine (excepted interstate veya excepted intrastate) sertifika veren sürücülerin bir tıbbi muayene sertifikası sağlamaları gerekmez; yalnızca non-excepted interstate ve non-excepted intrastate sürücüleri sağlamalıdır. Kaynak: Virginia DMV, CDL Medical Certification Requirements."},"85":{"q":"Virginia'da non-excepted interstate olarak kendi kendine sertifika veren bir sürücünün fizik muayenesini yapan tıbbi muayene uzmanı şu olmalıdır:","options":["FMCSA'nın National Registry of Certified Medical Examiners listesinde yer alan biri","Doğrudan Virginia DMV tarafından istihdam edilen biri","Virginia Department of Health tarafından onaylanmış biri","Sürücünün seçtiği herhangi bir lisanslı hekim"],"explanation":"Non-excepted sürücüler, FMCSA'nın National Registry of Certified Medical Examiners listesinde yer alan bir tıbbi muayene uzmanı tarafından muayene edilmelidir. Her lisanslı hekim uygun değildir. Kaynak: Virginia DMV, CDL Medical Certification Requirements."},"86":{"q":"5 Mayıs 2025'ten itibaren, bir Tıbbi Muayene Sertifikası (MEC) Virginia DMV'ye nasıl sunulmalıdır?","options":["Tıbbi muayene uzmanı tarafından FMCSA National Registry portalı aracılığıyla elektronik olarak","Sürücünün kağıt sertifikayı bir DMV ofisine getirmesiyle","Sürücünün taranmış bir kopyayı DMV web sitesine yüklemesiyle","Sürücünün işvereninin FMCSA'ya faks göndermesiyle"],"explanation":"5 Mayıs 2025 itibarıyla, Virginia DMV artık MEC'leri doğrudan sürücülerden kabul etmez; tıbbi muayene uzmanı sertifikayı FMCSA National Registry portalı aracılığıyla elektronik olarak sunmalıdır. Kaynak: Virginia DMV, CDL Medical Certification Requirements."},"87":{"q":"Bir Virginia CLP'si almak için, bir başvuru sahibi en az hangi bilgi sınavını geçmelidir?","options":["CDL genel bilgi sınavı","Yalnızca kombinasyon araçları sınavı","Yalnızca hava frenleri sınavı","Tehlikeli maddeler sınavı"],"explanation":"Bir CLP almak için CDL genel bilgi sınavını ve kullanmayı düşündüğünüz araçlar için ek bilgi sınavlarını (hava frenleri veya tank gibi) geçmelisiniz. Kaynak: Virginia DMV, Commercial Learner's Permit."},"88":{"q":"Bir Virginia CLP'si verildikten sonra, CDL beceri testine girmeye hak kazanmadan önce onu ne kadar süre elinizde tutmalısınız?","options":["En az 14 gün","En az 30 gün","En az 7 gün","En az 60 gün"],"explanation":"Virginia, beceri testine girmeden önce minimum 14 günlük bir CLP elde tutma süresi gerektirir. Bu süre, önceki bir CDL kanıtı veya Entry-Level Driver Training tamamlanma kanıtıyla muaf tutulabilir. Kaynak: Virginia DMV, CDL Skills Test Eligibility / Commercial Learner's Permit."},"89":{"q":"Bir Virginia Ticari Öğrenici Belgesi (CLP) ne kadar süre geçerlidir ve yenilenebilir mi?","options":["1 yıl geçerlidir ve yenilenemez","180 gün geçerlidir ve bir kez yenilenebilir","2 yıl geçerlidir ve yıllık olarak yenilenir","6 ay geçerlidir ve sınırsız yenileme imkanı vardır"],"explanation":"Bir Virginia CLP'si 1 yıl geçerlidir ve yenilenemez; süresi dolarsa yeniden başvurmanız ve yeniden test olmanız gerekir. Kaynak: Virginia DMV, Commercial Learner's Permit."},"90":{"q":"Virginia CDL beceri testi, sırasıyla gerçekleştirilen hangi üç bölümden oluşur?","options":["Sefer öncesi muayene, temel araç kontrolü ve yolda sürüş","Yazılı bilgi, görme taraması ve yol testi","Hava freni kontrolü, geri gitme ve otoyola katılma","Bağlama/çözme, paralel park ve gece sürüşü"],"explanation":"CDL beceri testinin üç bölümü vardır: sefer öncesi araç muayenesi, temel araç kontrol becerileri ve yolda sürüş testi, bu sırayla yapılır. Kaynak: Virginia'da uygulanan FMCSA CDL standardı; Virginia DMV CDL Skills Tests."},"91":{"q":"Virginia CDL yolda sürüş testi için kullanılan aracı kim sağlamalıdır?","options":["Başvuru sahibi, kullanmak istediği türden düzgün şekilde kayıtlı bir araç getirmelidir","Bir test kamyonu sağlayan Virginia DMV","Yalnızca başvuru sahibinin ELDT eğitim okulu","Bölgesel muayene filosundan FMCSA"],"explanation":"Başvuru sahibi, yolda test için aradığı CDL sınıfını/türünü temsil eden, düzgün şekilde kayıtlı bir araç sağlamalıdır. Kaynak: Virginia DMV, CDL Skills Test Eligibility."},"92":{"q":"Virginia'da geçerli olan federal Entry-Level Driver Training (ELDT) gereksinimi ne zaman yürürlüğe girdi?","options":["7 Şubat 2022","5 Mayıs 2025","1 Ocak 2020","1 Temmuz 2023"],"explanation":"ELDT gereksinimleri 7 Şubat 2022'de yürürlüğe girdi. (5 Mayıs 2025, elektronik MEC sunum değişikliği için ayrı bir tarihtir.) Kaynak: Virginia DMV, Entry-Level Driver Training."},"93":{"q":"Bir Virginia CDL başvuru sahibi tarafından kullanılan bir ELDT eğitim sağlayıcısı şu olmalıdır:","options":["FMCSA'nın Training Provider Registry (TPR) listesinde yer alan biri","Yalnızca Virginia DMV tarafından sertifikalandırılmış biri","Virginia Board of Education tarafından akredite edilmiş biri","İş ruhsatı olan herhangi bir ticari sürücü okulu"],"explanation":"ELDT, FMCSA'nın Training Provider Registry (TPR) listesinde yer alan bir sağlayıcı aracılığıyla tamamlanmalıdır. Genel bir iş ruhsatı veya eyalet kurulu akreditasyonu yeterli değildir. Kaynak: Virginia DMV, Entry-Level Driver Training."},"94":{"q":"Virginia'da ilk kez Class A veya B başvuru sahibi için, ELDT teori ve direksiyon başında eğitiminin ne zaman tamamlanması gerekir?","options":["Yolda beceri sınavına girmeden önce","CLP için başvurmadan önce","Beceri testini geçtikten sonraki 30 gün içinde","Genel bilgi sınavına girmeden önce"],"explanation":"CDL sınıfları (ve P/S onayları) için, ELDT teori ve direksiyon başında eğitimi, yolda beceri sınavından önce tamamlanmalıdır. (Hazmat için, teori bölümü hazmat bilgi sınavından önce yapılmalıdır.) Kaynak: Virginia DMV, Entry-Level Driver Training."},"95":{"q":"Virginia'da tehlikeli maddeler (H) onayı için, ELDT teori bölümünün şundan önce tamamlanması gerekir:","options":["Hazmat bilgi sınavına girmeden önce","Yolda beceri testine girmeden önce","Kendi kendine sertifikalandırma formunu sunmadan önce","CLP verilmeden önce"],"explanation":"CDL sınıf eğitiminin aksine, hazmat ELDT teori bölümü, hazmat bilgi sınavına girmeden önce tamamlanmalıdır (ayrı bir hazmat beceri testi yoktur). Kaynak: Virginia DMV, Entry-Level Driver Training."},"96":{"q":"Eyalet içi bir Virginia CDL'i ile eyaletler arası bir CDL almak için minimum yaş nedir?","options":["Eyalet içi için 18 ve eyaletler arası için 21","Eyalet içi için 21 ve eyaletler arası için 25","Eyalet içi için 16 ve eyaletler arası için 18","Hem eyalet içi hem eyaletler arası için 18"],"explanation":"Eyalet içi bir CDL almak için en az 18, eyaletler arası bir CDL almak için en az 21 yaşında olmalısınız. Kaynak: Virginia DMV, CDL Skills Test Eligibility / Apply for a CDL or CLP."},"97":{"q":"Virginia'da daha önce hiç Virginia ehliyeti veya kimliği olmayan bir CDL başvuru sahibi, aşağıdakilerden hangisinin iki kanıtını sağlamalıdır?","options":["Virginia ikameti","Sosyal güvenlik numarası","Yasal varlık","Kimlik"],"explanation":"İlk kez başvuran Virginia başvuru sahipleri, bir kimlik kanıtı, bir yasal varlık kanıtı, bir sosyal güvenlik numarası kanıtı ve iki Virginia ikameti kanıtı sunmalıdır. Kaynak: Virginia DMV, Apply for a CDL or CLP."},"98":{"q":"Çoğu sürücü için, standart bir Virginia CDL'i yenilenmesi gerekmeden önce ne kadar süre geçerlidir?","options":["8 yıl, sahibinin doğum gününde sona erer","4 yıl, sahibinin doğum gününde sona erer","5 yıl, yıl sonunda sona erer","10 yıl, veriliş tarihinin yıl dönümünde sona erer"],"explanation":"Standart bir Virginia CDL'i 8 yıl geçerlidir ve sahibinin doğum gününde sona erer (75 yaş ve üzeri sürücüler 5 yıllık bir döngü alır). Kaynak: Virginia DMV, Renew Your CDL."},"99":{"q":"Virginia'da, bir CDL'in süresi bir yıldan uzun süredir dolmuş veya düşürülmüşse, sahibinin onu geri almak için ne yapması gerekir?","options":["O CDL türü için hem bilgi sınavını hem de yolda beceri testini yeniden vermeli","Sadece bir gecikme ücreti ödemeli ve çevrimiçi yenilemeli","Yalnızca görme taramasını yeniden vermeli","Yalnızca ek bir 14 günlük elde tutma süresi beklemeli"],"explanation":"Bir Virginia CDL'inin süresi bir yıldan uzun süredir dolmuş veya düşürülmüşse, sahibi, sahip olduğu CDL türü için gerekli olan bilgi sınavını ve yolda beceri testini yeniden vermelidir. Kaynak: Virginia DMV, Renew Your CDL."}},"es":{"0":{"q":"¿Cuál es el ancho exterior total máximo permitido para un vehículo y su carga en las carreteras de Virginia (sin contar los espejos)?","options":["96 inches","100 inches","102 inches","108 inches"],"explanation":"El Código de Virginia 46.2-1105 establece el ancho exterior total máximo de un vehículo, incluida cualquier carga, en 102 inches (8 feet 6 inches), sin contar los espejos ni ciertos dispositivos de advertencia de los autobuses escolares. Fuente: Code of Virginia 46.2-1105; Virginia CDL Manual / DMV 109."},"1":{"q":"¿Cuál es la altura máxima permitida para un vehículo cargado o vacío en las carreteras de Virginia?","options":["13 feet","13 feet 6 inches","14 feet","12 feet 6 inches"],"explanation":"El Código de Virginia 46.2-1110 prohíbe que cualquier vehículo cargado o vacío supere una altura de 13 feet 6 inches. Fuente: Code of Virginia 46.2-1110; Virginia DMV 109."},"2":{"q":"En las carreteras de Virginia, ¿cuál es el peso máximo permitido por eje sencillo?","options":["18,000 pounds","20,000 pounds","22,400 pounds","24,000 pounds"],"explanation":"El Código de Virginia 46.2-1124 limita el peso por eje sencillo de cualquier vehículo o combinación a 20,000 pounds. Fuente: Code of Virginia 46.2-1124; Virginia DMV 109."},"3":{"q":"¿Cuál es el peso máximo permitido por eje tándem en las carreteras de Virginia?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"El Código de Virginia 46.2-1125 limita el peso por eje tándem de cualquier vehículo o combinación a 34,000 pounds. Fuente: Code of Virginia 46.2-1125; Virginia DMV 109."},"4":{"q":"¿Cuál es el peso bruto máximo, sin importar la separación entre ejes, permitido en las carreteras interestatales de Virginia?","options":["73,280 pounds","76,000 pounds","80,000 pounds","90,000 pounds"],"explanation":"El Código de Virginia 46.2-1127 prohíbe un peso bruto, sin importar la separación entre ejes, superior a 80,000 pounds en las carreteras interestatales del Estado. Fuente: Code of Virginia 46.2-1127."},"5":{"q":"En las carreteras interestatales de Virginia, los límites de peso por eje sencillo y por eje tándem son, respectivamente:","options":["20,000 lb and 34,000 lb","18,000 lb and 32,000 lb","22,000 lb and 36,000 lb","20,000 lb and 40,000 lb"],"explanation":"El Código de Virginia 46.2-1127 establece el límite interestatal por eje sencillo en 20,000 pounds y el límite por eje tándem en 34,000 pounds, coincidiendo con los límites de las carreteras generales. Fuente: Code of Virginia 46.2-1127."},"6":{"q":"¿Cuál es la longitud máxima de un solo semirremolque operado en una combinación de tractocamión/semirremolque en las carreteras de Virginia en general?","options":["45 feet","48 feet","53 feet","57 feet"],"explanation":"El Código de Virginia 46.2-1112 limita un semirremolque en una combinación de tractocamión/semirremolque a 48 feet, aunque se permiten semirremolques de 53 feet en el sistema interestatal y en ciertas carreteras que cumplan los requisitos. Fuente: Code of Virginia 46.2-1112; orientación del Virginia DMV sobre transporte de carga."},"7":{"q":"En el sistema interestatal de Virginia, se permite a un semirremolque una longitud máxima de hasta:","options":["48 feet","50 feet","53 feet","60 feet"],"explanation":"Conforme al Código de Virginia 46.2-1112, se permiten semirremolques de hasta 53 feet en el sistema interestatal (y en carreteras que cumplan los requisitos) cuando la distancia desde el pivote (kingpin) hasta el eje más trasero no supera el límite establecido; la base general en carretera es de 48 feet. Fuente: Code of Virginia 46.2-1112."},"8":{"q":"En una combinación de doble remolque (gemelos) en las carreteras de Virginia, ¿cuál es la longitud máxima de cada remolque o semirremolque individual?","options":["27 feet","28 feet","28 1/2 feet","30 feet"],"explanation":"El Código de Virginia 46.2-1112 dispone que ningún semirremolque o remolque individual en una combinación podrá superar los 28 1/2 feet de longitud. Fuente: Code of Virginia 46.2-1112; Virginia DMV 109."},"9":{"q":"¿Cuál es la longitud máxima general para una combinación de vehículo/remolque acoplados en las carreteras de Virginia (excluyendo las excepciones especiales de tractocamión-semirremolque)?","options":["60 feet","65 feet","70 feet","75 feet"],"explanation":"El Código de Virginia 46.2-1112 establece un máximo general de 65 feet para vehículos acoplados (en combinación), con excepciones específicas para las combinaciones de tractocamión-semirremolque en carreteras designadas. Fuente: Code of Virginia 46.2-1112."},"10":{"q":"En las carreteras de Virginia, ¿cuál es la longitud máxima de un solo vehículo de motor (un camión rígido/de una sola unidad, distinto de los autobuses y las casas rodantes)?","options":["35 feet","40 feet","45 feet","48 feet"],"explanation":"El Código de Virginia 46.2-1112 prohíbe operar un solo vehículo de motor de más de 40 feet de longitud en una carretera (los autobuses y las casas rodantes tienen disposiciones separadas). Fuente: Code of Virginia 46.2-1112; orientación del Virginia DMV sobre transporte de carga."},"11":{"q":"¿Cómo determina Virginia el peso bruto máximo permitido conforme a su fórmula de puentes (Código 46.2-1126)?","options":["Únicamente por el peso registrado en el título del vehículo","Por el número de ejes y la distancia entre el primer y el último eje","Por la potencia del motor (caballos de fuerza) y la clasificación de las llantas","Por el volumen total de carga en pies cúbicos"],"explanation":"El Código de Virginia 46.2-1126 ofrece una tabla (la fórmula federal de puentes según se aplica en Virginia) que establece el peso bruto máximo con base en el número de ejes y la distancia entre los ejes extremos (el primero y el último). Fuente: Code of Virginia 46.2-1126."},"12":{"q":"Conforme a la tabla de peso bruto de Virginia (Código 46.2-1126), ¿cuál es el peso bruto más alto que permite la tabla sin importar lo favorable que sea la separación entre ejes?","options":["76,000 pounds","80,000 pounds","84,000 pounds","88,000 pounds"],"explanation":"La tabla del Código de Virginia 46.2-1126 limita el peso bruto máximo a 80,000 pounds (el valor máximo, aplicable a un vehículo de 7 ejes con la separación completa); 80,000 pounds es también el tope legal absoluto conforme al 46.2-1127. Fuente: Code of Virginia 46.2-1126 and 46.2-1127."},"13":{"q":"Un camión cuyas dimensiones, reducidas a la configuración práctica más pequeña, aún superan los límites legales de tamaño o peso de Virginia, ¿qué debe hacer antes de circular por las carreteras de Virginia?","options":["Pagar una multa fija por sobrepeso en la siguiente estación de pesaje","Obtener un permiso de transporte (sobredimensión/sobrepeso) con anticipación","Registrar el vehículo como vehículo agrícola","Circular únicamente entre la medianoche y las 5 a.m."],"explanation":"Virginia exige que, si un vehículo reducido a sus dimensiones prácticas más pequeñas todavía supera los límites legales, el operador debe obtener un permiso de transporte antes de circular por las carreteras del Estado. Fuente: Virginia Code Article 18 (46.2-1139 et seq.); Virginia DMV Hauling Permits."},"14":{"q":"¿Qué agencia de Virginia emite los permisos de transporte por sobredimensión/sobrepeso?","options":["La Virginia State Police","Únicamente el Virginia Department of Transportation","El Virginia Department of Motor Vehicles","La oficina del sheriff local"],"explanation":"El Virginia Department of Motor Vehicles emite los permisos de transporte por sobredimensión/sobrepeso; se solicitan a través del sistema automatizado en línea de permisos de transporte del estado. Fuente: Virginia DMV Hauling Permits; Code of Virginia Article 18."},"15":{"q":"¿Cómo se obtienen normalmente los permisos de transporte por sobredimensión/sobrepeso de Virginia?","options":["Enviando por correo un formulario impreso a Richmond","A través del sistema automatizado en línea de permisos de transporte del DMV","Únicamente en persona, en un centro de atención al cliente del DMV","Llamando a la línea de despacho de la Virginia State Police"],"explanation":"Los permisos de transporte de Virginia se solicitan a través del sistema automatizado en línea de permisos de transporte del DMV (portal actual en ezhaulvirginia.com), que reemplazó al antiguo VAHPS. Fuente: Virginia DMV Hauling Permits."},"16":{"q":"Un permiso emitido conforme al Código de Virginia 46.2-1129 para transportar productos agrícolas o forestales cultivados en Virginia amplía los límites de peso por eje sencillo, por eje tándem y de peso bruto, ¿en qué porcentaje?","options":["Tres por ciento","Cinco por ciento","Diez por ciento","Quince por ciento"],"explanation":"El Código de Virginia 46.2-1129 permite un permiso que amplía los límites de peso por eje sencillo, por eje tándem y de peso bruto en un cinco por ciento cada uno para ciertos vehículos que transportan productos agrícolas o forestales cultivados en Virginia. Fuente: Code of Virginia 46.2-1129."},"17":{"q":"Conforme a la ampliación de peso para productos agrícolas/forestales del Código de Virginia 46.2-1129, un permiso no puede autorizar un peso bruto superior a:","options":["80,000 pounds","82,000 pounds","84,000 pounds","90,000 pounds"],"explanation":"El Código de Virginia 46.2-1129 dispone que ningún permiso de este tipo podrá autorizar la operación de un vehículo de motor cuyo peso bruto supere las 84,000 pounds. Fuente: Code of Virginia 46.2-1129."},"18":{"q":"¿Se aplica la ampliación de peso del cinco por ciento para productos agrícolas/forestales del Código de Virginia 46.2-1129 en el sistema de carreteras interestatales?","options":["Sí, hasta 84,000 pounds en las interestatales","No; los límites interestatales permanecen en 20,000/34,000/80,000 pounds","Sí, pero solo con escolta de la State Police","Sí, hasta 88,000 pounds en las interestatales"],"explanation":"La ampliación para productos agrícolas/forestales no eleva los límites interestatales; el Código de Virginia 46.2-1127 mantiene los topes interestatales en 20,000 lb por eje sencillo, 34,000 lb por eje tándem y 80,000 lb de peso bruto, sin importar la separación entre ejes. Fuente: Code of Virginia 46.2-1129 and 46.2-1127."},"19":{"q":"En Virginia, ¿al superar qué umbral de ancho una carga se considera de sobredimensión y requiere un permiso de transporte?","options":["Más de 8 feet 0 inches (96 inches)","Más de 8 feet 6 inches (102 inches)","Más de 9 feet 0 inches (108 inches)","Más de 10 feet 0 inches (120 inches)"],"explanation":"El ancho legal de Virginia es de 8 feet 6 inches (102 inches) según el Código 46.2-1105; cualquier carga más ancha de 8 feet 6 inches es de sobredimensión y requiere un permiso de transporte del DMV. Fuente: Code of Virginia 46.2-1105; Virginia DMV Hauling Permits."},"20":{"q":"En Virginia, ¿qué clase de CDL se requiere para operar un solo vehículo con una clasificación de peso bruto vehicular (GVWR) de 26,001 pounds o más que no remolca un remolque de más de 10,000 pounds?","options":["Class A","Class B","Class C","Class D"],"explanation":"El Virginia DMV define una CDL Class B como cualquier vehículo sencillo con un GVWR de 26,001 pounds o más, o dicho vehículo remolcando una unidad de no más de 10,000 pounds GVWR. Fuente: Virginia DMV, CDL Classifications, Endorsements and Restrictions (dmv.virginia.gov/licenses-ids/cdl/class)."},"21":{"q":"Conforme a las reglas de Virginia, se requiere una CDL Class A para cualquier combinación de vehículos con una clasificación de peso bruto combinado (GCWR) de 26,001 pounds o más, siempre que el vehículo remolcado tenga un GVWR de más de qué cantidad?","options":["5,000 pounds","8,000 pounds","10,000 pounds","15,000 pounds"],"explanation":"El Virginia DMV define la Class A como una combinación con un GCWR de 26,001+ pounds en la que la(s) unidad(es) remolcada(s) superan las 10,000 pounds GVWR. Fuente: Virginia DMV, CDL Classifications, Endorsements and Restrictions (dmv.virginia.gov/licenses-ids/cdl/class)."},"22":{"q":"Un conductor de Virginia opera un vehículo que no cumple los umbrales de peso de la Class A o B, pero está diseñado para transportar 16 o más pasajeros incluyendo al conductor. ¿Qué clase de CDL corresponde?","options":["Class A","Class B","Class C","No se requiere CDL"],"explanation":"El Virginia DMV define la Class C como cualquier vehículo que no cumple con la Class A o B y que transporta 16 o más ocupantes (incluyendo al conductor) o transporta materiales peligrosos que requieren letreros (placards). Fuente: Virginia DMV, CDL Classifications, Endorsements and Restrictions (dmv.virginia.gov/licenses-ids/cdl/class)."},"23":{"q":"¿Qué endoso de la CDL de Virginia permite al titular conducir un vehículo cisterna (tanque)?","options":["Endorsement N","Endorsement T","Endorsement H","Endorsement P"],"explanation":"El Virginia DMV asigna el endoso N para vehículos cisterna (tanque). El endoso H es para materiales peligrosos, el T para dobles/triples y el P para vehículos de pasajeros. Fuente: Virginia DMV, CDL Classifications, Endorsements and Restrictions (dmv.virginia.gov/licenses-ids/cdl/class)."},"24":{"q":"¿Qué endoso de la CDL de Virginia se requiere para conducir un vehículo que remolca dobles o triples remolques?","options":["Endorsement P","Endorsement N","Endorsement T","Endorsement S"],"explanation":"El Virginia DMV asigna el endoso T para permitir conducir un vehículo que remolca un doble o triple remolque. Fuente: Virginia DMV, CDL Classifications, Endorsements and Restrictions (dmv.virginia.gov/licenses-ids/cdl/class)."},"25":{"q":"¿Cuál es la edad mínima para obtener una CDL de Virginia válida únicamente para conducir dentro del estado (intraestatal, dentro de Virginia)?","options":["16 años","18 años","21 años","25 años"],"explanation":"El Virginia DMV exige que el solicitante tenga al menos 18 años de edad para una CDL intraestatal y al menos 21 para una CDL interestatal. Fuente: Virginia DMV, CDL Skills Test Eligibility Requirements (dmv.virginia.gov/licenses-ids/cdl/eligibility)."},"26":{"q":"¿Cuál es la edad mínima para obtener una CDL de Virginia válida para la operación interestatal (cruzando líneas estatales)?","options":["18 años","19 años","20 años","21 años"],"explanation":"El Virginia DMV exige que el solicitante tenga al menos 21 años de edad para una CDL interestatal; 18 es la edad mínima para una CDL solo intraestatal. Fuente: Virginia DMV, CDL Skills Test Eligibility Requirements (dmv.virginia.gov/licenses-ids/cdl/eligibility)."},"27":{"q":"Antes de tomar el examen de habilidades de la CDL, un solicitante de Virginia generalmente debe haber tenido un Permiso de Aprendiz Comercial (CLP) durante un mínimo de cuántos días?","options":["7 days","10 days","14 days","30 days"],"explanation":"Conforme al estándar federal adoptado por Virginia, el solicitante debe tener el CLP durante un mínimo de 14 days antes de tomar el examen de habilidades (a menos que haya tenido una CDL previa o haya completado una capacitación aprobada). Fuente: Virginia DMV, CDL Skills Test Eligibility Requirements / Commercial Learner's Permit (dmv.virginia.gov/licenses-ids/cdl/eligibility)."},"28":{"q":"Al conducir un vehículo comercial con un Permiso de Aprendiz Comercial (CLP) de Virginia, ¿por quién debe estar acompañado el titular del permiso?","options":["Cualquier adulto con licencia mayor de 21 años","Una persona que tenga una CDL válida para el mismo tipo de vehículo","Únicamente un examinador del DMV","Nadie; se permite conducir solo"],"explanation":"El Virginia DMV indica que un CLP permite operar un vehículo comercial únicamente cuando una persona con licencia para conducir el mismo tipo de vehículo (un titular de CDL válida para esa clase/tipo) está físicamente presente con el titular del permiso. Fuente: Virginia DMV, Commercial Learner's Permit (dmv.virginia.gov/licenses-ids/cdl/permit)."},"29":{"q":"¿Qué documento o verificación se requiere de forma exclusiva para obtener un endoso HazMat (H) de Virginia que NO se requiere para otros endosos?","options":["Una evaluación de amenazas de seguridad de la TSA basada en huellas dactilares","Una segunda evaluación de la vista","Una carta de patrocinio del empleador","Un registro de conducción notariado"],"explanation":"El Virginia DMV exige que los solicitantes de HazMat (HME) completen una verificación de antecedentes basada en huellas dactilares; el DMV reenvía la información a la TSA, que realiza la evaluación de amenazas de seguridad y aprueba o deniega el endoso. Fuente: Virginia DMV, Hazardous Materials Endorsement (HME) (dmv.virginia.gov/licenses-ids/cdl/hazmat)."},"30":{"q":"¿Por cuánto tiempo es válida la verificación de antecedentes basada en huellas dactilares para un endoso HazMat (H) de Virginia?","options":["1 year","3 years","5 years","10 years"],"explanation":"El Virginia DMV indica que la verificación de antecedentes basada en huellas dactilares para el endoso HazMat es válida por hasta cinco años, después de lo cual debe renovarse. Fuente: Virginia DMV, Hazardous Materials Endorsement (HME) (dmv.virginia.gov/licenses-ids/cdl/hazmat)."},"31":{"q":"Un solicitante de Virginia que tiene una TWIC (Transportation Worker Identification Credential) válida, ¿qué beneficio recibe al solicitar un endoso HazMat?","options":["Se exime el examen de conocimientos","Una tarifa reducida y sin nueva toma de huellas dactilares","Aprobación automática sin revisión de la TSA","Un endoso vitalicio que nunca vence"],"explanation":"El Virginia DMV cobra a los titulares de TWIC una tarifa de HazMat reducida y no reembolsable ($41 en lugar de $83) y no exige una nueva toma de huellas dactilares, ya que la TWIC ya implica una evaluación de amenazas de la TSA comparable. Fuente: Virginia DMV, Hazardous Materials Endorsement / Applying for a CDL (dmv.virginia.gov/licenses-ids/cdl/hazmat)."},"32":{"q":"Conforme a la regla federal de Capacitación para Conductores de Nivel Inicial (ELDT) aplicada en Virginia, la capacitación debe completarse a través de un proveedor inscrito en qué registro antes del examen de habilidades?","options":["La Virginia DMV Approved Schools List","El FMCSA Training Provider Registry (TPR)","El National CDL Academy Directory","El DOT Carrier Safety Index"],"explanation":"La ELDT debe completarse con un proveedor inscrito en el FMCSA Training Provider Registry (TPR); el Virginia DMV verifica electrónicamente que se haya completado antes del examen de habilidades. Fuente: Virginia DMV / FMCSA Entry-Level Driver Training (tpr.fmcsa.dot.gov; dmv.virginia.gov/licenses-ids/cdl/eligibility)."},"33":{"q":"¿Cuál de las siguientes acciones por primera vez NO activa el requisito federal de capacitación ELDT en Virginia?","options":["Obtener una CDL por primera vez","Mejorar una CDL Class B a una CDL Class A","Renovar una CDL existente con la misma clase y endosos","Obtener un endoso de Pasajeros (P) por primera vez"],"explanation":"La ELDT se requiere para los solicitantes de CDL por primera vez, para una mejora de Class B a Class A y para los endosos H, P o S por primera vez. Una simple renovación de una CDL existente sin nueva clase ni endoso no requiere ELDT. Fuente: FMCSA Entry-Level Driver Training rule, aplicada por el Virginia DMV (fmcsa.dot.gov; dmv.virginia.gov)."},"34":{"q":"Para un solicitante de HazMat de Virginia por primera vez, ¿cuándo debe completarse la parte teórica de la ELDT?","options":["Después de aprobar el examen de conocimientos de HazMat","Antes de tomar el examen de conocimientos de HazMat en el DMV","Solo después de que la TSA apruebe la verificación de antecedentes","Dentro de los 30 días posteriores a la emisión del endoso"],"explanation":"Conforme a la regla de ELDT aplicada en Virginia, los solicitantes de un endoso HazMat (H) por primera vez deben completar la capacitación teórica de ELDT antes de tomar el examen de conocimientos de HazMat en el DMV. Fuente: FMCSA ELDT rule / Virginia DMV (fmcsa.dot.gov; dmv.virginia.gov/licenses-ids/cdl)."},"35":{"q":"¿Entre cuántas categorías de autocertificación médica debe elegir un solicitante de CDL de Virginia con respecto a su tipo de operación de vehículo motorizado comercial?","options":["Dos","Tres","Cuatro","Cinco"],"explanation":"El Virginia DMV exige que los solicitantes se autocertifiquen en una de cuatro categorías: interestatal exento, interestatal no exento, intraestatal exento o intraestatal no exento. Fuente: Virginia DMV, Apply for a CDL or CLP (dmv.virginia.gov/licenses-ids/cdl/applying)."},"36":{"q":"Un solicitante de CDL de Virginia que conduce cruzando líneas estatales y NO está exento de las reglas federales de calificación física, ¿bajo qué categoría debe autocertificarse?","options":["Interestatal exento","Interestatal no exento","Intraestatal exento","Intraestatal no exento"],"explanation":"Un conductor que opera en el comercio interestatal y que debe cumplir con los estándares federales de calificación médica se autocertifica como 'interestatal no exento' y debe mantener un certificado válido de examinador médico. Fuente: Virginia DMV, Apply for a CDL or CLP, autocertificación médica (dmv.virginia.gov/licenses-ids/cdl/applying)."},"37":{"q":"Un solicitante de CDL de Virginia por primera vez que nunca ha tenido una licencia de Virginia debe presentar comprobante de identidad, comprobante de presencia legal, un número de Seguro Social y ¿cuántos comprobantes de residencia en Virginia?","options":["Un comprobante de residencia","Dos comprobantes de residencia","Tres comprobantes de residencia","No se requiere comprobante de residencia"],"explanation":"El Virginia DMV exige que un solicitante por primera vez que nunca ha tenido una licencia/identificación de Virginia presente un comprobante de identidad, un comprobante de presencia legal, un comprobante del número de Seguro Social y dos comprobantes de residencia en Virginia. Fuente: Virginia DMV, Apply for a CDL or CLP (dmv.virginia.gov/licenses-ids/cdl/applying)."},"38":{"q":"Una persona que debe registrarse en el Registro de Delincuentes Sexuales y Delitos Contra Menores de Virginia (Sex Offender and Crimes Against Minors Registry) no es elegible para qué endoso de CDL mientras se exija el registro?","options":["N (Tanque)","T (Dobles/Triples)","S (Autobús Escolar)","H (HazMat)"],"explanation":"Virginia prohíbe la emisión del endoso S (Autobús Escolar) a cualquier persona que deba registrarse en el Sex Offender and Crimes Against Minors Registry durante cualquier periodo en que se exija el registro. Fuente: Virginia DMV, CDL Classifications, Endorsements and Restrictions (dmv.virginia.gov/licenses-ids/cdl/class)."},"39":{"q":"En una CDL o CLP de Virginia, ¿qué código de restricción indica que el titular NO puede operar un vehículo equipado con frenos de aire?","options":["Restriction E","Restriction L","Restriction K","Restriction B"],"explanation":"El Virginia DMV aplica la restricción L (sin frenos de aire) cuando el solicitante no aprueba el examen de conocimientos de frenos de aire o realiza la prueba en un vehículo sin frenos de aire. La restricción E es sin transmisión manual, la K es solo Virginia/intraestatal y la B es lentes correctivos. Fuente: Virginia DMV, CDL Classifications, Endorsements and Restrictions (dmv.virginia.gov/licenses-ids/cdl/class)."},"40":{"q":"En Virginia, ¿cuál es la concentración máxima de alcohol en la sangre (BAC) con la que una persona puede operar legalmente un vehículo motorizado comercial (CMV)?","options":["0.02","0.04","0.08","0.10"],"explanation":"Virginia descalifica a un titular de CDL que opera un CMV con un BAC de 0.04 o más, la mitad del límite de 0.08 que aplica a los conductores comunes. Fuente: Virginia DMV CDL Disqualifications page; Va. Code § 46.2-341.24."},"41":{"q":"Conforme a la ley de consentimiento implícito de Virginia para conductores comerciales, al operar un CMV en una carretera de Virginia se considera que el conductor ha aceptado qué cosa?","options":["Una inspección de seguridad del vehículo en cualquier estación de pesaje","Pruebas químicas de sangre y/o aliento si es arrestado legalmente por un delito de DUI","Una prueba obligatoria de drogas antes de cada turno","Interrogatorios aleatorios por parte de cualquier oficial de la ley"],"explanation":"El estatuto de consentimiento implícito de Virginia dispone que cualquier persona que opera un CMV en una carretera ha consentido a dar sangre, aliento, o ambos, para pruebas químicas del contenido de alcohol/drogas si es arrestada por un delito conforme al § 46.2-341.24, tomadas dentro de las tres horas posteriores al delito. Fuente: Va. Code § 46.2-341.26:2; Virginia DMV CDL manual."},"42":{"q":"Un titular de CDL de Virginia es condenado por un primer delito mayor (como un DUI en un CMV) mientras NO transporta materiales peligrosos con letreros (placards). ¿Cuál es el periodo de descalificación?","options":["60 days","6 months","1 year","3 years"],"explanation":"Un primer delito mayor (DUI, BAC 0.04+, negarse a la prueba, abandonar la escena, etc.) resulta en una descalificación de CDL de 1 year en Virginia. Fuente: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 1, aplicada como la regla de Virginia."},"43":{"q":"Si un conductor de Virginia comete un primer delito mayor mientras opera un CMV que transporta materiales peligrosos que requieren letreros (placards), el periodo de descalificación aumenta a:","options":["1 year","2 years","3 years","5 years"],"explanation":"Un primer delito mayor cometido mientras se transportan materiales peligrosos con letreros (placards) eleva la descalificación de 1 year a 3 years. Fuente: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 1."},"44":{"q":"¿Cuál es la descalificación de CDL en Virginia por un segundo delito mayor (por ejemplo, una segunda condena por DUI en un CMV)?","options":["3 years","5 years","10 years","De por vida"],"explanation":"Un segundo delito mayor resulta en una descalificación de CDL de por vida en Virginia, aunque la reinstalación puede ser posible después de 10 years bajo ciertas condiciones. Fuente: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 1."},"45":{"q":"Un titular de CDL de Virginia se niega a someterse a una prueba requerida de sangre o aliento después de ser arrestado legalmente por operar un CMV bajo los efectos del alcohol. ¿Cómo se trata esto para efectos de la descalificación de CDL?","options":["Es solo una infracción de tránsito grave (60 days)","Es un delito mayor, que conlleva una descalificación de 1 year por primera ofensa","No conlleva descalificación de CDL, solo una multa","Resulta en una descalificación automática de por vida en la primera negativa"],"explanation":"Negarse a la prueba química es un delito mayor, que descalifica al conductor por 1 year en una primera ofensa (3 years si lleva materiales peligrosos con letreros), igual que una condena por DUI. Fuente: Virginia DMV CDL Disqualifications; Va. Code § 46.2-341.26:2; 49 CFR 383.51 Table 1."},"46":{"q":"¿Cuál de las siguientes es clasificada por Virginia como una 'infracción de tránsito grave' para un titular de CDL?","options":["Estacionar un CMV en una zona de no estacionar","Exceder en 15 mph o más el límite de velocidad señalado","Una calcomanía de registro vehicular vencida","No portar el comprobante de seguro"],"explanation":"Virginia incluye exceder en 15 mph o más el límite como una infracción de tránsito grave, junto con conducción imprudente (reckless driving), cambio de carril indebido/errático, seguir demasiado cerca, enviar mensajes de texto mientras se conduce un CMV e infracciones de tránsito vinculadas a un accidente fatal. Fuente: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 2."},"47":{"q":"¿Por cuántos días se descalifica a un titular de CDL de Virginia por ser condenado por DOS infracciones de tránsito graves (en incidentes separados) dentro de un periodo de 3 años?","options":["30 days","60 days","90 days","120 days"],"explanation":"Dos infracciones de tránsito graves dentro de 3 años resultan en una descalificación de CDL de 60 days en Virginia. Fuente: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 2."},"48":{"q":"Un titular de CDL de Virginia es condenado por TRES infracciones de tránsito graves (incidentes separados) dentro de un periodo de 3 años. ¿Cuál es la descalificación?","options":["60 days","90 days","120 days","180 days"],"explanation":"Tres o más infracciones de tránsito graves dentro de 3 años resultan en una descalificación de CDL de 120 days en Virginia. Fuente: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 2."},"49":{"q":"Las descalificaciones por infracciones de tránsito graves (60 / 120 days) se aplican únicamente cuando las infracciones se cuentan dentro de qué ventana de tiempo?","options":["1 year","3 years","5 years","10 years"],"explanation":"Las infracciones de tránsito graves se cuentan dentro de un periodo de 3 años para efectos de las descalificaciones por 2 infracciones (60 days) y 3 infracciones (120 days). Fuente: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 2."},"50":{"q":"¿Cuál es la descalificación para la PRIMERA infracción de un titular de CDL de Virginia en un cruce a nivel de ferrocarril y carretera mientras opera un CMV?","options":["30 days","60 days","120 days","1 year"],"explanation":"Una primera infracción en un cruce de ferrocarril resulta en una descalificación de no menos de 60 days. Fuente: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 3."},"51":{"q":"Un titular de CDL de Virginia comete una SEGUNDA infracción en un cruce a nivel de ferrocarril y carretera dentro de 3 años. ¿Cuál es la descalificación?","options":["60 days","120 days","180 days","1 year"],"explanation":"Una segunda infracción en un cruce de ferrocarril dentro de 3 años resulta en una descalificación de no menos de 120 days. Fuente: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 3."},"52":{"q":"Un titular de CDL de Virginia comete una TERCERA infracción en un cruce a nivel de ferrocarril y carretera dentro de 3 años. ¿Cuál es la descalificación?","options":["120 days","180 days","1 year","3 years"],"explanation":"Una tercera o subsiguiente infracción en un cruce de ferrocarril dentro de 3 años resulta en una descalificación de no menos de 1 year. Fuente: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 3."},"53":{"q":"¿Cuál es la descalificación mínima en Virginia para la PRIMERA condena de un titular de CDL por violar una orden de fuera de servicio (OOS) mientras conduce un CMV?","options":["90 days","120 days","180 days","1 year"],"explanation":"Virginia descalifica a un conductor por no menos de 180 days (hasta 1 year) por una primera violación de una orden de fuera de servicio. Fuente: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 4."},"54":{"q":"En comparación con violar una orden de fuera de servicio mientras transporta carga ordinaria, un conductor de CDL de Virginia que viola una orden OOS mientras transporta materiales peligrosos con letreros (placards) o 16+ pasajeros enfrenta:","options":["Una descalificación mínima menor","El mismo mínimo pero una descalificación máxima mayor","Ninguna penalidad adicional","Únicamente una multa monetaria"],"explanation":"Una violación de orden OOS mientras se transportan materiales peligrosos con letreros (placards) o cargas diseñadas para 16+ pasajeros mantiene el mínimo de 180 days pero eleva el máximo de la primera ofensa a 2 years (frente a 1 year para carga general). Fuente: 49 CFR 383.51 Table 4, aplicada como la regla de Virginia; Virginia DMV CDL Disqualifications."},"55":{"q":"Conforme a la ley de Virginia, a un conductor de CDL que envía mensajes de texto o usa un teléfono móvil de mano mientras conduce un CMV se le puede imponer una sanción civil que no exceda de:","options":["$250","$1,000","$2,750","$5,000"],"explanation":"El Va. Code § 46.2-341.20:5 prohíbe a un conductor de CMV enviar mensajes de texto o usar un teléfono móvil de mano y autoriza una sanción civil de hasta $2,750; dicha condena también es una infracción de tránsito grave para efectos de la CDL. Fuente: Va. Code § 46.2-341.20:5; Virginia DMV CDL Disqualifications."},"56":{"q":"La condena por enviar mensajes de texto mientras se opera un vehículo motorizado comercial en Virginia se trata, para efectos de la CDL, como:","options":["Un delito mayor (descalificación de 1 year)","Una infracción de tránsito grave","Una violación de orden de fuera de servicio","Una infracción no reportable"],"explanation":"Enviar mensajes de texto mientras se conduce un CMV está incluido entre las infracciones de tránsito graves de Virginia, por lo que las condenas reiteradas cuentan para las descalificaciones de 2 en 3 años (60 days) y de 3 en 3 años (120 days). Fuente: Virginia DMV CDL Disqualifications; Va. Code § 46.2-341.20:5; 49 CFR 383.51 Table 2."},"57":{"q":"¿A qué velocidad por encima del límite el exceso de velocidad ordinario se convierte en 'conducción imprudente' (reckless driving) conforme al estatuto general de conducción imprudente por velocidad de Virginia (un cargo que también es una infracción grave de CDL)?","options":["10 mph por encima del límite","15 mph por encima del límite","20 mph por encima del límite, o cualquier velocidad superior a 85 mph","25 mph por encima del límite, o cualquier velocidad superior a 90 mph"],"explanation":"El Va. Code § 46.2-862 define la conducción imprudente por velocidad como 20 mph o más por encima del límite, o superior a 85 mph sin importar el límite; la conducción imprudente también es una infracción de tránsito grave de CDL (separada del umbral de infracción grave de 15 mph por encima). Fuente: Va. Code § 46.2-862; Virginia DMV CDL Disqualifications."},"58":{"q":"Un titular de CDL de Virginia es condenado por usar un CMV en la comisión de un delito grave (felony) que involucra la fabricación, distribución o dispensación de una sustancia controlada. ¿Cuál es la descalificación?","options":["1 year","3 years","10 years","De por vida sin posibilidad de reinstalación a los 10 años"],"explanation":"Usar un CMV para fabricar, distribuir o dispensar sustancias controladas es un delito mayor que conlleva una descalificación de por vida que NO es elegible para la reinstalación a los 10 años disponible para otras descalificaciones de por vida. Fuente: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 1."},"59":{"q":"La descalificación de un titular de CDL por un DUI en un CMV en Virginia afecta principalmente, ¿qué privilegio de conducción?","options":["Únicamente el privilegio de operar motocicletas","El privilegio de conducción comercial (CDL)","Únicamente los privilegios de conducción fuera del estado","Los privilegios de navegación y embarcaciones acuáticas"],"explanation":"La descalificación de CDL elimina el privilegio de operar vehículos motorizados comerciales; también puede aplicarse una suspensión de licencia por separado, pero la descalificación se dirige específicamente al privilegio de conducción CDL/comercial. Fuente: Virginia DMV CDL Disqualifications; Va. Code § 46.2-341.18."},"60":{"q":"Según la ley \"Move Over\" de Virginia, ¿cuántos carriles debe tener una carretera (y en qué configuración) para que aplique el deber de cambiar de carril ante un vehículo de emergencia detenido con luces intermitentes?","options":["Al menos cuatro carriles, con al menos dos carriles para el tránsito que circula en la misma dirección que el conductor","Cualquier carretera no dividida de dos carriles","Al menos seis carriles, tres en cada dirección","Solo en autopistas interestatales señalizadas"],"explanation":"El Código de Virginia 46.2-861.1 (la ley \"Move Over\" de Virginia) exige que los conductores en vías con al menos cuatro carriles, dos de los cuales llevan tránsito en la misma dirección, cambien de carril para alejarse de un vehículo de emergencia detenido que muestra luces de advertencia intermitentes; si no es posible un cambio de carril seguro, el conductor debe reducir la velocidad y proceder con precaución. Fuente: Código de Virginia 46.2-861.1."},"61":{"q":"En Virginia, cuando un conductor no puede cambiar de carril de forma segura para alejarse de un vehículo de emergencia detenido que muestra luces intermitentes, ¿qué debe hacer en su lugar?","options":["Proceder con precaución y reducir la velocidad por debajo del límite señalizado","Detenerse por completo hasta que el vehículo de emergencia se retire","Tocar la bocina y mantener la velocidad señalizada","Activar las luces intermitentes de emergencia y continuar a velocidad normal"],"explanation":"Según el Código de Virginia 46.2-861.1, si no se puede realizar un cambio de carril de forma segura, el conductor debe proceder con la debida precaución y mantener una velocidad segura para las condiciones de la carretera, reduciendo la velocidad para proteger al personal de emergencia en el lugar. Una infracción se considera conducción imprudente (delito menor de Clase 1). Fuente: Código de Virginia 46.2-861.1."},"62":{"q":"En Virginia, una infracción de la ley \"Move Over\" (no apartarse ni reducir la velocidad ante un vehículo de emergencia detenido) se considera ¿qué?","options":["Conducción imprudente, un delito menor de Clase 1","Una infracción civil sin desplazamiento","Una simple infracción de tránsito sin puntos","Un delito grave si no ocurre ninguna lesión"],"explanation":"El Código de Virginia 46.2-861.1 establece que no ceder el paso ni apartarse ante un vehículo de emergencia detenido es una forma de conducción imprudente, que es un delito menor de Clase 1 con posible pena de cárcel, multas de hasta $2,500 y suspensión de la licencia. Fuente: Código de Virginia 46.2-861.1."},"63":{"q":"En las carreteras de Virginia de acceso no limitado (no interestatales), ¿cuál es el límite de velocidad máximo para un tractocamión o camión diseñado para transportar carga, salvo excepciones señalizadas?","options":["45 mph","55 mph","60 mph","65 mph"],"explanation":"El Código de Virginia 46.2-870 establece el límite predeterminado en carreteras de acceso no limitado en 55 mph para vehículos de pasajeros y autobuses, pero solo 45 mph para camiones, tractocamiones y combinaciones diseñadas para transportar carga, es decir, 10 mph menos que los vehículos de pasajeros. Fuente: Código de Virginia 46.2-870."},"64":{"q":"En una autopista interestatal de Virginia, ¿cuál es el límite de velocidad máximo para un camión comercial donde el límite más alto está señalizado tras un estudio de ingeniería de tránsito?","options":["70 mph, igual que para los vehículos de pasajeros","55 mph, mientras que los autos pueden ir a 70 mph","65 mph solo para camiones","75 mph"],"explanation":"El Código de Virginia 46.2-870 establece el máximo interestatal en 55 mph, o 70 mph donde se hayan colocado legalmente señales tras un estudio de ingeniería. En las interestatales, el límite más alto señalizado aplica a todos los vehículos, incluidos los camiones; Virginia no impone un límite de velocidad más bajo separado para camiones en las interestatales. Fuente: Código de Virginia 46.2-870."},"65":{"q":"En un cruce a nivel de ferrocarril en Virginia, un vehículo con materiales peligrosos señalizados con carteles o un autobús que lleva pasajeros de pago debe detenerse a qué distancia del riel más cercano?","options":["A menos de 50 pies pero no menos de 15 pies","A menos de 100 pies pero no menos de 25 pies","A menos de 30 pies pero no menos de 10 pies","A menos de 15 pies pero no menos de 5 pies"],"explanation":"El Código de Virginia 46.2-886 exige que los vehículos que llevan pasajeros de pago o que transportan sustancias explosivas o líquidos inflamables como carga se detengan a menos de 50 pies pero no menos de 15 pies del riel más cercano, y luego miren y escuchen antes de continuar. Esto coincide con la regla de cruce de ferrocarril del Manual CDL de Virginia. Fuente: Código de Virginia 46.2-886; Manual CDL de Virginia."},"66":{"q":"Después de detenerse en un cruce de ferrocarril, ¿qué exige la ley de Virginia respecto a los cambios de marcha mientras el vehículo está sobre las vías?","options":["El conductor debe cruzar en una marcha que no requiera cambio de marcha mientras está sobre las vías","El conductor debe reducir a la marcha más baja a mitad del cruce","El conductor puede cambiar de marcha libremente siempre que mantenga la velocidad","El conductor debe poner punto muerto mientras cruza"],"explanation":"El Código de Virginia 46.2-886 establece que, tras detenerse y al continuar, el conductor debe cruzar únicamente en una marcha tal que no sea necesario cambiar de marcha mientras atraviesa el cruce, y no debe cambiar de marcha al cruzar. Fuente: Código de Virginia 46.2-886; Manual CDL de Virginia."},"67":{"q":"En Virginia, un automovilista que se aproxima a un autobús escolar detenido que está cargando o descargando niños en un camino no dividido de dos carriles debe hacer ¿qué?","options":["Detenerse al aproximarse desde cualquier dirección y permanecer detenido hasta que el autobús se mueva o deje de parpadear","Detenerse solo si circula en la misma dirección que el autobús","Reducir a 20 mph pero no necesita detenerse","Detenerse solo si hay niños cruzando visiblemente"],"explanation":"El Código de Virginia 46.2-859 exige que un conductor que se aproxima desde cualquier dirección se detenga ante un autobús escolar que está detenido y muestra sus dispositivos de advertencia para cargar o descargar pasajeros, y que permanezca detenido hasta que las personas estén despejadas y el autobús vuelva a estar en movimiento. Una infracción es conducción imprudente. Fuente: Código de Virginia 46.2-859."},"68":{"q":"En una carretera dividida de Virginia, ¿bajo qué condición un conductor que viene en sentido contrario NO está obligado a detenerse ante un autobús escolar detenido en la calzada opuesta?","options":["Cuando las calzadas están separadas por una barrera física o un área sin pavimentar","Cuando hay una línea central doble amarilla pintada","Cuando el límite de velocidad es de 45 mph o más","Cuando hay un carril central de giro entre las calzadas"],"explanation":"El Código de Virginia 46.2-859 exime a un conductor de detenerse solo cuando el autobús escolar está en la otra calzada de una carretera dividida (o un camino de acceso/entrada) que está separada de la calzada del conductor por una barrera física o un área sin pavimentar. Una simple línea pintada o un carril de giro no califica. Fuente: Código de Virginia 46.2-859."},"69":{"q":"Cuando un vehículo comercial debe detenerse en una carretera de Virginia, el conductor debe colocar los dispositivos de advertencia triangulares reflectantes rojos dentro de cuántos minutos tras detenerse?","options":["Dentro de los 10 minutos","Dentro de los 5 minutos","Dentro de los 15 minutos","De inmediato, dentro de 1 minuto"],"explanation":"El Código de Virginia 46.2-111 exige que el operador de un vehículo comercial detenido coloque los dispositivos de advertencia triangulares reflectantes rojos requeridos dentro de los 10 minutos tras detenerse, manteniendo las luces intermitentes de emergencia encendidas hasta que estén colocados. Fuente: Código de Virginia 46.2-111."},"70":{"q":"Para un vehículo comercial detenido en una carretera de Virginia plana y recta, ¿dónde se deben colocar los tres triángulos de advertencia?","options":["A 100 pies por detrás, 100 pies por delante, y uno en el lado del tránsito a menos de 10 pies del vehículo","A 10 pies, 100 pies y 200 pies, todos por detrás","A 50 pies, 100 pies y 150 pies solo por detrás","Uno a cada lado y uno en el techo"],"explanation":"El Código de Virginia 46.2-111 indica la colocación de un triángulo a no menos de 100 pies en la dirección del tránsito que se aproxima, uno a no menos de 100 pies en la dirección opuesta, y uno en el lado del tránsito a no menos de 10 pies de la parte delantera o trasera del vehículo. Fuente: Código de Virginia 46.2-111."},"71":{"q":"Si un vehículo comercial de Virginia está detenido a menos de 500 pies de una curva, la cima de una colina u otra obstrucción, ¿cómo se debe colocar el dispositivo de advertencia en esa dirección?","options":["Lo suficientemente lejos para dar amplia advertencia, pero en ningún caso a menos de 500 pies del vehículo","Exactamente a 100 pies del vehículo","A no más de 200 pies del vehículo","Directamente sobre la obstrucción misma"],"explanation":"El Código de Virginia 46.2-111 exige que, cuando una parada esté a menos de 500 pies de una curva, la cresta de una colina u otra obstrucción, el dispositivo de advertencia en esa dirección se coloque de modo que brinde amplia advertencia, en ningún caso a menos de 500 pies del vehículo detenido. Fuente: Código de Virginia 46.2-111."},"72":{"q":"En la Interestatal 81 de Virginia y en las interestatales con más de dos carriles en cada dirección, ¿qué restricción de carril aplica a los vehículos comerciales motorizados?","options":["Tienen prohibido circular en el carril más a la izquierda","Solo pueden usar el carril más a la izquierda","Deben mantenerse dentro de 10 mph de la velocidad mínima para camiones","Están restringidos únicamente al carril central"],"explanation":"El Código de Virginia 46.2-803.1 prohíbe que los vehículos comerciales motorizados circulen en el carril más a la izquierda en la I-81 y en las autopistas interestatales con más de dos carriles de circulación en cada dirección (generalmente donde el límite es de 65 mph o más). Se exceptúan los autobuses y los vehículos que se preparan para una salida a la izquierda. Fuente: Código de Virginia 46.2-803.1."},"73":{"q":"En una carretera de Virginia con carriles, ¿dónde debe circular cualquier vehículo que viaje más lento que la velocidad normal del tránsito?","options":["En el carril más cercano al borde derecho o al bordillo derecho, excepto al rebasar o prepararse para girar a la izquierda","En cualquier carril que el conductor elija","En el carril central para equilibrar el tránsito","En el carril izquierdo para mantenerse alejado del tránsito que se incorpora"],"explanation":"El Código de Virginia 46.2-804 exige que un vehículo que circula más lento que la velocidad normal del tránsito se conduzca en el carril más cercano al borde derecho o al bordillo, excepto al alcanzar y rebasar, prepararse para un giro a la izquierda, o donde los carriles derechos estén reservados para el tránsito lento. Fuente: Código de Virginia 46.2-804."},"74":{"q":"¿Cuáles carreteras escénicas (parkways) de Virginia generalmente prohíben que los camiones comerciales circulen por ellas?","options":["El George Washington Memorial Parkway y el Colonial Parkway","La Interestatal 95 y la Interestatal 64","El Capital Beltway (I-495)","La Ruta 29 de EE. UU. y la Ruta 58 de EE. UU."],"explanation":"El George Washington Memorial Parkway, administrado por el gobierno federal, y el Colonial Parkway en Virginia prohíben los camiones comerciales; el GW Parkway requiere un permiso especial del Servicio de Parques Nacionales para cualquier vehículo comercial, y el Colonial Parkway prohíbe los camiones excepto los autobuses de pasajeros. Fuente: orientación sobre restricciones de camiones del Servicio de Parques Nacionales / VDOT."},"75":{"q":"Ciertas clases de materiales peligrosos tienen prohibido el paso por los túneles de Virginia próximos al agua, como el Hampton Roads Bridge-Tunnel. ¿Qué rige estas restricciones?","options":["Las regulaciones de VDOT que rigen los materiales peligrosos a través de las instalaciones de puentes-túneles (24VAC30-61), según la clase de peligro","Solo los límites de peso interestatales federales","Únicamente la calificación de peso bruto combinado del vehículo","Si la carga está asegurada o no"],"explanation":"La regulación administrativa de Virginia 24VAC30-61 rige el transporte de materiales peligrosos a través de los túneles urbanos y próximos al agua del estado (Hampton Roads, Monitor-Merrimac y los túneles del río Elizabeth), prohibiendo ciertas clases de peligro como los explosivos y los gases venenosos. Fuente: 24VAC30-61; orientación sobre materiales peligrosos de VDOT."},"76":{"q":"Los camiones que descienden hacia el sur por la empinada pendiente de Fancy Gap en la Interestatal 77 en Virginia deben prestar especial atención a ¿qué característica de seguridad?","options":["Múltiples rampas de escape para camiones sin frenos en la larga bajada","Una estación de pesaje obligatoria para camiones en la cima","Un túnel que prohíbe todos los camiones","Un carril HOV reversible"],"explanation":"La Interestatal 77 asciende más de 1,500 pies por Fancy Gap con pendientes de hasta aproximadamente 4.5%; el largo descenso hacia el sur hacia Carolina del Norte incluye múltiples rampas de escape para camiones que pierden el frenado. Los conductores deben seleccionar una marcha baja antes de descender. Fuente: orientación sobre conducción en montaña de VDOT/Manual CDL de Virginia."},"77":{"q":"En Virginia, la regla de velocidad mínima establece que un conductor no debe circular a una velocidad tan lenta como para hacer ¿qué?","options":["Impedir o bloquear el movimiento normal y razonable del tránsito, excepto cuando la velocidad reducida sea necesaria por seguridad o por ley","Viajar por debajo de 40 mph en cualquier carretera","Caer más de 5 mph por debajo del límite señalizado","Hacer que otros conductores usen sus bocinas"],"explanation":"El Código de Virginia 46.2-877 prohíbe conducir a una velocidad tan lenta como para impedir el movimiento normal y razonable del tránsito, excepto cuando la velocidad reducida sea necesaria para una operación segura o para cumplir con la ley. Fuente: Código de Virginia 46.2-877."},"78":{"q":"Además del requisito de los cuatro carriles, el deber \"Move Over\" de Virginia aplica a los vehículos detenidos que muestran luces de advertencia operados por ¿cuál de los siguientes?","options":["Policía, bomberos, ambulancia, VDOT, servicios públicos y grúas","Solo policía y ambulancias","Solo patrullas de la policía estatal","Solo vehículos propiedad de VDOT"],"explanation":"El Código de Virginia 46.2-861.1 extiende el deber \"Move Over\" a un amplio conjunto de vehículos detenidos que muestran luces de advertencia intermitentes, incluidos los vehículos de las fuerzas del orden, de bomberos, de ambulancia, del Departamento de Transporte de Virginia, de servicios públicos y de remolque/recuperación. Fuente: Código de Virginia 46.2-861.1."},"79":{"q":"Como alternativa menor a la conducción imprudente, la ley de Virginia permite que una infracción por rebasar un autobús escolar detenido se sancione como una multa civil de qué monto, con el propietario del vehículo potencialmente responsable?","options":["$250","$50","$1,000","$2,500"],"explanation":"El Código de Virginia 46.2-844 establece una alternativa de multa civil de $250 por no detenerse ante un autobús escolar detenido, y el propietario registrado del vehículo puede ser considerado responsable cuando el sistema de videomonitoreo del autobús capta la infracción. El delito penal bajo 46.2-859 sigue siendo conducción imprudente. Fuente: Código de Virginia 46.2-844 y 46.2-859."},"80":{"q":"¿Qué agencia emite las Licencias de Conducir Comerciales (CDL) en Virginia?","options":["El Departamento de Vehículos Motorizados de Virginia (DMV)","La Administración Federal de Seguridad de Autotransportes (FMCSA)","El Departamento de Transporte de Virginia (VDOT)","La División de Transportistas Motorizados de la Policía Estatal de Virginia"],"explanation":"Las CDL en Virginia son emitidas por el Departamento de Vehículos Motorizados de Virginia (DMV). La FMCSA establece los estándares federales pero no emite licencias, y VDOT se encarga de las carreteras/permisos, no de las licencias. Fuente: Virginia DMV, Apply for a CDL or CLP."},"81":{"q":"¿A dónde debe ir para solicitar una CDL o un Permiso de Aprendiz Comercial (CLP) de Virginia?","options":["En persona a un centro de servicio al cliente del DMV","Completamente en línea a través del sitio web del DMV","En cualquier concesionario de camiones aprobado por la FMCSA","Por correo a la sede del DMV en Richmond"],"explanation":"Virginia exige que solicite una CDL o un CLP en persona en un centro de servicio al cliente del DMV; la solicitud inicial de CDL/CLP no se puede completar totalmente en línea. Fuente: Virginia DMV, Apply for a CDL or CLP."},"82":{"q":"Las regulaciones federales exigen que cada solicitante de CDL o CLP en Virginia se autocertifique en cuántas categorías de operación de vehículos comerciales motorizados?","options":["Cuatro","Dos","Tres","Cinco"],"explanation":"Cualquier persona que tenga o solicite una CDL/CLP en Virginia debe autocertificarse en una de cuatro categorías de operación de CMV. Fuente: Virginia DMV, CDL Medical Certification Requirements."},"83":{"q":"¿Cuál de las siguientes es una de las cuatro categorías de autocertificación usadas por el Virginia DMV?","options":["Interestatal No Exceptuado (NI)","Operación Comercial Restringida","Solo Hazmat Intraestatal","Transportista Federal Exceptuado"],"explanation":"Las cuatro categorías son Interestatal Exceptuado (EI), Intraestatal Exceptuado (EA), Interestatal No Exceptuado (NI) e Intraestatal No Exceptuado (NA). \"Interestatal No Exceptuado\" es una categoría válida; las demás enumeradas no lo son. Fuente: Virginia DMV, CDL Medical Certification Requirements."},"84":{"q":"¿Cuál categoría de autocertificación generalmente NO requiere que el conductor mantenga un certificado de examinador médico en archivo con el Virginia DMV?","options":["Interestatal Exceptuado (EI)","Interestatal No Exceptuado (NI)","Intraestatal No Exceptuado (NA)","Cualquier categoría interestatal"],"explanation":"Los conductores que se certifican en categorías exceptuadas (interestatal exceptuado o intraestatal exceptuado) no están obligados a presentar un certificado de examinador médico; solo los conductores interestatales no exceptuados e intraestatales no exceptuados deben hacerlo. Fuente: Virginia DMV, CDL Medical Certification Requirements."},"85":{"q":"Un conductor que se autocertifica como interestatal no exceptuado en Virginia debe realizarse el examen físico con un examinador médico que esté:","options":["Listado en el Registro Nacional de Examinadores Médicos Certificados de la FMCSA","Empleado directamente por el Virginia DMV","Aprobado por el Departamento de Salud de Virginia","Cualquier médico licenciado que el conductor elija"],"explanation":"Los conductores no exceptuados deben ser examinados por un examinador médico listado en el Registro Nacional de Examinadores Médicos Certificados de la FMCSA. No todo médico licenciado califica. Fuente: Virginia DMV, CDL Medical Certification Requirements."},"86":{"q":"A partir del 5 de mayo de 2025, ¿cómo se debe presentar un Certificado de Examinador Médico (MEC) al Virginia DMV?","options":["Electrónicamente por el examinador médico a través del portal del Registro Nacional de la FMCSA","Por el conductor llevando el certificado en papel a una oficina del DMV","Por el conductor subiendo una copia escaneada al sitio web del DMV","Por el empleador del conductor enviándolo por fax a la FMCSA"],"explanation":"A partir del 5 de mayo de 2025, el Virginia DMV ya no acepta MEC directamente de los conductores; el examinador médico debe presentar el certificado electrónicamente a través del portal del Registro Nacional de la FMCSA. Fuente: Virginia DMV, CDL Medical Certification Requirements."},"87":{"q":"Para obtener un CLP de Virginia, un solicitante debe como mínimo aprobar ¿qué examen de conocimientos?","options":["El examen de conocimientos generales de CDL","Solo el examen de vehículos combinados","Solo el examen de frenos de aire","El examen de materiales peligrosos"],"explanation":"Para obtener un CLP debe aprobar el examen de conocimientos generales de CDL, además de cualquier examen de conocimientos adicional (como frenos de aire o tanque) para los vehículos que pretenda conducir. Fuente: Virginia DMV, Commercial Learner's Permit."},"88":{"q":"Después de que se le emita un CLP de Virginia, ¿cuánto tiempo debe tenerlo antes de ser elegible para tomar el examen de habilidades de CDL?","options":["Al menos 14 días","Al menos 30 días","Al menos 7 días","Al menos 60 días"],"explanation":"Virginia exige un período mínimo de tenencia del CLP de 14 días antes de tomar el examen de habilidades. Esto puede eximirse con prueba de una CDL previa o la finalización de la Capacitación para Conductores de Nivel Inicial (ELDT). Fuente: Virginia DMV, CDL Skills Test Eligibility / Commercial Learner's Permit."},"89":{"q":"¿Por cuánto tiempo es válido un Permiso de Aprendiz Comercial (CLP) de Virginia, y se puede renovar?","options":["Válido por 1 año y no se puede renovar","Válido por 180 días y se puede renovar una vez","Válido por 2 años y se renueva anualmente","Válido por 6 meses con renovaciones ilimitadas"],"explanation":"Un CLP de Virginia es válido por 1 año y no se puede renovar; si vence, debe volver a solicitarlo y volver a examinarse. Fuente: Virginia DMV, Commercial Learner's Permit."},"90":{"q":"El examen de habilidades de CDL de Virginia consta de ¿cuáles tres partes, realizadas en orden?","options":["Inspección previaje, control básico del vehículo y conducción en carretera","Conocimientos escritos, examen de visión y examen de manejo","Verificación de frenos de aire, retroceso e incorporación a la autopista","Acople/desacople, estacionamiento en paralelo y conducción nocturna"],"explanation":"El examen de habilidades de CDL tiene tres partes: la inspección previaje del vehículo, las habilidades básicas de control del vehículo y el examen de conducción en carretera, realizadas en ese orden. Fuente: estándar CDL de la FMCSA aplicado en Virginia; Virginia DMV CDL Skills Tests."},"91":{"q":"¿Quién debe proporcionar el vehículo utilizado para el examen de conducción en carretera de CDL de Virginia?","options":["El solicitante, quien debe traer un vehículo debidamente registrado del tipo que desea conducir","El Virginia DMV, que suministra un camión de prueba","Únicamente la escuela de capacitación ELDT del solicitante","La FMCSA, de su flota regional de inspección"],"explanation":"El solicitante debe proporcionar un vehículo debidamente registrado representativo de la clase/tipo de CDL que busca para el examen en carretera. Fuente: Virginia DMV, CDL Skills Test Eligibility."},"92":{"q":"¿Cuándo entró en vigor el requisito federal de Capacitación para Conductores de Nivel Inicial (ELDT) que aplica en Virginia?","options":["7 de febrero de 2022","5 de mayo de 2025","1 de enero de 2020","1 de julio de 2023"],"explanation":"Los requisitos de ELDT entraron en vigor el 7 de febrero de 2022. (El 5 de mayo de 2025 es la fecha separada para el cambio de presentación electrónica del MEC). Fuente: Virginia DMV, Entry-Level Driver Training."},"93":{"q":"Un proveedor de capacitación ELDT utilizado por un solicitante de CDL de Virginia debe estar:","options":["Listado en el Registro de Proveedores de Capacitación (TPR) de la FMCSA","Certificado únicamente por el Virginia DMV","Acreditado por la Junta de Educación de Virginia","Cualquier escuela de manejo comercial con una licencia comercial"],"explanation":"La ELDT debe completarse a través de un proveedor listado en el Registro de Proveedores de Capacitación (TPR) de la FMCSA. Una licencia comercial general o una acreditación de junta estatal no es suficiente. Fuente: Virginia DMV, Entry-Level Driver Training."},"94":{"q":"Para un solicitante de Clase A o B por primera vez en Virginia, ¿cuándo se debe completar la capacitación teórica y al volante de ELDT?","options":["Antes de tomar el examen de habilidades en carretera","Antes de solicitar el CLP","Dentro de los 30 días después de aprobar el examen de habilidades","Antes de tomar el examen de conocimientos generales"],"explanation":"Para las clases de CDL (y los endosos P/S), la capacitación teórica y al volante de ELDT debe completarse antes del examen de habilidades en carretera. (Para hazmat, la porción teórica debe realizarse antes del examen de conocimientos de hazmat). Fuente: Virginia DMV, Entry-Level Driver Training."},"95":{"q":"Para el endoso de materiales peligrosos (H) en Virginia, la porción teórica de ELDT debe completarse antes de:","options":["Tomar el examen de conocimientos de hazmat","Tomar el examen de habilidades en carretera","Presentar el formulario de autocertificación","Que se emita el CLP"],"explanation":"A diferencia de la capacitación de clase de CDL, la porción teórica de ELDT de hazmat debe completarse antes de tomar el examen de conocimientos de hazmat (no hay un examen de habilidades de hazmat separado). Fuente: Virginia DMV, Entry-Level Driver Training."},"96":{"q":"¿Cuál es la edad mínima para obtener una CDL intraestatal de Virginia frente a una CDL interestatal?","options":["18 para intraestatal y 21 para interestatal","21 para intraestatal y 25 para interestatal","16 para intraestatal y 18 para interestatal","18 tanto para intraestatal como para interestatal"],"explanation":"Debe tener al menos 18 años para obtener una CDL intraestatal y al menos 21 años para obtener una CDL interestatal. Fuente: Virginia DMV, CDL Skills Test Eligibility / Apply for a CDL or CLP."},"97":{"q":"Una persona que solicita una CDL en Virginia que nunca ha tenido una licencia de conducir o identificación de Virginia debe proporcionar dos pruebas de ¿cuál de las siguientes?","options":["Residencia en Virginia","Número de Seguro Social","Presencia legal","Identidad"],"explanation":"Los solicitantes primerizos de Virginia deben presentar una prueba de identidad, una prueba de presencia legal, una prueba del número de Seguro Social y dos pruebas de residencia en Virginia. Fuente: Virginia DMV, Apply for a CDL or CLP."},"98":{"q":"Para la mayoría de los conductores, ¿por cuánto tiempo es válida una CDL estándar de Virginia antes de que deba renovarse?","options":["8 años, venciendo en el cumpleaños del titular","4 años, venciendo en el cumpleaños del titular","5 años, venciendo al final del año","10 años, venciendo en el aniversario de la fecha de emisión"],"explanation":"Una CDL estándar de Virginia es válida por 8 años y vence en el cumpleaños del titular (los conductores de 75 años o más reciben un ciclo de 5 años). Fuente: Virginia DMV, Renew Your CDL."},"99":{"q":"En Virginia, si una CDL ha estado vencida o degradada por más de un año, ¿qué debe hacer el titular para recuperarla?","options":["Volver a tomar tanto el examen de conocimientos como el examen de habilidades en carretera para ese tipo de CDL","Simplemente pagar una multa por mora y renovar en línea","Volver a tomar únicamente el examen de visión","Esperar únicamente un período adicional de tenencia de 14 días"],"explanation":"Si una CDL de Virginia ha estado vencida o degradada por más de un año, el titular debe volver a tomar el examen de conocimientos y el examen de habilidades en carretera requeridos para el tipo de CDL que tenía. Fuente: Virginia DMV, Renew Your CDL."}},"hi":{"0":{"q":"वर्जीनिया के राजमार्गों पर किसी वाहन और उसके भार के लिए अधिकतम कुल बाहरी चौड़ाई कितनी अनुमत है (दर्पणों को छोड़कर)?","options":["96 inches","100 inches","102 inches","108 inches"],"explanation":"वर्जीनिया कोड 46.2-1105 किसी भी भार सहित वाहन की अधिकतम कुल बाहरी चौड़ाई 102 inches (8 feet 6 inches) निर्धारित करता है, जिसमें दर्पण और कुछ स्कूल-बस चेतावनी उपकरण शामिल नहीं हैं। स्रोत: Code of Virginia 46.2-1105; Virginia CDL Manual / DMV 109।"},"1":{"q":"वर्जीनिया के राजमार्गों पर भरे हुए या खाली वाहन के लिए अधिकतम ऊँचाई कितनी अनुमत है?","options":["13 feet","13 feet 6 inches","14 feet","12 feet 6 inches"],"explanation":"वर्जीनिया कोड 46.2-1110 किसी भी भरे हुए या खाली वाहन को 13 feet 6 inches की ऊँचाई से अधिक होने से प्रतिबंधित करता है। स्रोत: Code of Virginia 46.2-1110; Virginia DMV 109।"},"2":{"q":"वर्जीनिया के राजमार्गों पर अधिकतम एकल-धुरी (single-axle) भार कितना अनुमत है?","options":["18,000 pounds","20,000 pounds","22,400 pounds","24,000 pounds"],"explanation":"वर्जीनिया कोड 46.2-1124 किसी भी वाहन या संयोजन के एकल-धुरी भार को 20,000 pounds तक सीमित करता है। स्रोत: Code of Virginia 46.2-1124; Virginia DMV 109।"},"3":{"q":"वर्जीनिया के राजमार्गों पर अधिकतम युग्म-धुरी (tandem-axle) भार कितना अनुमत है?","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"वर्जीनिया कोड 46.2-1125 किसी भी वाहन या संयोजन के युग्म-धुरी भार को 34,000 pounds तक सीमित करता है। स्रोत: Code of Virginia 46.2-1125; Virginia DMV 109।"},"4":{"q":"वर्जीनिया के इंटरस्टेट राजमार्गों पर, धुरी अंतराल की परवाह किए बिना, अधिकतम सकल भार (gross weight) कितना अनुमत है?","options":["73,280 pounds","76,000 pounds","80,000 pounds","90,000 pounds"],"explanation":"वर्जीनिया कोड 46.2-1127 कॉमनवेल्थ के इंटरस्टेट राजमार्गों पर, धुरी अंतराल की परवाह किए बिना, 80,000 pounds से अधिक सकल भार को प्रतिबंधित करता है। स्रोत: Code of Virginia 46.2-1127।"},"5":{"q":"वर्जीनिया के इंटरस्टेट राजमार्गों पर, एकल-धुरी और युग्म-धुरी भार सीमाएँ क्रमशः क्या हैं:","options":["20,000 lb and 34,000 lb","18,000 lb and 32,000 lb","22,000 lb and 36,000 lb","20,000 lb and 40,000 lb"],"explanation":"वर्जीनिया कोड 46.2-1127 इंटरस्टेट एकल-धुरी सीमा को 20,000 pounds और युग्म-धुरी सीमा को 34,000 pounds निर्धारित करता है, जो सामान्य-राजमार्ग सीमाओं के समान है। स्रोत: Code of Virginia 46.2-1127।"},"6":{"q":"वर्जीनिया के राजमार्गों पर आम तौर पर ट्रैक्टर-ट्रक/सेमीट्रेलर संयोजन में संचालित एकल सेमीट्रेलर के लिए अधिकतम लंबाई कितनी है?","options":["45 feet","48 feet","53 feet","57 feet"],"explanation":"वर्जीनिया कोड 46.2-1112 ट्रैक्टर-ट्रक/सेमीट्रेलर संयोजन में सेमीट्रेलर को 48 feet तक सीमित करता है, हालाँकि इंटरस्टेट प्रणाली और कुछ योग्य राजमार्गों पर 53-foot सेमीट्रेलरों की अनुमति है। स्रोत: Code of Virginia 46.2-1112; Virginia DMV ढुलाई मार्गदर्शन।"},"7":{"q":"वर्जीनिया की इंटरस्टेट प्रणाली पर, एक सेमीट्रेलर को कितनी अधिकतम लंबाई तक की अनुमति है:","options":["48 feet","50 feet","53 feet","60 feet"],"explanation":"वर्जीनिया कोड 46.2-1112 के तहत, इंटरस्टेट प्रणाली (और योग्य राजमार्गों) पर 53 feet तक के सेमीट्रेलरों की अनुमति है, जब किंगपिन-से-पिछली-धुरी की दूरी निर्धारित सीमा से अधिक न हो; सामान्य-राजमार्ग आधार रेखा 48 feet है। स्रोत: Code of Virginia 46.2-1112।"},"8":{"q":"वर्जीनिया के राजमार्गों पर दोहरे-ट्रेलर (twin) संयोजन में, प्रत्येक व्यक्तिगत ट्रेलर या सेमीट्रेलर की अधिकतम लंबाई कितनी है?","options":["27 feet","28 feet","28 1/2 feet","30 feet"],"explanation":"वर्जीनिया कोड 46.2-1112 प्रावधान करता है कि किसी संयोजन में कोई भी व्यक्तिगत सेमीट्रेलर या ट्रेलर लंबाई में 28 1/2 feet से अधिक नहीं होगा। स्रोत: Code of Virginia 46.2-1112; Virginia DMV 109।"},"9":{"q":"वर्जीनिया के राजमार्गों पर युग्मित वाहन/ट्रेलर संयोजन के लिए सामान्य अधिकतम लंबाई कितनी है (विशेष ट्रैक्टर-सेमीट्रेलर अपवादों को छोड़कर)?","options":["60 feet","65 feet","70 feet","75 feet"],"explanation":"वर्जीनिया कोड 46.2-1112 युग्मित (संयोजन) वाहनों के लिए सामान्य 65-foot अधिकतम सीमा निर्धारित करता है, जिसमें निर्दिष्ट राजमार्गों पर ट्रैक्टर-सेमीट्रेलर संयोजनों के लिए विशिष्ट अपवाद हैं। स्रोत: Code of Virginia 46.2-1112।"},"10":{"q":"वर्जीनिया के राजमार्गों पर एकल मोटर वाहन (एक सीधा/एकल-इकाई ट्रक, बसों और मोटर होम के अलावा) की अधिकतम लंबाई कितनी है?","options":["35 feet","40 feet","45 feet","48 feet"],"explanation":"वर्जीनिया कोड 46.2-1112 किसी राजमार्ग पर 40 feet से अधिक लंबे एकल मोटर वाहन को संचालित करने से प्रतिबंधित करता है (बसों और मोटर होम के लिए अलग प्रावधान हैं)। स्रोत: Code of Virginia 46.2-1112; Virginia DMV ढुलाई मार्गदर्शन।"},"11":{"q":"वर्जीनिया अपने ब्रिज फॉर्मूला (Code 46.2-1126) के तहत अधिकतम अनुमेय सकल भार कैसे निर्धारित करता है?","options":["केवल वाहन के टाइटल पर पंजीकृत भार के आधार पर","धुरियों की संख्या और पहली व अंतिम धुरी के बीच की दूरी के आधार पर","इंजन की हॉर्सपावर और टायर रेटिंग के आधार पर","घन फुट में कुल कार्गो आयतन के आधार पर"],"explanation":"वर्जीनिया कोड 46.2-1126 एक तालिका (वर्जीनिया में लागू संघीय ब्रिज फॉर्मूला) प्रदान करता है जो धुरियों की संख्या और अंतिम छोर की (पहली और अंतिम) धुरियों के बीच की दूरी के आधार पर अधिकतम सकल भार निर्धारित करता है। स्रोत: Code of Virginia 46.2-1126।"},"12":{"q":"वर्जीनिया की सकल-भार तालिका (Code 46.2-1126) के तहत, धुरी अंतराल कितना भी अनुकूल हो, तालिका द्वारा अनुमत उच्चतम सकल भार कितना है?","options":["76,000 pounds","80,000 pounds","84,000 pounds","88,000 pounds"],"explanation":"वर्जीनिया कोड 46.2-1126 की तालिका अधिकतम सकल भार को 80,000 pounds पर सीमित करती है (शीर्ष मूल्य, जो पूर्ण अंतराल वाले 7-धुरी वाहन पर लागू होता है); 80,000 pounds 46.2-1127 के तहत पूर्ण वैधानिक अधिकतम सीमा भी है। स्रोत: Code of Virginia 46.2-1126 and 46.2-1127।"},"13":{"q":"एक ट्रक, जिसके आयाम सबसे व्यावहारिक विन्यास तक कम करने के बाद भी वर्जीनिया की कानूनी आकार या भार सीमाओं से अधिक हैं, को वर्जीनिया के राजमार्गों पर यात्रा करने से पहले क्या करना चाहिए?","options":["अगले वज़न स्टेशन पर एक निश्चित अधिक-भार जुर्माना भरें","अग्रिम रूप से एक ढुलाई (oversize/overweight) परमिट प्राप्त करें","वाहन को कृषि वाहन के रूप में पंजीकृत करें","केवल आधी रात से 5 a.m. के बीच यात्रा करें"],"explanation":"वर्जीनिया अपेक्षा करता है कि यदि कोई वाहन अपने सबसे व्यावहारिक आयामों तक कम करने के बाद भी कानूनी सीमाओं से अधिक है, तो संचालक को कॉमनवेल्थ के राजमार्गों पर यात्रा करने से पहले एक ढुलाई परमिट प्राप्त करना होगा। स्रोत: Virginia Code Article 18 (46.2-1139 et seq.); Virginia DMV Hauling Permits।"},"14":{"q":"कौन सी वर्जीनिया एजेंसी oversize/overweight ढुलाई परमिट जारी करती है?","options":["The Virginia State Police","केवल The Virginia Department of Transportation","The Virginia Department of Motor Vehicles","स्थानीय शेरिफ का कार्यालय"],"explanation":"The Virginia Department of Motor Vehicles oversize/overweight ढुलाई परमिट जारी करता है; इन्हें राज्य की स्वचालित ऑनलाइन ढुलाई परमिट प्रणाली के माध्यम से ऑर्डर किया जाता है। स्रोत: Virginia DMV Hauling Permits; Code of Virginia Article 18।"},"15":{"q":"वर्जीनिया के oversize/overweight ढुलाई परमिट आमतौर पर कैसे प्राप्त किए जाते हैं?","options":["रिचमंड को एक कागज़ी फॉर्म मेल करके","DMV की ऑनलाइन स्वचालित ढुलाई परमिट प्रणाली के माध्यम से","केवल व्यक्तिगत रूप से, DMV ग्राहक सेवा केंद्र पर","Virginia State Police डिस्पैच लाइन पर कॉल करके"],"explanation":"वर्जीनिया ढुलाई परमिट DMV की स्वचालित ऑनलाइन ढुलाई परमिट प्रणाली (वर्तमान पोर्टल ezhaulvirginia.com पर) के माध्यम से ऑर्डर किए जाते हैं, जिसने पुराने VAHPS को प्रतिस्थापित किया। स्रोत: Virginia DMV Hauling Permits।"},"16":{"q":"वर्जीनिया में उगाए गए कृषि या वन उत्पादों की ढुलाई के लिए वर्जीनिया कोड 46.2-1129 के तहत जारी एक परमिट एकल-धुरी, युग्म-धुरी और सकल-भार सीमाओं को किस प्रतिशत से बढ़ाता है?","options":["तीन प्रतिशत","पाँच प्रतिशत","दस प्रतिशत","पंद्रह प्रतिशत"],"explanation":"वर्जीनिया कोड 46.2-1129 वर्जीनिया में उगाए गए कृषि या वन उत्पादों की ढुलाई करने वाले कुछ वाहनों के लिए एकल-धुरी, युग्म-धुरी और सकल-भार सीमाओं को प्रत्येक पाँच प्रतिशत बढ़ाने वाला परमिट अनुमत करता है। स्रोत: Code of Virginia 46.2-1129।"},"17":{"q":"वर्जीनिया कोड 46.2-1129 में कृषि/वन-उत्पाद भार विस्तार के तहत, एक परमिट किस सकल भार से अधिक को अधिकृत नहीं कर सकता:","options":["80,000 pounds","82,000 pounds","84,000 pounds","90,000 pounds"],"explanation":"वर्जीनिया कोड 46.2-1129 प्रावधान करता है कि ऐसा कोई भी परमिट उस मोटर वाहन के संचालन को अधिकृत नहीं करेगा जिसका सकल भार 84,000 pounds से अधिक है। स्रोत: Code of Virginia 46.2-1129।"},"18":{"q":"क्या वर्जीनिया कोड 46.2-1129 के तहत पाँच प्रतिशत कृषि/वन-उत्पाद भार विस्तार इंटरस्टेट राजमार्ग प्रणाली पर लागू होता है?","options":["हाँ, इंटरस्टेट पर 84,000 pounds तक","नहीं; इंटरस्टेट सीमाएँ 20,000/34,000/80,000 pounds ही रहती हैं","हाँ, लेकिन केवल State Police एस्कॉर्ट के साथ","हाँ, इंटरस्टेट पर 88,000 pounds तक"],"explanation":"कृषि/वन-उत्पाद विस्तार इंटरस्टेट सीमाओं को नहीं बढ़ाता; वर्जीनिया कोड 46.2-1127 इंटरस्टेट अधिकतम सीमाओं को धुरी अंतराल की परवाह किए बिना 20,000 lb एकल धुरी, 34,000 lb युग्म धुरी, और 80,000 lb सकल पर बनाए रखता है। स्रोत: Code of Virginia 46.2-1129 and 46.2-1127।"},"19":{"q":"वर्जीनिया में, किस चौड़ाई सीमा से अधिक होने का अर्थ है कि एक भार oversize है और उसके लिए ढुलाई परमिट की आवश्यकता है?","options":["8 feet 0 inches (96 inches) से अधिक","8 feet 6 inches (102 inches) से अधिक","9 feet 0 inches (108 inches) से अधिक","10 feet 0 inches (120 inches) से अधिक"],"explanation":"कोड 46.2-1105 के अनुसार वर्जीनिया की कानूनी चौड़ाई 8 feet 6 inches (102 inches) है; 8 feet 6 inches से अधिक चौड़ा कोई भी भार oversize है और उसके लिए DMV ढुलाई परमिट की आवश्यकता होती है। स्रोत: Code of Virginia 46.2-1105; Virginia DMV Hauling Permits।"},"20":{"q":"वर्जीनिया में, 26,001 pounds या उससे अधिक के सकल वाहन भार रेटिंग (GVWR) वाले एकल वाहन को संचालित करने के लिए कौन सी CDL श्रेणी आवश्यक है, जो 10,000 pounds से अधिक के ट्रेलर को नहीं खींच रहा हो?","options":["Class A","Class B","Class C","Class D"],"explanation":"Virginia DMV एक Class B CDL को 26,001 pounds या उससे अधिक GVWR वाले किसी भी एकल वाहन, या ऐसे वाहन के रूप में परिभाषित करता है जो 10,000 pounds GVWR से अधिक न होने वाली इकाई को खींच रहा हो। स्रोत: Virginia DMV, CDL Classifications, Endorsements and Restrictions (dmv.virginia.gov/licenses-ids/cdl/class)।"},"21":{"q":"वर्जीनिया नियमों के तहत, 26,001 pounds या उससे अधिक के सकल संयोजन भार रेटिंग (GCWR) वाले वाहनों के किसी भी संयोजन के लिए Class A CDL आवश्यक है, बशर्ते खींचे जा रहे वाहन का GVWR किस मात्रा से अधिक हो?","options":["5,000 pounds","8,000 pounds","10,000 pounds","15,000 pounds"],"explanation":"Virginia DMV Class A को 26,001+ pounds GCWR वाले संयोजन के रूप में परिभाषित करता है जहाँ खींची जा रही इकाई(याँ) 10,000 pounds GVWR से अधिक हों। स्रोत: Virginia DMV, CDL Classifications, Endorsements and Restrictions (dmv.virginia.gov/licenses-ids/cdl/class)।"},"22":{"q":"एक वर्जीनिया चालक एक ऐसे वाहन को संचालित करता है जो Class A या B भार सीमाओं को पूरा नहीं करता लेकिन चालक सहित 16 या अधिक यात्रियों को ले जाने के लिए डिज़ाइन किया गया है। कौन सी CDL श्रेणी लागू होती है?","options":["Class A","Class B","Class C","किसी CDL की आवश्यकता नहीं है"],"explanation":"Virginia DMV Class C को किसी भी ऐसे वाहन के रूप में परिभाषित करता है जो Class A या B को पूरा नहीं करता और जो या तो 16 या अधिक यात्रियों (चालक सहित) को ले जाता है या प्लेकार्ड की आवश्यकता वाली खतरनाक सामग्री ले जाता है। स्रोत: Virginia DMV, CDL Classifications, Endorsements and Restrictions (dmv.virginia.gov/licenses-ids/cdl/class)।"},"23":{"q":"कौन सा वर्जीनिया CDL एंडोर्समेंट धारक को टैंक वाहन चलाने की अनुमति देता है?","options":["Endorsement N","Endorsement T","Endorsement H","Endorsement P"],"explanation":"Virginia DMV टैंक (tanker) वाहनों के लिए N एंडोर्समेंट निर्दिष्ट करता है। H एंडोर्समेंट खतरनाक सामग्री के लिए, T डबल/ट्रिपल के लिए, और P यात्री वाहनों के लिए है। स्रोत: Virginia DMV, CDL Classifications, Endorsements and Restrictions (dmv.virginia.gov/licenses-ids/cdl/class)।"},"24":{"q":"डबल या ट्रिपल ट्रेलर खींचने वाले वाहन को चलाने के लिए कौन सा वर्जीनिया CDL एंडोर्समेंट आवश्यक है?","options":["Endorsement P","Endorsement N","Endorsement T","Endorsement S"],"explanation":"Virginia DMV डबल या ट्रिपल ट्रेलर खींचने वाले वाहन को चलाने की अनुमति देने के लिए T एंडोर्समेंट निर्दिष्ट करता है। स्रोत: Virginia DMV, CDL Classifications, Endorsements and Restrictions (dmv.virginia.gov/licenses-ids/cdl/class)।"},"25":{"q":"केवल इंट्रास्टेट (वर्जीनिया के भीतर) ड्राइविंग के लिए वैध वर्जीनिया CDL प्राप्त करने की न्यूनतम आयु क्या है?","options":["16 years old","18 years old","21 years old","25 years old"],"explanation":"Virginia DMV को इंट्रास्टेट CDL के लिए आवेदक का कम से कम 18 वर्ष का होना और इंटरस्टेट CDL के लिए कम से कम 21 वर्ष का होना आवश्यक है। स्रोत: Virginia DMV, CDL Skills Test Eligibility Requirements (dmv.virginia.gov/licenses-ids/cdl/eligibility)।"},"26":{"q":"इंटरस्टेट (राज्य की सीमाओं के पार) संचालन के लिए वैध वर्जीनिया CDL प्राप्त करने की न्यूनतम आयु क्या है?","options":["18 years old","19 years old","20 years old","21 years old"],"explanation":"Virginia DMV को इंटरस्टेट CDL के लिए आवेदक का कम से कम 21 वर्ष का होना आवश्यक है; केवल-इंट्रास्टेट CDL के लिए न्यूनतम 18 वर्ष है। स्रोत: Virginia DMV, CDL Skills Test Eligibility Requirements (dmv.virginia.gov/licenses-ids/cdl/eligibility)।"},"27":{"q":"CDL स्किल्स टेस्ट देने से पहले, एक वर्जीनिया आवेदक को आम तौर पर कम से कम कितने दिनों तक एक Commercial Learner's Permit (CLP) धारण करना चाहिए?","options":["7 days","10 days","14 days","30 days"],"explanation":"वर्जीनिया द्वारा अपनाए गए संघीय मानक के अनुसार, एक आवेदक को स्किल्स टेस्ट देने से पहले कम से कम 14 days तक CLP धारण करना चाहिए (जब तक कि उसके पास पूर्व CDL न हो या स्वीकृत प्रशिक्षण पूरा न किया हो)। स्रोत: Virginia DMV, CDL Skills Test Eligibility Requirements / Commercial Learner's Permit (dmv.virginia.gov/licenses-ids/cdl/eligibility)।"},"28":{"q":"वर्जीनिया Commercial Learner's Permit (CLP) पर एक वाणिज्यिक वाहन चलाते समय, परमिट धारक के साथ किसका होना आवश्यक है?","options":["21 से अधिक उम्र का कोई भी लाइसेंस प्राप्त वयस्क","उसी प्रकार के वाहन के लिए वैध CDL धारण करने वाला व्यक्ति","केवल एक DMV परीक्षक","कोई नहीं; अकेले ड्राइविंग की अनुमति है"],"explanation":"Virginia DMV कहता है कि CLP एक वाणिज्यिक वाहन के संचालन की अनुमति केवल तब देता है जब उसी प्रकार के वाहन को चलाने के लिए लाइसेंस प्राप्त व्यक्ति (उस श्रेणी/प्रकार के लिए एक वैध CDL धारक) परमिट धारक के साथ शारीरिक रूप से उपस्थित हो। स्रोत: Virginia DMV, Commercial Learner's Permit (dmv.virginia.gov/licenses-ids/cdl/permit)।"},"29":{"q":"वर्जीनिया HazMat (H) एंडोर्समेंट प्राप्त करने के लिए कौन सा दस्तावेज़ या जाँच विशिष्ट रूप से आवश्यक है जो अन्य एंडोर्समेंट के लिए आवश्यक नहीं है?","options":["एक फिंगरप्रिंट-आधारित TSA सुरक्षा खतरा मूल्यांकन","एक दूसरी दृष्टि जाँच","एक नियोक्ता प्रायोजन पत्र","एक नोटरीकृत ड्राइविंग लॉग"],"explanation":"Virginia DMV को HazMat (HME) आवेदकों से एक फिंगरप्रिंट-आधारित पृष्ठभूमि जाँच पूरी करना आवश्यक है; DMV जानकारी TSA को अग्रेषित करता है, जो सुरक्षा खतरा मूल्यांकन करता है और एंडोर्समेंट को मंजूरी देता है या अस्वीकार करता है। स्रोत: Virginia DMV, Hazardous Materials Endorsement (HME) (dmv.virginia.gov/licenses-ids/cdl/hazmat)।"},"30":{"q":"वर्जीनिया HazMat (H) एंडोर्समेंट के लिए फिंगरप्रिंट-आधारित पृष्ठभूमि जाँच कितने समय के लिए वैध है?","options":["1 year","3 years","5 years","10 years"],"explanation":"Virginia DMV कहता है कि HazMat एंडोर्समेंट के लिए फिंगरप्रिंट-आधारित पृष्ठभूमि जाँच पाँच वर्ष तक के लिए वैध है, जिसके बाद इसे नवीनीकृत किया जाना चाहिए। स्रोत: Virginia DMV, Hazardous Materials Endorsement (HME) (dmv.virginia.gov/licenses-ids/cdl/hazmat)।"},"31":{"q":"एक वर्जीनिया आवेदक जिसके पास वैध TWIC (Transportation Worker Identification Credential) है, HazMat एंडोर्समेंट के लिए आवेदन करते समय कौन सा लाभ प्राप्त करता है?","options":["ज्ञान परीक्षा माफ कर दी जाती है","कम शुल्क और कोई नई फिंगरप्रिंटिंग नहीं","TSA समीक्षा के बिना स्वचालित अनुमोदन","एक आजीवन एंडोर्समेंट जो कभी समाप्त नहीं होता"],"explanation":"Virginia DMV TWIC धारकों से कम गैर-वापसी योग्य HazMat शुल्क ($41 बनाम $83) लेता है और नई फिंगरप्रिंटिंग की आवश्यकता नहीं रखता, क्योंकि TWIC में पहले से ही एक तुलनीय TSA खतरा मूल्यांकन शामिल है। स्रोत: Virginia DMV, Hazardous Materials Endorsement / Applying for a CDL (dmv.virginia.gov/licenses-ids/cdl/hazmat)।"},"32":{"q":"वर्जीनिया में लागू संघीय Entry-Level Driver Training (ELDT) नियम के तहत, स्किल्स टेस्ट से पहले किस रजिस्ट्री पर सूचीबद्ध प्रदाता के माध्यम से प्रशिक्षण पूरा किया जाना चाहिए?","options":["The Virginia DMV Approved Schools List","The FMCSA Training Provider Registry (TPR)","The National CDL Academy Directory","The DOT Carrier Safety Index"],"explanation":"ELDT को FMCSA Training Provider Registry (TPR) पर सूचीबद्ध प्रदाता द्वारा पूरा किया जाना चाहिए; Virginia DMV स्किल्स टेस्ट से पहले इलेक्ट्रॉनिक रूप से पूर्णता सत्यापित करता है। स्रोत: Virginia DMV / FMCSA Entry-Level Driver Training (tpr.fmcsa.dot.gov; dmv.virginia.gov/licenses-ids/cdl/eligibility)।"},"33":{"q":"निम्नलिखित में से कौन सी पहली-बार की कार्रवाई वर्जीनिया में संघीय ELDT प्रशिक्षण आवश्यकता को ट्रिगर नहीं करती है?","options":["पहली बार CDL प्राप्त करना","एक Class B CDL को Class A CDL में अपग्रेड करना","समान श्रेणी और एंडोर्समेंट के साथ मौजूदा CDL को नवीनीकृत करना","पहली बार Passenger (P) एंडोर्समेंट प्राप्त करना"],"explanation":"ELDT पहली बार CDL आवेदकों, Class B-से-Class A अपग्रेड, और पहली बार H, P, या S एंडोर्समेंट के लिए आवश्यक है। बिना किसी नई श्रेणी या एंडोर्समेंट के मौजूदा CDL का साधारण नवीनीकरण ELDT की आवश्यकता नहीं रखता। स्रोत: FMCSA Entry-Level Driver Training rule, applied by Virginia DMV (fmcsa.dot.gov; dmv.virginia.gov)।"},"34":{"q":"पहली बार वर्जीनिया HazMat आवेदक के लिए, ELDT का सिद्धांत भाग कब पूरा किया जाना चाहिए?","options":["HazMat ज्ञान परीक्षा पास करने के बाद","DMV में HazMat ज्ञान परीक्षा देने से पहले","केवल TSA द्वारा पृष्ठभूमि जाँच को मंजूरी देने के बाद","एंडोर्समेंट जारी होने के 30 दिनों के भीतर"],"explanation":"वर्जीनिया में लागू ELDT नियम के तहत, पहली बार HazMat (H) एंडोर्समेंट आवेदकों को DMV में HazMat ज्ञान परीक्षा देने से पहले ELDT सिद्धांत प्रशिक्षण पूरा करना होगा। स्रोत: FMCSA ELDT rule / Virginia DMV (fmcsa.dot.gov; dmv.virginia.gov/licenses-ids/cdl)।"},"35":{"q":"एक वर्जीनिया CDL आवेदक को अपने वाणिज्यिक मोटर वाहन संचालन के प्रकार के संबंध में कितनी चिकित्सा स्व-प्रमाणन श्रेणियों में से चुनना होगा?","options":["दो","तीन","चार","पाँच"],"explanation":"Virginia DMV को आवेदकों से चार श्रेणियों में से एक के लिए स्व-प्रमाणन करना आवश्यक है: excepted interstate, non-excepted interstate, excepted intrastate, या non-excepted intrastate। स्रोत: Virginia DMV, Apply for a CDL or CLP (dmv.virginia.gov/licenses-ids/cdl/applying)।"},"36":{"q":"एक वर्जीनिया CDL आवेदक जो राज्य की सीमाओं के पार वाहन चलाता है और संघीय शारीरिक योग्यता नियमों से छूट प्राप्त नहीं है, उसे किस श्रेणी के तहत स्व-प्रमाणन करना चाहिए?","options":["Excepted interstate","Non-excepted interstate","Excepted intrastate","Non-excepted intrastate"],"explanation":"इंटरस्टेट वाणिज्य में संचालन करने वाला एक चालक जिसे संघीय चिकित्सा योग्यता मानकों को पूरा करना होगा, 'non-excepted interstate' के रूप में स्व-प्रमाणन करता है और उसे एक वैध medical examiner's certificate बनाए रखना होगा। स्रोत: Virginia DMV, Apply for a CDL or CLP, medical self-certification (dmv.virginia.gov/licenses-ids/cdl/applying)।"},"37":{"q":"एक पहली बार वर्जीनिया CDL आवेदक जिसने कभी वर्जीनिया लाइसेंस धारण नहीं किया है, उसे पहचान का प्रमाण, कानूनी उपस्थिति का प्रमाण, एक Social Security number, और वर्जीनिया निवास के कितने प्रमाण प्रदान करने होंगे?","options":["निवास का एक प्रमाण","निवास के दो प्रमाण","निवास के तीन प्रमाण","निवास प्रमाण आवश्यक नहीं है"],"explanation":"Virginia DMV को एक पहली बार आवेदक से, जिसने कभी वर्जीनिया लाइसेंस/ID धारण नहीं किया है, पहचान का एक प्रमाण, कानूनी उपस्थिति का एक प्रमाण, Social Security number का एक प्रमाण, और वर्जीनिया निवास के दो प्रमाण प्रस्तुत करना आवश्यक है। स्रोत: Virginia DMV, Apply for a CDL or CLP (dmv.virginia.gov/licenses-ids/cdl/applying)।"},"38":{"q":"वर्जीनिया की Sex Offender and Crimes Against Minors Registry के साथ पंजीकरण करने के लिए आवश्यक एक व्यक्ति, जब तक पंजीकरण आवश्यक है, किस CDL एंडोर्समेंट के लिए अयोग्य है?","options":["N (Tanker)","T (Doubles/Triples)","S (School Bus)","H (HazMat)"],"explanation":"वर्जीनिया किसी भी ऐसे व्यक्ति को S (School Bus) एंडोर्समेंट जारी करने से प्रतिबंधित करता है जिसे Sex Offender and Crimes Against Minors Registry के साथ पंजीकरण करना आवश्यक है, किसी भी अवधि के दौरान जब पंजीकरण आवश्यक हो। स्रोत: Virginia DMV, CDL Classifications, Endorsements and Restrictions (dmv.virginia.gov/licenses-ids/cdl/class)।"},"39":{"q":"वर्जीनिया CDL या CLP पर, कौन सा प्रतिबंध कोड इंगित करता है कि धारक एयर ब्रेक से सुसज्जित वाहन को संचालित नहीं कर सकता?","options":["Restriction E","Restriction L","Restriction K","Restriction B"],"explanation":"Virginia DMV L प्रतिबंध (कोई एयर ब्रेक नहीं) लागू करता है जब आवेदक एयर ब्रेक ज्ञान परीक्षा पास नहीं करता या एयर ब्रेक रहित वाहन में परीक्षण देता है। Restriction E कोई मैनुअल ट्रांसमिशन नहीं, K केवल Virginia/intrastate, और B सुधारात्मक लेंस है। स्रोत: Virginia DMV, CDL Classifications, Endorsements and Restrictions (dmv.virginia.gov/licenses-ids/cdl/class)।"},"40":{"q":"वर्जीनिया में, अधिकतम रक्त अल्कोहल सांद्रता (BAC) कितनी है जिस पर एक व्यक्ति कानूनी रूप से एक वाणिज्यिक मोटर वाहन (CMV) को संचालित कर सकता है?","options":["0.02","0.04","0.08","0.10"],"explanation":"वर्जीनिया एक CDL धारक को अयोग्य ठहराता है जो 0.04 या उससे अधिक BAC के साथ एक CMV संचालित करता है — सामान्य चालकों के लिए 0.08 सीमा का आधा। स्रोत: Virginia DMV CDL Disqualifications page; Va. Code § 46.2-341.24।"},"41":{"q":"वाणिज्यिक चालकों के लिए वर्जीनिया के निहित-सहमति (implied-consent) कानून के तहत, वर्जीनिया राजमार्ग पर एक CMV संचालित करके एक चालक को किस बात पर सहमत माना जाता है?","options":["किसी भी वज़न स्टेशन पर एक वाहन सुरक्षा निरीक्षण","DUI अपराध के लिए कानूनी रूप से गिरफ्तार किए जाने पर रक्त और/या साँस का रासायनिक परीक्षण","हर शिफ्ट से पहले एक अनिवार्य ड्रग स्क्रीनिंग","किसी भी कानून-प्रवर्तन अधिकारी द्वारा यादृच्छिक पूछताछ"],"explanation":"वर्जीनिया का निहित-सहमति कानून प्रावधान करता है कि कोई भी व्यक्ति जो किसी राजमार्ग पर CMV संचालित करता है, उसने § 46.2-341.24 के तहत किसी अपराध के लिए गिरफ्तार किए जाने पर अल्कोहल/ड्रग सामग्री के रासायनिक परीक्षण के लिए रक्त, साँस, या दोनों देने की सहमति दी है, जो अपराध के तीन घंटे के भीतर लिया जाता है। स्रोत: Va. Code § 46.2-341.26:2; Virginia DMV CDL manual।"},"42":{"q":"एक वर्जीनिया CDL धारक को प्लेकार्ड वाली खतरनाक सामग्री नहीं ले जाते समय पहले प्रमुख अपराध (जैसे एक CMV DUI) के लिए दोषी ठहराया जाता है। अयोग्यता अवधि क्या है?","options":["60 days","6 months","1 year","3 years"],"explanation":"एक पहला प्रमुख अपराध (DUI, BAC 0.04+, परीक्षण से इनकार, घटनास्थल छोड़ना, आदि) वर्जीनिया में 1-year CDL अयोग्यता में परिणत होता है। स्रोत: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 1, वर्जीनिया नियम के रूप में लागू।"},"43":{"q":"यदि एक वर्जीनिया चालक प्लेकार्ड की आवश्यकता वाली खतरनाक सामग्री ले जा रहे CMV को संचालित करते समय पहला प्रमुख अपराध करता है, तो अयोग्यता अवधि बढ़कर हो जाती है:","options":["1 year","2 years","3 years","5 years"],"explanation":"प्लेकार्ड वाली खतरनाक सामग्री ले जाते समय किया गया पहला प्रमुख अपराध अयोग्यता को 1 year से 3 years तक बढ़ा देता है। स्रोत: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 1।"},"44":{"q":"एक दूसरे प्रमुख अपराध (उदाहरण के लिए, दूसरी CMV DUI दोषसिद्धि) के लिए वर्जीनिया में CDL अयोग्यता क्या है?","options":["3 years","5 years","10 years","Lifetime"],"explanation":"एक दूसरा प्रमुख अपराध वर्जीनिया में आजीवन (lifetime) CDL अयोग्यता में परिणत होता है, हालाँकि कुछ शर्तों के तहत 10 years के बाद पुनर्बहाली संभव हो सकती है। स्रोत: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 1।"},"45":{"q":"एक वर्जीनिया CDL धारक नशे में CMV संचालित करने के लिए कानूनी रूप से गिरफ्तार किए जाने के बाद एक आवश्यक रक्त या साँस परीक्षण देने से इनकार करता है। CDL अयोग्यता के लिए इसे कैसे माना जाता है?","options":["यह केवल एक गंभीर यातायात उल्लंघन है (60 days)","यह एक प्रमुख अपराध है, जिसमें 1-year पहले-अपराध की अयोग्यता है","इसमें कोई CDL अयोग्यता नहीं है, केवल एक जुर्माना है","इसके परिणामस्वरूप पहले इनकार पर एक स्वचालित आजीवन अयोग्यता होती है"],"explanation":"रासायनिक परीक्षण से इनकार करना एक प्रमुख अपराध है, जो पहले अपराध पर चालक को 1 year के लिए अयोग्य ठहराता है (प्लेकार्ड वाली hazmat के लिए 3 years) — एक DUI दोषसिद्धि के समान। स्रोत: Virginia DMV CDL Disqualifications; Va. Code § 46.2-341.26:2; 49 CFR 383.51 Table 1।"},"46":{"q":"निम्नलिखित में से किसे वर्जीनिया द्वारा एक CDL धारक के लिए 'गंभीर यातायात उल्लंघन' के रूप में वर्गीकृत किया गया है?","options":["नो-पार्किंग ज़ोन में एक CMV पार्क करना","पोस्ट की गई गति सीमा से 15 mph या अधिक तेज गति से चलना","एक समाप्त वाहन पंजीकरण स्टिकर","बीमा का प्रमाण साथ न रखना"],"explanation":"वर्जीनिया सीमा से 15 mph या अधिक तेज गति को एक गंभीर यातायात उल्लंघन के रूप में सूचीबद्ध करता है, साथ ही लापरवाह ड्राइविंग, अनुचित/अनियमित लेन परिवर्तन, बहुत करीब से चलना, CMV चलाते समय टेक्स्टिंग, और एक घातक दुर्घटना से जुड़े यातायात अपराध। स्रोत: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 2।"},"47":{"q":"एक 3-year अवधि के भीतर (अलग-अलग घटनाओं में) दो गंभीर यातायात उल्लंघनों के लिए दोषी ठहराए जाने पर एक वर्जीनिया CDL धारक को कितने दिनों के लिए अयोग्य ठहराया जाता है?","options":["30 days","60 days","90 days","120 days"],"explanation":"3 years के भीतर दो गंभीर यातायात उल्लंघन वर्जीनिया में 60-day CDL अयोग्यता में परिणत होते हैं। स्रोत: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 2।"},"48":{"q":"एक वर्जीनिया CDL धारक को एक 3-year अवधि के भीतर तीन गंभीर यातायात उल्लंघनों (अलग-अलग घटनाओं) के लिए दोषी ठहराया जाता है। अयोग्यता क्या है?","options":["60 days","90 days","120 days","180 days"],"explanation":"3 years के भीतर तीन या अधिक गंभीर यातायात उल्लंघन वर्जीनिया में 120-day CDL अयोग्यता में परिणत होते हैं। स्रोत: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 2।"},"49":{"q":"गंभीर-यातायात-उल्लंघन अयोग्यताएँ (60 / 120 days) केवल तभी लागू होती हैं जब उल्लंघनों को किस समय अवधि के भीतर गिना जाता है?","options":["1 year","3 years","5 years","10 years"],"explanation":"2-उल्लंघन (60-day) और 3-उल्लंघन (120-day) अयोग्यताओं के प्रयोजनों के लिए गंभीर यातायात उल्लंघनों को एक 3-year अवधि के भीतर गिना जाता है। स्रोत: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 2।"},"50":{"q":"एक CMV संचालित करते समय एक वर्जीनिया CDL धारक के पहले रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन के लिए अयोग्यता क्या है?","options":["30 days","60 days","120 days","1 year"],"explanation":"एक पहला रेलमार्ग-क्रॉसिंग उल्लंघन 60 days से कम नहीं की अयोग्यता में परिणत होता है। स्रोत: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 3।"},"51":{"q":"एक वर्जीनिया CDL धारक 3 years के भीतर एक दूसरा रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन करता है। अयोग्यता क्या है?","options":["60 days","120 days","180 days","1 year"],"explanation":"3 years के भीतर एक दूसरा रेलमार्ग-क्रॉसिंग उल्लंघन 120 days से कम नहीं की अयोग्यता में परिणत होता है। स्रोत: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 3।"},"52":{"q":"एक वर्जीनिया CDL धारक 3 years के भीतर एक तीसरा रेलमार्ग-राजमार्ग ग्रेड क्रॉसिंग उल्लंघन करता है। अयोग्यता क्या है?","options":["120 days","180 days","1 year","3 years"],"explanation":"3 years के भीतर एक तीसरा या बाद का रेलमार्ग-क्रॉसिंग उल्लंघन 1 year से कम नहीं की अयोग्यता में परिणत होता है। स्रोत: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 3।"},"53":{"q":"एक CMV चलाते समय एक आउट-ऑफ-सर्विस (OOS) आदेश का उल्लंघन करने की पहली दोषसिद्धि के लिए वर्जीनिया में एक CDL धारक के लिए न्यूनतम अयोग्यता क्या है?","options":["90 days","120 days","180 days","1 year"],"explanation":"वर्जीनिया एक पहले आउट-ऑफ-सर्विस-आदेश उल्लंघन के लिए चालक को 180 days से कम नहीं (1 year तक) के लिए अयोग्य ठहराता है। स्रोत: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 4।"},"54":{"q":"साधारण कार्गो ले जाते समय एक आउट-ऑफ-सर्विस आदेश का उल्लंघन करने की तुलना में, एक वर्जीनिया CDL चालक जो प्लेकार्ड वाली खतरनाक सामग्री या 16+ यात्रियों को ले जाते समय एक OOS आदेश का उल्लंघन करता है, उसका सामना करता है:","options":["एक कम न्यूनतम अयोग्यता","वही न्यूनतम लेकिन एक उच्चतर अधिकतम अयोग्यता","कोई अतिरिक्त दंड नहीं","केवल एक मौद्रिक जुर्माना"],"explanation":"प्लेकार्ड वाली hazmat या 16+ यात्रियों के लिए डिज़ाइन किए गए भार ले जाते समय एक OOS-आदेश उल्लंघन 180-day न्यूनतम को बनाए रखता है लेकिन पहले-अपराध अधिकतम को 2 years तक बढ़ा देता है (सामान्य कार्गो के लिए 1 year के बजाय)। स्रोत: 49 CFR 383.51 Table 4, वर्जीनिया नियम के रूप में लागू; Virginia DMV CDL Disqualifications।"},"55":{"q":"वर्जीनिया कानून के तहत, एक CDL चालक जो एक CMV चलाते समय टेक्स्ट करता है या एक हैंडहेल्ड मोबाइल टेलीफोन का उपयोग करता है, उस पर एक नागरिक दंड लगाया जा सकता है जो इससे अधिक न हो:","options":["$250","$1,000","$2,750","$5,000"],"explanation":"Va. Code § 46.2-341.20:5 एक CMV चालक को टेक्स्ट करने या एक हैंडहेल्ड मोबाइल टेलीफोन का उपयोग करने से प्रतिबंधित करता है और $2,750 तक के नागरिक दंड को अधिकृत करता है; ऐसी दोषसिद्धि CDL प्रयोजनों के लिए एक गंभीर यातायात उल्लंघन भी है। स्रोत: Va. Code § 46.2-341.20:5; Virginia DMV CDL Disqualifications।"},"56":{"q":"वर्जीनिया में एक वाणिज्यिक मोटर वाहन संचालित करते समय टेक्स्टिंग के लिए दोषसिद्धि को CDL प्रयोजनों के लिए किस रूप में माना जाता है:","options":["प्रमुख अपराध (1-year अयोग्यता)","गंभीर यातायात उल्लंघन","आउट-ऑफ-सर्विस आदेश उल्लंघन","गैर-रिपोर्ट योग्य उल्लंघन"],"explanation":"एक CMV चलाते समय टेक्स्टिंग वर्जीनिया के गंभीर यातायात उल्लंघनों में सूचीबद्ध है, इसलिए बार-बार दोषसिद्धि 2-इन-3-years (60-day) और 3-इन-3-years (120-day) अयोग्यताओं की ओर गिनी जाती हैं। स्रोत: Virginia DMV CDL Disqualifications; Va. Code § 46.2-341.20:5; 49 CFR 383.51 Table 2।"},"57":{"q":"वर्जीनिया के सामान्य लापरवाह-ड्राइविंग-बाय-स्पीड कानून (एक आरोप जो एक CDL गंभीर उल्लंघन भी है) के तहत, सीमा से कितनी गति पर साधारण तेज गति 'लापरवाह ड्राइविंग' बन जाती है?","options":["सीमा से 10 mph अधिक","सीमा से 15 mph अधिक","सीमा से 20 mph अधिक, या 85 mph से अधिक कोई भी गति","सीमा से 25 mph अधिक, या 90 mph से अधिक कोई भी गति"],"explanation":"Va. Code § 46.2-862 गति द्वारा लापरवाह ड्राइविंग को सीमा से 20 mph या अधिक, या सीमा की परवाह किए बिना 85 mph से अधिक के रूप में परिभाषित करता है; लापरवाह ड्राइविंग एक CDL गंभीर यातायात उल्लंघन भी है (15-mph-अधिक गंभीर-उल्लंघन सीमा से अलग)। स्रोत: Va. Code § 46.2-862; Virginia DMV CDL Disqualifications।"},"58":{"q":"एक वर्जीनिया CDL धारक को एक नियंत्रित पदार्थ के निर्माण, वितरण, या वितरण से जुड़े एक गुनाह (felony) में एक CMV का उपयोग करने के लिए दोषी ठहराया जाता है। अयोग्यता क्या है?","options":["1 year","3 years","10 years","10-year पुनर्बहाली की संभावना के बिना आजीवन"],"explanation":"नियंत्रित पदार्थों के निर्माण, वितरण, या वितरण के लिए एक CMV का उपयोग करना एक प्रमुख अपराध है जो एक आजीवन अयोग्यता ले जाता है जो अन्य आजीवन अयोग्यताओं के लिए उपलब्ध 10-year पुनर्बहाली के लिए पात्र नहीं है। स्रोत: Virginia DMV CDL Disqualifications; 49 CFR 383.51 Table 1।"},"59":{"q":"वर्जीनिया में एक CMV DUI के लिए एक CDL धारक की अयोग्यता मुख्य रूप से किस ड्राइविंग विशेषाधिकार को प्रभावित करती है?","options":["केवल मोटरसाइकिल संचालित करने का विशेषाधिकार","वाणिज्यिक (CDL) ड्राइविंग विशेषाधिकार","केवल राज्य के बाहर ड्राइविंग विशेषाधिकार","नौका विहार और जलयान विशेषाधिकार"],"explanation":"CDL अयोग्यता वाणिज्यिक मोटर वाहनों को संचालित करने का विशेषाधिकार हटा देती है; एक अलग लाइसेंस निलंबन भी लागू हो सकता है, लेकिन अयोग्यता विशेष रूप से CDL/वाणिज्यिक ड्राइविंग विशेषाधिकार को लक्षित करती है। स्रोत: Virginia DMV CDL Disqualifications; Va. Code § 46.2-341.18।"},"60":{"q":"वर्जीनिया के 'मूव ओवर' कानून के अंतर्गत, किसी रुकी हुई, चमकती हुई आपातकालीन गाड़ी के लिए लेन बदलने का कर्तव्य लागू होने से पहले राजमार्ग में कितनी लेन (और किस विन्यास में) होनी चाहिए?","options":["कम से कम चार लेन, जिनमें कम से कम दो लेन चालक की दिशा में चलने वाले यातायात के लिए हों","कोई भी दो-लेन वाला अविभाजित राजमार्ग","कम से कम छह लेन, प्रत्येक दिशा में तीन","केवल चिह्नित इंटरस्टेट राजमार्गों पर"],"explanation":"Code of Virginia 46.2-861.1 (वर्जीनिया का 'मूव ओवर' कानून) में ऐसी सड़कों पर, जिनमें कम से कम चार लेन हों और जिनमें से दो लेन एक ही दिशा में यातायात ले जाती हों, चालकों से चमकती चेतावनी लाइट दिखा रही किसी स्थिर आपातकालीन गाड़ी से दूर लेन बदलने की अपेक्षा की जाती है; यदि सुरक्षित रूप से लेन बदलना संभव न हो, तो चालक को गति कम करनी होगी और सावधानी से आगे बढ़ना होगा। स्रोत: Code of Virginia 46.2-861.1।"},"61":{"q":"वर्जीनिया में, जब कोई चालक चमकती लाइट दिखा रही किसी रुकी हुई आपातकालीन गाड़ी से दूर सुरक्षित रूप से लेन नहीं बदल सकता, तो उसके बदले चालक को क्या करना चाहिए?","options":["सावधानी से आगे बढ़ें और चिह्नित सीमा से नीचे गति कम करें","जब तक आपातकालीन गाड़ी न चली जाए तब तक पूरी तरह रुकें","हॉर्न बजाएं और चिह्नित गति बनाए रखें","खतरे की फ्लैशर चालू करें और सामान्य गति से चलते रहें"],"explanation":"Code of Virginia 46.2-861.1 के अंतर्गत, यदि सुरक्षित रूप से लेन नहीं बदली जा सकती, तो चालक को उचित सावधानी से आगे बढ़ना होगा और राजमार्ग की स्थितियों के अनुसार सुरक्षित गति बनाए रखनी होगी, घटनास्थल पर मौजूद आपातकालीन कर्मियों की रक्षा के लिए गति कम करनी होगी। उल्लंघन को लापरवाह ड्राइविंग (Class 1 misdemeanor) के रूप में दर्ज किया जाता है। स्रोत: Code of Virginia 46.2-861.1।"},"62":{"q":"वर्जीनिया में, 'मूव ओवर' कानून का उल्लंघन (किसी रुकी हुई आपातकालीन गाड़ी के लिए लेन बदलने या गति कम करने में विफलता) को किस रूप में दर्ज किया जाता है?","options":["लापरवाह ड्राइविंग, एक Class 1 misdemeanor","एक गैर-गतिशील दीवानी उल्लंघन","बिना अंकों वाला एक साधारण यातायात उल्लंघन","यदि कोई चोट न हो तो एक felony"],"explanation":"Code of Virginia 46.2-861.1 किसी स्थिर आपातकालीन गाड़ी के लिए रास्ता देने या लेन बदलने में विफलता को लापरवाह ड्राइविंग का एक रूप बनाता है, जो एक Class 1 misdemeanor है जिसमें संभावित जेल समय, $2,500 तक का जुर्माना, और लाइसेंस निलंबन शामिल है। स्रोत: Code of Virginia 46.2-861.1।"},"63":{"q":"वर्जीनिया के गैर-सीमित-पहुंच (गैर-इंटरस्टेट) राजमार्गों पर, संपत्ति परिवहन के लिए डिज़ाइन किए गए ट्रैक्टर-ट्रेलर या ट्रक के लिए अधिकतम गति सीमा क्या है, यदि कोई चिह्नित अपवाद न हो?","options":["45 mph","55 mph","60 mph","65 mph"],"explanation":"Code of Virginia 46.2-870 गैर-सीमित-पहुंच राजमार्गों पर यात्री वाहनों और बसों के लिए डिफ़ॉल्ट सीमा 55 mph निर्धारित करता है, लेकिन संपत्ति परिवहन के लिए डिज़ाइन किए गए ट्रकों, ट्रैक्टर ट्रकों, और संयोजनों के लिए केवल 45 mph, यानी यात्री वाहनों से 10 mph कम। स्रोत: Code of Virginia 46.2-870।"},"64":{"q":"वर्जीनिया इंटरस्टेट राजमार्ग पर, जहां यातायात इंजीनियरिंग अध्ययन के बाद उच्च सीमा चिह्नित की गई है, वहां वाणिज्यिक ट्रक के लिए अधिकतम गति सीमा क्या है?","options":["70 mph, यात्री वाहनों के समान ही","55 mph, जबकि कारें 70 mph जा सकती हैं","केवल ट्रकों के लिए 65 mph","75 mph"],"explanation":"Code of Virginia 46.2-870 इंटरस्टेट अधिकतम सीमा 55 mph निर्धारित करता है, या जहां इंजीनियरिंग अध्ययन के बाद वैध रूप से चिह्नित संकेत लगाए गए हैं वहां 70 mph। इंटरस्टेट पर उच्च चिह्नित सीमा ट्रकों सहित सभी वाहनों पर लागू होती है; वर्जीनिया इंटरस्टेट पर ट्रकों के लिए अलग से कम गति सीमा नहीं लगाता। स्रोत: Code of Virginia 46.2-870।"},"65":{"q":"वर्जीनिया में रेलमार्ग ग्रेड क्रॉसिंग पर, चिह्नित खतरनाक-सामग्री वाली गाड़ी या किराए पर यात्रियों को ले जाने वाली बस को निकटतम रेल से कितनी दूरी के भीतर रुकना चाहिए?","options":["50 feet के भीतर लेकिन 15 feet से कम नहीं","100 feet के भीतर लेकिन 25 feet से कम नहीं","30 feet के भीतर लेकिन 10 feet से कम नहीं","15 feet के भीतर लेकिन 5 feet से कम नहीं"],"explanation":"Code of Virginia 46.2-886 किराए पर यात्रियों को ले जाने वाली या विस्फोटक पदार्थ या ज्वलनशील तरल पदार्थ को माल के रूप में ले जाने वाली गाड़ियों से निकटतम रेल से 50 feet के भीतर लेकिन 15 feet से कम नहीं की दूरी पर रुकने, फिर आगे बढ़ने से पहले देखने और सुनने की अपेक्षा करता है। यह Virginia CDL Manual के रेलमार्ग-क्रॉसिंग नियम से मेल खाता है। स्रोत: Code of Virginia 46.2-886; Virginia CDL Manual।"},"66":{"q":"रेलमार्ग क्रॉसिंग पर रुकने के बाद, गाड़ी के पटरियों पर होने के दौरान गियर बदलने के संबंध में वर्जीनिया कानून क्या अपेक्षा करता है?","options":["चालक को ऐसे गियर में पार करना चाहिए जिसमें पटरियों पर होने के दौरान गियर बदलने की आवश्यकता न हो","चालक को पार करने के बीच में सबसे निचले गियर में डाउनशिफ्ट करना चाहिए","जब तक गति बनी रहती है चालक स्वतंत्र रूप से शिफ्ट कर सकता है","चालक को पार करते समय न्यूट्रल में शिफ्ट करना चाहिए"],"explanation":"Code of Virginia 46.2-886 कहता है कि रुकने के बाद और आगे बढ़ते समय, चालक को केवल ऐसे गियर में पार करना चाहिए जिसमें क्रॉसिंग पार करते समय गियर बदलने की कोई आवश्यकता न हो, और पार करते समय गियर शिफ्ट नहीं करना चाहिए। स्रोत: Code of Virginia 46.2-886; Virginia CDL Manual।"},"67":{"q":"वर्जीनिया में, अविभाजित दो-लेन सड़क पर बच्चों को चढ़ाने या उतारने के लिए रुकी हुई स्कूल बस के पास आ रहे मोटर चालक को क्या करना चाहिए?","options":["किसी भी दिशा से आ रहे हों तो रुकें और तब तक रुके रहें जब तक बस आगे न बढ़े या चमकना बंद न कर दे","केवल तभी रुकें जब बस की दिशा में ही यात्रा कर रहे हों","20 mph तक गति कम करें लेकिन रुकने की आवश्यकता नहीं","केवल तभी रुकें जब बच्चे प्रत्यक्ष रूप से पार कर रहे हों"],"explanation":"Code of Virginia 46.2-859 किसी भी दिशा से आ रहे चालक से अपेक्षा करता है कि वह यात्रियों को चढ़ाने या उतारने के लिए रुकी हुई और अपनी चेतावनी उपकरण दिखा रही स्कूल बस के लिए रुके, और तब तक रुका रहे जब तक व्यक्ति दूर न हो जाएं और बस फिर से गति में न आ जाए। उल्लंघन लापरवाह ड्राइविंग है। स्रोत: Code of Virginia 46.2-859।"},"68":{"q":"वर्जीनिया के विभाजित राजमार्ग पर, किस स्थिति में विपरीत सड़क पर रुकी हुई स्कूल बस के लिए आ रहे चालक को रुकने की आवश्यकता नहीं है?","options":["जब सड़कें किसी भौतिक अवरोध या किसी कच्ची भूमि से अलग हों","जब बीच में दोहरी-पीली रेखा खींची हो","जब गति सीमा 45 mph या उससे अधिक हो","जब सड़कों के बीच एक केंद्रीय मोड़ लेन हो"],"explanation":"Code of Virginia 46.2-859 चालक को रुकने से केवल तभी छूट देता है जब स्कूल बस विभाजित राजमार्ग की दूसरी सड़क पर हो (या किसी एक्सेस रोड/ड्राइववे पर हो) जो चालक की सड़क से किसी भौतिक अवरोध या कच्ची भूमि द्वारा अलग हो। केवल खींची हुई रेखा या मोड़ लेन योग्य नहीं है। स्रोत: Code of Virginia 46.2-859।"},"69":{"q":"जब किसी वाणिज्यिक गाड़ी को वर्जीनिया राजमार्ग पर रुकना पड़े, तो चालक को रुकने के कितने मिनट के भीतर लाल परावर्तक त्रिकोण चेतावनी उपकरण रखने चाहिए?","options":["10 मिनट के भीतर","5 मिनट के भीतर","15 मिनट के भीतर","तुरंत, 1 मिनट के भीतर"],"explanation":"Code of Virginia 46.2-111 रुकी हुई वाणिज्यिक मोटर गाड़ी के संचालक से अपेक्षा करता है कि वह रुकने के 10 मिनट के भीतर आवश्यक लाल परावर्तक त्रिकोणीय चेतावनी उपकरण रखे, और उनके स्थान पर लगने तक खतरे की फ्लैशर चालू रखे। स्रोत: Code of Virginia 46.2-111।"},"70":{"q":"समतल, सीधी वर्जीनिया सड़क पर रुकी हुई वाणिज्यिक गाड़ी के लिए, तीन चेतावनी त्रिकोण कहां रखे जाने चाहिए?","options":["पीछे की ओर 100 ft, आगे की ओर 100 ft, और एक यातायात की ओर गाड़ी के 10 ft के भीतर","10 ft, 100 ft, और 200 ft सभी पीछे की ओर","केवल पीछे की ओर 50 ft, 100 ft, और 150 ft","प्रत्येक तरफ एक और एक छत पर"],"explanation":"Code of Virginia 46.2-111 एक त्रिकोण को आ रहे यातायात की दिशा में 100 feet से कम नहीं, एक को विपरीत दिशा में 100 feet से कम नहीं, और एक को यातायात की ओर गाड़ी के आगे या पीछे 10 feet से अधिक नज़दीक नहीं रखने का निर्देश देता है। स्रोत: Code of Virginia 46.2-111।"},"71":{"q":"यदि कोई वर्जीनिया वाणिज्यिक गाड़ी किसी मोड़, पहाड़ी की चोटी, या अन्य अवरोध के 500 feet के भीतर रुकी हो, तो उस दिशा में चेतावनी उपकरण कैसे रखा जाना चाहिए?","options":["पर्याप्त चेतावनी देने के लिए काफी दूर, लेकिन किसी भी स्थिति में गाड़ी से 500 feet से कम नहीं","गाड़ी से ठीक 100 feet","गाड़ी से 200 feet से अधिक दूर नहीं","सीधे अवरोध पर ही"],"explanation":"Code of Virginia 46.2-111 अपेक्षा करता है कि जहां रुकाव किसी मोड़, पहाड़ी की चोटी, या अन्य अवरोध के 500 feet के भीतर हो, वहां उस दिशा में चेतावनी उपकरण पर्याप्त चेतावनी देने के लिए रखा जाए, किसी भी स्थिति में रुकी हुई गाड़ी से 500 feet से कम नहीं। स्रोत: Code of Virginia 46.2-111।"},"72":{"q":"वर्जीनिया के Interstate 81 पर और प्रत्येक दिशा में दो से अधिक लेन वाले इंटरस्टेट पर, वाणिज्यिक मोटर गाड़ियों पर कौन सा लेन प्रतिबंध लागू होता है?","options":["उन्हें सबसे बाईं लेन में चलाने से प्रतिबंधित किया जाता है","वे केवल सबसे बाईं लेन का उपयोग कर सकते हैं","उन्हें ट्रक न्यूनतम गति के 10 mph के भीतर रहना चाहिए","वे केवल केंद्रीय लेन तक सीमित हैं"],"explanation":"Code of Virginia 46.2-803.1 वाणिज्यिक मोटर गाड़ियों को I-81 पर और प्रत्येक दिशा में दो से अधिक यात्रा लेन वाले इंटरस्टेट राजमार्गों (आमतौर पर जहां सीमा 65 mph या उससे अधिक हो) पर सबसे बाईं लेन में चलाने से प्रतिबंधित करता है। बसों और बाईं ओर निकास की तैयारी कर रही गाड़ियों को छूट है। स्रोत: Code of Virginia 46.2-803.1।"},"73":{"q":"वर्जीनिया के लेन वाले राजमार्ग पर, यातायात की सामान्य गति से धीमी चल रही किसी भी गाड़ी को कहां चलाया जाना चाहिए?","options":["दाएं किनारे या दाएं कर्ब के निकटतम लेन में, सिवाय इसके कि जब आगे निकल रहे हों या बाएं मुड़ने की तैयारी कर रहे हों","चालक द्वारा चुनी गई किसी भी लेन में","यातायात को संतुलित करने के लिए केंद्रीय लेन में","विलयन यातायात से दूर रहने के लिए बाईं लेन में"],"explanation":"Code of Virginia 46.2-804 यातायात की सामान्य गति से धीमी चल रही गाड़ी से दाएं किनारे या कर्ब के निकटतम लेन में चलने की अपेक्षा करता है, सिवाय इसके कि जब आगे निकल रहे हों और पास कर रहे हों, बाएं मोड़ की तैयारी कर रहे हों, या जहां दाईं लेन धीमे यातायात के लिए आरक्षित हों। स्रोत: Code of Virginia 46.2-804।"},"74":{"q":"वर्जीनिया के कौन से दर्शनीय पार्कवे आमतौर पर वाणिज्यिक ट्रकों को उन पर चलने से प्रतिबंधित करते हैं?","options":["George Washington Memorial Parkway और Colonial Parkway","Interstate 95 और Interstate 64","Capital Beltway (I-495)","U.S. Route 29 और U.S. Route 58"],"explanation":"वर्जीनिया में संघीय रूप से प्रशासित George Washington Memorial Parkway और Colonial Parkway वाणिज्यिक ट्रकों को प्रतिबंधित करते हैं; GW Parkway किसी भी वाणिज्यिक गाड़ी के लिए विशेष National Park Service परमिट की अपेक्षा करता है, और Colonial Parkway यात्री बसों को छोड़कर ट्रकों को रोकता है। स्रोत: National Park Service / VDOT ट्रक-प्रतिबंध मार्गदर्शन।"},"75":{"q":"कुछ खतरनाक-सामग्री वर्गों को वर्जीनिया की पानी-निकटवर्ती सुरंगों जैसे Hampton Roads Bridge-Tunnel से प्रतिबंधित किया जाता है। इन प्रतिबंधों को क्या नियंत्रित करता है?","options":["ब्रिज-टनल सुविधाओं के माध्यम से खतरनाक सामग्री को नियंत्रित करने वाले VDOT नियम (24VAC30-61), खतरा वर्ग के आधार पर","केवल संघीय इंटरस्टेट वजन सीमाएं","केवल गाड़ी की सकल संयोजन वजन रेटिंग","क्या माल बीमाकृत है"],"explanation":"वर्जीनिया प्रशासनिक नियम 24VAC30-61 राज्य की शहरी और पानी-निकटवर्ती सुरंगों (Hampton Roads, Monitor-Merrimac, और Elizabeth River सुरंगें) के माध्यम से खतरनाक सामग्री के परिवहन को नियंत्रित करता है, विस्फोटक और जहरीली गैसों जैसे कुछ खतरा वर्गों को प्रतिबंधित करता है। स्रोत: 24VAC30-61; VDOT Hazardous Materials मार्गदर्शन।"},"76":{"q":"वर्जीनिया में Interstate 77 पर खड़ी Fancy Gap ढलान से उतर रहे दक्षिण की ओर जा रहे ट्रकों को किस सुरक्षा सुविधा के बारे में विशेष रूप से जागरूक होना चाहिए?","options":["लंबी ढलान पर कई भगोड़ा-ट्रक बचाव रैंप","शिखर पर एक अनिवार्य ट्रक वजन स्टेशन","एक सुरंग जो सभी ट्रकों को प्रतिबंधित करती है","एक उत्क्रमणीय HOV लेन"],"explanation":"Interstate 77 Fancy Gap पर 1,500 feet से अधिक ऊपर चढ़ता है, जहां ढलान लगभग 4.5% तक होती है; North Carolina में लंबी दक्षिण-दिशा वाली उतराई में ब्रेक खो देने वाली गाड़ियों के लिए कई भगोड़ा-ट्रक बचाव रैंप शामिल हैं। चालकों को उतरने से पहले निचला गियर चुनना चाहिए। स्रोत: VDOT/Virginia CDL Manual पर्वतीय-ड्राइविंग मार्गदर्शन।"},"77":{"q":"वर्जीनिया में, न्यूनतम-गति नियम कहता है कि चालक इतनी धीमी गति से नहीं चलाएगा कि क्या हो?","options":["यातायात की सामान्य और उचित गति में बाधा डाले या रोके, सिवाय इसके कि जब सुरक्षा या कानून के लिए कम गति आवश्यक हो","किसी भी राजमार्ग पर 40 mph से नीचे यात्रा करे","चिह्नित सीमा से 5 mph से अधिक नीचे गिरे","अन्य चालकों को अपने हॉर्न का उपयोग करने पर मजबूर करे"],"explanation":"Code of Virginia 46.2-877 इतनी धीमी गति से चलाने को प्रतिबंधित करता है जो यातायात की सामान्य और उचित गति में बाधा डाले, सिवाय इसके कि जब सुरक्षित संचालन के लिए या कानून का पालन करने के लिए कम गति आवश्यक हो। स्रोत: Code of Virginia 46.2-877।"},"78":{"q":"चार-लेन की आवश्यकता के अलावा, वर्जीनिया का 'मूव ओवर' कर्तव्य निम्नलिखित में से किसके द्वारा संचालित, चेतावनी लाइट दिखा रही स्थिर गाड़ियों पर लागू होता है?","options":["पुलिस, अग्निशमन, एम्बुलेंस, VDOT, उपयोगिता, और टो ट्रक","केवल पुलिस और एम्बुलेंस","केवल राज्य पुलिस गश्ती गाड़ियां","केवल VDOT के स्वामित्व वाली गाड़ियां"],"explanation":"Code of Virginia 46.2-861.1 'मूव ओवर' कर्तव्य को चमकती चेतावनी लाइट दिखा रही स्थिर गाड़ियों के एक व्यापक समूह तक विस्तारित करता है, जिसमें कानून-प्रवर्तन, अग्निशमन, एम्बुलेंस, Virginia Department of Transportation, उपयोगिता, और टोइंग/रिकवरी गाड़ियां शामिल हैं। स्रोत: Code of Virginia 46.2-861.1।"},"79":{"q":"लापरवाह ड्राइविंग के एक कम विकल्प के रूप में, वर्जीनिया कानून रुकी हुई स्कूल बस को पार करने के उल्लंघन को कितनी राशि के दीवानी दंड के रूप में लागू करने की अनुमति देता है, जिसमें गाड़ी का मालिक संभावित रूप से उत्तरदायी हो सकता है?","options":["$250","$50","$1,000","$2,500"],"explanation":"Code of Virginia 46.2-844 रुकी हुई स्कूल बस के लिए रुकने में विफलता हेतु $250 का दीवानी-दंड विकल्प प्रदान करता है, और जब बस की वीडियो-निगरानी प्रणाली उल्लंघन को कैद करती है तो गाड़ी का पंजीकृत मालिक उत्तरदायी ठहराया जा सकता है। 46.2-859 के अंतर्गत आपराधिक अपराध लापरवाह ड्राइविंग बना रहता है। स्रोत: Code of Virginia 46.2-844 और 46.2-859।"},"80":{"q":"वर्जीनिया में वाणिज्यिक चालक लाइसेंस (CDL) कौन सी एजेंसी जारी करती है?","options":["Virginia Department of Motor Vehicles (DMV)","Federal Motor Carrier Safety Administration (FMCSA)","Virginia Department of Transportation (VDOT)","Virginia State Police Motor Carrier Division"],"explanation":"वर्जीनिया में CDL Virginia Department of Motor Vehicles (DMV) द्वारा जारी किए जाते हैं। FMCSA संघीय मानक निर्धारित करता है लेकिन लाइसेंस जारी नहीं करता, और VDOT सड़कें/परमिट संभालता है, लाइसेंसिंग नहीं। स्रोत: Virginia DMV, Apply for a CDL or CLP।"},"81":{"q":"वर्जीनिया CDL या वाणिज्यिक शिक्षार्थी परमिट (CLP) के लिए आवेदन करने के लिए आपको कहां जाना होगा?","options":["DMV ग्राहक सेवा केंद्र में व्यक्तिगत रूप से","DMV वेबसाइट के माध्यम से पूरी तरह ऑनलाइन","किसी भी FMCSA-अनुमोदित ट्रक डीलरशिप पर","Richmond में DMV मुख्यालय को डाक द्वारा"],"explanation":"वर्जीनिया में आपको CDL या CLP के लिए DMV ग्राहक सेवा केंद्र में व्यक्तिगत रूप से आवेदन करना होगा; प्रारंभिक CDL/CLP आवेदन पूरी तरह ऑनलाइन पूरा नहीं किया जा सकता। स्रोत: Virginia DMV, Apply for a CDL or CLP।"},"82":{"q":"संघीय नियम वर्जीनिया में प्रत्येक CDL या CLP आवेदक से वाणिज्यिक मोटर गाड़ी संचालन की कितनी श्रेणियों के लिए स्व-प्रमाणन की अपेक्षा करते हैं?","options":["चार","दो","तीन","पांच"],"explanation":"वर्जीनिया में CDL/CLP धारण करने या आवेदन करने वाले किसी भी व्यक्ति को CMV संचालन की चार श्रेणियों में से एक के लिए स्व-प्रमाणन करना होगा। स्रोत: Virginia DMV, CDL Medical Certification Requirements।"},"83":{"q":"निम्नलिखित में से कौन सी Virginia DMV द्वारा उपयोग की जाने वाली चार स्व-प्रमाणन श्रेणियों में से एक है?","options":["Non-excepted Interstate (NI)","Restricted Commercial Operation","Intrastate Hazmat Only","Federal Excepted Carrier"],"explanation":"चार श्रेणियां हैं Excepted Interstate (EI), Excepted Intrastate (EA), Non-excepted Interstate (NI), और Non-excepted Intrastate (NA)। 'Non-excepted Interstate' एक वैध श्रेणी है; सूचीबद्ध अन्य नहीं हैं। स्रोत: Virginia DMV, CDL Medical Certification Requirements।"},"84":{"q":"किस स्व-प्रमाणन श्रेणी में आमतौर पर चालक को Virginia DMV के पास एक चिकित्सा परीक्षक का प्रमाणपत्र फाइल पर रखने की आवश्यकता नहीं होती?","options":["Excepted Interstate (EI)","Non-excepted Interstate (NI)","Non-excepted Intrastate (NA)","कोई भी इंटरस्टेट श्रेणी"],"explanation":"अपवादित श्रेणियों (excepted interstate या excepted intrastate) के लिए प्रमाणन करने वाले चालकों को चिकित्सा परीक्षक का प्रमाणपत्र प्रदान करने की आवश्यकता नहीं है; केवल non-excepted interstate और non-excepted intrastate चालकों को ही करना होगा। स्रोत: Virginia DMV, CDL Medical Certification Requirements।"},"85":{"q":"वर्जीनिया में non-excepted interstate के रूप में स्व-प्रमाणन करने वाले चालक का शारीरिक परीक्षण ऐसे चिकित्सा परीक्षक द्वारा किया जाना चाहिए जो:","options":["FMCSA's National Registry of Certified Medical Examiners पर सूचीबद्ध हो","Virginia DMV द्वारा सीधे नियोजित हो","Virginia Department of Health द्वारा अनुमोदित हो","चालक की पसंद का कोई भी लाइसेंस प्राप्त चिकित्सक हो"],"explanation":"Non-excepted चालकों का परीक्षण FMCSA's National Registry of Certified Medical Examiners पर सूचीबद्ध किसी चिकित्सा परीक्षक द्वारा किया जाना चाहिए। हर लाइसेंस प्राप्त चिकित्सक योग्य नहीं है। स्रोत: Virginia DMV, CDL Medical Certification Requirements।"},"86":{"q":"May 5, 2025 से प्रभावी, Medical Examiner's Certificate (MEC) को Virginia DMV को कैसे प्रस्तुत किया जाना चाहिए?","options":["चिकित्सा परीक्षक द्वारा FMCSA National Registry portal के माध्यम से इलेक्ट्रॉनिक रूप से","चालक द्वारा कागज़ी प्रमाणपत्र को DMV कार्यालय में लाकर","चालक द्वारा एक स्कैन की गई प्रति DMV वेबसाइट पर अपलोड करके","चालक के नियोक्ता द्वारा इसे FMCSA को फैक्स करके"],"explanation":"May 5, 2025 से, Virginia DMV अब चालकों से सीधे MEC स्वीकार नहीं करता; चिकित्सा परीक्षक को FMCSA National Registry portal के माध्यम से प्रमाणपत्र इलेक्ट्रॉनिक रूप से प्रस्तुत करना होगा। स्रोत: Virginia DMV, CDL Medical Certification Requirements।"},"87":{"q":"वर्जीनिया CLP प्राप्त करने के लिए, आवेदक को कम से कम कौन सी ज्ञान परीक्षा उत्तीर्ण करनी चाहिए?","options":["CDL सामान्य ज्ञान परीक्षा","केवल संयोजन गाड़ी परीक्षा","केवल एयर ब्रेक परीक्षा","खतरनाक सामग्री परीक्षा"],"explanation":"CLP प्राप्त करने के लिए आपको CDL सामान्य ज्ञान परीक्षा उत्तीर्ण करनी होगी, साथ ही उन गाड़ियों के लिए कोई भी अतिरिक्त ज्ञान परीक्षा (जैसे एयर ब्रेक या टैंक) जिन्हें आप चलाने का इरादा रखते हैं। स्रोत: Virginia DMV, Commercial Learner's Permit।"},"88":{"q":"वर्जीनिया CLP जारी होने के बाद, CDL कौशल परीक्षा देने के योग्य होने से पहले आपको इसे कितने समय तक धारण करना होगा?","options":["कम से कम 14 days","कम से कम 30 days","कम से कम 7 days","कम से कम 60 days"],"explanation":"वर्जीनिया कौशल परीक्षा देने से पहले न्यूनतम 14-day CLP धारण अवधि की अपेक्षा करता है। पूर्व CDL या Entry-Level Driver Training पूरा करने के प्रमाण के साथ इसे माफ किया जा सकता है। स्रोत: Virginia DMV, CDL Skills Test Eligibility / Commercial Learner's Permit।"},"89":{"q":"वर्जीनिया वाणिज्यिक शिक्षार्थी परमिट (CLP) कितने समय के लिए वैध है, और क्या इसे नवीनीकृत किया जा सकता है?","options":["1 year के लिए वैध और नवीनीकृत नहीं किया जा सकता","180 days के लिए वैध और एक बार नवीनीकृत किया जा सकता है","2 years के लिए वैध और प्रतिवर्ष नवीनीकृत","6 months के लिए वैध और असीमित नवीनीकरण के साथ"],"explanation":"वर्जीनिया CLP 1 year के लिए वैध है और इसे नवीनीकृत नहीं किया जा सकता; यदि यह समाप्त हो जाता है तो आपको फिर से आवेदन करना होगा और फिर से परीक्षा देनी होगी। स्रोत: Virginia DMV, Commercial Learner's Permit।"},"90":{"q":"वर्जीनिया CDL कौशल परीक्षा किन तीन भागों से मिलकर बनती है, जो क्रम में किए जाते हैं?","options":["यात्रा-पूर्व निरीक्षण, बुनियादी गाड़ी नियंत्रण, और सड़क पर ड्राइविंग","लिखित ज्ञान, दृष्टि जांच, और सड़क परीक्षा","एयर ब्रेक जांच, बैकिंग, और राजमार्ग विलयन","कपलिंग/अनकपलिंग, समानांतर पार्किंग, और रात्रि ड्राइविंग"],"explanation":"CDL कौशल परीक्षा के तीन भाग हैं: यात्रा-पूर्व गाड़ी निरीक्षण, बुनियादी गाड़ी नियंत्रण कौशल, और सड़क पर ड्राइविंग परीक्षा, जो उसी क्रम में दी जाती हैं। स्रोत: वर्जीनिया में लागू FMCSA CDL मानक; Virginia DMV CDL Skills Tests।"},"91":{"q":"वर्जीनिया CDL सड़क-पर ड्राइविंग परीक्षा के लिए उपयोग की जाने वाली गाड़ी कौन प्रदान करे?","options":["आवेदक, जिसे उस प्रकार की ठीक से पंजीकृत गाड़ी लानी होगी जिसे वह चलाना चाहता है","Virginia DMV, जो एक परीक्षण ट्रक प्रदान करता है","केवल आवेदक का ELDT प्रशिक्षण स्कूल","FMCSA, अपने क्षेत्रीय निरीक्षण बेड़े से"],"explanation":"आवेदक को सड़क-पर परीक्षा के लिए उस CDL की श्रेणी/प्रकार का प्रतिनिधित्व करने वाली ठीक से पंजीकृत गाड़ी प्रदान करनी होगी जिसकी वह मांग कर रहा है। स्रोत: Virginia DMV, CDL Skills Test Eligibility।"},"92":{"q":"वर्जीनिया में लागू होने वाली संघीय Entry-Level Driver Training (ELDT) आवश्यकता कब प्रभावी हुई?","options":["February 7, 2022","May 5, 2025","January 1, 2020","July 1, 2023"],"explanation":"ELDT आवश्यकताएं February 7, 2022 को प्रभावी हुईं। (May 5, 2025 इलेक्ट्रॉनिक MEC प्रस्तुति परिवर्तन के लिए अलग तिथि है।) स्रोत: Virginia DMV, Entry-Level Driver Training।"},"93":{"q":"वर्जीनिया CDL आवेदक द्वारा उपयोग किया जाने वाला ELDT प्रशिक्षण प्रदाता होना चाहिए:","options":["FMCSA's Training Provider Registry (TPR) पर सूचीबद्ध","केवल Virginia DMV द्वारा प्रमाणित","Virginia Board of Education द्वारा मान्यता प्राप्त","व्यवसाय लाइसेंस वाला कोई भी वाणिज्यिक ड्राइविंग स्कूल"],"explanation":"ELDT को FMCSA's Training Provider Registry (TPR) पर सूचीबद्ध प्रदाता के माध्यम से पूरा किया जाना चाहिए। एक सामान्य व्यवसाय लाइसेंस या राज्य-बोर्ड मान्यता पर्याप्त नहीं है। स्रोत: Virginia DMV, Entry-Level Driver Training।"},"94":{"q":"वर्जीनिया में पहली बार Class A या B आवेदक के लिए, ELDT सिद्धांत और पहिए-के-पीछे प्रशिक्षण कब पूरा किया जाना चाहिए?","options":["सड़क कौशल परीक्षा देने से पहले","CLP के लिए आवेदन करने से पहले","कौशल परीक्षा उत्तीर्ण करने के 30 days के भीतर","सामान्य ज्ञान परीक्षा देने से पहले"],"explanation":"CDL श्रेणियों (और P/S endorsements) के लिए, ELDT सिद्धांत और पहिए-के-पीछे प्रशिक्षण सड़क कौशल परीक्षा से पहले पूरा किया जाना चाहिए। (HazMat के लिए, सिद्धांत भाग HazMat ज्ञान परीक्षा से पहले किया जाना चाहिए।) स्रोत: Virginia DMV, Entry-Level Driver Training।"},"95":{"q":"वर्जीनिया में खतरनाक सामग्री (H) endorsement के लिए, ELDT सिद्धांत भाग किससे पहले पूरा किया जाना चाहिए:","options":["HazMat ज्ञान परीक्षा देने से","सड़क-पर कौशल परीक्षा देने से","स्व-प्रमाणन फॉर्म प्रस्तुत करने से","CLP जारी होने से"],"explanation":"CDL श्रेणी प्रशिक्षण के विपरीत, HazMat ELDT सिद्धांत भाग HazMat ज्ञान परीक्षा देने से पहले पूरा किया जाना चाहिए (कोई अलग HazMat कौशल परीक्षा नहीं है)। स्रोत: Virginia DMV, Entry-Level Driver Training।"},"96":{"q":"इंट्रास्टेट वर्जीनिया CDL बनाम इंटरस्टेट CDL प्राप्त करने के लिए न्यूनतम आयु क्या है?","options":["इंट्रास्टेट के लिए 18 और इंटरस्टेट के लिए 21","इंट्रास्टेट के लिए 21 और इंटरस्टेट के लिए 25","इंट्रास्टेट के लिए 16 और इंटरस्टेट के लिए 18","इंट्रास्टेट और इंटरस्टेट दोनों के लिए 18"],"explanation":"इंट्रास्टेट CDL प्राप्त करने के लिए आपकी आयु कम से कम 18 और इंटरस्टेट CDL प्राप्त करने के लिए कम से कम 21 होनी चाहिए। स्रोत: Virginia DMV, CDL Skills Test Eligibility / Apply for a CDL or CLP।"},"97":{"q":"वर्जीनिया में CDL के लिए आवेदन करने वाला व्यक्ति जिसने कभी वर्जीनिया चालक लाइसेंस या ID धारण नहीं किया, उसे निम्नलिखित में से किसके दो प्रमाण प्रदान करने होंगे?","options":["वर्जीनिया निवास","Social Security number","वैध उपस्थिति","पहचान"],"explanation":"पहली बार वर्जीनिया आवेदकों को एक पहचान प्रमाण, एक वैध उपस्थिति प्रमाण, एक Social Security number प्रमाण, और दो वर्जीनिया निवास प्रमाण प्रस्तुत करने होंगे। स्रोत: Virginia DMV, Apply for a CDL or CLP।"},"98":{"q":"अधिकांश चालकों के लिए, एक मानक वर्जीनिया CDL नवीनीकृत किए जाने से पहले कितने समय तक वैध है?","options":["8 years, धारक के जन्मदिन पर समाप्त होता है","4 years, धारक के जन्मदिन पर समाप्त होता है","5 years, वर्ष के अंत में समाप्त होता है","10 years, जारी-तिथि वर्षगांठ पर समाप्त होता है"],"explanation":"एक मानक वर्जीनिया CDL 8 years के लिए वैध है और धारक के जन्मदिन पर समाप्त होता है (75 वर्ष या उससे अधिक आयु के चालकों को 5-year चक्र मिलता है)। स्रोत: Virginia DMV, Renew Your CDL।"},"99":{"q":"वर्जीनिया में, यदि कोई CDL एक वर्ष से अधिक समय से समाप्त या डाउनग्रेड हो गया है, तो धारक को इसे वापस पाने के लिए क्या करना होगा?","options":["उस CDL प्रकार के लिए ज्ञान परीक्षा और सड़क कौशल परीक्षा दोनों फिर से देनी होगी","बस एक विलंब शुल्क का भुगतान करें और ऑनलाइन नवीनीकृत करें","केवल दृष्टि जांच फिर से दें","केवल एक अतिरिक्त 14-day धारण अवधि की प्रतीक्षा करें"],"explanation":"यदि कोई वर्जीनिया CDL एक वर्ष से अधिक समय से समाप्त या डाउनग्रेड हो गया है, तो धारक को उस प्रकार के CDL के लिए आवश्यक ज्ञान परीक्षा और सड़क कौशल परीक्षा फिर से देनी होगी जो उसके पास था। स्रोत: Virginia DMV, Renew Your CDL।"}},"ar":{"0":{"q":"ما هو الحد الأقصى لإجمالي العرض الخارجي المسموح به لمركبة وحمولتها على الطرق السريعة في فرجينيا (باستثناء المرايا)؟","options":["96 inches","100 inches","102 inches","108 inches"],"explanation":"يحدد قانون فرجينيا 46.2-1105 الحد الأقصى لإجمالي العرض الخارجي للمركبة، بما في ذلك أي حمولة، بـ 102 inches (8 feet 6 inches)، باستثناء المرايا وبعض أجهزة التحذير الخاصة بحافلات المدارس. المصدر: Code of Virginia 46.2-1105؛ Virginia CDL Manual / DMV 109."},"1":{"q":"ما هو الحد الأقصى للارتفاع المسموح به لمركبة محملة أو غير محملة على الطرق السريعة في فرجينيا؟","options":["13 feet","13 feet 6 inches","14 feet","12 feet 6 inches"],"explanation":"يحظر قانون فرجينيا 46.2-1110 على أي مركبة محملة أو غير محملة تجاوز ارتفاع 13 feet 6 inches. المصدر: Code of Virginia 46.2-1110؛ Virginia DMV 109."},"2":{"q":"على الطرق السريعة في فرجينيا، ما هو الحد الأقصى المسموح به لوزن المحور الفردي؟","options":["18,000 pounds","20,000 pounds","22,400 pounds","24,000 pounds"],"explanation":"يحدد قانون فرجينيا 46.2-1124 وزن المحور الفردي لأي مركبة أو تركيبة بـ 20,000 pounds. المصدر: Code of Virginia 46.2-1124؛ Virginia DMV 109."},"3":{"q":"ما هو الحد الأقصى المسموح به لوزن المحور المزدوج على الطرق السريعة في فرجينيا؟","options":["32,000 pounds","34,000 pounds","36,000 pounds","40,000 pounds"],"explanation":"يحدد قانون فرجينيا 46.2-1125 وزن المحور المزدوج لأي مركبة أو تركيبة بـ 34,000 pounds. المصدر: Code of Virginia 46.2-1125؛ Virginia DMV 109."},"4":{"q":"ما هو الحد الأقصى للوزن الإجمالي، بغض النظر عن تباعد المحاور، المسموح به على الطرق السريعة بين الولايات في فرجينيا؟","options":["73,280 pounds","76,000 pounds","80,000 pounds","90,000 pounds"],"explanation":"يحظر قانون فرجينيا 46.2-1127 وزناً إجمالياً، بغض النظر عن تباعد المحاور، يتجاوز 80,000 pounds على الطرق السريعة بين الولايات في الكومنولث. المصدر: Code of Virginia 46.2-1127."},"5":{"q":"على الطرق السريعة بين الولايات في فرجينيا، فإن حدود وزن المحور الفردي والمحور المزدوج هي، على التوالي:","options":["20,000 lb and 34,000 lb","18,000 lb and 32,000 lb","22,000 lb and 36,000 lb","20,000 lb and 40,000 lb"],"explanation":"يحدد قانون فرجينيا 46.2-1127 حد المحور الفردي بين الولايات بـ 20,000 pounds وحد المحور المزدوج بـ 34,000 pounds، بما يتطابق مع حدود الطرق السريعة العامة. المصدر: Code of Virginia 46.2-1127."},"6":{"q":"ما هو الحد الأقصى لطول نصف المقطورة الفردية المشغّلة في تركيبة جرار-شاحنة/نصف مقطورة على الطرق السريعة في فرجينيا بشكل عام؟","options":["45 feet","48 feet","53 feet","57 feet"],"explanation":"يحدد قانون فرجينيا 46.2-1112 نصف المقطورة في تركيبة جرار-شاحنة/نصف مقطورة بـ 48 feet، رغم أنه يُسمح بنصف المقطورات بطول 53 feet على نظام الطرق بين الولايات وبعض الطرق السريعة المؤهلة. المصدر: Code of Virginia 46.2-1112؛ إرشادات النقل الخاصة بـ Virginia DMV."},"7":{"q":"على نظام الطرق بين الولايات في فرجينيا، يُسمح لنصف المقطورة بطول أقصى يصل إلى:","options":["48 feet","50 feet","53 feet","60 feet"],"explanation":"بموجب قانون فرجينيا 46.2-1112، يُسمح بنصف المقطورات بطول يصل إلى 53 feet على نظام الطرق بين الولايات (والطرق السريعة المؤهلة) عندما لا تتجاوز المسافة من مسمار الملك إلى المحور الخلفي الأقصى الحد المقرر؛ والأساس على الطرق السريعة العامة هو 48 feet. المصدر: Code of Virginia 46.2-1112."},"8":{"q":"في تركيبة المقطورة المزدوجة (التوأم) على الطرق السريعة في فرجينيا، ما هو الحد الأقصى لطول كل مقطورة أو نصف مقطورة فردية؟","options":["27 feet","28 feet","28 1/2 feet","30 feet"],"explanation":"ينص قانون فرجينيا 46.2-1112 على أنه لا يجوز لأي نصف مقطورة أو مقطورة فردية في تركيبة أن تتجاوز 28 1/2 feet في الطول. المصدر: Code of Virginia 46.2-1112؛ Virginia DMV 109."},"9":{"q":"ما هو الحد الأقصى العام لطول تركيبة مركبة/مقطورة مقترنة على الطرق السريعة في فرجينيا (باستثناء الاستثناءات الخاصة بالجرار-نصف المقطورة)؟","options":["60 feet","65 feet","70 feet","75 feet"],"explanation":"يحدد قانون فرجينيا 46.2-1112 حداً أقصى عاماً قدره 65 feet للمركبات المقترنة (المركبة)، مع استثناءات محددة لتركيبات الجرار-نصف المقطورة على الطرق السريعة المخصصة. المصدر: Code of Virginia 46.2-1112."},"10":{"q":"على الطرق السريعة في فرجينيا، ما هو الحد الأقصى لطول مركبة آلية فردية (شاحنة مستقيمة/أحادية الوحدة، بخلاف الحافلات والمنازل المتنقلة)؟","options":["35 feet","40 feet","45 feet","48 feet"],"explanation":"يحظر قانون فرجينيا 46.2-1112 تشغيل مركبة آلية فردية يزيد طولها عن 40 feet على الطريق السريع (الحافلات والمنازل المتنقلة لها أحكام منفصلة). المصدر: Code of Virginia 46.2-1112؛ إرشادات النقل الخاصة بـ Virginia DMV."},"11":{"q":"كيف تحدد فرجينيا الحد الأقصى المسموح به للوزن الإجمالي بموجب صيغة الجسر الخاصة بها (القانون 46.2-1126)؟","options":["بناءً على الوزن المسجل في سند ملكية المركبة فقط","بناءً على عدد المحاور والمسافة بين المحور الأول والأخير","بناءً على قوة حصان المحرك وتصنيف الإطارات","بناءً على إجمالي حجم البضائع بالأقدام المكعبة"],"explanation":"يوفر قانون فرجينيا 46.2-1126 جدولاً (صيغة الجسر الفيدرالية كما هي مطبقة في فرجينيا) يحدد الحد الأقصى للوزن الإجمالي بناءً على عدد المحاور والمسافة بين المحورين الطرفيين (الأول والأخير). المصدر: Code of Virginia 46.2-1126."},"12":{"q":"بموجب جدول الوزن الإجمالي في فرجينيا (القانون 46.2-1126)، ما هو أعلى وزن إجمالي يسمح به الجدول بغض النظر عن مدى ملاءمة تباعد المحاور؟","options":["76,000 pounds","80,000 pounds","84,000 pounds","88,000 pounds"],"explanation":"يحدد جدول قانون فرجينيا 46.2-1126 سقف الحد الأقصى للوزن الإجمالي عند 80,000 pounds (القيمة العليا، المطبقة على مركبة بسبعة محاور عند التباعد الكامل)؛ كما أن 80,000 pounds هو السقف القانوني المطلق بموجب 46.2-1127. المصدر: Code of Virginia 46.2-1126 and 46.2-1127."},"13":{"q":"ما الذي يجب أن تفعله الشاحنة التي لا تزال أبعادها، بعد تقليصها إلى أصغر تكوين عملي، تتجاوز الحدود القانونية للحجم أو الوزن في فرجينيا قبل السفر على الطرق السريعة في فرجينيا؟","options":["دفع غرامة ثابتة للحمولة الزائدة عند محطة الوزن التالية","الحصول على تصريح نقل (للحجم/الوزن الزائد) مسبقاً","تسجيل المركبة كمركبة زراعية","السفر فقط بين منتصف الليل والساعة 5 a.m."],"explanation":"تشترط فرجينيا أنه إذا كانت المركبة، بعد تقليصها إلى أصغر أبعادها العملية، لا تزال تتجاوز الحدود القانونية، فيجب على المشغّل الحصول على تصريح نقل قبل السفر على الطرق السريعة في الكومنولث. المصدر: Virginia Code Article 18 (46.2-1139 et seq.)؛ Virginia DMV Hauling Permits."},"14":{"q":"أي جهة في فرجينيا تصدر تصاريح النقل للحجم/الوزن الزائد؟","options":["شرطة ولاية فرجينيا","إدارة النقل في فرجينيا فقط","إدارة المركبات الآلية في فرجينيا (Virginia Department of Motor Vehicles)","مكتب عمدة المقاطعة المحلي"],"explanation":"تصدر إدارة المركبات الآلية في فرجينيا (Virginia Department of Motor Vehicles) تصاريح النقل للحجم/الوزن الزائد؛ ويتم طلبها عبر نظام تصاريح النقل الآلي عبر الإنترنت الخاص بالولاية. المصدر: Virginia DMV Hauling Permits؛ Code of Virginia Article 18."},"15":{"q":"كيف يتم عادةً الحصول على تصاريح النقل للحجم/الوزن الزائد في فرجينيا؟","options":["عن طريق إرسال نموذج ورقي بالبريد إلى ريتشموند","من خلال نظام تصاريح النقل الآلي عبر الإنترنت الخاص بـ DMV","شخصياً فقط، في مركز خدمة عملاء DMV","عن طريق الاتصال بخط إرسال شرطة ولاية فرجينيا"],"explanation":"يتم طلب تصاريح النقل في فرجينيا من خلال نظام تصاريح النقل الآلي عبر الإنترنت الخاص بـ DMV (البوابة الحالية على ezhaulvirginia.com)، الذي حل محل نظام VAHPS الأقدم. المصدر: Virginia DMV Hauling Permits."},"16":{"q":"التصريح الصادر بموجب قانون فرجينيا 46.2-1129 لنقل المنتجات الزراعية أو الحرجية المزروعة في فرجينيا يرفع حدود المحور الفردي والمحور المزدوج والوزن الإجمالي بأي نسبة مئوية؟","options":["ثلاثة في المائة","خمسة في المائة","عشرة في المائة","خمسة عشر في المائة"],"explanation":"يسمح قانون فرجينيا 46.2-1129 بتصريح يرفع حدود المحور الفردي والمحور المزدوج والوزن الإجمالي بنسبة خمسة في المائة لكل منها لبعض المركبات التي تنقل منتجات زراعية أو حرجية مزروعة في فرجينيا. المصدر: Code of Virginia 46.2-1129."},"17":{"q":"بموجب رفع وزن المنتجات الزراعية/الحرجية في قانون فرجينيا 46.2-1129، لا يجوز للتصريح أن يأذن بوزن إجمالي يتجاوز:","options":["80,000 pounds","82,000 pounds","84,000 pounds","90,000 pounds"],"explanation":"ينص قانون فرجينيا 46.2-1129 على أنه لا يجوز لأي تصريح من هذا القبيل أن يأذن بتشغيل مركبة آلية يتجاوز وزنها الإجمالي 84,000 pounds. المصدر: Code of Virginia 46.2-1129."},"18":{"q":"هل ينطبق رفع وزن المنتجات الزراعية/الحرجية بنسبة خمسة في المائة بموجب قانون فرجينيا 46.2-1129 على نظام الطرق السريعة بين الولايات؟","options":["نعم، حتى 84,000 pounds على الطرق بين الولايات","لا؛ تبقى حدود الطرق بين الولايات 20,000/34,000/80,000 pounds","نعم، ولكن فقط مع مرافقة شرطة الولاية","نعم، حتى 88,000 pounds على الطرق بين الولايات"],"explanation":"لا يرفع رفع المنتجات الزراعية/الحرجية حدود الطرق بين الولايات؛ فقانون فرجينيا 46.2-1127 يبقي حدود الطرق بين الولايات عند 20,000 lb للمحور الفردي، و34,000 lb للمحور المزدوج، و80,000 lb للوزن الإجمالي بغض النظر عن تباعد المحاور. المصدر: Code of Virginia 46.2-1129 and 46.2-1127."},"19":{"q":"في فرجينيا، تجاوز أي حد من حدود العرض يعني أن الحمولة زائدة الحجم وتتطلب تصريح نقل؟","options":["أكثر من 8 feet 0 inches (96 inches)","أكثر من 8 feet 6 inches (102 inches)","أكثر من 9 feet 0 inches (108 inches)","أكثر من 10 feet 0 inches (120 inches)"],"explanation":"العرض القانوني في فرجينيا هو 8 feet 6 inches (102 inches) وفقاً للقانون 46.2-1105؛ وأي حمولة أعرض من 8 feet 6 inches تُعد زائدة الحجم وتتطلب تصريح نقل من DMV. المصدر: Code of Virginia 46.2-1105؛ Virginia DMV Hauling Permits."},"20":{"q":"في فرجينيا، أي فئة من فئات CDL مطلوبة لتشغيل مركبة فردية بتصنيف وزن إجمالي للمركبة (GVWR) قدره 26,001 pounds أو أكثر ولا تقطر مقطورة تزيد عن 10,000 pounds؟","options":["Class A","Class B","Class C","Class D"],"explanation":"تعرّف Virginia DMV رخصة Class B CDL بأنها أي مركبة فردية بتصنيف GVWR قدره 26,001 pounds أو أكثر، أو مركبة من هذا القبيل تقطر وحدة لا تزيد عن 10,000 pounds GVWR. المصدر: Virginia DMV, CDL Classifications, Endorsements and Restrictions (dmv.virginia.gov/licenses-ids/cdl/class)."},"21":{"q":"بموجب قواعد فرجينيا، رخصة Class A CDL مطلوبة لأي تركيبة مركبات بتصنيف وزن إجمالي مركّب (GCWR) قدره 26,001 pounds أو أكثر، بشرط أن يكون للمركبة المقطورة تصنيف GVWR يزيد عن أي مقدار؟","options":["5,000 pounds","8,000 pounds","10,000 pounds","15,000 pounds"],"explanation":"تعرّف Virginia DMV الفئة Class A بأنها تركيبة بتصنيف GCWR قدره 26,001+ pounds حيث تتجاوز الوحدة (الوحدات) المقطورة 10,000 pounds GVWR. المصدر: Virginia DMV, CDL Classifications, Endorsements and Restrictions (dmv.virginia.gov/licenses-ids/cdl/class)."},"22":{"q":"يشغّل سائق في فرجينيا مركبة لا تستوفي حدود وزن Class A أو B لكنها مصممة لنقل 16 راكباً أو أكثر بما في ذلك السائق. أي فئة CDL تنطبق؟","options":["Class A","Class B","Class C","لا يلزم CDL"],"explanation":"تعرّف Virginia DMV الفئة Class C بأنها أي مركبة لا تستوفي Class A أو B وتنقل إما 16 شاغلاً أو أكثر (بما في ذلك السائق) أو تحمل مواد خطرة تتطلب لافتات. المصدر: Virginia DMV, CDL Classifications, Endorsements and Restrictions (dmv.virginia.gov/licenses-ids/cdl/class)."},"23":{"q":"أي تظهير CDL في فرجينيا يسمح لحامله بقيادة مركبة صهريج؟","options":["Endorsement N","Endorsement T","Endorsement H","Endorsement P"],"explanation":"تخصص Virginia DMV التظهير N لمركبات الصهاريج (الناقلات). التظهير H للمواد الخطرة، وT للمقطورات المزدوجة/الثلاثية، وP لمركبات الركاب. المصدر: Virginia DMV, CDL Classifications, Endorsements and Restrictions (dmv.virginia.gov/licenses-ids/cdl/class)."},"24":{"q":"أي تظهير CDL في فرجينيا مطلوب لقيادة مركبة تقطر مقطورات مزدوجة أو ثلاثية؟","options":["Endorsement P","Endorsement N","Endorsement T","Endorsement S"],"explanation":"تخصص Virginia DMV التظهير T للسماح بقيادة مركبة تقطر مقطورة مزدوجة أو ثلاثية. المصدر: Virginia DMV, CDL Classifications, Endorsements and Restrictions (dmv.virginia.gov/licenses-ids/cdl/class)."},"25":{"q":"ما هو الحد الأدنى للعمر للحصول على رخصة CDL في فرجينيا صالحة فقط للقيادة داخل الولاية (داخل فرجينيا)؟","options":["16 years old","18 years old","21 years old","25 years old"],"explanation":"تشترط Virginia DMV أن يكون عمر مقدم الطلب 18 عاماً على الأقل للحصول على CDL داخل الولاية و21 عاماً على الأقل للحصول على CDL بين الولايات. المصدر: Virginia DMV, CDL Skills Test Eligibility Requirements (dmv.virginia.gov/licenses-ids/cdl/eligibility)."},"26":{"q":"ما هو الحد الأدنى للعمر للحصول على رخصة CDL في فرجينيا صالحة للتشغيل بين الولايات (عبر حدود الولايات)؟","options":["18 years old","19 years old","20 years old","21 years old"],"explanation":"تشترط Virginia DMV أن يكون عمر مقدم الطلب 21 عاماً على الأقل للحصول على CDL بين الولايات؛ و18 هو الحد الأدنى لـ CDL داخل الولاية فقط. المصدر: Virginia DMV, CDL Skills Test Eligibility Requirements (dmv.virginia.gov/licenses-ids/cdl/eligibility)."},"27":{"q":"قبل إجراء اختبار مهارات CDL، يجب على مقدم الطلب في فرجينيا بشكل عام أن يكون قد حمل تصريح المتعلم التجاري (CLP) لمدة لا تقل عن كم يوماً؟","options":["7 days","10 days","14 days","30 days"],"explanation":"وفقاً للمعيار الفيدرالي الذي تتبناه فرجينيا، يجب على مقدم الطلب حمل CLP لمدة 14 days كحد أدنى قبل إجراء اختبار المهارات (ما لم يكن قد حمل CDL سابقاً أو أكمل تدريباً معتمداً). المصدر: Virginia DMV, CDL Skills Test Eligibility Requirements / Commercial Learner's Permit (dmv.virginia.gov/licenses-ids/cdl/eligibility)."},"28":{"q":"عند قيادة مركبة تجارية بموجب تصريح المتعلم التجاري (CLP) في فرجينيا، يجب أن يكون حامل التصريح مصحوباً بمن؟","options":["أي بالغ مرخص له يزيد عمره عن 21","شخص يحمل CDL سارية لنفس نوع المركبة","فاحص DMV فقط","لا أحد؛ القيادة الفردية مسموحة"],"explanation":"تنص Virginia DMV على أن CLP يسمح بتشغيل مركبة تجارية فقط عندما يكون شخص مرخص له بقيادة نفس نوع المركبة (حامل CDL سارية لتلك الفئة/النوع) حاضراً جسدياً مع حامل التصريح. المصدر: Virginia DMV, Commercial Learner's Permit (dmv.virginia.gov/licenses-ids/cdl/permit)."},"29":{"q":"أي مستند أو فحص مطلوب بشكل فريد للحصول على تظهير HazMat (H) في فرجينيا والذي لا يُطلب للتظهيرات الأخرى؟","options":["تقييم تهديد أمني من TSA قائم على بصمات الأصابع","فحص ثانٍ للرؤية","خطاب رعاية من صاحب العمل","سجل قيادة موثّق"],"explanation":"تشترط Virginia DMV على مقدمي طلب HazMat (HME) إكمال فحص خلفية قائم على بصمات الأصابع؛ وتقوم DMV بإحالة المعلومات إلى TSA، التي تجري تقييم التهديد الأمني وتوافق على التظهير أو ترفضه. المصدر: Virginia DMV, Hazardous Materials Endorsement (HME) (dmv.virginia.gov/licenses-ids/cdl/hazmat)."},"30":{"q":"ما هي مدة صلاحية فحص الخلفية القائم على بصمات الأصابع لتظهير HazMat (H) في فرجينيا؟","options":["1 year","3 years","5 years","10 years"],"explanation":"تنص Virginia DMV على أن فحص الخلفية القائم على بصمات الأصابع لتظهير HazMat صالح لمدة تصل إلى five years، وبعدها يجب تجديده. المصدر: Virginia DMV, Hazardous Materials Endorsement (HME) (dmv.virginia.gov/licenses-ids/cdl/hazmat)."},"31":{"q":"ما الفائدة التي يحصل عليها مقدم الطلب في فرجينيا الذي يحمل بطاقة TWIC (بطاقة هوية عامل النقل) سارية عند التقدم لتظهير HazMat؟","options":["يتم إعفاؤه من اختبار المعرفة","رسوم مخفضة وعدم الحاجة إلى أخذ بصمات جديدة","موافقة تلقائية دون مراجعة TSA","تظهير مدى الحياة لا تنتهي صلاحيته أبداً"],"explanation":"تفرض Virginia DMV على حاملي TWIC رسوماً مخفضة وغير قابلة للاسترداد لـ HazMat ($41 مقابل $83) ولا تتطلب أخذ بصمات جديدة، لأن TWIC ينطوي بالفعل على تقييم تهديد مماثل من TSA. المصدر: Virginia DMV, Hazardous Materials Endorsement / Applying for a CDL (dmv.virginia.gov/licenses-ids/cdl/hazmat)."},"32":{"q":"بموجب قاعدة تدريب السائقين المبتدئين الفيدرالية (ELDT) المطبقة في فرجينيا، يجب إكمال التدريب من خلال مزوّد مدرج في أي سجل قبل اختبار المهارات؟","options":["قائمة المدارس المعتمدة لدى Virginia DMV","سجل مزوّدي التدريب لدى FMCSA (TPR)","دليل الأكاديمية الوطنية لـ CDL","مؤشر سلامة الناقلين لدى DOT"],"explanation":"يجب إكمال ELDT من قبل مزوّد مدرج في سجل مزوّدي التدريب لدى FMCSA (TPR)؛ وتتحقق Virginia DMV من الإكمال إلكترونياً قبل اختبار المهارات. المصدر: Virginia DMV / FMCSA Entry-Level Driver Training (tpr.fmcsa.dot.gov؛ dmv.virginia.gov/licenses-ids/cdl/eligibility)."},"33":{"q":"أي من الإجراءات التالية التي تتم لأول مرة لا تستدعي شرط تدريب ELDT الفيدرالي في فرجينيا؟","options":["الحصول على CDL لأول مرة","ترقية CDL من Class B إلى Class A","تجديد CDL قائمة بنفس الفئة والتظهيرات","الحصول على تظهير الركاب (P) لأول مرة"],"explanation":"ELDT مطلوب لمقدمي طلب CDL لأول مرة، وترقية Class B إلى Class A، وتظهيرات H أو P أو S لأول مرة. أما التجديد البسيط لـ CDL قائمة دون فئة أو تظهير جديد فلا يتطلب ELDT. المصدر: FMCSA Entry-Level Driver Training rule، المطبقة من قبل Virginia DMV (fmcsa.dot.gov؛ dmv.virginia.gov)."},"34":{"q":"بالنسبة لمقدم طلب HazMat لأول مرة في فرجينيا، متى يجب إكمال الجزء النظري من ELDT؟","options":["بعد اجتياز اختبار معرفة HazMat","قبل إجراء اختبار معرفة HazMat في DMV","فقط بعد موافقة TSA على فحص الخلفية","خلال 30 days بعد إصدار التظهير"],"explanation":"بموجب قاعدة ELDT المطبقة في فرجينيا، يجب على مقدمي طلب تظهير HazMat (H) لأول مرة إكمال التدريب النظري لـ ELDT قبل إجراء اختبار معرفة HazMat في DMV. المصدر: FMCSA ELDT rule / Virginia DMV (fmcsa.dot.gov؛ dmv.virginia.gov/licenses-ids/cdl)."},"35":{"q":"من كم فئة من فئات التصديق الذاتي الطبي يجب على مقدم طلب CDL في فرجينيا أن يختار فيما يتعلق بنوع تشغيله للمركبة التجارية الآلية؟","options":["اثنتان","ثلاث","أربع","خمس"],"explanation":"تشترط Virginia DMV على مقدمي الطلب التصديق الذاتي على إحدى أربع فئات: مستثنى بين الولايات، أو غير مستثنى بين الولايات، أو مستثنى داخل الولاية، أو غير مستثنى داخل الولاية. المصدر: Virginia DMV, Apply for a CDL or CLP (dmv.virginia.gov/licenses-ids/cdl/applying)."},"36":{"q":"مقدم طلب CDL في فرجينيا يقود عبر حدود الولايات وليس مستثنى من قواعد التأهيل البدني الفيدرالية ينبغي أن يصدّق ذاتياً تحت أي فئة؟","options":["مستثنى بين الولايات","غير مستثنى بين الولايات","مستثنى داخل الولاية","غير مستثنى داخل الولاية"],"explanation":"السائق الذي يعمل في التجارة بين الولايات والذي يجب أن يستوفي معايير التأهيل الطبي الفيدرالية يصدّق ذاتياً بأنه 'غير مستثنى بين الولايات' ويجب أن يحتفظ بشهادة فاحص طبي سارية. المصدر: Virginia DMV, Apply for a CDL or CLP, medical self-certification (dmv.virginia.gov/licenses-ids/cdl/applying)."},"37":{"q":"مقدم طلب CDL لأول مرة في فرجينيا لم يحمل قط رخصة فرجينيا يجب أن يقدّم إثبات هوية، وإثبات وجود قانوني، ورقم ضمان اجتماعي، وكم عدداً من إثباتات الإقامة في فرجينيا؟","options":["إثبات إقامة واحد","إثباتا إقامة","ثلاثة إثباتات إقامة","إثبات الإقامة غير مطلوب"],"explanation":"تشترط Virginia DMV على مقدم الطلب لأول مرة الذي لم يحمل قط رخصة/هوية فرجينيا أن يقدّم إثبات هوية واحداً، وإثبات وجود قانوني واحداً، وإثبات رقم ضمان اجتماعي واحداً، وإثباتي إقامة في فرجينيا. المصدر: Virginia DMV, Apply for a CDL or CLP (dmv.virginia.gov/licenses-ids/cdl/applying)."},"38":{"q":"الشخص المطالب بالتسجيل في سجل فرجينيا للمعتدين جنسياً والجرائم ضد القاصرين غير مؤهل لأي تظهير CDL طالما كان التسجيل مطلوباً؟","options":["N (Tanker)","T (Doubles/Triples)","S (School Bus)","H (HazMat)"],"explanation":"تحظر فرجينيا إصدار تظهير S (School Bus) لأي شخص مطالب بالتسجيل في سجل المعتدين جنسياً والجرائم ضد القاصرين خلال أي فترة يكون فيها التسجيل مطلوباً. المصدر: Virginia DMV, CDL Classifications, Endorsements and Restrictions (dmv.virginia.gov/licenses-ids/cdl/class)."},"39":{"q":"على رخصة CDL أو CLP في فرجينيا، أي رمز قيد يشير إلى أنه لا يجوز لحامله تشغيل مركبة مزودة بمكابح هوائية؟","options":["Restriction E","Restriction L","Restriction K","Restriction B"],"explanation":"تطبق Virginia DMV القيد L (لا مكابح هوائية) عندما لا يجتاز مقدم الطلب اختبار معرفة المكابح الهوائية أو يختبر في مركبة بدون مكابح هوائية. القيد E يعني لا ناقل حركة يدوي، وK يعني فرجينيا/داخل الولاية فقط، وB يعني عدسات تصحيحية. المصدر: Virginia DMV, CDL Classifications, Endorsements and Restrictions (dmv.virginia.gov/licenses-ids/cdl/class)."},"40":{"q":"في فرجينيا، ما هو الحد الأقصى لتركيز الكحول في الدم (BAC) الذي يجوز عنده لشخص أن يشغّل قانونياً مركبة تجارية آلية (CMV)؟","options":["0.02","0.04","0.08","0.10"],"explanation":"تجرّد فرجينيا أهلية حامل CDL الذي يشغّل CMV بتركيز BAC قدره 0.04 أو أعلى — أي نصف حد الـ 0.08 للسائقين العاديين. المصدر: Virginia DMV CDL Disqualifications page؛ Va. Code § 46.2-341.24."},"41":{"q":"بموجب قانون الموافقة الضمنية لفرجينيا للسائقين التجاريين، فإن السائق بتشغيله CMV على طريق سريع في فرجينيا يُعتبر قد وافق على ماذا؟","options":["فحص سلامة المركبة في أي محطة وزن","الفحص الكيميائي للدم و/أو النفَس في حال القبض عليه قانونياً بتهمة قيادة تحت تأثير الكحول (DUI)","فحص إلزامي للمخدرات قبل كل وردية","استجواب عشوائي من قبل أي ضابط إنفاذ قانون"],"explanation":"ينص قانون الموافقة الضمنية في فرجينيا على أن أي شخص يشغّل CMV على طريق سريع قد وافق على تقديم الدم أو النفَس أو كليهما للفحص الكيميائي لمحتوى الكحول/المخدرات في حال القبض عليه بتهمة مخالفة بموجب § 46.2-341.24، مأخوذة خلال ثلاث ساعات من المخالفة. المصدر: Va. Code § 46.2-341.26:2؛ Virginia DMV CDL manual."},"42":{"q":"أُدين حامل CDL في فرجينيا بأول مخالفة كبرى (مثل قيادة CMV تحت تأثير الكحول) أثناء عدم حمله مواد خطرة موسومة بلافتات. ما هي فترة تجريد الأهلية؟","options":["60 days","6 months","1 year","3 years"],"explanation":"تؤدي أول مخالفة كبرى (DUI، أو BAC 0.04+، أو رفض الاختبار، أو مغادرة موقع الحادث، إلخ) إلى تجريد أهلية CDL لمدة 1-year في فرجينيا. المصدر: Virginia DMV CDL Disqualifications؛ 49 CFR 383.51 Table 1، مطبقة كقاعدة فرجينيا."},"43":{"q":"إذا ارتكب سائق في فرجينيا أول مخالفة كبرى أثناء تشغيل CMV ينقل مواد خطرة تتطلب لافتات، تزداد فترة تجريد الأهلية إلى:","options":["1 year","2 years","3 years","5 years"],"explanation":"أول مخالفة كبرى تُرتكب أثناء نقل مواد خطرة موسومة بلافتات ترفع تجريد الأهلية من 1 year إلى 3 years. المصدر: Virginia DMV CDL Disqualifications؛ 49 CFR 383.51 Table 1."},"44":{"q":"ما هو تجريد أهلية CDL في فرجينيا لثاني مخالفة كبرى (على سبيل المثال، إدانة ثانية بقيادة CMV تحت تأثير الكحول)؟","options":["3 years","5 years","10 years","مدى الحياة"],"explanation":"تؤدي ثاني مخالفة كبرى إلى تجريد أهلية CDL مدى الحياة في فرجينيا، رغم أن إعادة الترخيص قد تكون ممكنة بعد 10 years بموجب شروط معينة. المصدر: Virginia DMV CDL Disqualifications؛ 49 CFR 383.51 Table 1."},"45":{"q":"يرفض حامل CDL في فرجينيا الخضوع لاختبار دم أو نفَس مطلوب بعد القبض عليه قانونياً بتهمة تشغيل CMV تحت التأثير. كيف يُعامل هذا الأمر لأغراض تجريد أهلية CDL؟","options":["إنه مجرد مخالفة مرورية خطيرة (60 days)","إنه مخالفة كبرى، تحمل تجريد أهلية لمدة 1-year لأول مخالفة","لا يحمل أي تجريد لأهلية CDL، بل غرامة فقط","يؤدي إلى تجريد أهلية تلقائي مدى الحياة عند أول رفض"],"explanation":"رفض الاختبار الكيميائي مخالفة كبرى، تجرّد أهلية السائق لمدة 1 year لأول مخالفة (3 years إذا كانت مواد خطرة موسومة بلافتات) — وهو نفس إدانة DUI. المصدر: Virginia DMV CDL Disqualifications؛ Va. Code § 46.2-341.26:2؛ 49 CFR 383.51 Table 1."},"46":{"q":"أي مما يلي تصنّفه فرجينيا على أنه 'مخالفة مرورية خطيرة' لحامل CDL؟","options":["إيقاف CMV في منطقة ممنوع الوقوف فيها","تجاوز السرعة بمقدار 15 mph أو أكثر فوق حد السرعة المقرر","ملصق تسجيل مركبة منتهي الصلاحية","عدم حمل إثبات تأمين"],"explanation":"تدرج فرجينيا تجاوز السرعة بمقدار 15 mph أو أكثر فوق الحد كمخالفة مرورية خطيرة، إلى جانب القيادة المتهورة، وتغيير الحارة غير السليم/المتقطع، والاقتراب الشديد من المركبة الأمامية، وكتابة الرسائل النصية أثناء قيادة CMV، والمخالفات المرورية المرتبطة بحادث مميت. المصدر: Virginia DMV CDL Disqualifications؛ 49 CFR 383.51 Table 2."},"47":{"q":"كم يوماً تُجرّد أهلية حامل CDL في فرجينيا للإدانة بمخالفتين مروريتين خطيرتين (في حادثتين منفصلتين) خلال فترة 3 سنوات؟","options":["30 days","60 days","90 days","120 days"],"explanation":"مخالفتان مروريتان خطيرتان خلال 3 سنوات تؤديان إلى تجريد أهلية CDL لمدة 60-day في فرجينيا. المصدر: Virginia DMV CDL Disqualifications؛ 49 CFR 383.51 Table 2."},"48":{"q":"أُدين حامل CDL في فرجينيا بثلاث مخالفات مرورية خطيرة (حوادث منفصلة) خلال فترة 3 سنوات. ما هو تجريد الأهلية؟","options":["60 days","90 days","120 days","180 days"],"explanation":"ثلاث مخالفات مرورية خطيرة أو أكثر خلال 3 سنوات تؤدي إلى تجريد أهلية CDL لمدة 120-day في فرجينيا. المصدر: Virginia DMV CDL Disqualifications؛ 49 CFR 383.51 Table 2."},"49":{"q":"تجريدات الأهلية للمخالفات المرورية الخطيرة (60 / 120 days) تنطبق فقط عندما تُحتسب المخالفات ضمن أي نافذة زمنية؟","options":["1 year","3 years","5 years","10 years"],"explanation":"تُحتسب المخالفات المرورية الخطيرة ضمن فترة 3 سنوات لأغراض تجريد الأهلية للمخالفتين (60-day) والثلاث مخالفات (120-day). المصدر: Virginia DMV CDL Disqualifications؛ 49 CFR 383.51 Table 2."},"50":{"q":"ما هو تجريد الأهلية لأول مخالفة لتقاطع السكة الحديدية مع الطريق السريع يرتكبها حامل CDL في فرجينيا أثناء تشغيل CMV؟","options":["30 days","60 days","120 days","1 year"],"explanation":"تؤدي أول مخالفة لتقاطع السكة الحديدية إلى تجريد أهلية لمدة لا تقل عن 60 days. المصدر: Virginia DMV CDL Disqualifications؛ 49 CFR 383.51 Table 3."},"51":{"q":"يرتكب حامل CDL في فرجينيا مخالفة ثانية لتقاطع السكة الحديدية مع الطريق السريع خلال 3 سنوات. ما هو تجريد الأهلية؟","options":["60 days","120 days","180 days","1 year"],"explanation":"تؤدي مخالفة ثانية لتقاطع السكة الحديدية خلال 3 سنوات إلى تجريد أهلية لمدة لا تقل عن 120 days. المصدر: Virginia DMV CDL Disqualifications؛ 49 CFR 383.51 Table 3."},"52":{"q":"يرتكب حامل CDL في فرجينيا مخالفة ثالثة لتقاطع السكة الحديدية مع الطريق السريع خلال 3 سنوات. ما هو تجريد الأهلية؟","options":["120 days","180 days","1 year","3 years"],"explanation":"تؤدي مخالفة ثالثة أو لاحقة لتقاطع السكة الحديدية خلال 3 سنوات إلى تجريد أهلية لمدة لا تقل عن 1 year. المصدر: Virginia DMV CDL Disqualifications؛ 49 CFR 383.51 Table 3."},"53":{"q":"ما هو الحد الأدنى لتجريد الأهلية في فرجينيا لأول إدانة لحامل CDL بانتهاك أمر إخراج من الخدمة (OOS) أثناء قيادة CMV؟","options":["90 days","120 days","180 days","1 year"],"explanation":"تجرّد فرجينيا أهلية السائق لمدة لا تقل عن 180 days (حتى 1 year) لأول انتهاك لأمر الإخراج من الخدمة. المصدر: Virginia DMV CDL Disqualifications؛ 49 CFR 383.51 Table 4."},"54":{"q":"مقارنةً بانتهاك أمر الإخراج من الخدمة أثناء حمل بضائع عادية، فإن سائق CDL في فرجينيا الذي ينتهك أمر OOS أثناء نقل مواد خطرة موسومة بلافتات أو 16+ راكباً يواجه:","options":["حداً أدنى أقل لتجريد الأهلية","نفس الحد الأدنى لكن حداً أقصى أعلى لتجريد الأهلية","لا عقوبة إضافية","غرامة مالية فقط"],"explanation":"انتهاك أمر OOS أثناء نقل مواد خطرة موسومة بلافتات أو حمولات مصممة لـ 16+ راكباً يبقي الحد الأدنى عند 180 days لكنه يرفع الحد الأقصى لأول مخالفة إلى 2 years (مقابل 1 year للبضائع العامة). المصدر: 49 CFR 383.51 Table 4، مطبقة كقاعدة فرجينيا؛ Virginia DMV CDL Disqualifications."},"55":{"q":"بموجب قانون فرجينيا، قد يُفرض على سائق CDL الذي يكتب رسائل نصية أو يستخدم هاتفاً محمولاً باليد أثناء قيادة CMV غرامة مدنية لا تتجاوز:","options":["$250","$1,000","$2,750","$5,000"],"explanation":"يحظر Va. Code § 46.2-341.20:5 على سائق CMV كتابة الرسائل النصية أو استخدام هاتف محمول باليد ويأذن بغرامة مدنية تصل إلى $2,750؛ كما تُعد هذه الإدانة مخالفة مرورية خطيرة لأغراض CDL. المصدر: Va. Code § 46.2-341.20:5؛ Virginia DMV CDL Disqualifications."},"56":{"q":"تُعامَل الإدانة بكتابة الرسائل النصية أثناء تشغيل مركبة تجارية آلية في فرجينيا لأغراض CDL على أنها:","options":["مخالفة كبرى (تجريد أهلية لمدة 1-year)","مخالفة مرورية خطيرة","انتهاك أمر إخراج من الخدمة","مخالفة غير قابلة للإبلاغ"],"explanation":"كتابة الرسائل النصية أثناء قيادة CMV مدرجة ضمن المخالفات المرورية الخطيرة في فرجينيا، لذا تُحتسب الإدانات المتكررة ضمن تجريد الأهلية لمخالفتين خلال 3 سنوات (60-day) وثلاث مخالفات خلال 3 سنوات (120-day). المصدر: Virginia DMV CDL Disqualifications؛ Va. Code § 46.2-341.20:5؛ 49 CFR 383.51 Table 2."},"57":{"q":"عند أي سرعة فوق الحد يصبح تجاوز السرعة العادي 'قيادة متهورة' بموجب قانون فرجينيا العام للقيادة المتهورة بسبب السرعة (وهي تهمة تُعد أيضاً مخالفة CDL خطيرة)؟","options":["10 mph فوق الحد","15 mph فوق الحد","20 mph فوق الحد، أو أي سرعة تتجاوز 85 mph","25 mph فوق الحد، أو أي سرعة تتجاوز 90 mph"],"explanation":"يعرّف Va. Code § 46.2-862 القيادة المتهورة بسبب السرعة بأنها 20 mph أو أكثر فوق الحد، أو ما يتجاوز 85 mph بغض النظر عن الحد؛ والقيادة المتهورة هي أيضاً مخالفة مرورية خطيرة لـ CDL (منفصلة عن عتبة المخالفة الخطيرة البالغة 15 mph فوق الحد). المصدر: Va. Code § 46.2-862؛ Virginia DMV CDL Disqualifications."},"58":{"q":"أُدين حامل CDL في فرجينيا باستخدام CMV في ارتكاب جناية تتعلق بتصنيع مادة خاضعة للرقابة أو توزيعها أو صرفها. ما هو تجريد الأهلية؟","options":["1 year","3 years","10 years","مدى الحياة دون إمكانية إعادة الترخيص بعد 10 years"],"explanation":"استخدام CMV لتصنيع المواد الخاضعة للرقابة أو توزيعها أو صرفها مخالفة كبرى تحمل تجريد أهلية مدى الحياة وهي غير مؤهلة لإعادة الترخيص بعد 10 years المتاحة لتجريدات الأهلية مدى الحياة الأخرى. المصدر: Virginia DMV CDL Disqualifications؛ 49 CFR 383.51 Table 1."},"59":{"q":"تجريد أهلية حامل CDL بسبب قيادة CMV تحت تأثير الكحول في فرجينيا يؤثر بشكل أساسي على أي امتياز قيادة؟","options":["فقط امتياز تشغيل الدراجات النارية","امتياز القيادة التجارية (CDL)","فقط امتيازات القيادة خارج الولاية","امتيازات القوارب والمراكب المائية"],"explanation":"يزيل تجريد أهلية CDL امتياز تشغيل المركبات التجارية الآلية؛ وقد ينطبق أيضاً تعليق رخصة منفصل، لكن تجريد الأهلية يستهدف على وجه التحديد امتياز القيادة التجارية/CDL. المصدر: Virginia DMV CDL Disqualifications؛ Va. Code § 46.2-341.18."},"60":{"q":"بموجب قانون \"التزحزح جانبًا\" (Move Over) في فرجينيا، كم عدد المسارات التي يجب أن يحتوي عليها الطريق السريع (وبأي تكوين) قبل أن ينطبق واجب تغيير المسار لمركبة طوارئ متوقفة تومض أضواؤها؟","options":["أربعة مسارات على الأقل، مع مسارين على الأقل لحركة المرور المتجهة في نفس اتجاه السائق","أي طريق سريع غير مقسوم بمسارين","ستة مسارات على الأقل، ثلاثة في كل اتجاه","فقط على الطرق السريعة بين الولايات التي تحمل لافتات"],"explanation":"يقتضي قانون فرجينيا Code of Virginia 46.2-861.1 (قانون \"التزحزح جانبًا\" في فرجينيا) من السائقين على الطرق التي تحتوي على أربعة مسارات على الأقل، يحمل اثنان منها حركة المرور في نفس الاتجاه، أن يغيّروا المسار بعيدًا عن مركبة الطوارئ الثابتة التي تعرض أضواء تحذير وامضة؛ وإذا تعذّر تغيير المسار بأمان، فيجب على السائق تخفيف السرعة والمتابعة بحذر. المصدر: Code of Virginia 46.2-861.1."},"61":{"q":"في فرجينيا، عندما لا يستطيع السائق تغيير المسار بأمان بعيدًا عن مركبة طوارئ متوقفة تعرض أضواء وامضة، ماذا يجب على السائق أن يفعل بدلاً من ذلك؟","options":["المتابعة بحذر وتخفيف السرعة إلى أقل من الحد المعلن","التوقف تمامًا حتى تغادر مركبة الطوارئ","إطلاق البوق والحفاظ على السرعة المعلنة","تشغيل أضواء التحذير من الخطر والمتابعة بالسرعة العادية"],"explanation":"بموجب Code of Virginia 46.2-861.1، إذا تعذّر تغيير المسار بأمان، فيجب على السائق المتابعة بالحذر الواجب والحفاظ على سرعة آمنة لظروف الطريق السريع، مع تخفيف السرعة لحماية أفراد الطوارئ في موقع الحادث. وتُصنّف المخالفة على أنها قيادة متهورة (جنحة من الدرجة الأولى - Class 1 misdemeanor). المصدر: Code of Virginia 46.2-861.1."},"62":{"q":"في فرجينيا، كيف تُصنّف مخالفة قانون \"التزحزح جانبًا\" (عدم التزحزح أو تخفيف السرعة لمركبة طوارئ متوقفة)؟","options":["قيادة متهورة، وهي جنحة من الدرجة الأولى (Class 1 misdemeanor)","مخالفة مدنية غير متعلقة بالحركة","مخالفة مرورية بسيطة بدون نقاط","جناية إذا لم تقع إصابة"],"explanation":"يجعل Code of Virginia 46.2-861.1 من عدم إفساح الطريق أو التزحزح جانبًا لمركبة طوارئ ثابتة شكلاً من أشكال القيادة المتهورة، وهي جنحة من الدرجة الأولى (Class 1 misdemeanor) تترتب عليها احتمالية السجن وغرامات تصل إلى $2,500 وتعليق الرخصة. المصدر: Code of Virginia 46.2-861.1."},"63":{"q":"على الطرق السريعة غير محدودة الوصول (غير الطرق بين الولايات) في فرجينيا، ما هو الحد الأقصى للسرعة لشاحنة الجرّ والمقطورة أو شاحنة مصممة لنقل البضائع، في غياب استثناءات معلنة؟","options":["45 mph","55 mph","60 mph","65 mph"],"explanation":"يحدد Code of Virginia 46.2-870 الحد الافتراضي على الطرق السريعة غير محدودة الوصول بـ 55 mph للمركبات الركاب والحافلات لكن 45 mph فقط للشاحنات وشاحنات الجرّ والمركبات المركّبة المصممة لنقل البضائع، أي أقل بمقدار 10 mph من مركبات الركاب. المصدر: Code of Virginia 46.2-870."},"64":{"q":"على طريق سريع بين الولايات في فرجينيا، ما هو الحد الأقصى للسرعة لشاحنة تجارية حيث يكون الحد الأعلى معلنًا بعد دراسة هندسية مرورية؟","options":["70 mph، وهو نفسه المطبق على مركبات الركاب","55 mph، بينما قد تسير السيارات بسرعة 70 mph","65 mph للشاحنات فقط","75 mph"],"explanation":"يحدد Code of Virginia 46.2-870 الحد الأقصى على الطرق بين الولايات بـ 55 mph، أو 70 mph حيث تُنصب لافتات معلنة قانونيًا عقب دراسة هندسية. وعلى الطرق بين الولايات ينطبق الحد الأعلى المعلن على جميع المركبات، بما فيها الشاحنات؛ ولا تفرض فرجينيا حدًا أدنى منفصلاً لسرعة الشاحنات على الطرق بين الولايات. المصدر: Code of Virginia 46.2-870."},"65":{"q":"عند تقاطع سكة حديد على مستوى الأرض في فرجينيا، يجب على مركبة تحمل لافتات مواد خطرة أو حافلة تنقل ركابًا مقابل أجر أن تتوقف ضمن أي مسافة من أقرب قضيب سكة؟","options":["ضمن 50 قدمًا لكن ليس أقل من 15 قدمًا","ضمن 100 قدم لكن ليس أقل من 25 قدمًا","ضمن 30 قدمًا لكن ليس أقل من 10 أقدام","ضمن 15 قدمًا لكن ليس أقل من 5 أقدام"],"explanation":"يقتضي Code of Virginia 46.2-886 من المركبات التي تنقل ركابًا مقابل أجر أو تحمل مواد متفجرة أو سوائل قابلة للاشتعال كحمولة أن تتوقف ضمن 50 قدمًا لكن ليس أقل من 15 قدمًا من أقرب قضيب سكة، ثم تنظر وتستمع قبل المتابعة. وهذا يطابق قاعدة عبور سكة الحديد في دليل Virginia CDL Manual. المصدر: Code of Virginia 46.2-886؛ Virginia CDL Manual."},"66":{"q":"بعد التوقف عند تقاطع سكة حديد، ماذا يقتضي قانون فرجينيا بشأن تغيير التروس أثناء وجود المركبة على القضبان؟","options":["يجب على السائق العبور بترس لا يتطلب أي تغيير للتروس أثناء وجوده على القضبان","ينبغي على السائق خفض الترس إلى أدنى ترس في منتصف العبور","يجوز للسائق تغيير التروس بحرية طالما حافظ على السرعة","يجب على السائق التحويل إلى الترس المحايد أثناء العبور"],"explanation":"ينص Code of Virginia 46.2-886 على أنه بعد التوقف وعند المتابعة، يجب على السائق العبور فقط بترس بحيث لا تكون هناك ضرورة لتغيير التروس أثناء اجتياز التقاطع، ويجب ألا يغيّر التروس أثناء العبور. المصدر: Code of Virginia 46.2-886؛ Virginia CDL Manual."},"67":{"q":"في فرجينيا، ماذا يجب على سائق يقترب من حافلة مدرسية متوقفة تُحمّل أو تُنزل الأطفال على طريق غير مقسوم بمسارين أن يفعل؟","options":["التوقف عند الاقتراب من أي اتجاه والبقاء متوقفًا حتى تتحرك الحافلة أو تتوقف عن الوميض","التوقف فقط إذا كان يسير في نفس اتجاه الحافلة","التخفيف إلى 20 mph دون الحاجة إلى التوقف","التوقف فقط إذا كان الأطفال يعبرون بشكل ظاهر"],"explanation":"يقتضي Code of Virginia 46.2-859 من السائق المقترب من أي اتجاه أن يتوقف للحافلة المدرسية المتوقفة والتي تعرض أجهزة التحذير الخاصة بها لتحميل أو إنزال الركاب، وأن يبقى متوقفًا حتى يبتعد الأشخاص وتعود الحافلة إلى الحركة. وتُعد المخالفة قيادة متهورة. المصدر: Code of Virginia 46.2-859."},"68":{"q":"على طريق سريع مقسوم في فرجينيا، تحت أي شرط لا يُطلب من سائق قادم في الاتجاه المعاكس التوقف لحافلة مدرسية متوقفة على الطريق المقابل؟","options":["عندما يفصل بين الطريقين حاجز مادي أو منطقة غير معبدة","عندما يوجد خط مركزي مزدوج أصفر مطلي","عندما يكون حد السرعة 45 mph أو أعلى","عندما يوجد مسار انعطاف مركزي بين الطريقين"],"explanation":"يعفي Code of Virginia 46.2-859 السائق من التوقف فقط عندما تكون الحافلة المدرسية على الطريق الآخر من طريق سريع مقسوم (أو طريق وصول/ممر) يفصله عن طريق السائق حاجز مادي أو منطقة غير معبدة. ومجرد خط مطلي أو مسار انعطاف لا يُعد كافيًا. المصدر: Code of Virginia 46.2-859."},"69":{"q":"عندما يجب أن تتوقف مركبة تجارية على طريق سريع في فرجينيا، يجب على السائق وضع أجهزة تحذير مثلثية عاكسة حمراء ضمن كم دقيقة من التوقف؟","options":["ضمن 10 دقائق","ضمن 5 دقائق","ضمن 15 دقيقة","فورًا، ضمن دقيقة واحدة"],"explanation":"يقتضي Code of Virginia 46.2-111 من مشغّل المركبة التجارية المتوقفة وضع أجهزة التحذير المثلثية العاكسة الحمراء المطلوبة ضمن 10 دقائق من التوقف، مع إبقاء أضواء التحذير من الخطر مشغّلة حتى يتم وضعها. المصدر: Code of Virginia 46.2-111."},"70":{"q":"بالنسبة لمركبة تجارية متوقفة على طريق مستوٍ ومستقيم في فرجينيا، أين يجب وضع المثلثات التحذيرية الثلاثة؟","options":["100 قدم إلى الخلف، و100 قدم إلى الأمام، وواحد على جانب حركة المرور ضمن 10 أقدام من المركبة","10 أقدام و100 قدم و200 قدم جميعها إلى الخلف","50 قدمًا و100 قدم و150 قدمًا إلى الخلف فقط","واحد على كل جانب وواحد على السطح"],"explanation":"يوجّه Code of Virginia 46.2-111 بوضع مثلث واحد على مسافة لا تقل عن 100 قدم في اتجاه حركة المرور القادمة، وواحد على مسافة لا تقل عن 100 قدم في الاتجاه المعاكس، وواحد على جانب حركة المرور على مسافة لا تقل عن 10 أقدام من مقدمة المركبة أو مؤخرتها. المصدر: Code of Virginia 46.2-111."},"71":{"q":"إذا توقفت مركبة تجارية في فرجينيا ضمن 500 قدم من منعطف أو قمة تل أو عائق آخر، فكيف ينبغي وضع جهاز التحذير في ذلك الاتجاه؟","options":["على مسافة كافية لإعطاء تحذير وافٍ، لكن في أي حال لا تقل عن 500 قدم من المركبة","على مسافة 100 قدم تمامًا من المركبة","على مسافة لا تزيد عن 200 قدم من المركبة","مباشرة على العائق نفسه"],"explanation":"يقتضي Code of Virginia 46.2-111 أنه حيث يكون التوقف ضمن 500 قدم من منعطف أو قمة تل أو عائق آخر، يُوضع جهاز التحذير في ذلك الاتجاه بحيث يوفّر تحذيرًا وافيًا، وفي أي حال لا تقل المسافة عن 500 قدم من المركبة المتوقفة. المصدر: Code of Virginia 46.2-111."},"72":{"q":"على الطريق بين الولايات Interstate 81 وعلى الطرق بين الولايات التي تحتوي على أكثر من مسارين في كل اتجاه، ما هو قيد المسار الذي ينطبق على المركبات التجارية الآلية؟","options":["يُحظر عليها القيادة في المسار الأقصى يسارًا","يجوز لها استخدام المسار الأقصى يسارًا فقط","يجب أن تبقى ضمن 10 mph من الحد الأدنى لسرعة الشاحنات","تُقيّد بالمسار الأوسط فقط"],"explanation":"يحظر Code of Virginia 46.2-803.1 على المركبات التجارية الآلية السير في المسار الأقصى يسارًا على I-81 وعلى الطرق السريعة بين الولايات التي تحتوي على أكثر من مسارين للسير في كل اتجاه (عمومًا حيث يكون الحد 65 mph أو أعلى). وتُستثنى الحافلات والمركبات التي تستعد لمخرج على اليسار. المصدر: Code of Virginia 46.2-803.1."},"73":{"q":"على طريق سريع مقسّم إلى مسارات في فرجينيا، أين يجب أن تُقاد أي مركبة تسير أبطأ من السرعة الطبيعية لحركة المرور؟","options":["في المسار الأقرب إلى الحافة اليمنى أو الرصيف الأيمن، عدا عند التجاوز أو الاستعداد للانعطاف يسارًا","في أي مسار يختاره السائق","في المسار الأوسط لتحقيق توازن حركة المرور","في المسار الأيسر للابتعاد عن حركة المرور المندمجة"],"explanation":"يقتضي Code of Virginia 46.2-804 أن تُقاد المركبة التي تسير أبطأ من السرعة الطبيعية لحركة المرور في المسار الأقرب إلى الحافة اليمنى أو الرصيف، عدا عند اللحاق والتجاوز أو الاستعداد للانعطاف يسارًا أو حيث تكون المسارات اليمنى مخصصة لحركة المرور البطيئة. المصدر: Code of Virginia 46.2-804."},"74":{"q":"أي من الطرق ذات المناظر الخلابة في فرجينيا تحظر عمومًا على الشاحنات التجارية السير عليها؟","options":["George Washington Memorial Parkway و Colonial Parkway","Interstate 95 و Interstate 64","Capital Beltway (I-495)","U.S. Route 29 و U.S. Route 58"],"explanation":"يحظر كل من George Washington Memorial Parkway المُدار اتحاديًا و Colonial Parkway في فرجينيا الشاحنات التجارية؛ إذ يتطلب GW Parkway تصريحًا خاصًا من National Park Service لأي مركبة تجارية، بينما يمنع Colonial Parkway الشاحنات باستثناء حافلات الركاب. المصدر: National Park Service / إرشادات VDOT بشأن قيود الشاحنات."},"75":{"q":"تُحظر فئات معينة من المواد الخطرة من أنفاق فرجينيا القريبة من المياه مثل Hampton Roads Bridge-Tunnel. ما الذي يحكم هذه القيود؟","options":["لوائح VDOT التي تحكم نقل المواد الخطرة عبر مرافق الجسور-الأنفاق (24VAC30-61)، استنادًا إلى فئة الخطر","حدود الوزن الاتحادية بين الولايات فقط","تصنيف الوزن الإجمالي المركّب للمركبة وحده","ما إذا كانت الحمولة مؤمّنًا عليها"],"explanation":"تحكم اللائحة الإدارية لفرجينيا 24VAC30-61 نقل المواد الخطرة عبر الأنفاق الحضرية والقريبة من المياه في الولاية (Hampton Roads و Monitor-Merrimac وأنفاق Elizabeth River)، حيث تحظر فئات خطر معينة مثل المتفجرات والغازات السامة. المصدر: 24VAC30-61؛ إرشادات VDOT بشأن المواد الخطرة."},"76":{"q":"ينبغي على الشاحنات المتجهة جنوبًا والنازلة على منحدر Fancy Gap الشديد على Interstate 77 في فرجينيا أن تكون على دراية خاصة بأي ميزة أمان؟","options":["منحدرات هروب متعددة للشاحنات الهاربة على المنحدر الطويل","محطة وزن إلزامية للشاحنات عند القمة","نفق يمنع جميع الشاحنات","مسار HOV قابل للعكس"],"explanation":"يرتفع Interstate 77 لأكثر من 1,500 قدم صعودًا عبر Fancy Gap بانحدارات تصل إلى نحو 4.5%؛ ويتضمن النزول الطويل المتجه جنوبًا إلى North Carolina منحدرات هروب متعددة للشاحنات للمركبات التي تفقد قدرة الكبح. وينبغي على السائقين اختيار ترس منخفض قبل النزول. المصدر: إرشادات القيادة الجبلية في VDOT/Virginia CDL Manual."},"77":{"q":"في فرجينيا، تنص قاعدة الحد الأدنى للسرعة على أنه لا يجوز للسائق القيادة بسرعة بطيئة لدرجة أن يفعل ماذا؟","options":["يعيق أو يعرقل الحركة الطبيعية والمعقولة لحركة المرور، عدا عندما يكون تخفيف السرعة ضروريًا للسلامة أو القانون","يسير بأقل من 40 mph على أي طريق سريع","ينخفض أكثر من 5 mph دون الحد المعلن","يتسبب في استخدام السائقين الآخرين لأبواقهم"],"explanation":"يحظر Code of Virginia 46.2-877 القيادة بسرعة بطيئة لدرجة تعيق الحركة الطبيعية والمعقولة لحركة المرور، عدا عندما يكون تخفيف السرعة ضروريًا للتشغيل الآمن أو للامتثال للقانون. المصدر: Code of Virginia 46.2-877."},"78":{"q":"إلى جانب اشتراط المسارات الأربعة، ينطبق واجب \"التزحزح جانبًا\" في فرجينيا على المركبات الثابتة التي تعرض أضواء تحذير ويشغّلها أي من التالي؟","options":["الشرطة والإطفاء وسيارات الإسعاف و VDOT ومركبات المرافق وشاحنات القطر","الشرطة وسيارات الإسعاف فقط","سيارات شرطة الولاية فقط","المركبات المملوكة لـ VDOT فقط"],"explanation":"يوسّع Code of Virginia 46.2-861.1 واجب \"التزحزح جانبًا\" ليشمل مجموعة واسعة من المركبات الثابتة التي تعرض أضواء تحذير وامضة، بما في ذلك مركبات إنفاذ القانون والإطفاء والإسعاف و Virginia Department of Transportation ومركبات المرافق ومركبات القطر/الإنقاذ. المصدر: Code of Virginia 46.2-861.1."},"79":{"q":"كبديل أخفّ عن القيادة المتهورة، يسمح قانون فرجينيا بإنفاذ مخالفة تجاوز حافلة مدرسية متوقفة كغرامة مدنية بأي مبلغ، مع احتمال تحميل مالك المركبة المسؤولية؟","options":["$250","$50","$1,000","$2,500"],"explanation":"يوفّر Code of Virginia 46.2-844 بديل غرامة مدنية بمبلغ $250 لعدم التوقف لحافلة مدرسية متوقفة، وقد يُحمَّل المالك المسجّل للمركبة المسؤولية عندما يلتقط نظام المراقبة بالفيديو في الحافلة المخالفة. وتظل الجريمة الجنائية بموجب 46.2-859 قيادة متهورة. المصدر: Code of Virginia 46.2-844 و 46.2-859."},"80":{"q":"أي جهة تصدر رخص القيادة التجارية (CDLs) في فرجينيا؟","options":["إدارة المركبات الآلية في فرجينيا (Virginia Department of Motor Vehicles - DMV)","الإدارة الاتحادية لسلامة الناقلين الآليين (FMCSA)","إدارة النقل في فرجينيا (VDOT)","قسم الناقلين الآليين بشرطة ولاية فرجينيا"],"explanation":"تُصدر رخص CDL في فرجينيا من قبل Virginia Department of Motor Vehicles (DMV). تضع FMCSA المعايير الاتحادية لكنها لا تصدر الرخص، وتتولى VDOT الطرق/التصاريح وليس إصدار الرخص. المصدر: Virginia DMV, Apply for a CDL or CLP."},"81":{"q":"إلى أين يجب أن تذهب للتقدم بطلب الحصول على CDL أو تصريح متعلّم القيادة التجارية (CLP) في فرجينيا؟","options":["شخصيًا إلى مركز خدمة العملاء التابع لـ DMV","بالكامل عبر الإنترنت من خلال موقع DMV الإلكتروني","في أي وكالة شاحنات معتمدة من FMCSA","بالبريد إلى مقر DMV في Richmond"],"explanation":"تشترط فرجينيا أن تتقدم بطلب الحصول على CDL أو CLP شخصيًا في مركز خدمة العملاء التابع لـ DMV؛ ولا يمكن إتمام طلب CDL/CLP الأولي بالكامل عبر الإنترنت. المصدر: Virginia DMV, Apply for a CDL or CLP."},"82":{"q":"تقتضي اللوائح الاتحادية من كل متقدم بطلب CDL أو CLP في فرجينيا أن يُصدّق ذاتيًا على كم فئة من فئات تشغيل المركبات التجارية الآلية؟","options":["أربع","اثنتان","ثلاث","خمس"],"explanation":"يجب على أي شخص يحمل أو يتقدم بطلب CDL/CLP في فرجينيا أن يُصدّق ذاتيًا على واحدة من أربع فئات لتشغيل المركبات التجارية الآلية (CMV). المصدر: Virginia DMV, CDL Medical Certification Requirements."},"83":{"q":"أي من التالي يُعد إحدى فئات التصديق الذاتي الأربع المستخدمة من قبل Virginia DMV؟","options":["غير المستثناة بين الولايات (Non-excepted Interstate - NI)","التشغيل التجاري المقيّد","المواد الخطرة داخل الولاية فقط","الناقل المستثنى اتحاديًا"],"explanation":"الفئات الأربع هي: المستثناة بين الولايات (Excepted Interstate - EI)، والمستثناة داخل الولاية (Excepted Intrastate - EA)، وغير المستثناة بين الولايات (Non-excepted Interstate - NI)، وغير المستثناة داخل الولاية (Non-excepted Intrastate - NA). \"غير المستثناة بين الولايات\" فئة صالحة؛ أما الباقية المذكورة فليست كذلك. المصدر: Virginia DMV, CDL Medical Certification Requirements."},"84":{"q":"أي فئة من فئات التصديق الذاتي لا تتطلب عمومًا من السائق الاحتفاظ بشهادة فاحص طبي في ملفه لدى Virginia DMV؟","options":["المستثناة بين الولايات (Excepted Interstate - EI)","غير المستثناة بين الولايات (Non-excepted Interstate - NI)","غير المستثناة داخل الولاية (Non-excepted Intrastate - NA)","أي فئة بين الولايات"],"explanation":"السائقون الذين يُصدّقون على الفئات المستثناة (المستثناة بين الولايات أو المستثناة داخل الولاية) غير مطالبين بتقديم شهادة فاحص طبي؛ فقط سائقو الفئة غير المستثناة بين الولايات وغير المستثناة داخل الولاية ملزمون بذلك. المصدر: Virginia DMV, CDL Medical Certification Requirements."},"85":{"q":"السائق الذي يُصدّق ذاتيًا كـ \"غير مستثنى بين الولايات\" في فرجينيا يجب أن يُجري الفحص البدني لديه فاحص طبي يكون:","options":["مدرجًا على السجل الوطني للفاحصين الطبيين المعتمدين التابع لـ FMCSA (National Registry of Certified Medical Examiners)","موظفًا مباشرة لدى Virginia DMV","معتمدًا من قبل إدارة الصحة في فرجينيا","أي طبيب مرخّص يختاره السائق"],"explanation":"يجب فحص السائقين غير المستثنين من قبل فاحص طبي مدرج على السجل الوطني للفاحصين الطبيين المعتمدين التابع لـ FMCSA. وليس كل طبيب مرخّص مؤهلاً. المصدر: Virginia DMV, CDL Medical Certification Requirements."},"86":{"q":"اعتبارًا من 5 مايو 2025، كيف يجب تقديم شهادة الفاحص الطبي (Medical Examiner's Certificate - MEC) إلى Virginia DMV؟","options":["إلكترونيًا من قبل الفاحص الطبي عبر بوابة السجل الوطني لـ FMCSA","بأن يحضر السائق الشهادة الورقية إلى مكتب DMV","بأن يرفع السائق نسخة ممسوحة ضوئيًا إلى موقع DMV الإلكتروني","بأن يرسل صاحب عمل السائق الشهادة بالفاكس إلى FMCSA"],"explanation":"اعتبارًا من 5 مايو 2025، لم تعد Virginia DMV تقبل شهادات MEC مباشرة من السائقين؛ إذ يجب على الفاحص الطبي تقديم الشهادة إلكترونيًا عبر بوابة السجل الوطني لـ FMCSA. المصدر: Virginia DMV, CDL Medical Certification Requirements."},"87":{"q":"للحصول على CLP في فرجينيا، يجب على المتقدم كحد أدنى اجتياز أي اختبار معرفي؟","options":["اختبار المعرفة العامة لـ CDL","اختبار المركبات المركّبة فقط","اختبار الكوابح الهوائية فقط","اختبار المواد الخطرة"],"explanation":"للحصول على CLP يجب أن تجتاز اختبار المعرفة العامة لـ CDL، بالإضافة إلى أي اختبارات معرفية إضافية (مثل الكوابح الهوائية أو الصهريج) للمركبات التي تنوي قيادتها. المصدر: Virginia DMV, Commercial Learner's Permit."},"88":{"q":"بعد إصدار CLP في فرجينيا، كم يجب أن تحتفظ به قبل أن تصبح مؤهلاً لإجراء اختبار مهارات CDL؟","options":["14 يومًا على الأقل","30 يومًا على الأقل","7 أيام على الأقل","60 يومًا على الأقل"],"explanation":"تشترط فرجينيا فترة احتفاظ بـ CLP لا تقل عن 14 يومًا قبل إجراء اختبار المهارات. ويمكن التنازل عن ذلك بإثبات حيازة سابقة لـ CDL أو إتمام تدريب السائق المبتدئ (Entry-Level Driver Training). المصدر: Virginia DMV, CDL Skills Test Eligibility / Commercial Learner's Permit."},"89":{"q":"كم مدة صلاحية تصريح متعلّم القيادة التجارية (CLP) في فرجينيا، وهل يمكن تجديده؟","options":["صالح لمدة سنة واحدة ولا يمكن تجديده","صالح لمدة 180 يومًا ويمكن تجديده مرة واحدة","صالح لمدة سنتين ويُجدّد سنويًا","صالح لمدة 6 أشهر مع تجديدات غير محدودة"],"explanation":"تصريح CLP في فرجينيا صالح لمدة سنة واحدة ولا يمكن تجديده؛ وإذا انتهت صلاحيته فيجب إعادة التقديم وإعادة الاختبار. المصدر: Virginia DMV, Commercial Learner's Permit."},"90":{"q":"يتكون اختبار مهارات CDL في فرجينيا من أي ثلاثة أجزاء، تُؤدّى بالترتيب؟","options":["فحص ما قبل الرحلة، والتحكم الأساسي بالمركبة، والقيادة على الطريق","المعرفة الكتابية، وفحص النظر، واختبار الطريق","فحص الكوابح الهوائية، والرجوع للخلف، والاندماج في الطريق السريع","الوصل/الفصل، والركن الموازي، والقيادة الليلية"],"explanation":"يتكوّن اختبار مهارات CDL من ثلاثة أجزاء: فحص المركبة قبل الرحلة، ومهارات التحكم الأساسي بالمركبة، واختبار القيادة على الطريق، تُعطى بهذا الترتيب. المصدر: معيار CDL لـ FMCSA المطبق في فرجينيا؛ Virginia DMV CDL Skills Tests."},"91":{"q":"من يجب أن يوفّر المركبة المستخدمة في اختبار القيادة على الطريق لـ CDL في فرجينيا؟","options":["المتقدم، الذي يجب أن يحضر مركبة مسجّلة بشكل صحيح من النوع الذي يرغب في قيادته","Virginia DMV، التي توفّر شاحنة اختبار","مدرسة تدريب ELDT الخاصة بالمتقدم فقط","FMCSA، من أسطول التفتيش الإقليمي التابع لها"],"explanation":"يجب على المتقدم توفير مركبة مسجّلة بشكل صحيح وممثّلة لفئة/نوع رخصة CDL التي يسعى للحصول عليها لاختبار الطريق. المصدر: Virginia DMV, CDL Skills Test Eligibility."},"92":{"q":"متى دخل اشتراط تدريب السائق المبتدئ الاتحادي (Entry-Level Driver Training - ELDT) المطبق في فرجينيا حيز التنفيذ؟","options":["7 فبراير 2022","5 مايو 2025","1 يناير 2020","1 يوليو 2023"],"explanation":"أصبحت اشتراطات ELDT سارية المفعول في 7 فبراير 2022. (5 مايو 2025 هو التاريخ المنفصل لتغيير التقديم الإلكتروني لشهادة MEC.) المصدر: Virginia DMV, Entry-Level Driver Training."},"93":{"q":"يجب أن يكون مقدّم تدريب ELDT الذي يستخدمه متقدم CDL في فرجينيا:","options":["مدرجًا على سجل مقدّمي التدريب (Training Provider Registry - TPR) التابع لـ FMCSA","معتمدًا فقط من قبل Virginia DMV","معتمدًا من قبل مجلس التعليم في فرجينيا","أي مدرسة قيادة تجارية لديها رخصة عمل"],"explanation":"يجب إتمام تدريب ELDT من خلال مقدّم مدرج على سجل مقدّمي التدريب (TPR) التابع لـ FMCSA. ولا تكفي رخصة عمل عامة أو اعتماد مجلس الولاية. المصدر: Virginia DMV, Entry-Level Driver Training."},"94":{"q":"بالنسبة لمتقدم من الفئة A أو B لأول مرة في فرجينيا، متى يجب إتمام تدريب ELDT النظري والتدريب خلف المقود؟","options":["قبل إجراء اختبار مهارات الطريق","قبل التقدم بطلب CLP","خلال 30 يومًا بعد اجتياز اختبار المهارات","قبل إجراء اختبار المعرفة العامة"],"explanation":"بالنسبة لفئات CDL (وتظهيرات P/S)، يجب إتمام تدريب ELDT النظري والتدريب خلف المقود قبل اختبار مهارات الطريق. (أما بالنسبة للمواد الخطرة، فيجب إتمام الجزء النظري قبل اختبار المعرفة الخاص بالمواد الخطرة.) المصدر: Virginia DMV, Entry-Level Driver Training."},"95":{"q":"بالنسبة لتظهير المواد الخطرة (H) في فرجينيا، يجب إتمام الجزء النظري من ELDT قبل:","options":["إجراء اختبار المعرفة الخاص بالمواد الخطرة","إجراء اختبار المهارات على الطريق","تقديم نموذج التصديق الذاتي","إصدار CLP"],"explanation":"بخلاف تدريب فئة CDL، يجب إتمام الجزء النظري من ELDT الخاص بالمواد الخطرة قبل إجراء اختبار المعرفة الخاص بالمواد الخطرة (لا يوجد اختبار مهارات منفصل للمواد الخطرة). المصدر: Virginia DMV, Entry-Level Driver Training."},"96":{"q":"ما هو الحد الأدنى للعمر للحصول على CDL داخل الولاية مقابل CDL بين الولايات في فرجينيا؟","options":["18 لداخل الولاية و21 لبين الولايات","21 لداخل الولاية و25 لبين الولايات","16 لداخل الولاية و18 لبين الولايات","18 لكل من داخل الولاية وبين الولايات"],"explanation":"يجب أن يكون عمرك 18 على الأقل للحصول على CDL داخل الولاية و21 على الأقل للحصول على CDL بين الولايات. المصدر: Virginia DMV, CDL Skills Test Eligibility / Apply for a CDL or CLP."},"97":{"q":"الشخص الذي يتقدم بطلب CDL في فرجينيا ولم يسبق له حمل رخصة قيادة أو بطاقة هوية فرجينية يجب أن يقدّم إثباتين لأي من التالي؟","options":["الإقامة في فرجينيا","رقم الضمان الاجتماعي","الوجود القانوني","الهوية"],"explanation":"يجب على المتقدمين لأول مرة في فرجينيا تقديم إثبات واحد للهوية، وإثبات واحد للوجود القانوني، وإثبات واحد لرقم الضمان الاجتماعي، وإثباتين للإقامة في فرجينيا. المصدر: Virginia DMV, Apply for a CDL or CLP."},"98":{"q":"بالنسبة لمعظم السائقين، كم مدة صلاحية رخصة CDL القياسية في فرجينيا قبل وجوب تجديدها؟","options":["8 سنوات، تنتهي في عيد ميلاد الحامل","4 سنوات، تنتهي في عيد ميلاد الحامل","5 سنوات، تنتهي في نهاية العام","10 سنوات، تنتهي في ذكرى تاريخ الإصدار"],"explanation":"رخصة CDL القياسية في فرجينيا صالحة لمدة 8 سنوات وتنتهي في عيد ميلاد الحامل (يحصل السائقون بعمر 75 عامًا أو أكثر على دورة مدتها 5 سنوات). المصدر: Virginia DMV, Renew Your CDL."},"99":{"q":"في فرجينيا، إذا كانت رخصة CDL منتهية الصلاحية أو مخفّضة الدرجة لأكثر من سنة واحدة، فماذا يجب على الحامل فعله لاستعادتها؟","options":["إعادة إجراء كل من اختبار المعرفة واختبار مهارات الطريق لنوع رخصة CDL تلك","مجرد دفع رسوم تأخير والتجديد عبر الإنترنت","إعادة إجراء فحص النظر فقط","الانتظار لفترة احتفاظ إضافية مدتها 14 يومًا فقط"],"explanation":"إذا كانت رخصة CDL في فرجينيا منتهية الصلاحية أو مخفّضة الدرجة لأكثر من سنة واحدة، فيجب على الحامل إعادة إجراء اختبار المعرفة واختبار مهارات الطريق المطلوبين لنوع رخصة CDL التي كان يحملها. المصدر: Virginia DMV, Renew Your CDL."}}};
